INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659184_1', 'Công an thu hơn 500 miếng vàng, 41 siêu xe trong vụ án Mr Pips', 'Quá trình khám xét vụ án Phó Đức Nam, tức Mr Piíp, công an đã thu hơn 48 phương tiện, 500 miếng vàng, gần 2 triệu USD, hàng trăm tỷ đồng cùng nhiều đồng hồ, túi xách hàng hiệu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/3copy-1773925635-1960-1773925674.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=IqvCGFk_3euJaWWjcS9c2Q', '2026-03-19', 'admin', 466, 'TECH', 0, 1, NULL);
