INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659765_27', 'Hóa chất Đức Giang triệu tập họp cổ đông bất thường sau khi chủ tịch bị bắt', 'Sau khi ông Đào Hữu Huyền bị bắt, Hóa chất Đức Giang triệu tập đại hội đồng cổ đông bất thường để bầu bổ sung 3 thành viên HĐQT. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-18-40-6761-7882-1773920509.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hTcTTMDa4_72Myt9L5TAHw', '2026-03-19', 'admin', 387, 'TECH', 1, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659783_28', 'Hà Nội đặt hàng nhà khoa học giải 30 bài toán lớn', 'Danh mục 30 bài toán lớn giai đoạn 2026-2030 được Hà Nội công bố nhằm định hướng chiến lược phát triển, đồng thời mời nhà khoa học, doanh nghiệp và toàn xã hội đề xuất lời giải cho các điểm nghẽn của Thủ đô. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/photrongrung-1773912948-2028-1773913188.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=xQ0roB_ew3FlGN16Cw2rIA', '2026-03-19', 'admin', 610, 'TECH', 0, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659803_29', 'Hoán đổi để có kỳ nghỉ 9 ngày liên tục từ giỗ Tổ Hùng Vương đến 30/4-1/5', 'Việc hoán đổi hai ngày làm việc bình thường tạo thành kỳ nghỉ kéo dài giúp người lao động có thời gian nghỉ ngơi, hồi phục sức khỏe tinh thần. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/capturejpg-1773915207-17739152-9977-1666-1773915250.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LZWcikZksrhg8bm5tJcAOQ', '2026-03-19', 'admin', 59, 'TECH', 1, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659822_30', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-19', 'admin', 927, 'TECH', 1, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659840_31', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-19', 'admin', 826, 'TECH', 0, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659860_32', 'Cựu du học sinh Anh đưa sân khấu kịch đến với khán giả khiếm thị', 'Lương Ngọc Linh, cựu sinh viên Đại học Brighton (Anh), trở thành Quán quân Giải thưởng Study UK Alumni Awards 2026 nhờ nỗ lực giúp cộng đồng người khiếm thị "xem" kịch. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/1-2-1-1773917381-1773917407-6978-1773917453.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZqKadOeHOUgYSPoAKsV02g', '2026-03-19', 'admin', 998, 'TECH', 0, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659877_33', 'Việt Nam phản bác thông tin trong báo cáo tự do tôn giáo của Mỹ', 'Việt Nam cho rằng báo cáo tự do tôn giáo của Mỹ có những đánh giá không khách quan, không chính xác, khẳng định sẽ trao đổi trên tinh thần tôn trọng lẫn nhau. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/npn1-1773914250-1773914265-3055-1773914295.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Q8DQybA1unhPefyJcusdkw', '2026-03-19', 'admin', 971, 'TECH', 0, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659898_34', 'Việt Nam đề nghị các nước Trung Đông hỗ trợ công dân mắc kẹt', 'Việt Nam đề nghị các nước Trung Đông hỗ trợ, tạo điều kiện thuận lợi để những công dân Việt Nam mắc kẹt rời khỏi khu vực bị ảnh hưởng vì chiến sự. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/afp-20260316-a3fh9ep-v2-highre-6799-7738-1773916460.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7ZE5yv4N4MBo0w_lj8Jn_g', '2026-03-19', 'admin', 78, 'TECH', 1, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659918_35', 'Đâm chết người vì nghĩ bị xem thường ''không có tiền uống bia''', 'Cho rằng bị xem thường không có tiền uống bia, Mai Trường Phúc, 28 tuổi về nhà lấy dao quay lại quán đâm người đàn ông tử vong. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/z7636511319019c22c77798e70830b-8030-4337-1773914031.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=S1nZA_FFBnb7xJbHJn9t-g', '2026-03-19', 'admin', 687, 'TECH', 1, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659936_36', 'Tôi không nỡ từ chối lời cầu hôn nhưng không đủ dũng khí cưới anh', 'Nếu cưới, tôi không biết mình có đủ khả năng để cùng anh gánh vác những khó khăn đó hay không. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/GeminiGeneratedImage2mkwm12mkw-8306-3652-1773910899.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=41_hL_isEZ1FPa1A_nE-AQ', '2026-03-19', 'admin', 386, 'TECH', 0, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659954_37', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-19', 'admin', 635, 'TECH', 0, 1, NULL);
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934659974_38', 'Sẹo rỗ nặng do mụn', 'Chị Bình, 42 tuổi, nhiều sẹo rỗ sâu vùng mũi và má do nặn mụn, được bác sĩ điều trị tách đáy sẹo kết hợp vi kim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ba-c-tra-n-la-m-rf-1773906650-2435-6137-1773906761.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VkkZlz2OpWhquWYG-ewRA', '2026-03-19', 'admin', 457, 'TECH', 0, 1, NULL);
