INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_1773934660012_40', 'Cristiano Ronaldo đầu tư 7,5 triệu USD vào Pro2col Technology', 'Cristiano Ronaldo rót 7,5 triệu USD vào Pro2col Technology, mua 10% cổ phần, cùng Herbalife thúc đẩy nền tảng sức khỏe cá nhân hóa dựa trên dữ liệu. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/th-1773913679-1773913688-5532-1773913714.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=OLOgIsUJdJ-0HeNdKv5_6Q', '2026-03-19', 'admin', 57, 'TECH', 0, 1, NULL);
