INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160124394900_33', 'Nhật Bản cấp hơn 8.300 tỷ đồng vốn ODA giúp Việt Nam tăng trưởng xanh', 'Nhật Bản sẽ cho Việt Nam vay ưu đãi 50 tỷ yen, tương đương 8.350 tỷ đồng để hoàn thiện chính sách cấp vốn xanh, dự án giảm phát thải. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/tran-quoc-phuong-1773817455-17-4291-1387-1773818283.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rHuwTPfC-5ynz9sA7-hbhg', '2026-03-20', 'admin', 51, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160139472000_34', 'Mua đúng ''đáy chứng khoán'' có lãi tốt hơn không?', 'Theo nghiên cứu của Dragon Capital, dù mua sớm, muộn hay đúng đáy chứng khoán đều cho ra hiệu suất sinh lời tương đương, với điều kiện đầu tư dài hạn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/thie-t-ke-chu-a-co-te-n-3-1773-7118-5103-1773723765.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=nIMhaqV1rhjsKTPQbYL5aA', '2026-03-20', 'admin', 406, 'BUSINESS', 0, 1, 'Thị trường');
