INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160184121900_37', 'Citigroup hạ dự báo giá Bitcoin', 'Ngân hàng đầu tư Phố Wall Citigroup giảm giá mục tiêu 12 tháng với Bitcoin từ 143.000 USD về còn 112.000 USD do lo ngại về pháp lý tại Mỹ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/108066362-1732206217070-gettyi-4990-7999-1773803219.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ba6Al2VG53qy9aYwHsJiVA', '2026-03-20', 'admin', 198, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160199792800_38', 'Nhiều nông sản rớt giá còn vài nghìn đồng một kg', 'Dư cung, xuất khẩu gặp khó khiến dưa hấu, cam sành tại các hộ trồng chỉ có giá 1.000-5.000 đồng mỗi kg khiến người dân thua lỗ nặng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/dua-1773735477-1773735492-1773-4318-7716-1773735831.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Qx6AMTC3QMwpTxv9B-7c7A', '2026-03-20', 'admin', 111, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160214185400_39', 'CEO Nvidia dự báo doanh thu 1.000 tỷ USD từ đơn hàng chip năm nay', 'CEO Jensen Huang dự báo "suy luận" (Inference) là giai đoạn bùng nổ tiếp theo của AI, mang lại cho Nvidia đơn hàng chip 1.000 tỷ USD vào cuối năm nay. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/iewl3fwmnvlajefmyupvsz4fpi-177-8527-8935-1773755858.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5dfCsK45_ImA2Isl0AMtvg', '2026-03-20', 'admin', 291, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160228123400_40', 'Quyền di trú trong chiến lược quản trị rủi ro của doanh nhân', 'Nhiều doanh nhân xem quyền di trú như một giải pháp giúp tăng khả năng di chuyển quốc tế, mở rộng hoạt động kinh doanh và giảm rủi ro trước những biến động toàn cầu. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/1-1773800262-1773800270-3080-1773800631.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=daXI3CwVNAUEgucxIFbnhg', '2026-03-20', 'admin', 160, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160241586000_41', 'Thủ tướng: Nguồn cung xăng dầu vẫn đảm bảo cho sản xuất, tiêu dùng', 'Thủ tướng Phạm Minh Chính khẳng định xăng dầu, năng lượng vẫn đảm bảo cho sản xuất, tiêu dùng hiện nay và những tháng tới. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/img216417737449072741582666504-3963-1784-1773753761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8NN4QbqVAp58MmX8RcKnBA', '2026-03-20', 'admin', 75, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160255111100_42', 'Doanh nghiệp Mỹ bán được 1 tỷ USD lithium tái chế từ pin thải', 'Nth Cycle sẽ cung cấp nickel và lithium carbonate tái chế từ 12.000 tấn pin cũ cho tập đoàn thương mại Trafigura trong 10 năm, giảm phụ thuộc vào nguồn cung Trung Quốc. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/2022-nth-cycle-team-7618-websi-6916-2430-1773747245.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=MuT2B9X5UWd86NRHPTtRwQ', '2026-03-20', 'admin', 58, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160269050700_43', 'Thị trường chuỗi đồ uống ở Việt Nam quy mô hơn 1,3 tỷ USD', 'Việt Nam có thị trường chuỗi cửa hàng cà phê và trà lớn thứ ba Đông Nam Á, đạt quy mô hơn 1,3 tỷ USD, theo Momentum Works. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/star-1-1773731796-7491-1773732359.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bH05JtfTRLFbl2ZN9IOnMg', '2026-03-20', 'admin', 298, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160282998500_44', 'Đại gia bán lẻ Việt muốn mở thêm 100 điểm bán năm nay', 'Saigon Co.op đặt mục tiêu tăng trưởng doanh thu hai chữ số năm nay, trên nền hơn 32.000 tỷ đồng của năm trước, đồng thời mở thêm gần 100 điểm bán. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/kha-ch-ha-ng-thanh-toa-n-da-ke-7083-9488-1773737673.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VaWSi4O99L7o2dvo6rCLIA', '2026-03-20', 'admin', 227, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160297288300_45', 'Thái Lan có thể mua dầu Nga', 'Phó thủ tướng Thái Lan Phiphat Ratchakitprakarn cho biết nước này đã thảo luận với chính phủ Nga về khả năng mua dầu thô. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/screenshot-2026-03-17-151220-1-7160-7022-1773735273.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wkLqhNbFHoY26LRBjVdPTQ', '2026-03-20', 'admin', 286, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160310967700_46', 'Cổ phiếu Đức Giang bị bán tháo', 'Cổ phiếu Hóa chất Đức Giang bị bán tháo trong một tiếng cuối phiên, chạm sàn 68.800 đồng, sau thông tin Chủ tịch HĐQT Đào Hữu Huyền và con trai bị bắt. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/ckdolua1-1773736424-1550-1773736430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GN6EtbortEo6RVs_imZHXQ', '2026-03-20', 'admin', 261, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160325602700_47', 'Xem xét cấp tín dụng vượt giới hạn với các dự án lớn ở Hà Nội', 'Ngân hàng Nhà nước đề xuất các nhà băng được cấp tín dụng vượt giới hạn, tối đa 52% vốn tự có, để đáp ứng nhu cầu tài chính khi triển khai dự án trọng điểm tại Thủ đô. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/VPBank-ThanhTung7-4592-1773720816.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=CjGCexCwaR1dY92qU8OfwQ', '2026-03-20', 'admin', 25, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160340364400_48', 'Việt Nam muốn tiếp cận nguồn dầu xuất kho dự trữ của Nhật Bản', 'Thủ tướng Phạm Minh Chính đề xuất Nhật Bản tạo điều kiện cho Việt Nam tiếp cận với nguồn dầu xuất kho dự trữ của nước này bằng hình thức phù hợp. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/img213217737192695542045407866-5944-2295-1773721958.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EophzEWArQm2NSdgutlowQ', '2026-03-20', 'admin', 313, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160355062800_49', 'Giá xăng tại Mỹ lên cao nhất gần 3 năm', 'Người dân Mỹ phải trả thêm 0,2 USD mỗi lít xăng kể từ khi xung đột tại Trung Đông nổ ra, do nguồn cung năng lượng toàn cầu gián đoạn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/screenshot-2026-03-17-105341-1-8354-4775-1773719803.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ikT0LWvOPQ_jeG32sVIWuw', '2026-03-20', 'admin', 392, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160369673900_50', 'Đà Nẵng sắp bán 849 căn nhà ở xã hội giá gần 21 triệu đồng một m2', 'Đà Nẵng chuẩn bị mở bán 849 căn hộ nhà ở xã hội tại khu dân cư Nam cầu Cẩm Lệ, giá khoảng 20,68 triệu đồng mỗi m2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/z7628175738895-5ebeff9745297c0-8089-8988-1773716606.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7IAKtdqybR6vr-ijldoxbQ', '2026-03-20', 'admin', 42, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160384444000_51', 'Nhiều hàng quán tăng giá', 'Sau Tết Nguyên đán, giá nguyên liệu và xăng tăng kéo chi phí vận chuyển, vận hành đi lên, nhiều quán ăn tăng giá 3-50% mỗi món. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/1e2c6f47-4aa0-412f-8146-d0feed-4950-6328-1773705121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xUxQh-lk8IhFI4heb9eGkg', '2026-03-20', 'admin', 469, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160400860700_52', 'Vì sao Bitcoin rớt giá nhanh nhưng cũng sớm phục hồi?', 'Khi có xung đột Trung Đông, Bitcoin lập tức sụt về 63.000 USD nhưng đến nay đã tăng trở lại 17% trong khi nhiều tài sản khác biến động mạnh. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/iran-crypto-1773647275-1773647-8727-4330-1773647568.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xK_ZBM0Fspz6firYs6suaQ', '2026-03-20', 'admin', 311, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160417201500_53', 'AmCham tại Việt Nam hợp nhất', 'Sau hơn 3 thập kỷ hoạt động tại Việt Nam dưới hai chi hội độc lập ở Hà Nội và TP HCM, Hiệp hội Thương mại Mỹ tại Việt Nam (AmCham) đã hợp nhất. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/amcham-1773684676-1773684726-9428-1773684775.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=PqH7YEYTYpoZaP1FHsPwgw', '2026-03-20', 'admin', 436, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160431317700_54', 'Vingroup tuyển 25.000 nhân sự cho đơn vị thi công hạ tầng', 'Các nhân sự có cơ hội được đào tạo bài bản, nhận lương cao và mức đãi ngộ, bảo hiểm đầy đủ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/a2-37-1773738506-1773738621-8171-1773745207.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gj9vHTRcAPpMlww0H_ykYA', '2026-03-20', 'admin', 503, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160446595200_55', 'F88 dự kiến chuyển cổ phiếu sang sàn HoSE', 'F88 trình Đại hội cổ đông xem xét kế hoạch tăng vốn điều lệ thêm 1.365 tỷ đồng và phương án chuyển niêm yết cổ phiếu từ sàn UPCoM sang Sở Giao dịch Chứng khoán TP HCM. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/f882-1773708751-1773708826-2723-1773708858.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Lv_EkZpapzynaM3BRTyhdg', '2026-03-20', 'admin', 468, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160462232600_56', 'VinFast thu hơn 90.000 tỷ đồng năm 2025', 'VinFast ghi nhận doanh thu 90.427 tỷ đồng trong năm 2025, tăng 139% so với thực hiện năm trước đó và cao nhất từ trước đến nay. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/654190570256712047492488528914-9844-7936-1773671864.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4zBctBmn8Sh80UkIcPuNbw', '2026-03-20', 'admin', 174, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160478407800_57', 'Thủ tướng: Xem xét bố trí ngân sách để bình ổn giá xăng dầu', 'Thủ tướng nói Việt Nam dứt khoát không để thiếu xăng dầu và nếu xung đột Trung Đông kéo dài, có thể xem xét bố trí ngân sách hỗ trợ bình ổn giá. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/img212117736648486191135771300-4191-4266-1773667239.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_HuYh0aJT1YGjO3EtaV3JQ', '2026-03-20', 'admin', 381, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_160492961400_58', 'SCB chuẩn bị đấu giá nhà đất, quần áo liên quan bà Trương Mỹ Lan', 'SCB đang tìm đơn vị tư vấn đấu thầu để xử lý 12 loại tài sản liên quan bà Trương Mỹ Lan như bất động sản, ôtô, quần áo, túi xách… (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/toaphuctham-94-JPG-9369-1773660326.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yZ7NnnTrd8y7VXboXlOzIg', '2026-03-20', 'admin', 181, 'BUSINESS', 0, 1, 'Thị trường');
