INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085215_1', 'Hóa chất Đức Giang triệu tập họp cổ đông bất thường sau khi chủ tịch bị bắt', 'Sau khi ông Đào Hữu Huyền bị bắt, Hóa chất Đức Giang triệu tập đại hội đồng cổ đông bất thường để bầu bổ sung 3 thành viên HĐQT. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-18-40-6761-7882-1773920509.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hTcTTMDa4_72Myt9L5TAHw', '2026-03-19', 'admin', 305, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085237_2', 'Bạc thỏi có thể được niêm yết trên Sở Giao dịch hàng hóa Việt Nam', 'Bạc thỏi có thể được niêm yết trên Sở Giao dịch hàng hóa Việt Nam nhằm chuẩn hóa hoạt động và hình thành cơ chế giá minh bạch. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/img0504jpg-1773909495-17739095-1247-7866-1773909897.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yx7FfEG7uI742aluPu6xGQ', '2026-03-19', 'admin', 356, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085259_3', 'Xuất khẩu sầu riêng, tôm hùm sang Trung Quốc tăng vọt', 'Sầu riêng xuất sang Trung Quốc tăng 469%, tôm hùm tăng 65% trong hai tháng đầu năm, trở thành điểm sáng giữa bối cảnh thị trường toàn cầu biến động. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-3-04-3529-3779-1773907667.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fMRVQUUmp7qJg6CEW52Y9g', '2026-03-19', 'admin', 72, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085280_4', 'Giá khí đốt châu Âu tăng hơn 30%', 'Các vụ tấn công liên tiếp vào hạ tầng năng lượng tại Trung Đông khiến giá khí đốt tại châu Âu tăng mạnh ngày 19/3. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/image-1773909826816-1773909842-3889-4639-1773909999.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=05miOxjfl32MKz6tV2QsVA', '2026-03-19', 'admin', 285, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085297_5', 'Nhóm Nutifood thành cổ đông lớn nhất Chứng khoán Rồng Việt', 'Thông qua hai công ty con, trong đó có Kido Foods, nhóm Nutifood trở thành cổ đông lớn nhất tại Chứng khoán Rồng Việt khi sở hữu gần 25% vốn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/a-nh-settop-vnexpress-17738968-5143-7261-1773896942.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ki4nAC9Jii9gAqvOZ9wShg', '2026-03-19', 'admin', 498, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085312_6', 'Cổ phiếu bất động sản đỡ thị trường', 'Chứng khoán điều chỉnh khi VN-Index sụt gần 15 điểm, nhưng các cổ phiếu bất động sản như VPL, NVL hay VHM ngược dòng giúp thị trường không giảm sâu. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/chungkhoan-10-jpg-1773908804-3507-1773908811.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kTOxXtgZZTHL1Xzp-Ig3Dg', '2026-03-19', 'admin', 430, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085332_7', 'Kinh Bắc lãi hơn 300 tỷ đồng khi mua tòa nhà trên đất vàng Láng Hạ', 'Tổng công ty Phát triển Đô thị Kinh Bắc ghi nhận khoản lãi 327 tỷ đồng nhờ mua 99% vốn của chủ đầu tư dự án tòa nhà 28 tầng tại Láng Hạ, Hà Nội. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/1alangha1766461709176646181324-2704-4395-1773905654.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=l6_27Xr1jGZzWSGmdwKUMQ', '2026-03-19', 'admin', 383, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085346_8', 'Việt Nam thí điểm phân bổ hạn ngạch phát thải cho 110 cơ sở', 'Bộ Nông nghiệp và Môi trường bắt đầu thí điểm phân bổ hạn ngạch phát thải khí nhà kính cho 110 cơ sở thuộc ba ngành phát thải lớn gồm thép, xi măng, nhiệt điện. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/huy-5340-1773902258-9942-1773902267.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OJV2ttrDjCZmQtBz-bckOQ', '2026-03-19', 'admin', 477, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936085358_9', 'Rủi ro từ vụ tập kích của Iran vào cơ sở LNG lớn nhất thế giới', 'Việc Iran tấn công cơ sở khí đốt của Qatar là bước leo thang mới trong xung đột, có thể khiến giá khí đốt châu Âu và châu Á neo ở mức cao lâu hơn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/2026-03-03t195914z-1772567949-1534-5006-1773894095.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gV6UKdnaFI9Q5uOLJvYOcg', '2026-03-19', 'admin', 336, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936120946_0', 'Vàng, bạc thế giới tiếp tục bị bán tháo', 'Giá vàng thế giới giảm hơn 200 USD tối 19/3, trong khi bạc mất hơn 6 USD, xuống thấp nhất hơn một tháng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/silvergold-1773923872-8836-1773923881.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qIQ_YqPFWnysRVhu1-cS0A', '2026-03-19', 'admin', 402, 'BUSINESS', 1, 1, 'Thị trường');
