INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936509520_8', 'Việt Nam thí điểm phân bổ hạn ngạch phát thải cho 110 cơ sở', 'Bộ Nông nghiệp và Môi trường bắt đầu thí điểm phân bổ hạn ngạch phát thải khí nhà kính cho 110 cơ sở thuộc ba ngành phát thải lớn gồm thép, xi măng, nhiệt điện. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/huy-5340-1773902258-9942-1773902267.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OJV2ttrDjCZmQtBz-bckOQ', '2026-03-19', 'admin', 70, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936509534_9', 'Rủi ro từ vụ tập kích của Iran vào cơ sở LNG lớn nhất thế giới', 'Việc Iran tấn công cơ sở khí đốt của Qatar là bước leo thang mới trong xung đột, có thể khiến giá khí đốt châu Âu và châu Á neo ở mức cao lâu hơn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/2026-03-03t195914z-1772567949-1534-5006-1773894095.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gV6UKdnaFI9Q5uOLJvYOcg', '2026-03-19', 'admin', 178, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936729907_0', 'Giá xăng tăng hơn 5.100 đồng', 'Giá xăng RON 95-III từ 23h ngày 19/3 tăng lên 30.690 đồng một lít, dầu diesel ở mức 30.420 đồng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/dsc3091copy-1773903072-1773903-4508-4186-1773903182.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qsUvPbqLrMYVGgviw2A3rg', '2026-03-19', 'admin', 460, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936729930_1', 'Vàng, bạc thế giới tiếp tục bị bán tháo', 'Giá vàng thế giới giảm hơn 200 USD tối 19/3, trong khi bạc mất hơn 6 USD, xuống thấp nhất hơn một tháng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/silvergold-1773923872-8836-1773923881.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qIQ_YqPFWnysRVhu1-cS0A', '2026-03-19', 'admin', 199, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936729952_2', 'Hóa chất Đức Giang triệu tập họp cổ đông bất thường sau khi chủ tịch bị bắt', 'Sau khi ông Đào Hữu Huyền bị bắt, Hóa chất Đức Giang triệu tập đại hội đồng cổ đông bất thường để bầu bổ sung 3 thành viên HĐQT. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-18-40-6761-7882-1773920509.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hTcTTMDa4_72Myt9L5TAHw', '2026-03-19', 'admin', 478, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936729978_3', 'Bạc thỏi có thể được niêm yết trên Sở Giao dịch hàng hóa Việt Nam', 'Bạc thỏi có thể được niêm yết trên Sở Giao dịch hàng hóa Việt Nam nhằm chuẩn hóa hoạt động và hình thành cơ chế giá minh bạch. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/img0504jpg-1773909495-17739095-1247-7866-1773909897.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yx7FfEG7uI742aluPu6xGQ', '2026-03-19', 'admin', 414, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936730002_4', 'Xuất khẩu sầu riêng, tôm hùm sang Trung Quốc tăng vọt', 'Sầu riêng xuất sang Trung Quốc tăng 469%, tôm hùm tăng 65% trong hai tháng đầu năm, trở thành điểm sáng giữa bối cảnh thị trường toàn cầu biến động. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-3-04-3529-3779-1773907667.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fMRVQUUmp7qJg6CEW52Y9g', '2026-03-19', 'admin', 446, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936730026_5', 'Giá khí đốt châu Âu tăng hơn 30%', 'Các vụ tấn công liên tiếp vào hạ tầng năng lượng tại Trung Đông khiến giá khí đốt tại châu Âu tăng mạnh ngày 19/3. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/image-1773909826816-1773909842-3889-4639-1773909999.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=05miOxjfl32MKz6tV2QsVA', '2026-03-19', 'admin', 291, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_1773936730050_6', 'Nhóm Nutifood thành cổ đông lớn nhất Chứng khoán Rồng Việt', 'Thông qua hai công ty con, trong đó có Kido Foods, nhóm Nutifood trở thành cổ đông lớn nhất tại Chứng khoán Rồng Việt khi sở hữu gần 25% vốn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/a-nh-settop-vnexpress-17738968-5143-7261-1773896942.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ki4nAC9Jii9gAqvOZ9wShg', '2026-03-19', 'admin', 353, 'BUSINESS', 0, 1, 'Thị trường');
