INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310294245900_10', 'Tổng thống Sri Lanka kêu gọi người dân ngừng sạc xe điện ban đêm', 'Sri Lanka kêu gọi người dân bỏ thói quen sạc xe điện ban đêm, bởi nguồn điện này chủ yếu từ than và dầu diesel, vốn đang khủng hoảng do xung đột Trung Đông. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/18165722a13bcec-1773887136-177-3883-2630-1773887333.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=nWRndm4ZqOQVKN2ubrW0OA', '2026-03-19', 'admin', 321, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310314429200_11', 'Thủ tướng đề nghị Algeria cung cấp dầu thô, khí đốt cho Việt Nam', 'Thủ tướng Phạm Minh Chính điện đàm với Thủ tướng Algeria, đề nghị hỗ trợ Việt Nam bảo đảm an ninh năng lượng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/z7634120652296811e0c7ceebe2ca4-3791-7190-1773887509.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=CQM7Re_TUKQOo0XaeMfXTw', '2026-03-19', 'admin', 461, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310330789200_12', 'Giá vàng miếng giảm 6 triệu đồng', 'Các thương hiệu giảm giá bán vàng miếng 6 triệu đồng, về 177 triệu đồng một lượng, theo đà đi xuống của thị trường quốc tế. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/viathantai-18-8327-1773887010.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fxieTu9VwqGmDXuXpMhfAQ', '2026-03-19', 'admin', 291, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310349621200_13', 'Giá dầu thế giới tăng cao, vượt 110 USD', 'Hàng loạt cơ sở năng lượng tại Trung Đông bị tấn công, khiến giá dầu thế giới tăng thêm gần 4% sáng 19/3. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/image-1773882365568-1773882605-2859-5713-1773882668.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=wDmqGNOVEK8SdAT1DUAk5A', '2026-03-19', 'admin', 465, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310365481400_14', 'Lãi suất tiết kiệm lên 8% một năm', 'Nhiều ngân hàng nhỏ hiện trả lãi suất tiết kiệm 8% trở lên cho khoản tiền gửi từ 50 triệu đến 100 triệu đồng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/vpbank-thanhtung2-1773823900-1-2536-6750-1773831131.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=FvlM68B7y4b2isKFkaVNvg', '2026-03-19', 'admin', 53, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310380126900_15', 'Fed giữ nguyên lãi suất', 'Cục Dự trữ liên bang Mỹ (Fed) giữ nguyên lãi suất trong phiên họp chính sách thứ 2 từ đầu năm nay, đúng như dự báo của thị trường. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/Powel-1773860095-9007-1773860117.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1ahmbSyPvLjaWjCSCcWgBA', '2026-03-19', 'admin', 245, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310394864200_16', 'Xuất khẩu tôm sang Mỹ giảm sâu', 'Áp lực rào cản thương mại và cước vận tải tăng khiến xuất khẩu tôm Việt sang Mỹ giảm mạnh trong hai tháng đầu năm. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-4-06-6096-3185-1773825036.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lLzI21_kmahNCxiRqvTDNQ', '2026-03-19', 'admin', 20, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310413720700_17', 'Giá xăng tăng có đủ sức kích cầu xe điện?', 'Giá xăng tăng do căng thẳng Trung Đông đang thúc đẩy nhiều khách hàng chuyển sang xe điện, song vẫn cần thời gian để tạo thành xu hướng diện rộng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/2021-10-19t143739z-1779608650-1365-4492-1773827748.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ln-7CX2kgPK_X-qF_M5IgA', '2026-03-19', 'admin', 223, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310428550700_18', 'Bài toán mang về 18,5 tỷ USD của gỗ nội thất Việt', 'Giữa biến động, việc gỗ nội thất đạt mục tiêu xuất khẩu 18,5 tỷ USD phụ thuộc việc đa dạng sản phẩm, thị trường và liên kết chuỗi cung ứng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/expo-1773812247-1773812266-1369-1773812331.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=TVptlxxdPUv1oLziJWQcEQ', '2026-03-19', 'admin', 218, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310442032800_19', 'MB tăng lãi suất tiết kiệm, cho phép rút trước hạn vẫn hưởng lãi', 'MB điều chỉnh lãi suất tiền gửi cao nhất lên 8,4%, cho kỳ hạn từ 6 tháng, đồng thời ra mắt tính năng cho phép khách hàng rút vốn trước hạn nhưng vẫn được hưởng phần lãi tương ứng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/anh-2-transferd-1773895465-177-4744-1732-1773895998.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=kP2SpzkSyG90SpNOT_Tn3A', '2026-03-19', 'admin', 239, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310455158400_20', 'Sun PhuQuoc Airways sắp mở đường bay đến 7 thị trường quốc tế', 'Sun PhuQuoc Airways triển khai chiến lược "Rise to Asia", mở 9 đường bay tới 7 thị trường trọng điểm châu Á, đồng thời thiết lập mạng lưới tổng đại lý (GSA) quốc tế. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/sun-phuquoc-airways-5-17738936-2266-6736-1773893864.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yUr4OvfGj_0aTx7qKu9nWw', '2026-03-19', 'admin', 333, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310468479100_21', 'VIB đặt mục tiêu lợi nhuận 11.550 tỷ trong năm 2026', 'VIB đặt kế hoạch lãi trước thuế 11.550 tỷ, tăng 27% so với 2025, dựa trên việc tối ưu danh mục tài sản, cải thiện biên lợi nhuận và kiểm soát chi phí hoạt động. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/1-3-1773850466-1773850618-5811-1773850743.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oGLFNCViOAJWT4pBFiXZMQ', '2026-03-19', 'admin', 51, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310481711300_22', 'FPT thay đổi cách hạch toán kết quả kinh doanh FPT Telecom', 'Từ năm nay, FPT không cộng gộp doanh thu với FPT Telecom, nhưng lợi nhuận ròng thực tế ghi nhận từ công ty viễn thông này sẽ không đổi. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/Toancanhtoanha2-1773841736-4400-1773841896.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GrT6mO8UPQVBQa0k3DYz8g', '2026-03-19', 'admin', 369, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310494714900_23', 'Giá vàng thế giới giảm mạnh', 'Giá vàng thế giới giảm gần 190 USD, xuống thấp nhất hơn một tháng, do giới đầu tư dự báo Fed giữ nguyên lãi suất thêm một thời gian nữa. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/2026-01-28T135021Z-1008590470-2214-5471-1773838760.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=TKcMS5B41ecQNpmkjdsUsg', '2026-03-19', 'admin', 491, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310508047700_24', 'Lượng xăng dầu nhập khẩu tăng hơn 40% nửa đầu tháng 3', 'Nửa đầu tháng 3, Việt Nam chi gần 492 triệu USD để nhập hơn 533.000 tấn xăng dầu các loại, tăng trên 41% so với cùng kỳ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/xangdau2-1773826043-1773826055-9382-1773827549.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DvAcBG4QR0OF_udIWFapRA', '2026-03-19', 'admin', 253, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310522120000_25', 'ACV bổ nhiệm quyền Chủ tịch Hội đồng quản trị', 'Ông Lê Văn Khiên được giao làm quyền Chủ tịch Hội đồng quản trị, kiêm đại diện pháp luật của Tổng công ty Cảng hàng không Việt Nam (ACV). (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/Anhmanhinh20260318luc162332-17-8232-5374-1773825910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ah6DCu1elbiiN7ik9rlCTw', '2026-03-19', 'admin', 494, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310539792500_26', 'Giá xăng tại Nhật Bản lên kỷ lục', 'Giá xăng bán lẻ tại Nhật Bản lên mức cao nhất đến nay, khi xung đột tại Trung Đông khiến giá năng lượng toàn cầu leo thang. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/2026-03-15t163624z-374434068-m-7511-1627-1773825538.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zSV0QnpzpKxnUR60h6FFVw', '2026-03-19', 'admin', 334, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310556079200_27', 'Nhà đầu tư nước ngoài liên tục xả cổ phiếu', 'Khối ngoại bán ròng 5 phiên liên tiếp với tổng giá trị hơn 5.000 tỷ đồng trong lúc VN-Index có dấu hiệu hồi phục sau nhịp điều chỉnh mạnh bởi xung đột Trung Đông. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/chungkhoan-17-JPG-2341-1773825107.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zi0Bg3Zxqs03zUERq31NJg', '2026-03-19', 'admin', 110, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310570111700_28', 'Nhật Bản cấp hơn 8.300 tỷ đồng vốn ODA giúp Việt Nam tăng trưởng xanh', 'Nhật Bản sẽ cho Việt Nam vay ưu đãi 50 tỷ yen, tương đương 8.350 tỷ đồng để hoàn thiện chính sách cấp vốn xanh, dự án giảm phát thải. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/tran-quoc-phuong-1773817455-17-4291-1387-1773818283.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rHuwTPfC-5ynz9sA7-hbhg', '2026-03-19', 'admin', 31, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310583045200_29', 'Mua đúng ''đáy chứng khoán'' có lãi tốt hơn không?', 'Theo nghiên cứu của Dragon Capital, dù mua sớm, muộn hay đúng đáy chứng khoán đều cho ra hiệu suất sinh lời tương đương, với điều kiện đầu tư dài hạn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/thie-t-ke-chu-a-co-te-n-3-1773-7118-5103-1773723765.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=nIMhaqV1rhjsKTPQbYL5aA', '2026-03-19', 'admin', 434, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310596316600_30', 'Sacombank muốn đổi tên', 'Sacombank sẽ trình cổ đông phương án đổi tên từ Ngân hàng Sài Gòn Thương Tín thành Ngân hàng Sài Gòn Tài Lộc. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/Sacombank-1773810424-8290-1773810481.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ri_R6m6Q_iyZT-SWns-9eA', '2026-03-19', 'admin', 316, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310609460300_31', 'Tuyến vận chuyển dầu thay Hormuz đối mặt rủi ro bởi xung đột Trung Đông', 'Tàu đi qua Biển Đỏ có nguy cơ bị tấn công, làm dấy lên lo ngại nguồn cung toàn cầu càng siết chặt và giá dầu tiếp tục tăng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/imgi-73-66g5h7m2zzjkrf43fzk73k-4233-6340-1773806705.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tvKZZwgmRYeEPrv-hM2UZQ', '2026-03-19', 'admin', 42, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310628857500_32', 'Citigroup hạ dự báo giá Bitcoin', 'Ngân hàng đầu tư Phố Wall Citigroup giảm giá mục tiêu 12 tháng với Bitcoin từ 143.000 USD về còn 112.000 USD do lo ngại về pháp lý tại Mỹ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/108066362-1732206217070-gettyi-4990-7999-1773803219.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ba6Al2VG53qy9aYwHsJiVA', '2026-03-19', 'admin', 267, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310648724800_33', 'Nhiều nông sản rớt giá còn vài nghìn đồng một kg', 'Dư cung, xuất khẩu gặp khó khiến dưa hấu, cam sành tại các hộ trồng chỉ có giá 1.000-5.000 đồng mỗi kg khiến người dân thua lỗ nặng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/dua-1773735477-1773735492-1773-4318-7716-1773735831.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Qx6AMTC3QMwpTxv9B-7c7A', '2026-03-19', 'admin', 123, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310669127400_34', 'CEO Nvidia dự báo doanh thu 1.000 tỷ USD từ đơn hàng chip năm nay', 'CEO Jensen Huang dự báo "suy luận" (Inference) là giai đoạn bùng nổ tiếp theo của AI, mang lại cho Nvidia đơn hàng chip 1.000 tỷ USD vào cuối năm nay. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/iewl3fwmnvlajefmyupvsz4fpi-177-8527-8935-1773755858.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5dfCsK45_ImA2Isl0AMtvg', '2026-03-19', 'admin', 180, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310687970700_35', 'Quyền di trú trong chiến lược quản trị rủi ro của doanh nhân', 'Nhiều doanh nhân xem quyền di trú như một giải pháp giúp tăng khả năng di chuyển quốc tế, mở rộng hoạt động kinh doanh và giảm rủi ro trước những biến động toàn cầu. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/1-1773800262-1773800270-3080-1773800631.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=daXI3CwVNAUEgucxIFbnhg', '2026-03-19', 'admin', 461, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310704642500_36', 'Thủ tướng: Nguồn cung xăng dầu vẫn đảm bảo cho sản xuất, tiêu dùng', 'Thủ tướng Phạm Minh Chính khẳng định xăng dầu, năng lượng vẫn đảm bảo cho sản xuất, tiêu dùng hiện nay và những tháng tới. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/img216417737449072741582666504-3963-1784-1773753761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8NN4QbqVAp58MmX8RcKnBA', '2026-03-19', 'admin', 33, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310722203100_37', 'Doanh nghiệp Mỹ bán được 1 tỷ USD lithium tái chế từ pin thải', 'Nth Cycle sẽ cung cấp nickel và lithium carbonate tái chế từ 12.000 tấn pin cũ cho tập đoàn thương mại Trafigura trong 10 năm, giảm phụ thuộc vào nguồn cung Trung Quốc. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/2022-nth-cycle-team-7618-websi-6916-2430-1773747245.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=MuT2B9X5UWd86NRHPTtRwQ', '2026-03-19', 'admin', 284, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310736641400_38', 'Thị trường chuỗi đồ uống ở Việt Nam quy mô hơn 1,3 tỷ USD', 'Việt Nam có thị trường chuỗi cửa hàng cà phê và trà lớn thứ ba Đông Nam Á, đạt quy mô hơn 1,3 tỷ USD, theo Momentum Works. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/star-1-1773731796-7491-1773732359.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bH05JtfTRLFbl2ZN9IOnMg', '2026-03-19', 'admin', 118, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310751382500_39', 'Đại gia bán lẻ Việt muốn mở thêm 100 điểm bán năm nay', 'Saigon Co.op đặt mục tiêu tăng trưởng doanh thu hai chữ số năm nay, trên nền hơn 32.000 tỷ đồng của năm trước, đồng thời mở thêm gần 100 điểm bán. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/kha-ch-ha-ng-thanh-toa-n-da-ke-7083-9488-1773737673.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VaWSi4O99L7o2dvo6rCLIA', '2026-03-19', 'admin', 230, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310764875300_40', 'Thái Lan có thể mua dầu Nga', 'Phó thủ tướng Thái Lan Phiphat Ratchakitprakarn cho biết nước này đã thảo luận với chính phủ Nga về khả năng mua dầu thô. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/screenshot-2026-03-17-151220-1-7160-7022-1773735273.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wkLqhNbFHoY26LRBjVdPTQ', '2026-03-19', 'admin', 292, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310777324100_41', 'Cổ phiếu Đức Giang bị bán tháo', 'Cổ phiếu Hóa chất Đức Giang bị bán tháo trong một tiếng cuối phiên, chạm sàn 68.800 đồng, sau thông tin Chủ tịch HĐQT Đào Hữu Huyền và con trai bị bắt. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/ckdolua1-1773736424-1550-1773736430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GN6EtbortEo6RVs_imZHXQ', '2026-03-19', 'admin', 347, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310790221700_42', 'Xem xét cấp tín dụng vượt giới hạn với các dự án lớn ở Hà Nội', 'Ngân hàng Nhà nước đề xuất các nhà băng được cấp tín dụng vượt giới hạn, tối đa 52% vốn tự có, để đáp ứng nhu cầu tài chính khi triển khai dự án trọng điểm tại Thủ đô. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/VPBank-ThanhTung7-4592-1773720816.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=CjGCexCwaR1dY92qU8OfwQ', '2026-03-19', 'admin', 40, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310803057400_43', 'Việt Nam muốn tiếp cận nguồn dầu xuất kho dự trữ của Nhật Bản', 'Thủ tướng Phạm Minh Chính đề xuất Nhật Bản tạo điều kiện cho Việt Nam tiếp cận với nguồn dầu xuất kho dự trữ của nước này bằng hình thức phù hợp. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/img213217737192695542045407866-5944-2295-1773721958.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EophzEWArQm2NSdgutlowQ', '2026-03-19', 'admin', 64, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310817297300_44', 'Giá xăng tại Mỹ lên cao nhất gần 3 năm', 'Người dân Mỹ phải trả thêm 0,2 USD mỗi lít xăng kể từ khi xung đột tại Trung Đông nổ ra, do nguồn cung năng lượng toàn cầu gián đoạn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/screenshot-2026-03-17-105341-1-8354-4775-1773719803.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ikT0LWvOPQ_jeG32sVIWuw', '2026-03-19', 'admin', 501, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310830294200_45', 'Đà Nẵng sắp bán 849 căn nhà ở xã hội giá gần 21 triệu đồng một m2', 'Đà Nẵng chuẩn bị mở bán 849 căn hộ nhà ở xã hội tại khu dân cư Nam cầu Cẩm Lệ, giá khoảng 20,68 triệu đồng mỗi m2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/z7628175738895-5ebeff9745297c0-8089-8988-1773716606.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7IAKtdqybR6vr-ijldoxbQ', '2026-03-19', 'admin', 473, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310843594400_46', 'Nhiều hàng quán tăng giá', 'Sau Tết Nguyên đán, giá nguyên liệu và xăng tăng kéo chi phí vận chuyển, vận hành đi lên, nhiều quán ăn tăng giá 3-50% mỗi món. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/1e2c6f47-4aa0-412f-8146-d0feed-4950-6328-1773705121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xUxQh-lk8IhFI4heb9eGkg', '2026-03-19', 'admin', 133, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310859390600_47', 'Vì sao Bitcoin rớt giá nhanh nhưng cũng sớm phục hồi?', 'Khi có xung đột Trung Đông, Bitcoin lập tức sụt về 63.000 USD nhưng đến nay đã tăng trở lại 17% trong khi nhiều tài sản khác biến động mạnh. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/iran-crypto-1773647275-1773647-8727-4330-1773647568.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xK_ZBM0Fspz6firYs6suaQ', '2026-03-19', 'admin', 123, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310875525900_48', 'AmCham tại Việt Nam hợp nhất', 'Sau hơn 3 thập kỷ hoạt động tại Việt Nam dưới hai chi hội độc lập ở Hà Nội và TP HCM, Hiệp hội Thương mại Mỹ tại Việt Nam (AmCham) đã hợp nhất. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/amcham-1773684676-1773684726-9428-1773684775.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=PqH7YEYTYpoZaP1FHsPwgw', '2026-03-19', 'admin', 396, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310890264500_49', 'Vingroup tuyển 25.000 nhân sự cho đơn vị thi công hạ tầng', 'Các nhân sự có cơ hội được đào tạo bài bản, nhận lương cao và mức đãi ngộ, bảo hiểm đầy đủ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/a2-37-1773738506-1773738621-8171-1773745207.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gj9vHTRcAPpMlww0H_ykYA', '2026-03-19', 'admin', 175, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310904752200_50', 'F88 dự kiến chuyển cổ phiếu sang sàn HoSE', 'F88 trình Đại hội cổ đông xem xét kế hoạch tăng vốn điều lệ thêm 1.365 tỷ đồng và phương án chuyển niêm yết cổ phiếu từ sàn UPCoM sang Sở Giao dịch Chứng khoán TP HCM. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/f882-1773708751-1773708826-2723-1773708858.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Lv_EkZpapzynaM3BRTyhdg', '2026-03-19', 'admin', 177, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310919100600_51', 'VinFast thu hơn 90.000 tỷ đồng năm 2025', 'VinFast ghi nhận doanh thu 90.427 tỷ đồng trong năm 2025, tăng 139% so với thực hiện năm trước đó và cao nhất từ trước đến nay. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/654190570256712047492488528914-9844-7936-1773671864.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4zBctBmn8Sh80UkIcPuNbw', '2026-03-19', 'admin', 397, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310933821700_52', 'Thủ tướng: Xem xét bố trí ngân sách để bình ổn giá xăng dầu', 'Thủ tướng nói Việt Nam dứt khoát không để thiếu xăng dầu và nếu xung đột Trung Đông kéo dài, có thể xem xét bố trí ngân sách hỗ trợ bình ổn giá. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/img212117736648486191135771300-4191-4266-1773667239.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_HuYh0aJT1YGjO3EtaV3JQ', '2026-03-19', 'admin', 137, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21310947120600_53', 'SCB chuẩn bị đấu giá nhà đất, quần áo liên quan bà Trương Mỹ Lan', 'SCB đang tìm đơn vị tư vấn đấu thầu để xử lý 12 loại tài sản liên quan bà Trương Mỹ Lan như bất động sản, ôtô, quần áo, túi xách… (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/toaphuctham-94-JPG-9369-1773660326.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yZ7NnnTrd8y7VXboXlOzIg', '2026-03-19', 'admin', 463, 'BUSINESS', 0, 1, 'Thị trường');
