INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_21311016394700_57', 'Vinaconex muốn bán 18% vốn công ty con', 'Vinaconex đăng ký bán 18% vốn của Viwaseen, công ty trong hệ sinh thái, sau khi giá cổ phiếu doanh nghiệp này tăng gần gấp 3 lần trong 7 phiên. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/vinaconex156402238714721564022-5828-1244-1773650326.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=9cyCHnlWLnLN0rzhg7x59Q', '2026-03-19', 'admin', 58, 'BUSINESS', 0, 1, 'Thị trường');
