INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_3538512484900_56', 'Vingroup tuyển 25.000 nhân sự cho đơn vị thi công hạ tầng', 'Các nhân sự có cơ hội được đào tạo bài bản, nhận lương cao và mức đãi ngộ, bảo hiểm đầy đủ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/a2-37-1773738506-1773738621-8171-1773745207.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gj9vHTRcAPpMlww0H_ykYA', '2026-03-20', 'admin', 500, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_3538546115000_57', 'F88 dự kiến chuyển cổ phiếu sang sàn HoSE', 'F88 trình Đại hội cổ đông xem xét kế hoạch tăng vốn điều lệ thêm 1.365 tỷ đồng và phương án chuyển niêm yết cổ phiếu từ sàn UPCoM sang Sở Giao dịch Chứng khoán TP HCM. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/f882-1773708751-1773708826-2723-1773708858.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Lv_EkZpapzynaM3BRTyhdg', '2026-03-20', 'admin', 48, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_3538575533200_58', 'VinFast thu hơn 90.000 tỷ đồng năm 2025', 'VinFast ghi nhận doanh thu 90.427 tỷ đồng trong năm 2025, tăng 139% so với thực hiện năm trước đó và cao nhất từ trước đến nay. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/654190570256712047492488528914-9844-7936-1773671864.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4zBctBmn8Sh80UkIcPuNbw', '2026-03-20', 'admin', 14, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_3538600828900_59', 'Thủ tướng: Xem xét bố trí ngân sách để bình ổn giá xăng dầu', 'Thủ tướng nói Việt Nam dứt khoát không để thiếu xăng dầu và nếu xung đột Trung Đông kéo dài, có thể xem xét bố trí ngân sách hỗ trợ bình ổn giá. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/img212117736648486191135771300-4191-4266-1773667239.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_HuYh0aJT1YGjO3EtaV3JQ', '2026-03-20', 'admin', 212, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774046885000_0', '''Cần giảm thuế, phí để ứng phó giá xăng dầu tăng cao''', 'Ngoài chi hàng nghìn tỷ đồng từ Quỹ bình ổn, chuyên gia kiến nghị cần linh hoạt giảm thuế, phí để hạ nhiệt giá xăng dầu, giảm áp lực cho người dân và doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/xangdau-1773824501-1773824640-9892-1773837762.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YPC83zjkrKWwQhMbTKE5oQ', '2026-03-20', 'admin', 350, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774058771700_1', 'Nhà đầu tư trữ tiền mặt với tốc độ nhanh nhất kể từ đại dịch', 'Trước rủi ro xung đột Trung Đông kéo dài, nhiều nhà quản lý tài sản đang gia tăng tỷ trọng tiền mặt với tốc độ nhanh nhất kể từ đại dịch. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/vpbank-thanhtung22-1773925238-2914-4754-1773925346.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=AO3XSohEo-SUbUXsxs1LnA', '2026-03-20', 'admin', 348, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774071832600_2', 'Cách các nước châu Âu đối phó giá xăng tăng', 'Để ứng phó giá xăng tăng, các nước châu Âu chọn cách áp trần, giới hạn tần suất điều chỉnh giá hoặc điều chỉnh cơ chế thuế năng lượng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/2026-03-03t135017z-456600389-m-3545-2625-1773914134.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ytJ1KCcEqbS8ALCoa7Hmzg', '2026-03-20', 'admin', 413, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774085341300_3', 'Từ thẻ chip đầu tiên đến ngân hàng số 17 triệu người dùng', 'Từ những tấm thẻ thanh toán gắn chip đầu tiên năm 1993, Vietcombank từng bước mở rộng hạ tầng công nghệ, đưa nhiều dịch vụ lên nền tảng số, phục vụ hơn 17 triệu khách hàng cá nhân. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/20/v2-1773965973-1773966096-3500-1773966236.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=StPFj_SRZlheDLGHYrrlXA', '2026-03-20', 'admin', 435, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774098696900_4', 'Giá xăng tăng hơn 5.100 đồng', 'Sau 5 ngày giữ nguyên, giá các loại xăng dầu cùng tăng từ 23h ngày 19/3, trong đó RON 95-III đã vượt 30.000 đồng một lít. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/dsc3091copy-1773903072-1773903-1759-8920-1773939223.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hRCmKMxE2-RNzuGzTlr__Q', '2026-03-20', 'admin', 322, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774111727400_5', 'Vàng, bạc thế giới tiếp tục bị bán tháo', 'Giá vàng thế giới có lúc giảm hơn 300 USD tối 19/3, trong khi bạc cũng có thời điểm sụt gần 10 USD, xuống thấp nhất hơn một tháng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/silvergold-1773923872-8836-1773923881.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qIQ_YqPFWnysRVhu1-cS0A', '2026-03-20', 'admin', 42, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774126695500_6', 'Hóa chất Đức Giang triệu tập họp cổ đông bất thường sau khi chủ tịch bị bắt', 'Sau khi ông Đào Hữu Huyền bị bắt, Hóa chất Đức Giang triệu tập đại hội đồng cổ đông bất thường để bầu bổ sung 3 thành viên HĐQT. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-18-40-6761-7882-1773920509.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hTcTTMDa4_72Myt9L5TAHw', '2026-03-20', 'admin', 223, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774139603100_7', 'Bạc thỏi có thể được niêm yết trên Sở Giao dịch hàng hóa Việt Nam', 'Bạc thỏi có thể được niêm yết trên Sở Giao dịch hàng hóa Việt Nam nhằm chuẩn hóa hoạt động và hình thành cơ chế giá minh bạch. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/img0504jpg-1773909495-17739095-1247-7866-1773909897.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yx7FfEG7uI742aluPu6xGQ', '2026-03-20', 'admin', 449, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774153286700_8', 'Xuất khẩu sầu riêng, tôm hùm sang Trung Quốc tăng vọt', 'Sầu riêng xuất sang Trung Quốc tăng 469%, tôm hùm tăng 65% trong hai tháng đầu năm, trở thành điểm sáng giữa bối cảnh thị trường toàn cầu biến động. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-3-04-3529-3779-1773907667.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fMRVQUUmp7qJg6CEW52Y9g', '2026-03-20', 'admin', 128, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774167126000_9', 'Giá khí đốt châu Âu tăng hơn 30%', 'Các vụ tấn công liên tiếp vào hạ tầng năng lượng tại Trung Đông khiến giá khí đốt tại châu Âu tăng mạnh ngày 19/3. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/image-1773909826816-1773909842-3889-4639-1773909999.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=05miOxjfl32MKz6tV2QsVA', '2026-03-20', 'admin', 23, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774181213700_10', 'Nhóm Nutifood thành cổ đông lớn nhất Chứng khoán Rồng Việt', 'Thông qua hai công ty con, trong đó có Kido Foods, nhóm Nutifood trở thành cổ đông lớn nhất tại Chứng khoán Rồng Việt khi sở hữu gần 25% vốn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/a-nh-settop-vnexpress-17738968-5143-7261-1773896942.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ki4nAC9Jii9gAqvOZ9wShg', '2026-03-20', 'admin', 112, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774197212800_11', 'Cổ phiếu bất động sản đỡ thị trường', 'Chứng khoán điều chỉnh khi VN-Index sụt gần 15 điểm, nhưng các cổ phiếu bất động sản như VPL, NVL hay VHM ngược dòng giúp thị trường không giảm sâu. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/chungkhoan-10-jpg-1773908804-3507-1773908811.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kTOxXtgZZTHL1Xzp-Ig3Dg', '2026-03-20', 'admin', 194, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774211016700_12', 'Kinh Bắc lãi hơn 300 tỷ đồng khi mua tòa nhà trên đất vàng Láng Hạ', 'Tổng công ty Phát triển Đô thị Kinh Bắc ghi nhận khoản lãi 327 tỷ đồng nhờ mua 99% vốn của chủ đầu tư dự án tòa nhà 28 tầng tại Láng Hạ, Hà Nội. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/1alangha1766461709176646181324-2704-4395-1773905654.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=l6_27Xr1jGZzWSGmdwKUMQ', '2026-03-20', 'admin', 143, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774226001400_13', 'Việt Nam thí điểm phân bổ hạn ngạch phát thải cho 110 cơ sở', 'Bộ Nông nghiệp và Môi trường bắt đầu thí điểm phân bổ hạn ngạch phát thải khí nhà kính cho 110 cơ sở thuộc ba ngành phát thải lớn gồm thép, xi măng, nhiệt điện. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/huy-5340-1773902258-9942-1773902267.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OJV2ttrDjCZmQtBz-bckOQ', '2026-03-20', 'admin', 103, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774239831500_14', 'Rủi ro từ vụ tập kích của Iran vào cơ sở LNG lớn nhất thế giới', 'Việc Iran tấn công cơ sở khí đốt của Qatar là bước leo thang mới trong xung đột, có thể khiến giá khí đốt châu Âu và châu Á neo ở mức cao lâu hơn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/2026-03-03t195914z-1772567949-1534-5006-1773894095.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gV6UKdnaFI9Q5uOLJvYOcg', '2026-03-20', 'admin', 423, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774253743000_15', 'Tổng thống Sri Lanka kêu gọi người dân ngừng sạc xe điện ban đêm', 'Sri Lanka kêu gọi người dân bỏ thói quen sạc xe điện ban đêm, bởi nguồn điện này chủ yếu từ than và dầu diesel, vốn đang khủng hoảng do xung đột Trung Đông. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/18165722a13bcec-1773887136-177-3883-2630-1773887333.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=nWRndm4ZqOQVKN2ubrW0OA', '2026-03-20', 'admin', 323, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774266734300_16', 'Thủ tướng đề nghị Algeria cung cấp dầu thô, khí đốt cho Việt Nam', 'Thủ tướng Phạm Minh Chính điện đàm với Thủ tướng Algeria, đề nghị hỗ trợ Việt Nam bảo đảm an ninh năng lượng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/z7634120652296811e0c7ceebe2ca4-3791-7190-1773887509.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=CQM7Re_TUKQOo0XaeMfXTw', '2026-03-20', 'admin', 18, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774280837300_17', 'Giá vàng miếng giảm 6 triệu đồng', 'Các thương hiệu giảm giá bán vàng miếng 6 triệu đồng, về 177 triệu đồng một lượng, theo đà đi xuống của thị trường quốc tế. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/viathantai-18-8327-1773887010.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fxieTu9VwqGmDXuXpMhfAQ', '2026-03-20', 'admin', 213, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774294633300_18', 'Giá dầu thế giới tăng cao, vượt 110 USD', 'Hàng loạt cơ sở năng lượng tại Trung Đông bị tấn công, khiến giá dầu thế giới tăng thêm gần 4% sáng 19/3. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/image-1773882365568-1773882605-2859-5713-1773882668.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=wDmqGNOVEK8SdAT1DUAk5A', '2026-03-20', 'admin', 108, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774309111700_19', 'Lãi suất tiết kiệm lên 8% một năm', 'Nhiều ngân hàng nhỏ hiện trả lãi suất tiết kiệm 8% trở lên cho khoản tiền gửi từ 50 triệu đến 100 triệu đồng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/vpbank-thanhtung2-1773823900-1-2536-6750-1773831131.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=FvlM68B7y4b2isKFkaVNvg', '2026-03-20', 'admin', 35, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774322813200_20', 'Fed giữ nguyên lãi suất', 'Cục Dự trữ liên bang Mỹ (Fed) giữ nguyên lãi suất trong phiên họp chính sách thứ 2 từ đầu năm nay, đúng như dự báo của thị trường. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/Powel-1773860095-9007-1773860117.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1ahmbSyPvLjaWjCSCcWgBA', '2026-03-20', 'admin', 351, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774336852200_21', 'Xuất khẩu tôm sang Mỹ giảm sâu', 'Áp lực rào cản thương mại và cước vận tải tăng khiến xuất khẩu tôm Việt sang Mỹ giảm mạnh trong hai tháng đầu năm. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-4-06-6096-3185-1773825036.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lLzI21_kmahNCxiRqvTDNQ', '2026-03-20', 'admin', 360, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774349627600_22', 'Giá xăng tăng có đủ sức kích cầu xe điện?', 'Giá xăng tăng do căng thẳng Trung Đông đang thúc đẩy nhiều khách hàng chuyển sang xe điện, song vẫn cần thời gian để tạo thành xu hướng diện rộng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/2021-10-19t143739z-1779608650-1365-4492-1773827748.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ln-7CX2kgPK_X-qF_M5IgA', '2026-03-20', 'admin', 177, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774362706200_23', 'Bài toán mang về 18,5 tỷ USD của gỗ nội thất Việt', 'Giữa biến động, việc gỗ nội thất đạt mục tiêu xuất khẩu 18,5 tỷ USD phụ thuộc việc đa dạng sản phẩm, thị trường và liên kết chuỗi cung ứng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/expo-1773812247-1773812266-1369-1773812331.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=TVptlxxdPUv1oLziJWQcEQ', '2026-03-20', 'admin', 163, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774375384400_24', 'MB tăng lãi suất tiết kiệm, cho phép rút trước hạn vẫn hưởng lãi', 'MB điều chỉnh lãi suất tiền gửi cao nhất lên 8,4%, cho kỳ hạn từ 6 tháng, đồng thời ra mắt tính năng cho phép khách hàng rút vốn trước hạn nhưng vẫn được hưởng phần lãi tương ứng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/anh-2-transferd-1773895465-177-4744-1732-1773895998.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=kP2SpzkSyG90SpNOT_Tn3A', '2026-03-20', 'admin', 313, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774388660700_25', 'Sun PhuQuoc Airways sắp mở đường bay đến 7 thị trường quốc tế', 'Sun PhuQuoc Airways triển khai chiến lược "Rise to Asia", mở 9 đường bay tới 7 thị trường trọng điểm châu Á, đồng thời thiết lập mạng lưới tổng đại lý (GSA) quốc tế. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/19/sun-phuquoc-airways-5-17738936-2266-6736-1773893864.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yUr4OvfGj_0aTx7qKu9nWw', '2026-03-20', 'admin', 195, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774402333900_26', 'VIB đặt mục tiêu lợi nhuận 11.550 tỷ trong năm 2026', 'VIB đặt kế hoạch lãi trước thuế 11.550 tỷ, tăng 27% so với 2025, dựa trên việc tối ưu danh mục tài sản, cải thiện biên lợi nhuận và kiểm soát chi phí hoạt động. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/1-3-1773850466-1773850618-5811-1773850743.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oGLFNCViOAJWT4pBFiXZMQ', '2026-03-20', 'admin', 413, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774415676800_27', 'FPT thay đổi cách hạch toán kết quả kinh doanh FPT Telecom', 'Từ năm nay, FPT không cộng gộp doanh thu với FPT Telecom, nhưng lợi nhuận ròng thực tế ghi nhận từ công ty viễn thông này sẽ không đổi. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/Toancanhtoanha2-1773841736-4400-1773841896.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GrT6mO8UPQVBQa0k3DYz8g', '2026-03-20', 'admin', 342, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774428325400_28', 'Giá vàng thế giới giảm mạnh', 'Giá vàng thế giới giảm gần 190 USD, xuống thấp nhất hơn một tháng, do giới đầu tư dự báo Fed giữ nguyên lãi suất thêm một thời gian nữa. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/2026-01-28T135021Z-1008590470-2214-5471-1773838760.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=TKcMS5B41ecQNpmkjdsUsg', '2026-03-20', 'admin', 416, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774440780800_29', 'Lượng xăng dầu nhập khẩu tăng hơn 40% nửa đầu tháng 3', 'Nửa đầu tháng 3, Việt Nam chi gần 492 triệu USD để nhập hơn 533.000 tấn xăng dầu các loại, tăng trên 41% so với cùng kỳ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/xangdau2-1773826043-1773826055-9382-1773827549.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DvAcBG4QR0OF_udIWFapRA', '2026-03-20', 'admin', 181, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774458089600_30', 'ACV bổ nhiệm quyền Chủ tịch Hội đồng quản trị', 'Ông Lê Văn Khiên được giao làm quyền Chủ tịch Hội đồng quản trị, kiêm đại diện pháp luật của Tổng công ty Cảng hàng không Việt Nam (ACV). (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/Anhmanhinh20260318luc162332-17-8232-5374-1773825910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ah6DCu1elbiiN7ik9rlCTw', '2026-03-20', 'admin', 161, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774475398500_31', 'Giá xăng tại Nhật Bản lên kỷ lục', 'Giá xăng bán lẻ tại Nhật Bản lên mức cao nhất đến nay, khi xung đột tại Trung Đông khiến giá năng lượng toàn cầu leo thang. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/2026-03-15t163624z-374434068-m-7511-1627-1773825538.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zSV0QnpzpKxnUR60h6FFVw', '2026-03-20', 'admin', 328, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774492976500_32', 'Nhà đầu tư nước ngoài liên tục xả cổ phiếu', 'Khối ngoại bán ròng 5 phiên liên tiếp với tổng giá trị hơn 5.000 tỷ đồng trong lúc VN-Index có dấu hiệu hồi phục sau nhịp điều chỉnh mạnh bởi xung đột Trung Đông. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/chungkhoan-17-JPG-2341-1773825107.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zi0Bg3Zxqs03zUERq31NJg', '2026-03-20', 'admin', 274, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774509722900_33', 'Nhật Bản cấp hơn 8.300 tỷ đồng vốn ODA giúp Việt Nam tăng trưởng xanh', 'Nhật Bản sẽ cho Việt Nam vay ưu đãi 50 tỷ yen, tương đương 8.350 tỷ đồng để hoàn thiện chính sách cấp vốn xanh, dự án giảm phát thải. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/tran-quoc-phuong-1773817455-17-4291-1387-1773818283.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rHuwTPfC-5ynz9sA7-hbhg', '2026-03-20', 'admin', 471, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774524663100_34', 'Mua đúng ''đáy chứng khoán'' có lãi tốt hơn không?', 'Theo nghiên cứu của Dragon Capital, dù mua sớm, muộn hay đúng đáy chứng khoán đều cho ra hiệu suất sinh lời tương đương, với điều kiện đầu tư dài hạn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/thie-t-ke-chu-a-co-te-n-3-1773-7118-5103-1773723765.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=nIMhaqV1rhjsKTPQbYL5aA', '2026-03-20', 'admin', 47, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774538451900_35', 'Sacombank muốn đổi tên', 'Sacombank sẽ trình cổ đông phương án đổi tên từ Ngân hàng Sài Gòn Thương Tín thành Ngân hàng Sài Gòn Tài Lộc. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/Sacombank-1773810424-8290-1773810481.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ri_R6m6Q_iyZT-SWns-9eA', '2026-03-20', 'admin', 122, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774552055100_36', 'Tuyến vận chuyển dầu thay Hormuz đối mặt rủi ro bởi xung đột Trung Đông', 'Tàu đi qua Biển Đỏ có nguy cơ bị tấn công, làm dấy lên lo ngại nguồn cung toàn cầu càng siết chặt và giá dầu tiếp tục tăng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/imgi-73-66g5h7m2zzjkrf43fzk73k-4233-6340-1773806705.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tvKZZwgmRYeEPrv-hM2UZQ', '2026-03-20', 'admin', 298, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774565089000_37', 'Citigroup hạ dự báo giá Bitcoin', 'Ngân hàng đầu tư Phố Wall Citigroup giảm giá mục tiêu 12 tháng với Bitcoin từ 143.000 USD về còn 112.000 USD do lo ngại về pháp lý tại Mỹ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/108066362-1732206217070-gettyi-4990-7999-1773803219.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ba6Al2VG53qy9aYwHsJiVA', '2026-03-20', 'admin', 232, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774577632600_38', 'Nhiều nông sản rớt giá còn vài nghìn đồng một kg', 'Dư cung, xuất khẩu gặp khó khiến dưa hấu, cam sành tại các hộ trồng chỉ có giá 1.000-5.000 đồng mỗi kg khiến người dân thua lỗ nặng. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/dua-1773735477-1773735492-1773-4318-7716-1773735831.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Qx6AMTC3QMwpTxv9B-7c7A', '2026-03-20', 'admin', 170, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774590375000_39', 'CEO Nvidia dự báo doanh thu 1.000 tỷ USD từ đơn hàng chip năm nay', 'CEO Jensen Huang dự báo "suy luận" (Inference) là giai đoạn bùng nổ tiếp theo của AI, mang lại cho Nvidia đơn hàng chip 1.000 tỷ USD vào cuối năm nay. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/iewl3fwmnvlajefmyupvsz4fpi-177-8527-8935-1773755858.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5dfCsK45_ImA2Isl0AMtvg', '2026-03-20', 'admin', 210, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774603787900_40', 'Quyền di trú trong chiến lược quản trị rủi ro của doanh nhân', 'Nhiều doanh nhân xem quyền di trú như một giải pháp giúp tăng khả năng di chuyển quốc tế, mở rộng hoạt động kinh doanh và giảm rủi ro trước những biến động toàn cầu. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/18/1-1773800262-1773800270-3080-1773800631.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=daXI3CwVNAUEgucxIFbnhg', '2026-03-20', 'admin', 411, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774616950900_41', 'Thủ tướng: Nguồn cung xăng dầu vẫn đảm bảo cho sản xuất, tiêu dùng', 'Thủ tướng Phạm Minh Chính khẳng định xăng dầu, năng lượng vẫn đảm bảo cho sản xuất, tiêu dùng hiện nay và những tháng tới. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/img216417737449072741582666504-3963-1784-1773753761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8NN4QbqVAp58MmX8RcKnBA', '2026-03-20', 'admin', 282, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774630347000_42', 'Doanh nghiệp Mỹ bán được 1 tỷ USD lithium tái chế từ pin thải', 'Nth Cycle sẽ cung cấp nickel và lithium carbonate tái chế từ 12.000 tấn pin cũ cho tập đoàn thương mại Trafigura trong 10 năm, giảm phụ thuộc vào nguồn cung Trung Quốc. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/2022-nth-cycle-team-7618-websi-6916-2430-1773747245.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=MuT2B9X5UWd86NRHPTtRwQ', '2026-03-20', 'admin', 389, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774643669900_43', 'Thị trường chuỗi đồ uống ở Việt Nam quy mô hơn 1,3 tỷ USD', 'Việt Nam có thị trường chuỗi cửa hàng cà phê và trà lớn thứ ba Đông Nam Á, đạt quy mô hơn 1,3 tỷ USD, theo Momentum Works. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/star-1-1773731796-7491-1773732359.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bH05JtfTRLFbl2ZN9IOnMg', '2026-03-20', 'admin', 335, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774657442900_44', 'Đại gia bán lẻ Việt muốn mở thêm 100 điểm bán năm nay', 'Saigon Co.op đặt mục tiêu tăng trưởng doanh thu hai chữ số năm nay, trên nền hơn 32.000 tỷ đồng của năm trước, đồng thời mở thêm gần 100 điểm bán. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/kha-ch-ha-ng-thanh-toa-n-da-ke-7083-9488-1773737673.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VaWSi4O99L7o2dvo6rCLIA', '2026-03-20', 'admin', 485, 'BUSINESS', 0, 1, 'Thị trường');
