INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774684554000_46', 'Cổ phiếu Đức Giang bị bán tháo', 'Cổ phiếu Hóa chất Đức Giang bị bán tháo trong một tiếng cuối phiên, chạm sàn 68.800 đồng, sau thông tin Chủ tịch HĐQT Đào Hữu Huyền và con trai bị bắt. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/ckdolua1-1773736424-1550-1773736430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GN6EtbortEo6RVs_imZHXQ', '2026-03-20', 'admin', 494, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774697278200_47', 'Xem xét cấp tín dụng vượt giới hạn với các dự án lớn ở Hà Nội', 'Ngân hàng Nhà nước đề xuất các nhà băng được cấp tín dụng vượt giới hạn, tối đa 52% vốn tự có, để đáp ứng nhu cầu tài chính khi triển khai dự án trọng điểm tại Thủ đô. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/VPBank-ThanhTung7-4592-1773720816.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=CjGCexCwaR1dY92qU8OfwQ', '2026-03-20', 'admin', 358, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774709727200_48', 'Việt Nam muốn tiếp cận nguồn dầu xuất kho dự trữ của Nhật Bản', 'Thủ tướng Phạm Minh Chính đề xuất Nhật Bản tạo điều kiện cho Việt Nam tiếp cận với nguồn dầu xuất kho dự trữ của nước này bằng hình thức phù hợp. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/img213217737192695542045407866-5944-2295-1773721958.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EophzEWArQm2NSdgutlowQ', '2026-03-20', 'admin', 335, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774721979500_49', 'Giá xăng tại Mỹ lên cao nhất gần 3 năm', 'Người dân Mỹ phải trả thêm 0,2 USD mỗi lít xăng kể từ khi xung đột tại Trung Đông nổ ra, do nguồn cung năng lượng toàn cầu gián đoạn. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/screenshot-2026-03-17-105341-1-8354-4775-1773719803.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ikT0LWvOPQ_jeG32sVIWuw', '2026-03-20', 'admin', 221, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774734494000_50', 'Đà Nẵng sắp bán 849 căn nhà ở xã hội giá gần 21 triệu đồng một m2', 'Đà Nẵng chuẩn bị mở bán 849 căn hộ nhà ở xã hội tại khu dân cư Nam cầu Cẩm Lệ, giá khoảng 20,68 triệu đồng mỗi m2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/z7628175738895-5ebeff9745297c0-8089-8988-1773716606.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7IAKtdqybR6vr-ijldoxbQ', '2026-03-20', 'admin', 136, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774747297100_51', 'Nhiều hàng quán tăng giá', 'Sau Tết Nguyên đán, giá nguyên liệu và xăng tăng kéo chi phí vận chuyển, vận hành đi lên, nhiều quán ăn tăng giá 3-50% mỗi món. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/1e2c6f47-4aa0-412f-8146-d0feed-4950-6328-1773705121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xUxQh-lk8IhFI4heb9eGkg', '2026-03-20', 'admin', 377, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774760181300_52', 'Vì sao Bitcoin rớt giá nhanh nhưng cũng sớm phục hồi?', 'Khi có xung đột Trung Đông, Bitcoin lập tức sụt về 63.000 USD nhưng đến nay đã tăng trở lại 17% trong khi nhiều tài sản khác biến động mạnh. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/iran-crypto-1773647275-1773647-8727-4330-1773647568.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xK_ZBM0Fspz6firYs6suaQ', '2026-03-20', 'admin', 218, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774772708500_53', 'AmCham tại Việt Nam hợp nhất', 'Sau hơn 3 thập kỷ hoạt động tại Việt Nam dưới hai chi hội độc lập ở Hà Nội và TP HCM, Hiệp hội Thương mại Mỹ tại Việt Nam (AmCham) đã hợp nhất. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/amcham-1773684676-1773684726-9428-1773684775.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=PqH7YEYTYpoZaP1FHsPwgw', '2026-03-20', 'admin', 97, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774785136700_54', 'Vingroup tuyển 25.000 nhân sự cho đơn vị thi công hạ tầng', 'Các nhân sự có cơ hội được đào tạo bài bản, nhận lương cao và mức đãi ngộ, bảo hiểm đầy đủ. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/a2-37-1773738506-1773738621-8171-1773745207.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gj9vHTRcAPpMlww0H_ykYA', '2026-03-20', 'admin', 41, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774798701800_55', 'F88 dự kiến chuyển cổ phiếu sang sàn HoSE', 'F88 trình Đại hội cổ đông xem xét kế hoạch tăng vốn điều lệ thêm 1.365 tỷ đồng và phương án chuyển niêm yết cổ phiếu từ sàn UPCoM sang Sở Giao dịch Chứng khoán TP HCM. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/17/f882-1773708751-1773708826-2723-1773708858.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Lv_EkZpapzynaM3BRTyhdg', '2026-03-20', 'admin', 394, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774811801300_56', 'VinFast thu hơn 90.000 tỷ đồng năm 2025', 'VinFast ghi nhận doanh thu 90.427 tỷ đồng trong năm 2025, tăng 139% so với thực hiện năm trước đó và cao nhất từ trước đến nay. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/654190570256712047492488528914-9844-7936-1773671864.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4zBctBmn8Sh80UkIcPuNbw', '2026-03-20', 'admin', 423, 'BUSINESS', 1, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774824555100_57', 'Thủ tướng: Xem xét bố trí ngân sách để bình ổn giá xăng dầu', 'Thủ tướng nói Việt Nam dứt khoát không để thiếu xăng dầu và nếu xung đột Trung Đông kéo dài, có thể xem xét bố trí ngân sách hỗ trợ bình ổn giá. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/img212117736648486191135771300-4191-4266-1773667239.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_HuYh0aJT1YGjO3EtaV3JQ', '2026-03-20', 'admin', 187, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774837505700_58', 'SCB chuẩn bị đấu giá nhà đất, quần áo liên quan bà Trương Mỹ Lan', 'SCB đang tìm đơn vị tư vấn đấu thầu để xử lý 12 loại tài sản liên quan bà Trương Mỹ Lan như bất động sản, ôtô, quần áo, túi xách… (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/toaphuctham-94-JPG-9369-1773660326.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yZ7NnnTrd8y7VXboXlOzIg', '2026-03-20', 'admin', 154, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_BUSINESS_774850719400_59', 'Trung Quốc tự tin vào nguồn cung năng lượng', 'Bắc Kinh khẳng định nguồn cung năng lượng của nước này đủ đối phó với biến động giá dầu, khí toàn cầu 2 tuần qua. (Nguồn: VNExpress)', 'https://i1-kinhdoanh.vnecdn.net/2026/03/16/china-oil-1773049456-6276-1773-9452-9626-1773653906.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=jEE4G4CowSBSisj-H3JtOA', '2026-03-20', 'admin', 477, 'BUSINESS', 0, 1, 'Thị trường');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1223882779100_0', 'Loạt trang phục gây tranh cãi của Lưu Diệc Phi', 'Diễn viên Lưu Diệc Phi nhiều lần mắc lỗi trang phục khi phối các món đồ không phù hợp với gương mặt và phong cách. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/luu-diec-phi-trang-phuc-gay-tranh-cai-1773739200.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vL_qA_V3bj2KM6ZSjOyb7w', '2026-03-20', 'admin', 119, 'ENTERTAINMENT', 0, 1, 'Showbiz');
