INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1223927577500_2', 'Tiết mục ''Tiếng trống Mê Linh'' của cháu gái Vũ Linh bị tuýt còi', 'Sở Văn hóa, Thể thao TP HCM sẽ xử lý đơn vị tổ chức diễn "Tiếng trống Mê Linh", có Bùm Bum, cháu nghệ sĩ Vũ Linh tham gia, vì tiết mục chưa được cấp phép. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bumbumtop1-1773911292-7344-1773911790.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=krxiAMaZpYDqxqhnesbpHQ', '2026-03-20', 'admin', 92, 'ENTERTAINMENT', 0, 1, 'Showbiz');
