INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1223973294800_4', 'Lý do ''One Battle After Another'' thắng Phim hay nhất Oscar', '"One Battle After Another", Leonardo Dicaprio đóng chính, thắng giải Phim xuất sắc Oscar 2026 nhờ câu chuyện thời sự, cách kể hấp dẫn. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/afp-20260316-a3ep8wx-v1-highre-1761-8406-1773807759.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nLa-Ixheu2BOQAvCPTdvYA', '2026-03-20', 'admin', 365, 'ENTERTAINMENT', 0, 1, 'Showbiz');
