INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224035659200_6', 'Diện quần ngủ dạo phố theo phong cách nhà giàu', 'Diện quần ngủ cùng đồ hiệu đắt đỏ lên phố đang là xu hướng được nhiều người hưởng ứng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/quan-ngu-phoi-do-hieu-phong-cach-nha-giau-1773570324.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GBDk7TkgaKq9nWEKStQ2iA', '2026-03-20', 'admin', 317, 'ENTERTAINMENT', 0, 1, 'Showbiz');
