INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224167319600_11', 'AI tái tạo hình ảnh tài tử Val Kilmer', 'Êkíp phim "As Deep as the Grave" dùng trí tuệ nhân tạo để mô phỏng hình ảnh diễn viên Val Kilmer, một năm sau khi ông qua đời. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/val-kilmer-as-deep-as-the-grav-7952-6701-1773890790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=HFz6t6oFtAb8ziqT_feC4w', '2026-03-20', 'admin', 415, 'ENTERTAINMENT', 0, 1, 'Showbiz');
