INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224584755100_33', 'Khán giả bức xúc khi Oscar cắt phát biểu của êkíp ''Kpop Demon Hunters''', 'Nhiều người cho rằng Oscar thiếu tôn trọng nghệ sĩ khi phát nhạc nền cắt ngang phát biểu nhận giải Ca khúc xuất sắc, cho nhạc phim "Kpop Demon Hunters". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/afp20260316a3eh9flv1highres98t-3879-6547-1773722520.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4UjpX0xp42tkqUhF1us-Jw', '2026-03-20', 'admin', 69, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224600953000_34', 'Dàn ''anh trai, em xinh'' khuấy động concert', 'Ca sĩ Thái Ngân, buitruonglinh, Yeolan, MaiQuinn vừa hát vừa chơi nhạc cụ, được cổ vũ trong concert ''''Anh trai say hi 2025''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/anhtraisayhi-1773716511-177371-3600-2908-1773716952.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-tIZ5NKe2bTv6CQevu8ptw', '2026-03-20', 'admin', 325, 'ENTERTAINMENT', 0, 1, 'Showbiz');
