INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224636794000_36', '''Nàng Bạch Tuyết'' bị trao hai giải Mâm Xôi Vàng', 'Phim "Nàng Bạch Tuyết" (Snow White) bản người đóng nhận hai giải Mâm Xôi Vàng gồm Nhóm diễn viên tệ nhất và Nam phụ tệ nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/1748753987213-i-1773634791-177-5905-9398-1773635220.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VG45Hq9CACZh5cM6pybb8w', '2026-03-20', 'admin', 310, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224654016000_37', 'Fan mang chăn, chiếu ngủ qua đêm chờ xem ''Anh trai say hi''', 'Nhiều khán giả ngủ qua đêm bên ngoài sân vận động Mỹ Đình để có chỗ đứng gần sân khấu concert ''''Anh trai say hi 2025'''' tối nay. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/648851068182607088168626557543-9893-4020-1773635013.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9zuo7kV8KFPDbMs97BM9vw', '2026-03-20', 'admin', 303, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224670620700_38', '''Kpop Demon Hunters'' ghi dấu ấn văn hóa Hàn ở Oscar', '"KPop Demon Hunters", lấy cảm hứng từ văn hóa Kpop Hàn Quốc, thắng giải Phim hoạt hình xuất sắc tại Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/kpop-1773621709-1773621961-6368-1773622008.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0w_IfTdwOqzJm7jsVk58tg', '2026-03-20', 'admin', 351, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224687133500_39', 'Người thân tiễn biệt Kasim Hoàng Vũ', 'Mẹ Kasim Hoàng Vũ - ca sĩ Bích Phương - nhắc lại kỷ niệm với con trai trong lễ tiễn biệt tại nhà quàn Vĩnh Phước, Houston. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/KasimHoangVu-1773623689-5086-1773623872.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=N67_YXNFqPRfFvYEipc1EA', '2026-03-20', 'admin', 308, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224704371500_40', '''One Battle After Another'' của Leonardo Dicaprio - phim hay nhất Oscar 2026', 'Sau gần bốn tiếng ngồi dưới khán phòng nhà hát Dolby theo dõi lễ trao giải, tài tử Leonardo Dicaprio có cơ hội lên sân khấu cùng êkíp nhận tượng vàng Oscar 98 ở hạng mục quan trọng nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/afp-20260316-a3el6nn-v1-highre-3670-9686-1773647770.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iDs0HNwF2k4zDXZS0YEiDw', '2026-03-20', 'admin', 418, 'ENTERTAINMENT', 1, 1, 'Showbiz');
