INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224739549700_42', 'Vợ tỷ phú Jeff Bezos mặc gợi cảm bên dàn sao ở tiệc hậu Oscar', 'Cựu MC Lauren Sánchez diện đầm quây ngực, cùng chồng tỷ phú Jeff Bezos dự tiệc của Hollywood sau lễ trao giải Oscar. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/vo-ty-phu-jeff-bezos-1773647241.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Qt7DYaYpKAHq1l4CvceBA', '2026-03-20', 'admin', 79, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224756685900_43', 'Vợ cũ nói ''tủi nhục'' trong hôn nhân với Mã Cảnh Đào', 'Diễn viên Trung Quốc Ngô Giai Ni cho biết từng ê chề vì phụ thuộc kinh tế Mã Cảnh Đào, dẫn đến hôn nhân tan vỡ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/ni2-1773632282-1773632310-3953-1773632724.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QDCmuHRpj-MQyp-sAbsV8w', '2026-03-20', 'admin', 195, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224772214200_44', 'Những bộ cánh ''thảm họa'' ở Oscar 2026', 'Váy đen như cô dâu ma, đầm hồng neon khiến Chloé Zhao, Maggie O''Farrell mất điểm phong cách trên thảm đỏ Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/batch-tham-hoa-thoi-trang-oscar-1773630547.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s0-c7ASODbCVlKcFdQ_ogw', '2026-03-20', 'admin', 401, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224793231800_45', 'Leonardo DiCaprio đưa bạn gái đến Oscar', 'Leonardo DiCaprio, 52 tuổi, đưa bạn gái 28 tuổi - người mẫu Vittoria Ceretti - đến dự lễ trao giải Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/leonardo-1773625775-6344-17736-3595-5719-1773626508.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=VpiXxkghfN8d4QjmhClBaw', '2026-03-20', 'admin', 17, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224815749300_46', 'Giấc mơ đẹp với ''Đảo ngàn sao''', 'Mình yêu cuốn ''''Đảo ngàn sao'''' vì đã chạm vào một góc rất sâu, lạ lùng trong tâm hồn mình, nơi những cảm xúc không cần gọi tên. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/dao-ngan-sao-1773578499-177357-6108-7455-1773578829.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pgaxeiDg7MLAthRHqzO-UA', '2026-03-20', 'admin', 194, 'ENTERTAINMENT', 0, 1, 'Showbiz');
