INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224849232500_48', 'Lan Phương: ''Tôi tự chữa lành sau ly hôn''', 'Diễn viên Lan Phương cho biết cô bình yên, hạnh phúc khi tập trung chăm sóc bản thân, nuôi dạy hai con, sau khi ly hôn chồng người Anh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/13/lan-phuong-1-1773395226-177339-2870-7140-1773395701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=USiGpJr18gUO_aYEDx6i4g', '2026-03-20', 'admin', 306, 'ENTERTAINMENT', 0, 1, 'Showbiz');
