INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224898244400_51', 'Sức hút của người mẫu gốc Hàn cao 1,78 m', 'Irene Kim, 39 tuổi, đắt show sự kiện, cộng tác loạt thương hiệu xa xỉ nhờ thần thái, gương mặt Á Đông, cách phối đồ tôn chiều cao 1,78 m. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/05/irene-kim-1772678647-1772678711.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JhCq73uffwQCZDMUsnJkmg', '2026-03-20', 'admin', 178, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224914282400_52', 'Oscar 2026 siết chặt an ninh trước giờ G', 'Trong bối cảnh xung đột Trung Đông căng thẳng, Oscar năm nay tăng cường công tác bảo vệ với nhiều lớp an ninh, hệ thống giám sát AI. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/afp-20260314-a3am69y-v1-highre-7596-4807-1773546878.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WlrzLGoyZKd6XkZfKdOIqw', '2026-03-20', 'admin', 362, 'ENTERTAINMENT', 0, 1, 'Showbiz');
