INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1224982076200_56', 'Lan Phương tái xuất với vai lập dị', 'Diễn viên Lan Phương nhập vai một phụ nữ chỉ coi đàn ông là thú tiêu khiển, có những hành động quái dị, ở phim ''''Đồng hồ đếm ngược''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/lanphuong-1773561593-177356161-7425-2697-1773561771.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=FFBEwiW5j3NOlut7PoB1AQ', '2026-03-20', 'admin', 110, 'ENTERTAINMENT', 0, 1, 'Showbiz');
