INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_162920616800_7', '''Bài học diệu kỳ từ chiếc xe rác'' - loại bỏ cảm xúc tiêu cực', 'Sau khi đọc ''''Bài học diệu kỳ từ chiếc xe rác'''', thay vì phàn nàn về khó khăn, tôi học cách tìm giải pháp, mở lòng với thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bai-hoc-dieu-ky-tu-chiec-xe-ra-9462-9872-1773935854.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UyphBgo2oo6qzKdZXpBsBg', '2026-03-20', 'admin', 187, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_162936226800_8', 'Kim Kardashian ngã vì giày ''cà kheo''', 'Mang giày cao 20 cm, ngôi sao truyền hình Kim Kardashian ngã nhào cạnh bụi cây trước giờ vào tiệc hậu Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/dnmi-1773919191-1773919213-6823-1773919221.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vysJW-CgjK1JqOtWQJesKQ', '2026-03-20', 'admin', 387, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_162951712800_9', 'Váy áo cắt xẻ, xuyên thấu của sao ''Squid Game''', 'Jung Ho Yeon - sao Hàn thành hiện tượng toàn cầu nhờ "Squid Game" - theo đuổi mốt váy áo cắt xẻ, xuyên thấu, hở eo và lưng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/jung-ho-yeon-squid-game-16-1773887384-1773887415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8u3I275h3AL7nvJUZdCYuA', '2026-03-20', 'admin', 316, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_162967625500_10', 'AI tái tạo hình ảnh tài tử Val Kilmer', 'Êkíp phim "As Deep as the Grave" dùng trí tuệ nhân tạo để mô phỏng hình ảnh diễn viên Val Kilmer, một năm sau khi ông qua đời. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/val-kilmer-as-deep-as-the-grav-7952-6701-1773890790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=HFz6t6oFtAb8ziqT_feC4w', '2026-03-20', 'admin', 21, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_162985114400_11', '''Doãn Chí Bình'' Trần Khải Thái: Vợ cứu tôi vượt trầm cảm', 'Tài tử Hong Kong Trần Khải Thái, đóng "Thần điêu đại hiệp" 1995, nói biết ơn bạn đời giúp anh vượt qua giai đoạn trầm cảm nặng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/thai3-1773891366-1773891382-6221-1773891745.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LiYdcQf8aZ8S9cnN5aRo5Q', '2026-03-20', 'admin', 379, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163001934500_12', 'Sức hút của Scarlett Johansson - nữ diễn viên kiếm tiền giỏi nhất 2025', 'Scarlett Johansson, diễn viên đứng đầu nhóm sao nữ kiếm tiền giỏi nhất 2025, nổi tiếng với vóc dáng gợi cảm, gu mặc tinh tế. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nu-dien-vien-kiem-tien-gioi-nhat-2025-1773830456.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oWPLgzkvIKfvIwF63iuJFQ', '2026-03-20', 'admin', 173, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163018740000_13', 'Tái diễn vở ballet đương đại ''Dó''', '''''Dó'''' - vở ballet cảm hứng từ giấy dó, kết hợp âm nhạc cổ điển châu Âu và văn hóa Việt - trở lại sau hai năm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/balletdo11-1773822991-17738230-3275-1706-1773823149.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=j-Upd5NjgEFwbkNg46-2TA', '2026-03-20', 'admin', 199, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163033346400_14', '7 kiểu áo có thể khiến bạn trông già đi', 'Áo đính đá, áo ren dày, áo khoác tweed nằm trong nhóm thiết kế khiến bạn như tăng thêm vài tuổi khi mặc. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nhung-kieu-ao-khien-ban-trong-gia-hon-1773832436.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pSMRvahLCRSsVqTX90Cmlg', '2026-03-20', 'admin', 326, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163047908900_15', '''Golden'' - bản Kpop làm nên lịch sử ở Oscar', '"Golden" - nhạc phim hoạt hình "KPop Demon Hunters" - lập kỳ tích khi trở thành ca khúc đầu tiên do người Hàn sản xuất thắng Oscar. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/mntrnhdingolden-1773744150-177-3339-7757-1773747320.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Q3KGZ5aUIo5LCgjI04UlkA', '2026-03-20', 'admin', 375, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163063237100_16', 'Nhạc sĩ Minh Khang xin lỗi sau khi khiếm nhã với tài xế', 'Nhạc sĩ Minh Khang - tác giả ca khúc "Đứa bé" - cho biết do uống nhiều rượu nên có hành vi, lời lẽ khiếm nhã với tài xế khi đi một hãng taxi công nghệ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/514414188-10222804158493103-50-9430-6554-1773825193.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tlkVHX7PDy_bDjHw0YVpNg', '2026-03-20', 'admin', 221, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163078657100_17', 'Chồng diễn viên ''Bích huyết kiếm'' bị phạt tù vì tội hiếp dâm', 'Lương Hiên An, chồng biểu tượng gợi cảm Đài Loan Tiêu Thục Thận, bị tòa tuyên phạt 4 năm 10 tháng tù vì cưỡng dâm một ca sĩ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/tieu3-1773823164-1773823201-4242-1773823450.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=jSt8CJ8DlLFBLQP7sjWS6A', '2026-03-20', 'admin', 42, 'ENTERTAINMENT', 0, 1, 'Showbiz');
