INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163244041400_27', 'Trang phục dạo biển của mỹ nhân ''Bên nhau trọn đời''', 'Gian Nhân Tư, diễn viên Trung Quốc đóng "Bên nhau trọn đời", nhận nhiều lời khen khỏe khoắn với trang phục đi biển. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/gian-4-1773367141-1773740581-1773740610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9tobbpQm0gCiakENyUWMXA', '2026-03-20', 'admin', 57, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163259125700_28', '''Gái nhảy'' Minh Thư tái xuất', 'Minh Thư, diễn viên phim "Gái nhảy", từ Mỹ về nước giữ vai trò sản xuất và đóng chính trong "Tình một đêm" sau 12 năm vắng bóng màn ảnh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/z7629099560897-863a1b21723fbc6-5299-6469-1773729322.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Kd8Ske1B-OKFqo2VU5r1oA', '2026-03-20', 'admin', 461, 'ENTERTAINMENT', 0, 1, 'Showbiz');
