INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163306563200_31', '6 năm ''yêu không cần cưới'' của Lệ Quyên, Lâm Bảo Châu', 'Ca sĩ Lệ Quyên cho biết gắn bó Lâm Bảo Châu bằng sự thấu hiểu, xem sáu năm qua là chặng đường bình yên sau một lần đổ vỡ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/Le-Quyen-Lam-Bao-Chau-25-top1-1773632486.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KctQh_a5niC9XDNOwuXMnA', '2026-03-20', 'admin', 416, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163320975300_32', 'Khán giả bức xúc khi Oscar cắt phát biểu của êkíp ''Kpop Demon Hunters''', 'Nhiều người cho rằng Oscar thiếu tôn trọng nghệ sĩ khi phát nhạc nền cắt ngang phát biểu nhận giải Ca khúc xuất sắc, cho nhạc phim "Kpop Demon Hunters". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/afp20260316a3eh9flv1highres98t-3879-6547-1773722520.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4UjpX0xp42tkqUhF1us-Jw', '2026-03-20', 'admin', 497, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163335732200_33', 'Dàn ''anh trai, em xinh'' khuấy động concert', 'Ca sĩ Thái Ngân, buitruonglinh, Yeolan, MaiQuinn vừa hát vừa chơi nhạc cụ, được cổ vũ trong concert ''''Anh trai say hi 2025''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/anhtraisayhi-1773716511-177371-3600-2908-1773716952.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-tIZ5NKe2bTv6CQevu8ptw', '2026-03-20', 'admin', 452, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163350045000_34', 'Chồng ca nương Kiều Anh đóng MV', 'Doanh nhân Đặng Văn Quỳnh, chồng ca nương Kiều Anh, diễn xuất cùng vợ trong MV "Nhả vía". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/1-a-nh-still-mv-nha-vi-a-ca-nu-1569-6977-1773715915.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eJ6j9i_oZ0xeAqe1MGiojw', '2026-03-20', 'admin', 20, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163364263700_35', '''Nàng Bạch Tuyết'' bị trao hai giải Mâm Xôi Vàng', 'Phim "Nàng Bạch Tuyết" (Snow White) bản người đóng nhận hai giải Mâm Xôi Vàng gồm Nhóm diễn viên tệ nhất và Nam phụ tệ nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/1748753987213-i-1773634791-177-5905-9398-1773635220.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VG45Hq9CACZh5cM6pybb8w', '2026-03-20', 'admin', 398, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163378007200_36', 'Fan mang chăn, chiếu ngủ qua đêm chờ xem ''Anh trai say hi''', 'Nhiều khán giả ngủ qua đêm bên ngoài sân vận động Mỹ Đình để có chỗ đứng gần sân khấu concert ''''Anh trai say hi 2025'''' tối nay. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/648851068182607088168626557543-9893-4020-1773635013.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9zuo7kV8KFPDbMs97BM9vw', '2026-03-20', 'admin', 155, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163391375600_37', '''Kpop Demon Hunters'' ghi dấu ấn văn hóa Hàn ở Oscar', '"KPop Demon Hunters", lấy cảm hứng từ văn hóa Kpop Hàn Quốc, thắng giải Phim hoạt hình xuất sắc tại Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/kpop-1773621709-1773621961-6368-1773622008.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0w_IfTdwOqzJm7jsVk58tg', '2026-03-20', 'admin', 104, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163407037500_38', 'Người thân tiễn biệt Kasim Hoàng Vũ', 'Mẹ Kasim Hoàng Vũ - ca sĩ Bích Phương - nhắc lại kỷ niệm với con trai trong lễ tiễn biệt tại nhà quàn Vĩnh Phước, Houston. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/KasimHoangVu-1773623689-5086-1773623872.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=N67_YXNFqPRfFvYEipc1EA', '2026-03-20', 'admin', 98, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163423412800_39', '''One Battle After Another'' của Leonardo Dicaprio - phim hay nhất Oscar 2026', 'Sau gần bốn tiếng ngồi dưới khán phòng nhà hát Dolby theo dõi lễ trao giải, tài tử Leonardo Dicaprio có cơ hội lên sân khấu cùng êkíp nhận tượng vàng Oscar 98 ở hạng mục quan trọng nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/afp-20260316-a3el6nn-v1-highre-3670-9686-1773647770.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iDs0HNwF2k4zDXZS0YEiDw', '2026-03-20', 'admin', 276, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163438361700_40', 'Những ngôi sao mặc đẹp nhất Oscar 2026', 'Anne Hathaway, Kirsten Dunst, Kate Hudson tỏa sáng trong những bộ đầm dạ hội của các nhà mốt hàng đầu thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/batch-afp-20260315-a3dz7a7-v1-highres-98thannualacademyawardsarrivals-1773649673-1773669775-1773669797.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=7GB6_Q1SaEGjXJBYEawnxw', '2026-03-20', 'admin', 488, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163455104300_41', 'Vợ tỷ phú Jeff Bezos mặc gợi cảm bên dàn sao ở tiệc hậu Oscar', 'Cựu MC Lauren Sánchez diện đầm quây ngực, cùng chồng tỷ phú Jeff Bezos dự tiệc của Hollywood sau lễ trao giải Oscar. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/vo-ty-phu-jeff-bezos-1773647241.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Qt7DYaYpKAHq1l4CvceBA', '2026-03-20', 'admin', 27, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163470234600_42', 'Vợ cũ nói ''tủi nhục'' trong hôn nhân với Mã Cảnh Đào', 'Diễn viên Trung Quốc Ngô Giai Ni cho biết từng ê chề vì phụ thuộc kinh tế Mã Cảnh Đào, dẫn đến hôn nhân tan vỡ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/ni2-1773632282-1773632310-3953-1773632724.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QDCmuHRpj-MQyp-sAbsV8w', '2026-03-20', 'admin', 118, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163485899300_43', 'Những bộ cánh ''thảm họa'' ở Oscar 2026', 'Váy đen như cô dâu ma, đầm hồng neon khiến Chloé Zhao, Maggie O''Farrell mất điểm phong cách trên thảm đỏ Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/batch-tham-hoa-thoi-trang-oscar-1773630547.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s0-c7ASODbCVlKcFdQ_ogw', '2026-03-20', 'admin', 164, 'ENTERTAINMENT', 0, 1, 'Showbiz');
