INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163723471400_57', 'Dàn ''Anh trai say hi'' mùa hai hóa trang hài hước', 'Rapper Gill hóa Bắc Đẩu, CongB đóng nhân vật trong phim "Vườn sao băng", được khán giả yêu thích. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/hermosa-1-1773548798-1773548913.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YPkMB9cp6NILIf-X0JBRaQ', '2026-03-20', 'admin', 64, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163743960100_58', 'Nhóm Quả Dưa Hấu gợi ký ức âm nhạc thập niên 1990', 'Bằng Kiều, Tuấn Hưng, Tú Dưa thể hiện các bản hit thập niên 1990 như "Mặt trời dịu êm", "Hè muộn", trong lần tái hợp sau 28 năm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/du-a-ha-u-1773544470-177354517-7488-9356-1773545273.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yGqBIGbPeZNjB9znvPvtRw', '2026-03-20', 'admin', 57, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_163763280900_59', '''Bugonia'' - hoài nghi về thế giới', 'Đạo diễn Yorgos Lanthimos phản ánh nỗi bất an của nhân loại trong thời đại bùng nổ thông tin, ở "Bugonia" - đề cử Phim hay nhất Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/14/trailers-clips-00-00-55-09-sti-6423-4547-1773486111.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VKe4kS37QxLnnvaW0Npq7A', '2026-03-20', 'admin', 150, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085556_0', 'Diện quần ngủ dạo phố theo phong cách nhà giàu', 'Diện quần ngủ cùng đồ hiệu đắt đỏ lên phố đang là xu hướng được nhiều người hưởng ứng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/quan-ngu-phoi-do-hieu-phong-cach-nha-giau-1773570324.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GBDk7TkgaKq9nWEKStQ2iA', '2026-03-19', 'admin', 51, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085569_1', 'Tiết mục ''Tiếng trống Mê Linh'' của cháu gái Vũ Linh bị tuýt còi', 'Sở Văn hóa, Thể thao TP HCM sẽ xử lý đơn vị tổ chức diễn "Tiếng trống Mê Linh", có Bùm Bum, cháu nghệ sĩ Vũ Linh tham gia, vì tiết mục chưa được cấp phép. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bumbumtop1-1773911292-7344-1773911790.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=krxiAMaZpYDqxqhnesbpHQ', '2026-03-19', 'admin', 494, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085581_2', 'Mốt đeo trang sức của Harper Beckham', 'Harper - con gái út David Beckham - đeo nhiều mẫu vòng của các nhà chế tác hàng đầu như Cartier, Van Cleef &amp; Arpels. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/con-gai-david-beckham-1-1773904643.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u-wK86i_e02YSQ9uZtEW4Q', '2026-03-19', 'admin', 411, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085594_3', 'Lý do ''One Battle After Another'' thắng Phim hay nhất Oscar', '"One Battle After Another", Leonardo Dicaprio đóng chính, thắng giải Phim xuất sắc Oscar 2026 nhờ câu chuyện thời sự, cách kể hấp dẫn. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/afp-20260316-a3ep8wx-v1-highre-1761-8406-1773807759.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nLa-Ixheu2BOQAvCPTdvYA', '2026-03-19', 'admin', 13, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085607_4', 'Chuyện tình của Leonardo DiCaprio và siêu mẫu 28 tuổi', 'Tài tử Leonardo DiCaprio muốn nghiêm túc hơn trong chuyện tình cảm với siêu mẫu Vittoria Ceretti, 28 tuổi, lần đầu đưa cô dự lễ trao giải lớn. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/LeonardoDiCapriovabangai-17738-3657-8958-1773821868.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ExTmirFnYBzfAw_tp4Z7_Q', '2026-03-19', 'admin', 205, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085620_5', 'Elle Fanning thoát hình tượng ''bình hoa di động''', 'Elle Fanning được khen khi hóa thân minh tinh gặp khủng hoảng sự nghiệp trong "Sentimental Value" - Phim quốc tế xuất sắc Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/610688199-18444696403097728-41-2772-4248-1773573805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VntITmMUNz56yEkK2DQ7A', '2026-03-19', 'admin', 263, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085634_6', '''Bài học diệu kỳ từ chiếc xe rác'' - loại bỏ cảm xúc tiêu cực', 'Sau khi đọc ''''Bài học diệu kỳ từ chiếc xe rác'''', thay vì phàn nàn về khó khăn, tôi học cách tìm giải pháp, mở lòng với thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bai-hoc-dieu-ky-tu-chiec-xe-ra-4975-6613-1773917242.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=3eviMs5vo7G_vIEeSYXTgA', '2026-03-19', 'admin', 68, 'ENTERTAINMENT', 0, 1, 'Showbiz');
