INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085661_8', 'Váy áo cắt xẻ, xuyên thấu của sao ''Squid Game''', 'Jung Ho Yeon - sao Hàn thành hiện tượng toàn cầu nhờ "Squid Game" - theo đuổi mốt váy áo cắt xẻ, xuyên thấu, hở eo và lưng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/jung-ho-yeon-squid-game-16-1773887384-1773887415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8u3I275h3AL7nvJUZdCYuA', '2026-03-19', 'admin', 26, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936085677_9', 'AI tái tạo hình ảnh tài tử Val Kilmer', 'Êkíp phim "As Deep as the Grave" dùng trí tuệ nhân tạo để mô phỏng hình ảnh diễn viên Val Kilmer, một năm sau khi ông qua đời. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/val-kilmer-as-deep-as-the-grav-7952-6701-1773890790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=HFz6t6oFtAb8ziqT_feC4w', '2026-03-19', 'admin', 441, 'ENTERTAINMENT', 1, 1, 'Showbiz');
