INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936509854_5', 'Sức hút của Scarlett Johansson - nữ diễn viên kiếm tiền giỏi nhất 2025', 'Scarlett Johansson, diễn viên đứng đầu nhóm sao nữ kiếm tiền giỏi nhất 2025, nổi tiếng với vóc dáng gợi cảm, gu mặc tinh tế. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nu-dien-vien-kiem-tien-gioi-nhat-2025-1773830456.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oWPLgzkvIKfvIwF63iuJFQ', '2026-03-19', 'admin', 10, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936509868_6', 'Lý do ''One Battle After Another'' thắng Phim hay nhất Oscar', '"One Battle After Another", Leonardo Dicaprio đóng chính, thắng giải Phim xuất sắc Oscar 2026 nhờ câu chuyện thời sự, cách kể hấp dẫn. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/afp-20260316-a3ep8wx-v1-highre-1761-8406-1773807759.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nLa-Ixheu2BOQAvCPTdvYA', '2026-03-19', 'admin', 85, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936509883_7', 'Chuyện tình của Leonardo DiCaprio và siêu mẫu 28 tuổi', 'Tài tử Leonardo DiCaprio muốn nghiêm túc hơn trong chuyện tình cảm với siêu mẫu Vittoria Ceretti, 28 tuổi, lần đầu đưa cô dự lễ trao giải lớn. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/LeonardoDiCapriovabangai-17738-3657-8958-1773821868.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ExTmirFnYBzfAw_tp4Z7_Q', '2026-03-19', 'admin', 199, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936509900_8', '''Bài học diệu kỳ từ chiếc xe rác'' - loại bỏ cảm xúc tiêu cực', 'Sau khi đọc ''''Bài học diệu kỳ từ chiếc xe rác'''', thay vì phàn nàn về khó khăn, tôi học cách tìm giải pháp, mở lòng với thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bai-hoc-dieu-ky-tu-chiec-xe-ra-4975-6613-1773917242.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=3eviMs5vo7G_vIEeSYXTgA', '2026-03-19', 'admin', 54, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936509919_9', 'Kim Kardashian ngã vì giày ''cà kheo''', 'Mang giày cao 20 cm, ngôi sao truyền hình Kim Kardashian ngã nhào cạnh bụi cây trước giờ vào tiệc hậu Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/dnmi-1773919191-1773919213-6823-1773919221.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vysJW-CgjK1JqOtWQJesKQ', '2026-03-19', 'admin', 179, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936730533_0', 'Diện quần ngủ dạo phố theo phong cách nhà giàu', 'Diện quần ngủ cùng đồ hiệu đắt đỏ lên phố đang là xu hướng được nhiều người hưởng ứng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/quan-ngu-phoi-do-hieu-phong-cach-nha-giau-1773570324.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GBDk7TkgaKq9nWEKStQ2iA', '2026-03-19', 'admin', 469, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936730551_1', 'Elle Fanning thoát hình tượng ''bình hoa di động''', 'Elle Fanning được khen khi hóa thân minh tinh gặp khủng hoảng sự nghiệp trong "Sentimental Value" - Phim quốc tế xuất sắc Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/610688199-18444696403097728-41-2772-4248-1773573805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VntITmMUNz56yEkK2DQ7A', '2026-03-19', 'admin', 11, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_1773936730569_2', 'Tiết mục ''Tiếng trống Mê Linh'' của cháu gái Vũ Linh bị tuýt còi', 'Sở Văn hóa, Thể thao TP HCM sẽ xử lý đơn vị tổ chức diễn "Tiếng trống Mê Linh", có Bùm Bum, cháu nghệ sĩ Vũ Linh tham gia, vì tiết mục chưa được cấp phép. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bumbumtop1-1773911292-7344-1773911790.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=krxiAMaZpYDqxqhnesbpHQ', '2026-03-19', 'admin', 326, 'ENTERTAINMENT', 0, 1, 'Showbiz');
