INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311744196500_10', 'Váy áo cắt xẻ, xuyên thấu của sao ''Squid Game''', 'Jung Ho Yeon - sao Hàn thành hiện tượng toàn cầu nhờ "Squid Game" - theo đuổi mốt váy áo cắt xẻ, xuyên thấu, hở eo và lưng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/jung-ho-yeon-squid-game-16-1773887384-1773887415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8u3I275h3AL7nvJUZdCYuA', '2026-03-19', 'admin', 386, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311758457000_11', 'AI tái tạo hình ảnh tài tử Val Kilmer', 'Êkíp phim "As Deep as the Grave" dùng trí tuệ nhân tạo để mô phỏng hình ảnh diễn viên Val Kilmer, một năm sau khi ông qua đời. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/val-kilmer-as-deep-as-the-grav-7952-6701-1773890790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=HFz6t6oFtAb8ziqT_feC4w', '2026-03-19', 'admin', 146, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311773371300_12', 'Tái diễn vở ballet đương đại ''Dó''', '''''Dó'''' - vở ballet cảm hứng từ giấy dó, kết hợp âm nhạc cổ điển châu Âu và văn hóa Việt - trở lại sau hai năm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/balletdo11-1773822991-17738230-3275-1706-1773823149.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=j-Upd5NjgEFwbkNg46-2TA', '2026-03-19', 'admin', 81, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311789173400_13', '7 kiểu áo có thể khiến bạn trông già đi', 'Áo đính đá, áo ren dày, áo khoác tweed nằm trong nhóm thiết kế khiến bạn như tăng thêm vài tuổi khi mặc. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nhung-kieu-ao-khien-ban-trong-gia-hon-1773832436.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pSMRvahLCRSsVqTX90Cmlg', '2026-03-19', 'admin', 358, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311807837800_14', '''Golden'' - bản Kpop làm nên lịch sử ở Oscar', '"Golden" - nhạc phim hoạt hình "KPop Demon Hunters" - lập kỳ tích khi trở thành ca khúc đầu tiên do người Hàn sản xuất thắng Oscar. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/mntrnhdingolden-1773744150-177-3339-7757-1773747320.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Q3KGZ5aUIo5LCgjI04UlkA', '2026-03-19', 'admin', 472, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311827260100_15', 'Nhạc sĩ Minh Khang xin lỗi sau khi khiếm nhã với tài xế', 'Nhạc sĩ Minh Khang - tác giả ca khúc "Đứa bé" - cho biết do uống nhiều rượu nên có hành vi, lời lẽ khiếm nhã với tài xế khi đi một hãng taxi công nghệ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/514414188-10222804158493103-50-9430-6554-1773825193.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tlkVHX7PDy_bDjHw0YVpNg', '2026-03-19', 'admin', 30, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311849369900_16', 'Chồng diễn viên ''Bích huyết kiếm'' bị phạt tù vì tội hiếp dâm', 'Lương Hiên An, chồng biểu tượng gợi cảm Đài Loan Tiêu Thục Thận, bị tòa tuyên phạt 4 năm 10 tháng tù vì cưỡng dâm một ca sĩ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/tieu3-1773823164-1773823201-4242-1773823450.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=jSt8CJ8DlLFBLQP7sjWS6A', '2026-03-19', 'admin', 115, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311872057400_17', 'Video AI mô phỏng biểu cảm Trương Mạn Ngọc gây chú ý', 'Diễn viên AI bắt chước biểu cảm của minh tinh Hong Kong Trương Mạn Ngọc, dấy thảo luận về khả năng "nghề diễn biến mất". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/topmanngoc-1773805571-1608-1773806614.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vFrGoIxhu892HKinZdECKA', '2026-03-19', 'admin', 122, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311891676500_18', 'Bức chân dung ngư dân Hội An thắng giải nhiếp ảnh của Anh', 'Bức "Mắt cá" - chụp chân dung ngư dân ở Hội An - giúp một tay máy không chuyên đoạt giải cao nhất cuộc thi nhiếp ảnh tại London, Anh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/fisheye-1773803378-1773803719-4325-1773803810.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8GATWbKTlsBFpkaaAnZJUw', '2026-03-19', 'admin', 37, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311907143900_19', 'Giới làm phim ngắn trở tay không kịp vì ''cơn lốc'' AI', 'Vương Bản Chí đậu phỏng vấn ở công ty sản xuất phim ngắn nhưng vài tuần sau, anh nhận thông báo nghỉ làm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/hoac-jfif-1773720125-177372013-9003-3017-1773720581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hinN42TgFR_8IEIWEKfK1Q', '2026-03-19', 'admin', 449, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311923646200_20', 'Vĩnh Đam thừa nhận diễn đơ', 'Vĩnh Đam - diễn viên "Bus: Chuyến xe một chiều" - nói rút kinh nghiệm khi bị nhận xét diễn "không cảm xúc" trong phim. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/vinhdamt1-1773800678-3531-1773800701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NPcJ7GHXHx2SGwhbGW_iGw', '2026-03-19', 'admin', 366, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311936930800_21', 'Thái Hòa: ''Tôi kiệt sức vì cảnh hành động''', 'Diễn viên Thái Hòa cho biết khi đóng cảnh cứu nạn nhân vụ hỏa hoạn trong phim "Anh Hùng", anh kiệt sức nên rơi từ trên cao xuống đệm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/thaihoatop2-1773659876-4550-1773660213.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VgNbTUtqr5aN9q0I7nGkNw', '2026-03-19', 'admin', 507, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311949810700_22', '''Hãy chăm sóc mẹ''', 'Sau 11 năm, tôi vẫn giữ cuốn ''''Hãy chăm sóc mẹ'''' để nhắc nhở bản thân trân trọng những khoảnh khắc khi còn mẹ ở bên. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/hay-cham-soc-me-jpg-1773761316-5599-7104-1773761819.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ycsgdgrS1-xtmsY6bbM4uA', '2026-03-19', 'admin', 180, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311962450700_23', 'Gwyneth Paltrow gây tranh cãi khi diện váy xẻ cao', 'Minh tinh Gwyneth Paltrow có khoảnh khắc gây tranh cãi khi diện chiếc váy xẻ hai bên thân tại lễ trao giải Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/gwyneth12-1773760817-177376083-6333-6502-1773760849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_J5GbyNjgF8HKQLT0_OLuQ', '2026-03-19', 'admin', 218, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311975338900_24', 'Đạo diễn hoạt hình ''Doraemon'' qua đời', 'Tsutomu Shibayama, nhà làm phim Nhật thực hiện hơn 20 bộ hoạt hình "Doraemon", mất ở tuổi 84 vì bệnh ung thư phổi. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/tsutomushibayamatop-1773759235-6245-1234-1773759256.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=yr9FNuRVBE7oum0tfX0sdA', '2026-03-19', 'admin', 19, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21311987971600_25', 'Thời trang cường điệu trong phim ''Đồi gió hú''', 'Nhân vật Cathy mặc chiếc corset thít chặt cơ thể, khi cô kết hôn với người đàn ông giàu có nhưng không yêu ở phim "Đồi gió hú". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/doi-gio-hu-4-1772445828-7911-1-5593-9032-1773747212.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=P0fH2obJPFeyBDqHPUZFeA', '2026-03-19', 'admin', 423, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312001495000_26', 'Trang phục dạo biển của mỹ nhân ''Bên nhau trọn đời''', 'Gian Nhân Tư, diễn viên Trung Quốc đóng "Bên nhau trọn đời", nhận nhiều lời khen khỏe khoắn với trang phục đi biển. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/gian-4-1773367141-1773740581-1773740610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9tobbpQm0gCiakENyUWMXA', '2026-03-19', 'admin', 390, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312014315200_27', '''Gái nhảy'' Minh Thư tái xuất', 'Minh Thư, diễn viên phim "Gái nhảy", từ Mỹ về nước giữ vai trò sản xuất và đóng chính trong "Tình một đêm" sau 12 năm vắng bóng màn ảnh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/z7629099560897-863a1b21723fbc6-5299-6469-1773729322.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Kd8Ske1B-OKFqo2VU5r1oA', '2026-03-19', 'admin', 100, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312026910700_28', 'Váy của nhà thiết kế Đỗ Long lên sân khấu Oscar', 'Ca sĩ Hàn Quốc Rei Ami diện đầm xuyên thấu do Đỗ Long thiết kế khi hát ở lễ trao giải Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/reiamimacdamdolongsankhauoscar-9220-6422-1773718057.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ViDz7TVDCHMYsKQx-xbMFg', '2026-03-19', 'admin', 84, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312040065200_29', 'Oscar 2026 nỗ lực trẻ hóa', 'Lễ trao giải Oscar 98 tôn vinh điện ảnh với tinh thần trẻ trung, hướng tới khán giả Gen Z qua các màn pha trò và trình diễn âm nhạc. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/afp-20260316-a3ek7d2-v1-highre-2555-7159-1773655530.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=wydd8s6fXX9bP1qXF6j5Ng', '2026-03-19', 'admin', 271, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312053252300_30', '6 năm ''yêu không cần cưới'' của Lệ Quyên, Lâm Bảo Châu', 'Ca sĩ Lệ Quyên cho biết gắn bó Lâm Bảo Châu bằng sự thấu hiểu, xem sáu năm qua là chặng đường bình yên sau một lần đổ vỡ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/Le-Quyen-Lam-Bao-Chau-25-top1-1773632486.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KctQh_a5niC9XDNOwuXMnA', '2026-03-19', 'admin', 292, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312066370000_31', 'Khán giả bức xúc khi Oscar cắt phát biểu của êkíp ''Kpop Demon Hunters''', 'Nhiều người cho rằng Oscar thiếu tôn trọng nghệ sĩ khi phát nhạc nền cắt ngang phát biểu nhận giải Ca khúc xuất sắc, cho nhạc phim "Kpop Demon Hunters". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/afp20260316a3eh9flv1highres98t-3879-6547-1773722520.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4UjpX0xp42tkqUhF1us-Jw', '2026-03-19', 'admin', 491, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312079487300_32', 'Dàn ''anh trai, em xinh'' khuấy động concert', 'Ca sĩ Thái Ngân, buitruonglinh, Yeolan, MaiQuinn vừa hát vừa chơi nhạc cụ, được cổ vũ trong concert ''''Anh trai say hi 2025''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/anhtraisayhi-1773716511-177371-3600-2908-1773716952.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-tIZ5NKe2bTv6CQevu8ptw', '2026-03-19', 'admin', 272, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312093496100_33', 'Chồng ca nương Kiều Anh đóng MV', 'Doanh nhân Đặng Văn Quỳnh, chồng ca nương Kiều Anh, diễn xuất cùng vợ trong MV "Nhả vía". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/1-a-nh-still-mv-nha-vi-a-ca-nu-1569-6977-1773715915.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eJ6j9i_oZ0xeAqe1MGiojw', '2026-03-19', 'admin', 103, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312111465200_34', '''Nàng Bạch Tuyết'' bị trao hai giải Mâm Xôi Vàng', 'Phim "Nàng Bạch Tuyết" (Snow White) bản người đóng nhận hai giải Mâm Xôi Vàng gồm Nhóm diễn viên tệ nhất và Nam phụ tệ nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/1748753987213-i-1773634791-177-5905-9398-1773635220.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VG45Hq9CACZh5cM6pybb8w', '2026-03-19', 'admin', 281, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312129160600_35', 'Fan mang chăn, chiếu ngủ qua đêm chờ xem ''Anh trai say hi''', 'Nhiều khán giả ngủ qua đêm bên ngoài sân vận động Mỹ Đình để có chỗ đứng gần sân khấu concert ''''Anh trai say hi 2025'''' tối nay. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/648851068182607088168626557543-9893-4020-1773635013.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9zuo7kV8KFPDbMs97BM9vw', '2026-03-19', 'admin', 122, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312144439100_36', '''Kpop Demon Hunters'' ghi dấu ấn văn hóa Hàn ở Oscar', '"KPop Demon Hunters", lấy cảm hứng từ văn hóa Kpop Hàn Quốc, thắng giải Phim hoạt hình xuất sắc tại Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/kpop-1773621709-1773621961-6368-1773622008.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0w_IfTdwOqzJm7jsVk58tg', '2026-03-19', 'admin', 24, 'ENTERTAINMENT', 0, 1, 'Showbiz');
