INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_21312201049500_39', 'Những ngôi sao mặc đẹp nhất Oscar 2026', 'Anne Hathaway, Kirsten Dunst, Kate Hudson tỏa sáng trong những bộ đầm dạ hội của các nhà mốt hàng đầu thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/batch-afp-20260315-a3dz7a7-v1-highres-98thannualacademyawardsarrivals-1773649673-1773669775-1773669797.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=7GB6_Q1SaEGjXJBYEawnxw', '2026-03-19', 'admin', 131, 'ENTERTAINMENT', 0, 1, 'Showbiz');
