INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306227880400_3', 'Mốt đeo trang sức của Harper Beckham', 'Harper - con gái út David Beckham - đeo nhiều mẫu vòng của các nhà chế tác hàng đầu như Cartier, Van Cleef &amp; Arpels. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/con-gai-david-beckham-1-1773904643.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u-wK86i_e02YSQ9uZtEW4Q', '2026-03-20', 'admin', 190, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306243545900_4', 'Lý do ''One Battle After Another'' thắng Phim hay nhất Oscar', '"One Battle After Another", Leonardo Dicaprio đóng chính, thắng giải Phim xuất sắc Oscar 2026 nhờ câu chuyện thời sự, cách kể hấp dẫn. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/afp-20260316-a3ep8wx-v1-highre-1761-8406-1773807759.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nLa-Ixheu2BOQAvCPTdvYA', '2026-03-20', 'admin', 325, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306259776000_5', 'Chuyện tình của Leonardo DiCaprio và siêu mẫu 28 tuổi', 'Tài tử Leonardo DiCaprio muốn nghiêm túc hơn trong chuyện tình cảm với siêu mẫu Vittoria Ceretti, 28 tuổi, lần đầu đưa cô dự lễ trao giải lớn. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/LeonardoDiCapriovabangai-17738-3657-8958-1773821868.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ExTmirFnYBzfAw_tp4Z7_Q', '2026-03-20', 'admin', 244, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306275435700_6', 'Diện quần ngủ dạo phố theo phong cách nhà giàu', 'Diện quần ngủ cùng đồ hiệu đắt đỏ lên phố đang là xu hướng được nhiều người hưởng ứng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/quan-ngu-phoi-do-hieu-phong-cach-nha-giau-1773570324.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GBDk7TkgaKq9nWEKStQ2iA', '2026-03-20', 'admin', 282, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306291198700_7', 'Elle Fanning thoát hình tượng ''bình hoa di động''', 'Elle Fanning được khen khi hóa thân minh tinh gặp khủng hoảng sự nghiệp trong "Sentimental Value" - Phim quốc tế xuất sắc Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/610688199-18444696403097728-41-2772-4248-1773573805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VntITmMUNz56yEkK2DQ7A', '2026-03-20', 'admin', 462, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306306990900_8', '''Bài học diệu kỳ từ chiếc xe rác'' - loại bỏ cảm xúc tiêu cực', 'Sau khi đọc ''''Bài học diệu kỳ từ chiếc xe rác'''', thay vì phàn nàn về khó khăn, tôi học cách tìm giải pháp, mở lòng với thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bai-hoc-dieu-ky-tu-chiec-xe-ra-9462-9872-1773935854.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UyphBgo2oo6qzKdZXpBsBg', '2026-03-20', 'admin', 175, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306322840000_9', 'Kim Kardashian ngã vì giày ''cà kheo''', 'Mang giày cao 20 cm, ngôi sao truyền hình Kim Kardashian ngã nhào cạnh bụi cây trước giờ vào tiệc hậu Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/dnmi-1773919191-1773919213-6823-1773919221.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vysJW-CgjK1JqOtWQJesKQ', '2026-03-20', 'admin', 359, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306339798600_10', 'Váy áo cắt xẻ, xuyên thấu của sao ''Squid Game''', 'Jung Ho Yeon - sao Hàn thành hiện tượng toàn cầu nhờ "Squid Game" - theo đuổi mốt váy áo cắt xẻ, xuyên thấu, hở eo và lưng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/jung-ho-yeon-squid-game-16-1773887384-1773887415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8u3I275h3AL7nvJUZdCYuA', '2026-03-20', 'admin', 154, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306356293700_11', 'AI tái tạo hình ảnh tài tử Val Kilmer', 'Êkíp phim "As Deep as the Grave" dùng trí tuệ nhân tạo để mô phỏng hình ảnh diễn viên Val Kilmer, một năm sau khi ông qua đời. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/val-kilmer-as-deep-as-the-grav-7952-6701-1773890790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=HFz6t6oFtAb8ziqT_feC4w', '2026-03-20', 'admin', 368, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306371175200_12', '''Doãn Chí Bình'' Trần Khải Thái: Vợ cứu tôi vượt trầm cảm', 'Tài tử Hong Kong Trần Khải Thái, đóng "Thần điêu đại hiệp" 1995, nói biết ơn bạn đời giúp anh vượt qua giai đoạn trầm cảm nặng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/thai3-1773891366-1773891382-6221-1773891745.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LiYdcQf8aZ8S9cnN5aRo5Q', '2026-03-20', 'admin', 474, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306386685800_13', 'Sức hút của Scarlett Johansson - nữ diễn viên kiếm tiền giỏi nhất 2025', 'Scarlett Johansson, diễn viên đứng đầu nhóm sao nữ kiếm tiền giỏi nhất 2025, nổi tiếng với vóc dáng gợi cảm, gu mặc tinh tế. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nu-dien-vien-kiem-tien-gioi-nhat-2025-1773830456.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oWPLgzkvIKfvIwF63iuJFQ', '2026-03-20', 'admin', 83, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306402084200_14', 'Tái diễn vở ballet đương đại ''Dó''', '''''Dó'''' - vở ballet cảm hứng từ giấy dó, kết hợp âm nhạc cổ điển châu Âu và văn hóa Việt - trở lại sau hai năm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/balletdo11-1773822991-17738230-3275-1706-1773823149.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=j-Upd5NjgEFwbkNg46-2TA', '2026-03-20', 'admin', 74, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306418213200_15', '7 kiểu áo có thể khiến bạn trông già đi', 'Áo đính đá, áo ren dày, áo khoác tweed nằm trong nhóm thiết kế khiến bạn như tăng thêm vài tuổi khi mặc. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nhung-kieu-ao-khien-ban-trong-gia-hon-1773832436.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pSMRvahLCRSsVqTX90Cmlg', '2026-03-20', 'admin', 487, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306434127100_16', '''Golden'' - bản Kpop làm nên lịch sử ở Oscar', '"Golden" - nhạc phim hoạt hình "KPop Demon Hunters" - lập kỳ tích khi trở thành ca khúc đầu tiên do người Hàn sản xuất thắng Oscar. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/mntrnhdingolden-1773744150-177-3339-7757-1773747320.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Q3KGZ5aUIo5LCgjI04UlkA', '2026-03-20', 'admin', 152, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306449884200_17', 'Nhạc sĩ Minh Khang xin lỗi sau khi khiếm nhã với tài xế', 'Nhạc sĩ Minh Khang - tác giả ca khúc "Đứa bé" - cho biết do uống nhiều rượu nên có hành vi, lời lẽ khiếm nhã với tài xế khi đi một hãng taxi công nghệ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/514414188-10222804158493103-50-9430-6554-1773825193.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tlkVHX7PDy_bDjHw0YVpNg', '2026-03-20', 'admin', 92, 'ENTERTAINMENT', 0, 1, 'Showbiz');
