INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306496350000_20', 'Bức chân dung ngư dân Hội An thắng giải nhiếp ảnh của Anh', 'Bức "Mắt cá" - chụp chân dung ngư dân ở Hội An - giúp một tay máy không chuyên đoạt giải cao nhất cuộc thi nhiếp ảnh tại London, Anh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/fisheye-1773803378-1773803719-4325-1773803810.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8GATWbKTlsBFpkaaAnZJUw', '2026-03-20', 'admin', 247, 'ENTERTAINMENT', 0, 1, 'Showbiz');
