INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306527556700_22', 'Vĩnh Đam thừa nhận diễn đơ', 'Vĩnh Đam - diễn viên "Bus: Chuyến xe một chiều" - nói rút kinh nghiệm khi bị nhận xét diễn "không cảm xúc" trong phim. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/vinhdamt1-1773800678-3531-1773800701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NPcJ7GHXHx2SGwhbGW_iGw', '2026-03-20', 'admin', 287, 'ENTERTAINMENT', 0, 1, 'Showbiz');
