INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306558080500_24', '''Hãy chăm sóc mẹ''', 'Sau 11 năm, tôi vẫn giữ cuốn ''''Hãy chăm sóc mẹ'''' để nhắc nhở bản thân trân trọng những khoảnh khắc khi còn mẹ ở bên. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/hay-cham-soc-me-jpg-1773761316-5599-7104-1773761819.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ycsgdgrS1-xtmsY6bbM4uA', '2026-03-20', 'admin', 374, 'ENTERTAINMENT', 0, 1, 'Showbiz');
