INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306638494200_29', '''Gái nhảy'' Minh Thư tái xuất', 'Minh Thư, diễn viên phim "Gái nhảy", từ Mỹ về nước giữ vai trò sản xuất và đóng chính trong "Tình một đêm" sau 12 năm vắng bóng màn ảnh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/z7629099560897-863a1b21723fbc6-5299-6469-1773729322.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Kd8Ske1B-OKFqo2VU5r1oA', '2026-03-20', 'admin', 56, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306653638800_30', 'Váy của nhà thiết kế Đỗ Long lên sân khấu Oscar', 'Ca sĩ Hàn Quốc Rei Ami diện đầm xuyên thấu do Đỗ Long thiết kế khi hát ở lễ trao giải Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/reiamimacdamdolongsankhauoscar-9220-6422-1773718057.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ViDz7TVDCHMYsKQx-xbMFg', '2026-03-20', 'admin', 442, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306669513900_31', 'Oscar 2026 nỗ lực trẻ hóa', 'Lễ trao giải Oscar 98 tôn vinh điện ảnh với tinh thần trẻ trung, hướng tới khán giả Gen Z qua các màn pha trò và trình diễn âm nhạc. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/afp-20260316-a3ek7d2-v1-highre-2555-7159-1773655530.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=wydd8s6fXX9bP1qXF6j5Ng', '2026-03-20', 'admin', 316, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306685393100_32', '6 năm ''yêu không cần cưới'' của Lệ Quyên, Lâm Bảo Châu', 'Ca sĩ Lệ Quyên cho biết gắn bó Lâm Bảo Châu bằng sự thấu hiểu, xem sáu năm qua là chặng đường bình yên sau một lần đổ vỡ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/Le-Quyen-Lam-Bao-Chau-25-top1-1773632486.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KctQh_a5niC9XDNOwuXMnA', '2026-03-20', 'admin', 122, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306718753700_33', 'Khán giả bức xúc khi Oscar cắt phát biểu của êkíp ''Kpop Demon Hunters''', 'Nhiều người cho rằng Oscar thiếu tôn trọng nghệ sĩ khi phát nhạc nền cắt ngang phát biểu nhận giải Ca khúc xuất sắc, cho nhạc phim "Kpop Demon Hunters". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/afp20260316a3eh9flv1highres98t-3879-6547-1773722520.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=4UjpX0xp42tkqUhF1us-Jw', '2026-03-20', 'admin', 138, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306753348000_34', 'Dàn ''anh trai, em xinh'' khuấy động concert', 'Ca sĩ Thái Ngân, buitruonglinh, Yeolan, MaiQuinn vừa hát vừa chơi nhạc cụ, được cổ vũ trong concert ''''Anh trai say hi 2025''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/anhtraisayhi-1773716511-177371-3600-2908-1773716952.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-tIZ5NKe2bTv6CQevu8ptw', '2026-03-20', 'admin', 89, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306777645000_35', 'Chồng ca nương Kiều Anh đóng MV', 'Doanh nhân Đặng Văn Quỳnh, chồng ca nương Kiều Anh, diễn xuất cùng vợ trong MV "Nhả vía". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/1-a-nh-still-mv-nha-vi-a-ca-nu-1569-6977-1773715915.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eJ6j9i_oZ0xeAqe1MGiojw', '2026-03-20', 'admin', 145, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306793641300_36', '''Nàng Bạch Tuyết'' bị trao hai giải Mâm Xôi Vàng', 'Phim "Nàng Bạch Tuyết" (Snow White) bản người đóng nhận hai giải Mâm Xôi Vàng gồm Nhóm diễn viên tệ nhất và Nam phụ tệ nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/1748753987213-i-1773634791-177-5905-9398-1773635220.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VG45Hq9CACZh5cM6pybb8w', '2026-03-20', 'admin', 126, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306809224400_37', 'Fan mang chăn, chiếu ngủ qua đêm chờ xem ''Anh trai say hi''', 'Nhiều khán giả ngủ qua đêm bên ngoài sân vận động Mỹ Đình để có chỗ đứng gần sân khấu concert ''''Anh trai say hi 2025'''' tối nay. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/648851068182607088168626557543-9893-4020-1773635013.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9zuo7kV8KFPDbMs97BM9vw', '2026-03-20', 'admin', 77, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306824592400_38', '''Kpop Demon Hunters'' ghi dấu ấn văn hóa Hàn ở Oscar', '"KPop Demon Hunters", lấy cảm hứng từ văn hóa Kpop Hàn Quốc, thắng giải Phim hoạt hình xuất sắc tại Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/kpop-1773621709-1773621961-6368-1773622008.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0w_IfTdwOqzJm7jsVk58tg', '2026-03-20', 'admin', 218, 'ENTERTAINMENT', 0, 1, 'Showbiz');
