INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3306856373200_40', '''One Battle After Another'' của Leonardo Dicaprio - phim hay nhất Oscar 2026', 'Sau gần bốn tiếng ngồi dưới khán phòng nhà hát Dolby theo dõi lễ trao giải, tài tử Leonardo Dicaprio có cơ hội lên sân khấu cùng êkíp nhận tượng vàng Oscar 98 ở hạng mục quan trọng nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/afp-20260316-a3el6nn-v1-highre-3670-9686-1773647770.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iDs0HNwF2k4zDXZS0YEiDw', '2026-03-20', 'admin', 113, 'ENTERTAINMENT', 0, 1, 'Showbiz');
