INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3307095959600_55', 'Sách nghiên cứu về nam tính', '''''Những nam tính'''' của Raewyn Connell là công trình nghiên cứu kinh điển, giúp độc giả nhìn lại cách xã hội định nghĩa về giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/nhung-nam-tinh-jpeg-1773569501-1932-8431-1773570552.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gUhhNsx_Rcrk66ka-4yLKA', '2026-03-20', 'admin', 95, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3307111878700_56', 'Lan Phương tái xuất với vai lập dị', 'Diễn viên Lan Phương nhập vai một phụ nữ chỉ coi đàn ông là thú tiêu khiển, có những hành động quái dị, ở phim ''''Đồng hồ đếm ngược''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/lanphuong-1773561593-177356161-7425-2697-1773561771.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=FFBEwiW5j3NOlut7PoB1AQ', '2026-03-20', 'admin', 319, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3307128969100_57', 'Thảm đỏ Oscar - ''cỗ máy'' tiếp thị thời trang quyền lực', 'Thảm đỏ Oscar như một bài kiểm tra, định đoạt hàng tỷ USD giá trị truyền thông và cơ hội của các nhà mốt hàng đầu. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/thamdooscar-1773548295-5402-1773548382.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RMIvK6oZiyQP5Knw7xIgEQ', '2026-03-20', 'admin', 94, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3307144516600_58', 'Dàn ''Anh trai say hi'' mùa hai hóa trang hài hước', 'Rapper Gill hóa Bắc Đẩu, CongB đóng nhân vật trong phim "Vườn sao băng", được khán giả yêu thích. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/hermosa-1-1773548798-1773548913.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YPkMB9cp6NILIf-X0JBRaQ', '2026-03-20', 'admin', 472, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3307159839000_59', 'Nhóm Quả Dưa Hấu gợi ký ức âm nhạc thập niên 1990', 'Bằng Kiều, Tuấn Hưng, Tú Dưa thể hiện các bản hit thập niên 1990 như "Mặt trời dịu êm", "Hè muộn", trong lần tái hợp sau 28 năm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/du-a-ha-u-1773544470-177354517-7488-9356-1773545273.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yGqBIGbPeZNjB9znvPvtRw', '2026-03-20', 'admin', 163, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3567838645200_0', 'Yến Nhi nhóm Mắt Ngọc tái xuất sau nhiều năm chật vật', 'Sau nhiều năm đi hát nhưng không thành công, Yến Nhi, cựu thành viên Mắt Ngọc, đổi nghệ danh, tham gia nhóm nhạc Violixx ở tuổi 37. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/yen-nhi-1773822906-1773823822-6302-1773823858.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gtAlh2lp-7sb5MG3IWX07w', '2026-03-20', 'admin', 129, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3567864195800_1', 'Loạt trang phục gây tranh cãi của Lưu Diệc Phi', 'Diễn viên Lưu Diệc Phi nhiều lần mắc lỗi trang phục khi phối các món đồ không phù hợp với gương mặt và phong cách. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/luu-diec-phi-trang-phuc-gay-tranh-cai-1773739200.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vL_qA_V3bj2KM6ZSjOyb7w', '2026-03-20', 'admin', 422, 'ENTERTAINMENT', 0, 1, 'Showbiz');
