INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568055429800_16', '7 kiểu áo có thể khiến bạn trông già đi', 'Áo đính đá, áo ren dày, áo khoác tweed nằm trong nhóm thiết kế khiến bạn như tăng thêm vài tuổi khi mặc. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nhung-kieu-ao-khien-ban-trong-gia-hon-1773832436.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pSMRvahLCRSsVqTX90Cmlg', '2026-03-20', 'admin', 58, 'ENTERTAINMENT', 0, 1, 'Showbiz');
