INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568217642100_28', 'Thời trang cường điệu trong phim ''Đồi gió hú''', 'Nhân vật Cathy mặc chiếc corset thít chặt cơ thể, khi cô kết hôn với người đàn ông giàu có nhưng không yêu ở phim "Đồi gió hú". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/doi-gio-hu-4-1772445828-7911-1-5593-9032-1773747212.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=P0fH2obJPFeyBDqHPUZFeA', '2026-03-20', 'admin', 60, 'ENTERTAINMENT', 1, 1, 'Showbiz');
