INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568358207500_38', 'Fan mang chăn, chiếu ngủ qua đêm chờ xem ''Anh trai say hi''', 'Nhiều khán giả ngủ qua đêm bên ngoài sân vận động Mỹ Đình để có chỗ đứng gần sân khấu concert ''''Anh trai say hi 2025'''' tối nay. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/648851068182607088168626557543-9893-4020-1773635013.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9zuo7kV8KFPDbMs97BM9vw', '2026-03-20', 'admin', 427, 'ENTERTAINMENT', 0, 1, 'Showbiz');
