INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568463097900_46', 'Leonardo DiCaprio đưa bạn gái đến Oscar', 'Leonardo DiCaprio, 52 tuổi, đưa bạn gái 28 tuổi - người mẫu Vittoria Ceretti - đến dự lễ trao giải Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/leonardo-1773625775-6344-17736-3595-5719-1773626508.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=VpiXxkghfN8d4QjmhClBaw', '2026-03-20', 'admin', 415, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568476498500_47', 'Giấc mơ đẹp với ''Đảo ngàn sao''', 'Mình yêu cuốn ''''Đảo ngàn sao'''' vì đã chạm vào một góc rất sâu, lạ lùng trong tâm hồn mình, nơi những cảm xúc không cần gọi tên. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/dao-ngan-sao-1773578499-177357-6108-7455-1773578829.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pgaxeiDg7MLAthRHqzO-UA', '2026-03-20', 'admin', 410, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568490093600_48', 'Mỹ nhân Hollywood hội tụ trên thảm đỏ Oscar', 'Elle Fanning, Emma Stone, Nicole Kidman diện đầm quây ngực, cắt xẻ ở lễ trao giải điện ảnh lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/tham-do-oscar-2026-1773614485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yrTuf8n2riwi7Z3_hB1xCA', '2026-03-20', 'admin', 282, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568503638900_49', 'Lan Phương: ''Tôi tự chữa lành sau ly hôn''', 'Diễn viên Lan Phương cho biết cô bình yên, hạnh phúc khi tập trung chăm sóc bản thân, nuôi dạy hai con, sau khi ly hôn chồng người Anh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/13/lan-phuong-1-1773395226-177339-2870-7140-1773395701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=USiGpJr18gUO_aYEDx6i4g', '2026-03-20', 'admin', 163, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568516675900_50', 'Sao ngoại theo đuổi họa tiết da báo', 'Bella Hadid, Paris Hilton, Jennifer Lopez lăng xê quần áo, giày, túi xách da báo - xu hướng hot năm nay. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/sao-ngoai-hoa-tiet-da-bao-1773563636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UaudI_f6yKbIqd9__Pa0wQ', '2026-03-20', 'admin', 348, 'ENTERTAINMENT', 1, 1, 'Showbiz');
