INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568553623700_52', 'Sức hút của người mẫu gốc Hàn cao 1,78 m', 'Irene Kim, 39 tuổi, đắt show sự kiện, cộng tác loạt thương hiệu xa xỉ nhờ thần thái, gương mặt Á Đông, cách phối đồ tôn chiều cao 1,78 m. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/05/irene-kim-1772678647-1772678711.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JhCq73uffwQCZDMUsnJkmg', '2026-03-20', 'admin', 186, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568573538000_53', 'Oscar 2026 siết chặt an ninh trước giờ G', 'Trong bối cảnh xung đột Trung Đông căng thẳng, Oscar năm nay tăng cường công tác bảo vệ với nhiều lớp an ninh, hệ thống giám sát AI. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/afp-20260314-a3am69y-v1-highre-7596-4807-1773546878.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WlrzLGoyZKd6XkZfKdOIqw', '2026-03-20', 'admin', 440, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568592050400_54', '10 diễn viên có thu nhập cao nhất năm 2025', 'Adam Sandler, Tom Cruise kiếm tiền nhiều nhất năm ngoái với gần 50 triệu USD mỗi người, Millie Bobby Brown lọt vào top 10 khi mới 22 tuổi. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/14/tom-cruise-ta-i-buo-i-qua-ng-ba-phim-mission-impossible-the-final-reckoning-2025-1773463494-1773466611-1773466706-1773487575.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=w5l40BxP9ZmT4AxMMoWSbQ', '2026-03-20', 'admin', 332, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568611178500_55', 'Brooklyn Beckham dự sinh nhật mẹ vợ', 'Brooklyn Beckham xuất hiện tại tiệc sinh nhật của mẹ vợ, chụp ảnh thân thiết giữa lúc mâu thuẫn với gia đình ruột thịt. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/brooklyn-jpg-1773574576-177357-3673-4177-1773574681.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=twbgVwwYawBJlbz06esgsw', '2026-03-20', 'admin', 35, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568629333300_56', 'Sách nghiên cứu về nam tính', '''''Những nam tính'''' của Raewyn Connell là công trình nghiên cứu kinh điển, giúp độc giả nhìn lại cách xã hội định nghĩa về giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/nhung-nam-tinh-jpeg-1773569501-1932-8431-1773570552.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gUhhNsx_Rcrk66ka-4yLKA', '2026-03-20', 'admin', 369, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568644305000_57', 'Lan Phương tái xuất với vai lập dị', 'Diễn viên Lan Phương nhập vai một phụ nữ chỉ coi đàn ông là thú tiêu khiển, có những hành động quái dị, ở phim ''''Đồng hồ đếm ngược''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/lanphuong-1773561593-177356161-7425-2697-1773561771.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=FFBEwiW5j3NOlut7PoB1AQ', '2026-03-20', 'admin', 60, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568658061300_58', 'Thảm đỏ Oscar - ''cỗ máy'' tiếp thị thời trang quyền lực', 'Thảm đỏ Oscar như một bài kiểm tra, định đoạt hàng tỷ USD giá trị truyền thông và cơ hội của các nhà mốt hàng đầu. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/thamdooscar-1773548295-5402-1773548382.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RMIvK6oZiyQP5Knw7xIgEQ', '2026-03-20', 'admin', 280, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_3568671132200_59', 'Dàn ''Anh trai say hi'' mùa hai hóa trang hài hước', 'Rapper Gill hóa Bắc Đẩu, CongB đóng nhân vật trong phim "Vườn sao băng", được khán giả yêu thích. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/hermosa-1-1773548798-1773548913.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YPkMB9cp6NILIf-X0JBRaQ', '2026-03-20', 'admin', 489, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_775813862300_0', 'Những nghệ sĩ giàu nhất thế giới', 'Đạo diễn Steven Spielberg tiếp tục đứng đầu danh sách người nổi tiếng giàu nhất, còn Taylor Swift, Rihanna và Beyoncé thuộc nhóm ca sĩ tỷ USD. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/ca-si-taylor-swift-1-1773369547-1773371053-1773371126-1773710323.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RmGTMsJD5pJHMTHMpZ1j7w', '2026-03-20', 'admin', 157, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_775827413200_1', 'Tiết mục ''Tiếng trống Mê Linh'' của cháu gái Vũ Linh bị tuýt còi', 'Sở Văn hóa, Thể thao TP HCM sẽ xử lý đơn vị tổ chức diễn "Tiếng trống Mê Linh", có Bùm Bum, cháu nghệ sĩ Vũ Linh tham gia, vì tiết mục chưa được cấp phép. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bumbumtop1-1773911292-7344-1773911790.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=krxiAMaZpYDqxqhnesbpHQ', '2026-03-20', 'admin', 373, 'ENTERTAINMENT', 1, 1, 'Showbiz');
