INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_775905161000_7', '''Bài học diệu kỳ từ chiếc xe rác'' - loại bỏ cảm xúc tiêu cực', 'Sau khi đọc ''''Bài học diệu kỳ từ chiếc xe rác'''', thay vì phàn nàn về khó khăn, tôi học cách tìm giải pháp, mở lòng với thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/bai-hoc-dieu-ky-tu-chiec-xe-ra-9462-9872-1773935854.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UyphBgo2oo6qzKdZXpBsBg', '2026-03-20', 'admin', 250, 'ENTERTAINMENT', 0, 1, 'Showbiz');
