INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_775957932400_11', '''Doãn Chí Bình'' Trần Khải Thái: Vợ cứu tôi vượt trầm cảm', 'Tài tử Hong Kong Trần Khải Thái, đóng "Thần điêu đại hiệp" 1995, nói biết ơn bạn đời giúp anh vượt qua giai đoạn trầm cảm nặng. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/19/thai3-1773891366-1773891382-6221-1773891745.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LiYdcQf8aZ8S9cnN5aRo5Q', '2026-03-20', 'admin', 377, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_775971277600_12', 'Sức hút của Scarlett Johansson - nữ diễn viên kiếm tiền giỏi nhất 2025', 'Scarlett Johansson, diễn viên đứng đầu nhóm sao nữ kiếm tiền giỏi nhất 2025, nổi tiếng với vóc dáng gợi cảm, gu mặc tinh tế. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nu-dien-vien-kiem-tien-gioi-nhat-2025-1773830456.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oWPLgzkvIKfvIwF63iuJFQ', '2026-03-20', 'admin', 124, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_775985231000_13', 'Tái diễn vở ballet đương đại ''Dó''', '''''Dó'''' - vở ballet cảm hứng từ giấy dó, kết hợp âm nhạc cổ điển châu Âu và văn hóa Việt - trở lại sau hai năm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/balletdo11-1773822991-17738230-3275-1706-1773823149.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=j-Upd5NjgEFwbkNg46-2TA', '2026-03-20', 'admin', 484, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_775999136500_14', '7 kiểu áo có thể khiến bạn trông già đi', 'Áo đính đá, áo ren dày, áo khoác tweed nằm trong nhóm thiết kế khiến bạn như tăng thêm vài tuổi khi mặc. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/nhung-kieu-ao-khien-ban-trong-gia-hon-1773832436.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pSMRvahLCRSsVqTX90Cmlg', '2026-03-20', 'admin', 506, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776013347700_15', '''Golden'' - bản Kpop làm nên lịch sử ở Oscar', '"Golden" - nhạc phim hoạt hình "KPop Demon Hunters" - lập kỳ tích khi trở thành ca khúc đầu tiên do người Hàn sản xuất thắng Oscar. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/mntrnhdingolden-1773744150-177-3339-7757-1773747320.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Q3KGZ5aUIo5LCgjI04UlkA', '2026-03-20', 'admin', 155, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776027283500_16', 'Nhạc sĩ Minh Khang xin lỗi sau khi khiếm nhã với tài xế', 'Nhạc sĩ Minh Khang - tác giả ca khúc "Đứa bé" - cho biết do uống nhiều rượu nên có hành vi, lời lẽ khiếm nhã với tài xế khi đi một hãng taxi công nghệ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/514414188-10222804158493103-50-9430-6554-1773825193.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tlkVHX7PDy_bDjHw0YVpNg', '2026-03-20', 'admin', 469, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776041389000_17', 'Chồng diễn viên ''Bích huyết kiếm'' bị phạt tù vì tội hiếp dâm', 'Lương Hiên An, chồng biểu tượng gợi cảm Đài Loan Tiêu Thục Thận, bị tòa tuyên phạt 4 năm 10 tháng tù vì cưỡng dâm một ca sĩ. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/tieu3-1773823164-1773823201-4242-1773823450.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=jSt8CJ8DlLFBLQP7sjWS6A', '2026-03-20', 'admin', 188, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776054138700_18', 'Video AI mô phỏng biểu cảm Trương Mạn Ngọc gây chú ý', 'Diễn viên AI bắt chước biểu cảm của minh tinh Hong Kong Trương Mạn Ngọc, dấy thảo luận về khả năng "nghề diễn biến mất". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/topmanngoc-1773805571-1608-1773806614.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vFrGoIxhu892HKinZdECKA', '2026-03-20', 'admin', 82, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776069072200_19', 'Bức chân dung ngư dân Hội An thắng giải nhiếp ảnh của Anh', 'Bức "Mắt cá" - chụp chân dung ngư dân ở Hội An - giúp một tay máy không chuyên đoạt giải cao nhất cuộc thi nhiếp ảnh tại London, Anh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/fisheye-1773803378-1773803719-4325-1773803810.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8GATWbKTlsBFpkaaAnZJUw', '2026-03-20', 'admin', 51, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776084328000_20', 'Giới làm phim ngắn trở tay không kịp vì ''cơn lốc'' AI', 'Vương Bản Chí đậu phỏng vấn ở công ty sản xuất phim ngắn nhưng vài tuần sau, anh nhận thông báo nghỉ làm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/hoac-jfif-1773720125-177372013-9003-3017-1773720581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hinN42TgFR_8IEIWEKfK1Q', '2026-03-20', 'admin', 209, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776097533600_21', 'Vĩnh Đam thừa nhận diễn đơ', 'Vĩnh Đam - diễn viên "Bus: Chuyến xe một chiều" - nói rút kinh nghiệm khi bị nhận xét diễn "không cảm xúc" trong phim. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/18/vinhdamt1-1773800678-3531-1773800701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NPcJ7GHXHx2SGwhbGW_iGw', '2026-03-20', 'admin', 91, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776109834800_22', 'Thái Hòa: ''Tôi kiệt sức vì cảnh hành động''', 'Diễn viên Thái Hòa cho biết khi đóng cảnh cứu nạn nhân vụ hỏa hoạn trong phim "Anh Hùng", anh kiệt sức nên rơi từ trên cao xuống đệm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/thaihoatop2-1773659876-4550-1773660213.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=VgNbTUtqr5aN9q0I7nGkNw', '2026-03-20', 'admin', 289, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776124688400_23', '''Hãy chăm sóc mẹ''', 'Sau 11 năm, tôi vẫn giữ cuốn ''''Hãy chăm sóc mẹ'''' để nhắc nhở bản thân trân trọng những khoảnh khắc khi còn mẹ ở bên. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/hay-cham-soc-me-jpg-1773761316-5599-7104-1773761819.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ycsgdgrS1-xtmsY6bbM4uA', '2026-03-20', 'admin', 113, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776137126100_24', 'Gwyneth Paltrow gây tranh cãi khi diện váy xẻ cao', 'Minh tinh Gwyneth Paltrow có khoảnh khắc gây tranh cãi khi diện chiếc váy xẻ hai bên thân tại lễ trao giải Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/gwyneth12-1773760817-177376083-6333-6502-1773760849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_J5GbyNjgF8HKQLT0_OLuQ', '2026-03-20', 'admin', 406, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776149967900_25', 'Đạo diễn hoạt hình ''Doraemon'' qua đời', 'Tsutomu Shibayama, nhà làm phim Nhật thực hiện hơn 20 bộ hoạt hình "Doraemon", mất ở tuổi 84 vì bệnh ung thư phổi. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/tsutomushibayamatop-1773759235-6245-1234-1773759256.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=yr9FNuRVBE7oum0tfX0sdA', '2026-03-20', 'admin', 116, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776169368500_26', 'Thời trang cường điệu trong phim ''Đồi gió hú''', 'Nhân vật Cathy mặc chiếc corset thít chặt cơ thể, khi cô kết hôn với người đàn ông giàu có nhưng không yêu ở phim "Đồi gió hú". (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/doi-gio-hu-4-1772445828-7911-1-5593-9032-1773747212.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=P0fH2obJPFeyBDqHPUZFeA', '2026-03-20', 'admin', 487, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776185941000_27', 'Trang phục dạo biển của mỹ nhân ''Bên nhau trọn đời''', 'Gian Nhân Tư, diễn viên Trung Quốc đóng "Bên nhau trọn đời", nhận nhiều lời khen khỏe khoắn với trang phục đi biển. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/gian-4-1773367141-1773740581-1773740610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9tobbpQm0gCiakENyUWMXA', '2026-03-20', 'admin', 360, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776200952300_28', '''Gái nhảy'' Minh Thư tái xuất', 'Minh Thư, diễn viên phim "Gái nhảy", từ Mỹ về nước giữ vai trò sản xuất và đóng chính trong "Tình một đêm" sau 12 năm vắng bóng màn ảnh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/z7629099560897-863a1b21723fbc6-5299-6469-1773729322.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Kd8Ske1B-OKFqo2VU5r1oA', '2026-03-20', 'admin', 432, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776217356000_29', 'Váy của nhà thiết kế Đỗ Long lên sân khấu Oscar', 'Ca sĩ Hàn Quốc Rei Ami diện đầm xuyên thấu do Đỗ Long thiết kế khi hát ở lễ trao giải Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/17/reiamimacdamdolongsankhauoscar-9220-6422-1773718057.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ViDz7TVDCHMYsKQx-xbMFg', '2026-03-20', 'admin', 110, 'ENTERTAINMENT', 0, 1, 'Showbiz');
