INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776310484100_36', 'Fan mang chăn, chiếu ngủ qua đêm chờ xem ''Anh trai say hi''', 'Nhiều khán giả ngủ qua đêm bên ngoài sân vận động Mỹ Đình để có chỗ đứng gần sân khấu concert ''''Anh trai say hi 2025'''' tối nay. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/648851068182607088168626557543-9893-4020-1773635013.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9zuo7kV8KFPDbMs97BM9vw', '2026-03-20', 'admin', 482, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776323016600_37', '''Kpop Demon Hunters'' ghi dấu ấn văn hóa Hàn ở Oscar', '"KPop Demon Hunters", lấy cảm hứng từ văn hóa Kpop Hàn Quốc, thắng giải Phim hoạt hình xuất sắc tại Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/kpop-1773621709-1773621961-6368-1773622008.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0w_IfTdwOqzJm7jsVk58tg', '2026-03-20', 'admin', 415, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776335973100_38', 'Người thân tiễn biệt Kasim Hoàng Vũ', 'Mẹ Kasim Hoàng Vũ - ca sĩ Bích Phương - nhắc lại kỷ niệm với con trai trong lễ tiễn biệt tại nhà quàn Vĩnh Phước, Houston. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/KasimHoangVu-1773623689-5086-1773623872.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=N67_YXNFqPRfFvYEipc1EA', '2026-03-20', 'admin', 416, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776348806300_39', '''One Battle After Another'' của Leonardo Dicaprio - phim hay nhất Oscar 2026', 'Sau gần bốn tiếng ngồi dưới khán phòng nhà hát Dolby theo dõi lễ trao giải, tài tử Leonardo Dicaprio có cơ hội lên sân khấu cùng êkíp nhận tượng vàng Oscar 98 ở hạng mục quan trọng nhất. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/afp-20260316-a3el6nn-v1-highre-3670-9686-1773647770.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iDs0HNwF2k4zDXZS0YEiDw', '2026-03-20', 'admin', 21, 'ENTERTAINMENT', 1, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776361767000_40', 'Những ngôi sao mặc đẹp nhất Oscar 2026', 'Anne Hathaway, Kirsten Dunst, Kate Hudson tỏa sáng trong những bộ đầm dạ hội của các nhà mốt hàng đầu thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/batch-afp-20260315-a3dz7a7-v1-highres-98thannualacademyawardsarrivals-1773649673-1773669775-1773669797.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=7GB6_Q1SaEGjXJBYEawnxw', '2026-03-20', 'admin', 141, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776375077100_41', 'Vợ tỷ phú Jeff Bezos mặc gợi cảm bên dàn sao ở tiệc hậu Oscar', 'Cựu MC Lauren Sánchez diện đầm quây ngực, cùng chồng tỷ phú Jeff Bezos dự tiệc của Hollywood sau lễ trao giải Oscar. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/vo-ty-phu-jeff-bezos-1773647241.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Qt7DYaYpKAHq1l4CvceBA', '2026-03-20', 'admin', 315, 'ENTERTAINMENT', 0, 1, 'Showbiz');
