INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776402885900_43', 'Những bộ cánh ''thảm họa'' ở Oscar 2026', 'Váy đen như cô dâu ma, đầm hồng neon khiến Chloé Zhao, Maggie O''Farrell mất điểm phong cách trên thảm đỏ Oscar 2026. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/batch-tham-hoa-thoi-trang-oscar-1773630547.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s0-c7ASODbCVlKcFdQ_ogw', '2026-03-20', 'admin', 375, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776416325300_44', 'Leonardo DiCaprio đưa bạn gái đến Oscar', 'Leonardo DiCaprio, 52 tuổi, đưa bạn gái 28 tuổi - người mẫu Vittoria Ceretti - đến dự lễ trao giải Oscar lần thứ 98. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/leonardo-1773625775-6344-17736-3595-5719-1773626508.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=VpiXxkghfN8d4QjmhClBaw', '2026-03-20', 'admin', 405, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776430698900_45', 'Giấc mơ đẹp với ''Đảo ngàn sao''', 'Mình yêu cuốn ''''Đảo ngàn sao'''' vì đã chạm vào một góc rất sâu, lạ lùng trong tâm hồn mình, nơi những cảm xúc không cần gọi tên. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/dao-ngan-sao-1773578499-177357-6108-7455-1773578829.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pgaxeiDg7MLAthRHqzO-UA', '2026-03-20', 'admin', 183, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776444408800_46', 'Mỹ nhân Hollywood hội tụ trên thảm đỏ Oscar', 'Elle Fanning, Emma Stone, Nicole Kidman diện đầm quây ngực, cắt xẻ ở lễ trao giải điện ảnh lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/16/tham-do-oscar-2026-1773614485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yrTuf8n2riwi7Z3_hB1xCA', '2026-03-20', 'admin', 54, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776458290900_47', 'Lan Phương: ''Tôi tự chữa lành sau ly hôn''', 'Diễn viên Lan Phương cho biết cô bình yên, hạnh phúc khi tập trung chăm sóc bản thân, nuôi dạy hai con, sau khi ly hôn chồng người Anh. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/13/lan-phuong-1-1773395226-177339-2870-7140-1773395701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=USiGpJr18gUO_aYEDx6i4g', '2026-03-20', 'admin', 418, 'ENTERTAINMENT', 0, 1, 'Showbiz');
