INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776548246900_54', 'Sách nghiên cứu về nam tính', '''''Những nam tính'''' của Raewyn Connell là công trình nghiên cứu kinh điển, giúp độc giả nhìn lại cách xã hội định nghĩa về giới. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/nhung-nam-tinh-jpeg-1773569501-1932-8431-1773570552.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gUhhNsx_Rcrk66ka-4yLKA', '2026-03-20', 'admin', 343, 'ENTERTAINMENT', 0, 1, 'Showbiz');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776562804400_55', 'Lan Phương tái xuất với vai lập dị', 'Diễn viên Lan Phương nhập vai một phụ nữ chỉ coi đàn ông là thú tiêu khiển, có những hành động quái dị, ở phim ''''Đồng hồ đếm ngược''''. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/lanphuong-1773561593-177356161-7425-2697-1773561771.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=FFBEwiW5j3NOlut7PoB1AQ', '2026-03-20', 'admin', 111, 'ENTERTAINMENT', 0, 1, 'Showbiz');
