INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_ENTERTAINMENT_776603665600_58', 'Nhóm Quả Dưa Hấu gợi ký ức âm nhạc thập niên 1990', 'Bằng Kiều, Tuấn Hưng, Tú Dưa thể hiện các bản hit thập niên 1990 như "Mặt trời dịu êm", "Hè muộn", trong lần tái hợp sau 28 năm. (Nguồn: VNExpress)', 'https://i1-giaitri.vnecdn.net/2026/03/15/du-a-ha-u-1773544470-177354517-7488-9356-1773545273.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yGqBIGbPeZNjB9znvPvtRw', '2026-03-20', 'admin', 447, 'ENTERTAINMENT', 0, 1, 'Showbiz');
