INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226593835100_2', 'Bác sĩ cảnh báo ''bẫy tâm lý'' khiến nhiều người sập bẫy thuốc gia truyền giả', 'Bác sĩ Ngô Văn Tỵ, Khoa Ung Bướu thuộc Bệnh viện Đại học Y Hà Nội, vẫn chưa thôi ám ảnh khi nhắc lại ca trực vừa qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z4553627269963-2f6fc10ad7c154e-2394-3553-1773818309.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JHP6dnV6gDB7g0SuN0IfFw', '2026-03-20', 'admin', 165, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226635820000_3', 'Án tử rình rập từ thử thách ''ngất xỉu'' trên TikTok', 'Chị Lan, 42 tuổi, bần thần khi phát hiện trong lịch sử xem video của con trai lớp 8 là cảnh một đám trẻ đang reo hò quanh một nam sinh vừa đổ gục, co giật nhẹ trên sàn nhà. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/2-1773366911-8280-1773367913-1-4012-5941-1773619069.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=uPJ_bYzYnVJz4Nrj5NLfaw', '2026-03-20', 'admin', 399, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226659732700_4', 'Ăn nhiều protein có gây hại thận?', 'Dù một hệ thận khỏe mạnh bình thường có thể xử lý lượng protein cao, nhưng đối với người đã có tổn thương thận, việc nạp quá nhiều protein có thể tạo ra gánh nặng quá mức. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/13/screenshot-2026-03-13-at-17-49-5249-6493-1773399093.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8oIup1SXwJUBFSAV6sCjA', '2026-03-20', 'admin', 500, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226679904000_5', 'Hội chứng lão hóa sớm', 'Hội chứng lão hóa sớm là một bệnh di truyền ít gặp khiến cơ thể trẻ em lão hóa nhanh bất thường. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/15312219thg32026-1773909094-17-3502-8851-1773909116.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1ZViTDl5vGm76l27f6ueOA', '2026-03-20', 'admin', 508, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226701321700_6', 'Viêm gan B mạn tính tiến triển ung thư', 'Ông Phi, 63 tuổi, viêm gan B mạn tính 10 năm sức khỏe ổn định nên không tái khám định kỳ, nay bác sĩ chẩn đoán ung thư gan giai đoạn sớm. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/hi-nh-thumb-1773971308-1773971-9835-9750-1773971433.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=yIc_kDHhvR_xD1pvP0VGhA', '2026-03-20', 'admin', 117, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226723648400_7', 'Xạ trị ung thư hạch bạch huyết như thế nào', 'Xạ trị ung thư hạch có thể được sử dụng đơn thuần hoặc kết hợp với hóa trị để tiêu diệt các tế bào u tại chỗ, giảm triệu chứng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/bs-loc-1773969177-1773969197-4790-1773969316.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hvcitarrhudIM5_CDo8IIQ', '2026-03-20', 'admin', 454, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226746784800_8', '7 thói quen làm tăng đường huyết buổi sáng', 'Mức đường huyết thường xuyên tăng vào buổi sáng có thể do nhiều nguyên nhân liên quan đến giấc ngủ, vận động, ăn uống vào đêm hôm trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-11-12-3935-2357-1773893572.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-FXnn5-oJXtAb5_GwQ-hpg', '2026-03-20', 'admin', 412, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226767041500_9', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-20', 'admin', 175, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226787833300_10', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-20', 'admin', 449, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226808556100_11', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-20', 'admin', 405, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226828402700_12', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-20', 'admin', 153, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226848060600_13', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-20', 'admin', 146, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226871904400_14', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-20', 'admin', 313, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226891433700_15', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-20', 'admin', 173, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226912552400_16', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-20', 'admin', 472, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226936461900_17', 'Thử thách giảm một cân mỡ đổi nửa cân thịt bò tại Trung Quốc', 'Hơn 2.400 người dân thành phố Vô Tích đăng ký tham gia thử thách giảm cân để quy đổi trọng lượng cơ thể sụt giảm thành các phần thịt bò, đuôi bò và lá sách. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/blujgsjcgkzgxov28r29h6slrhcdwp-3084-9216-1773851508.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cJByzTs2uf-iCO9WHvmVZw', '2026-03-20', 'admin', 473, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226957938100_18', 'Lòng trắng hay lòng đỏ trứng nhiều protein hơn?', 'Nhiều người cho rằng protein có ở lòng trắng trứng, còn lòng đỏ chủ yếu chứa chất béo song thực tế chất béo được phân bổ ở cả hai phần với tỷ lệ khá cân đối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/trungluoc-1773735015-177373503-3257-1653-1773735084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Fi6Q-5BdVlJjlX5EoICKfA', '2026-03-20', 'admin', 99, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1226979651600_19', 'Bẫy ''giảm đau nhanh'' từ thuốc đông y dởm', 'Thuốc đông y pha trộn hóa chất cấm tạo ảo giác hết bệnh tức thời, khiến nhiều người bệnh mạn tính và ung thư bỏ phác đồ điều trị chuẩn mực, dẫn đến đánh mất cơ hội sống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/b68c2082-b007-4e31-b108-003eb5-2978-8056-1773807046.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6sFkX8ilu6LKEesyjWQFng', '2026-03-20', 'admin', 219, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227001887500_20', '6 bài tập đơn giản tại nhà giúp kéo dài tuổi thọ', 'Chìa khóa của sự trường thọ nằm ở những chuyển động bền bỉ như đi bộ, đi cầu thang, squat, chống đẩy, đứng một chân và plank ngay tại chính ngôi nhà của bạn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/screenshot-2026-03-16-at-11-02-9494-7835-1773633846.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pf_-i646or_CqCdVKZYybw', '2026-03-20', 'admin', 117, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227023346800_21', 'Chàng trai suýt mất tinh hoàn vì cố chịu đau qua đêm', 'Chủ quan chịu đựng cơn đau vùng kín qua đêm, chàng trai 20 tuổi suýt hoại tử tinh hoàn do xoắn hai vòng, may mắn được bác sĩ Bệnh viện Quân y 175 mổ cấp cứu giữ lại kịp thời. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/233a1322-1773798712-4369-1773798922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tW7TIb8iGl4-yKI-tUdxiQ', '2026-03-20', 'admin', 214, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227044280700_22', '7 ''thủ phạm'' âm thầm khiến thận yếu đi', 'Ăn quá mặn, dùng thực phẩm chế biến sẵn, uống ít nước hoặc lạm dụng thuốc giảm đau có thể tăng áp lực lên thận theo thời gian. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/an-man-1773738708-1773738913-4727-1773738927.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NOq4Iuk7VwTI41RoRpSxfQ', '2026-03-20', 'admin', 10, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227064537000_23', 'Người gặp tai biến tử vong sau tiêm chủng có thể được bồi thường hơn 100 triệu đồng', 'Bộ Y tế đề xuất người gặp tai biến khi tiêm chủng thiệt hại tính mạng có thể được bồi thường 100 triệu đồng, phí mai táng bằng 10 lần mức lương cơ sở. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a7795-1754481674-1773899525-6921-8614-1773901922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fdofBhFGlUgbFwHFwI6a2w', '2026-03-20', 'admin', 225, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227084634000_24', 'Phát hiện mắc 2 loại ung thư từ triệu chứng vàng da', 'Người phụ nữ 59 tuổi vàng da, đau vùng hạ sườn kéo dài, đi khám được chẩn đoán mắc ung thư đại tràng và ung thư đường mật trong gan. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 141, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227106656700_25', 'Căn bệnh hiếm buộc bác sĩ chọn giải pháp ghép tạng domino', 'Từ dấu hiệu khó thở, các bác sĩ đã phát hiện ra căn bệnh hiếm nguy hiểm amyloidosis, giúp người đàn ông thoát cửa tử nhờ ghép đồng thời tim và gan thành công. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/img-8291-1773928219-1773928276-2399-1773928321.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GWtt0vlUJhMN1_b6wHCOVA', '2026-03-20', 'admin', 222, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227128811000_26', 'Dùng cà gai leo có giúp trị khỏi viêm gan B không?', 'Chồng tôi bị viêm gan B mạn tính, tôi tra cứu thông tin thấy dùng cà gai leo làm thuốc, giúp trị khỏi viêm gan B, có đúng không? (Đỗ Minh Hoa, 42 tuổi, Quảng Trị) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ca-gai-leo-1773916119-17739168-1342-4198-1773917298.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bkYSJaPU0S6ctMXtQqIOmw', '2026-03-20', 'admin', 361, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227145248100_27', 'Tán sỏi thận bằng ''đường hầm nhỏ'' qua da', 'Ông Đức, 66 tuổi, có viên sỏi san hô lớn ở thận trái, được bác sĩ dùng laser tán sạch sỏi qua da trong một lần. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/h2-1773912738-1773912762-9099-1773912790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=j38JjUzg5qR3qpK893tU5Q', '2026-03-20', 'admin', 330, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227160662100_28', 'Sẹo rỗ nặng do mụn', 'Chị Bình, 42 tuổi, nhiều sẹo rỗ sâu vùng mũi và má do nặn mụn, được bác sĩ điều trị tách đáy sẹo kết hợp vi kim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ba-c-tra-n-la-m-rf-1773906650-2435-6137-1773906761.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VkkZlz2OpWhquWYG-ewRA', '2026-03-20', 'admin', 213, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227176226200_29', 'Hệ thống trang thiết bị hiện đại tại Vinmec Ocean Park 2', 'Bệnh viện Đa khoa Quốc tế Vinmec Ocean Park 2 trang bị hàng loạt thiết bị y khoa tiên tiến như MRI 3.0, CT 512 lát cắt… đáp ứng nhu cầu khám chữa bệnh chuyên sâu với độ chính xác cao. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image1931552164extractword5out-975421-1773903823-1773913454.jpeg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BX_nsqPtleKJGP3xcwY0qQ', '2026-03-20', 'admin', 167, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227191522800_30', 'Tiểu đêm có phải do phì đại tuyến tiền liệt?', 'Ban đêm tôi thường đi tiểu 2-3 lần, khó tiểu, mệt mỏi. Có phải do phì đại tuyến tiền liệt không, điều trị thế nào? (Trọng Nghĩa, 55 tuổi, Đồng Nai) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/tah-8555-1-1773896092-17738961-3027-5635-1773896195.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5K75bH4lGA_9Lm7oZQauVA', '2026-03-20', 'admin', 197, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227206886700_31', '4 phương pháp điều trị rò hậu môn', 'Người bị rò hậu môn sau áp xe có thể được bác sĩ chỉ định mổ nội soi, điều trị tia laser hoặc keo sinh học. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/bs-luong-1773839125-1773839198-1501-1773839265.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mMANsiAEDnEcOmbLkYviAA', '2026-03-20', 'admin', 301, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227222169000_32', '5 khoáng chất cần thiết cho sức khỏe sinh lý nam', 'Kẽm, magie, kali, canxi, sắt tham gia vào quá trình sản xuất testosterone, duy trì sinh lý và sức khỏe nam giới. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773905181-1773905199-4800-1773905250.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=J7FYYReSZWjbjDl8OJm-8w', '2026-03-20', 'admin', 117, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227237535300_33', 'Những thói quen mỗi ngày giúp trẻ phát triển trí tuệ', 'Trẻ nên ngủ trước 22h, ăn sáng đầy đủ dinh dưỡng, duy trì thói quen đọc sách và tập thể dục mỗi ngày để phát triển trí não. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/93833d0df43141139173df329820a4-6130-7273-1773895766.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zoshz-NkGeLp3SvTGUEs5g', '2026-03-20', 'admin', 238, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227253023500_34', 'Dấu hiệu nhận biết bệnh về mắt', 'Thay đổi màu sắc mống mắt, hai mắt không thẳng hàng hoặc khó tập trung nhìn các vật ở gần hay xa có thể cảnh báo các vấn đề về mắt. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/momat3-1773892193-1773892202-3927-1773892212.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fX-6NRS3Zsww7n9bh7yqcg', '2026-03-20', 'admin', 481, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227268783200_35', '5 nhóm người nên hạn chế uống nước dừa', 'Người mắc tiểu đường, bệnh thận, đang dùng thuốc huyết áp hoặc có rối loạn điện giải nên hạn chế uống nước dừa để tránh ảnh hưởng sức khỏe. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/28b42ae376a74e37a5c7c694a5c3c4-1939-2018-1773891857.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=W03cZYxS8Wc_2LuiG6kP6w', '2026-03-20', 'admin', 159, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227284095000_36', 'Ba lần mắc zona thần kinh trong hai năm', 'Bà Dung, 62 tuổi, liên tiếp mắc zona thần kinh ở vùng lưng trong hai năm, lần sau nặng hơn lần trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/vnvc-zona-than-kinh-tai-phat-1-6377-2082-1773903517.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ot_zkYHKjIvfaOFuy5poIQ', '2026-03-20', 'admin', 215, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227300540600_37', '6 món chứa tinh bột người tiểu đường nên ăn', 'Thực phẩm giàu tinh bột phức hợp như yến mạch, ngũ cốc nguyên hạt, khoai lang giúp ổn định đường huyết và cung cấp năng lượng lâu dài cho cơ thể. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/Buoc-2-3355-1645172245-1773889121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ApfUYyAeH9YX9pzCl6WWCw', '2026-03-20', 'admin', 105, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227315913100_38', 'Tại sao lupus ban đỏ không thể chữa khỏi?', 'Bác sĩ chẩn đoán tôi mắc lupus ban đỏ. Bệnh nguy hiểm thế nào và tại sao không thể chữa khỏi hoàn toàn? (Nguyễn Dũng, Tiền Giang) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/taan08791-1773896320-177389644-1957-7425-1773897084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=a1vP8v6gMEZpjdw3KcbJiQ', '2026-03-20', 'admin', 213, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227331278200_39', 'Ăn mặn gây rối loạn tiền đình nặng hơn?', 'Tôi bị rối loạn tiền đình ngoại biên, được khuyên kiêng muối vì có thể làm bệnh nặng hơn, đúng không? (Lâm Phạm, 55 tuổi, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/a-nh-1773888613-1773888648-2147-1773888710.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u8tyXq22msAo0zpUDa0uew', '2026-03-20', 'admin', 399, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227347004000_40', 'Khó thở khi nằm cảnh báo bệnh gì?', 'Tôi thường cảm thấy khó thở khi nằm xuống, có liên quan đến bệnh hô hấp không? (Nguyễn Ngân, Hà Nội) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773887515-1773887563-7123-1773887636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=olNppiTaFzjv5NtxhAoN8w', '2026-03-20', 'admin', 330, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227363010900_41', 'Dùng sóng xung kích phá vôi hóa mạch vành', 'Bà Năm, 86 tuổi, đau ngực do động mạch vành hẹp tắc, được bác sĩ phá mảng vôi hóa bằng sóng xung kích ngăn nguy cơ nhồi máu cơ tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881685-1773881714-3499-2887-1773881937.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8a1D0rK_oLWWS9diLy28Bw', '2026-03-20', 'admin', 341, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227379032300_42', 'Cắt toàn bộ tuyến giáp chặn ung thư', 'Bà Loan, 50 tuổi, khám sức khỏe định kỳ phát hiện nhân giáp, sinh thiết lạnh xác định ung thư xâm lấn phải cắt toàn bộ tuyến giáp. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881289-1773881336-2586-1773881408.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yXQBUpD-Igp8_EDS1wUVEA', '2026-03-20', 'admin', 443, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227394745500_43', 'Suy buồng trứng ở tuổi 24', 'Chị gái bị vô sinh nên Hồng, 24 tuổi, chủ động đi khám sức khỏe sinh sản bất ngờ phát hiện buồng trứng gần cạn kiệt như phụ nữ mãn kinh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/key1103-3-1773817056-177381708-3143-7860-1773819558.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=CavEu2B_enyj5OEFH8VNdQ', '2026-03-20', 'admin', 84, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227410206500_44', 'Kỳ tích 90 ngày giữ song thai ''dọa'' sinh cực non', 'Chị Nhung, 33 tuổi, mang song thai 24 tuần dự báo nguy cơ 90% sinh non, được bác sĩ liên khoa phối hợp giữ thai thêm ba tháng đến khi sinh an toàn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881134-4834-1773881170.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1XDOjAjAXRUGNSkmDiyA0A', '2026-03-20', 'admin', 67, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227427139900_45', 'Trẻ bị lông mi mọc ngược có nguy hiểm?', 'Con tôi 5 tuổi, bị lông mi mọc ngược đâm vào mắt gây khó chịu, thường xuyên đỏ mắt. Tình trạng này có nguy hiểm và điều trị thế nào? (Trân, 31 tuổi, Long An) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/lo-ng-mi-mo-c-ngu-o-c-17738488-3850-2423-1773874352.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7CL5Pqz10iYGl92EJWXj0w', '2026-03-20', 'admin', 152, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227443013600_46', 'Cơn đau đầu cảnh báo sớm đột quỵ', 'Cơn đau đầu kéo dài, lúc âm ỉ, lúc dữ dội nhưng thoáng qua vài phút rồi biến mất có thể là dấu hiệu sớm đột quỵ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z7615389058820-b770c8502777a2a-3606-1286-1773839001.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DtpN1a4Sw8ZgN4_ZUIXC2Q', '2026-03-20', 'admin', 329, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227459251700_47', 'Ăn uống, dùng thuốc thế nào sau cắt toàn bộ tuyến giáp?', 'Tôi đã cắt toàn bộ tuyến giáp triệt căn ung thư, phải dùng hormone thay thế. Ăn uống thế nào, lưu ý gì để không ảnh hưởng hấp thu thuốc? (Quốc Bảo, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/a-nh-1-1773838561-1773838575-1902-1773838656.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KiTXzuR-XhOYEsReCOHtGQ', '2026-03-20', 'admin', 188, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227484787200_48', 'Ngủ đủ giấc - cách đơn giản bảo vệ trái tim', 'Ngủ đủ giấc hỗ trợ kiểm soát huyết áp, giảm viêm, tinh thần sảng khoái, từ đó tăng cường sức khỏe tim mạch. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/86262b59886c421faa325d79d43c42-3285-5331-1773807728.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=z2yoNwuRifB21tkyO55TgA', '2026-03-20', 'admin', 265, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227524758700_49', 'Ba thói quen ít ngờ có thể gây hại não', 'Ít tiếp xúc xã hội, sống ở nơi thiếu ánh sáng và nghe nhạc to lâu dài có thể ảnh hưởng tâm trạng, trí nhớ và sức khỏe não bộ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/geminigeneratedimage4gdeoq4gde-2334-2556-1773805576.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=6L8vpW0eIwiwb9yhfgyJEQ', '2026-03-20', 'admin', 349, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227543653200_50', 'Bé gái tử vong sau 9 giờ phát bệnh nghi do não mô cầu', 'Bé gái 10 tuổi tại Phú Quốc sốt, đau đầu, nổi ban, tím tái, khó thở, vào viện cấp cứu song không qua khỏi, nghi mắc viêm não mô cầu. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 437, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227564229200_51', 'Hai bác sĩ ép tim cứu người ngừng thở giữa sân bóng chuyền', 'Bác sĩ Trần Văn Biên và Nguyễn Cao Việt ép tim cứu sống người đàn ông 64 tuổi ngừng tuần hoàn, ngã quỵ giữa sân khi đang đánh bóng chuyền hơi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/eptim-1773824056-9512-1773824095.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=zKbi8S68AXzNCvOi1chXQw&t=image', '2026-03-20', 'admin', 218, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227578825200_52', 'Thử thách ''nằm một chỗ'' nhận tiền gây sốt tại Thượng Hải', 'Thí sinh tham gia thử thách ngủ được yêu cầu nằm một chỗ trong 24 giờ, không đi vệ sinh, không dùng điện thoại, máy tính để có cơ hội nhận tiền mặt cùng nhiều gói nghỉ dưỡng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/ngu-1773821005-1773821075-3441-1773821874.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8KlVBUvBMqmynOHVIVlLoA', '2026-03-20', 'admin', 378, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227594921700_53', 'Bác sĩ chỉ ra cách ăn uống giúp kéo dài tuổi thọ', 'Silvio Garattini, nhà dược học nổi tiếng người Italy, nhận định việc tiêu thụ ít thực phẩm có thể là chìa khóa để thêm nhiều năm sống khỏe mạnh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-17-at-14-42-3188-8472-1773733487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WtNm6z8rhaEufjF1U9dIpg', '2026-03-20', 'admin', 152, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227610417700_54', 'Hàng chục nghìn ca lao bị bỏ sót, TP HCM mở chiến dịch 100 ngày', 'TP HCM khởi động chiến dịch 100 ngày tầm soát lao chủ động bằng X-quang tích hợp AI cho 30.000 người dân có nguy cơ cao, trước tình trạng hàng chục nghìn ca bệnh bị bỏ sót. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/xn-be-nh-lao-1773813681-177381-6084-5180-1773814033.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=dhP9C3bqRRjz-Y8bvoWDCg', '2026-03-20', 'admin', 168, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227631241600_55', 'Trung Quốc chế tạo thiết bị bảo quản nội tạng hiến tặng trong nhiều ngày', 'Các nhà khoa học Trung Quốc vừa phát triển thành công hệ thống tưới máu máy đa nhiệt độ, giúp kéo dài thời gian bảo tồn nội tạng hiến tặng từ vài giờ lên nhiều ngày. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/1-1773810584-1773810598-6921-1773811859.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Mn8_w1WS1t3d0f_fsjsllg', '2026-03-20', 'admin', 258, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227653646900_56', 'Bắt bạn đời tránh thai, triệt sản vì định kiến giới sẽ bị phạt 12 triệu đồng', 'Từ ngày 1/5, cơ quan chức năng phạt tiền 10-12 triệu đồng đối với người ép buộc vợ hoặc chồng sử dụng biện pháp tránh thai, triệt sản với lý do định kiến giới. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 195, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227676677200_57', 'Uống nước chanh trị gout?', 'Nhiều người truyền tai nhau uống nước chanh tươi giúp rửa bớt acid uric, có thể dùng thay thuốc điều trị gout, điều này có đúng? (Tuấn, 32 tuổi, Hà Nội). (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/c15c6f48-ced4-4429-bfb5-9455cd-5801-6593-1773760546.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=W_kjheUzq2C2ME6zHgDgBg', '2026-03-20', 'admin', 31, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227699774500_58', 'Đề xuất hỗ trợ 1,5 triệu đồng sàng lọc bệnh trước và sau sinh', 'Bộ Y tế đề xuất mức chi 1,5 triệu đồng cho các dịch vụ sàng lọc phát hiện sớm bệnh bẩm sinh nhằm nâng cao chất lượng nòi giống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/anh-chup-man-hinh-2026-03-18-l-5391-3509-1773799029.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0k4SOQrMVLeMurI_aXm-A', '2026-03-20', 'admin', 296, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1227720919600_59', 'Tưởng đau bụng thông thường, hóa ung thư gan giai đoạn cuối', 'Người đàn ông 55 tuổi đến viện khám do đau tức vùng hạ sườn phải suốt một tháng, chán ăn, bác sĩ chẩn đoán ung thư gan giai đoạn cuối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-11-at-15-02-9133-1291-1773738650.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4LPRxOCxuzDWC9Ke0ApIMQ', '2026-03-20', 'admin', 189, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228852200700_0', 'Viện dưỡng lão đầu tiên trên thế giới vận hành bằng robot', 'Trạm dưỡng lão tại phố Vinh Hoa, Bắc Kinh trang bị 43 loại robot từ massage, châm cứu đến pha trà, nâng cao chất lượng sống cho người cao tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-8312-6385-1773934900.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VfFn7buTa9TsExFyHzR6g', '2026-03-20', 'admin', 461, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228868017600_1', 'Người trẻ đu trend ''gặp lại mình 10 năm trước''', 'Làm video đối thoại với mình 10 năm trước, nhiều người trẻ muốn nhìn lại hành trình trưởng thành, tự chữa lành tổn thương và định hướng tương lai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/10nam2-1773913137-3708-1773913342.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SmWlJhXMhpeoM7Fve9avQw', '2026-03-20', 'admin', 418, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228886729300_2', 'Cuộc sống bế tắc vì thiếu gas của người Ấn Độ', 'Xếp hàng bốn ngày không đổi được bình gas để nấu ăn, hàng triệu gia đình Ấn Độ đang lao đao vì chuỗi cung ứng năng lượng đứt gãy. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-15-4-3817-9609-1773910903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=TesnxCAAkCHU4m5yGF1yCQ', '2026-03-20', 'admin', 217, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228904323700_3', 'Vì sao nhiều người không quên được tình cũ?', 'Dưới lăng kính tâm lý học, việc chúng ta không ngừng tiếc nuối và lý tưởng hóa người yêu cũ thực chất chỉ là một "cú lừa" của não bộ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/nguoi-cu-1773906295-1773906318-6293-1773906415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=HVjiPxxd9gacVL6Y22uXqA', '2026-03-20', 'admin', 497, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228920928400_4', 'Bi kịch của nữ giám đốc lộ chuyện ngoại tình ở đêm nhạc', 'Từng là tâm điểm chỉ trích vì nụ hôn vụng trộm với sếp, cựu giám đốc Kristin Cabot lần đầu lên tiếng về bi kịch mất trắng sự nghiệp và tiêu chuẩn kép của dư luận. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-3953-9787-1773905123.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SnVW0ZXwG0D0cs-jv11r5w', '2026-03-20', 'admin', 75, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228937237000_5', 'Lợi ích bất ngờ của người thấp bé', 'Khác với lầm tưởng cao lớn đồng nghĩa với khỏe mạnh, người có vóc dáng khiêm tốn thực chất lại ít mắc ung thư, hiếm khi gãy xương và có xu hướng sống thọ hơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-16-1-3564-4232-1773826547.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WILYrMZI2_N_0dlS2haaeA', '2026-03-20', 'admin', 232, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228956937500_6', 'Bi kịch của những tình yêu AI', 'Tối 13/2, SkeweredKebab (nickname) đọc lại toàn bộ những cuộc hội thoại với ChatGPT để làm lễ tiễn biệt "người chồng AI" vừa bị khai tử. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-15-5-6470-2528-1773825011.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hywduvy6fBWG60Hqv4b41Q', '2026-03-20', 'admin', 156, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228974106800_7', 'Gia đình ''siêu nhân Gao'' ở Hưng Yên gây bão mạng', 'Giữ trọn đam mê siêu nhân từ nhỏ, anh Ngọc Trung sắm trang phục siêu nhân Gao rủ vợ hóa trang, sáng tạo loạt video hài hước mang lại tiếng cười cho cộng đồng. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7606213086839-ba7d4f64bbbc508-7613-9150-1773319405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mrTZfGPqSl0KOJOxGL3Etw', '2026-03-20', 'admin', 172, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1228991837500_8', 'Vụ ly hôn tỷ USD và góc khuất đời tư của chủ tịch tập đoàn SK', 'Cuộc chiến pháp lý giữa Chủ tịch tập đoàn SK Chey Tae-won và vợ cũ Roh Soh-yeong gây chấn động bởi khối tài sản khổng lồ và sự xuất hiện của "người thứ ba". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/00-1773805459-1773805465-7488-1773807993.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ma9jNQK-Y2L9EYbGcAWU3Q', '2026-03-20', 'admin', 142, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229007460200_9', 'Nhà hàng đập 600 bộ bát đĩa vì khách cho chó lên bàn ăn', 'Ông Giang, quản lý nhà hàng tại Thương Khâu (Hà Nam), đã đập bỏ 600 bộ bát đĩa và đóng cửa khử trùng quán khi phát hiện một thực khách mang chó lên bàn ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/pet-restaurant-2-1773823218-17-3022-8308-1773823607.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YJaopzEQ_wQcv0LriogkfQ', '2026-03-20', 'admin', 311, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229023418800_10', 'Nạn trộm cắp ở khu nhà giàu Mỹ', 'Từng là chốn an cư bình yên của giới tinh hoa, khu Sharon Heights (vùng vịnh San Francisco) giờ chìm trong bất an khi kẻ gian liều lĩnh đột nhập ngay lúc gia chủ đang ăn tối. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/ratio3x2-960-1773806447-177380-5965-1359-1773809180.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=XY--0saGjRWJfVzM5zTLrQ', '2026-03-20', 'admin', 193, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229038673200_11', 'Làn sóng ''nhân lực tinh hoa'' rời bỏ Israel', 'Từng coi Tel Aviv là "thiên đường công nghệ", kỹ sư Elizabeth Cohen quyết định rời đi vì không muốn sinh con giữa những tiếng còi báo động tên lửa. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-17-at-23-3-7325-4333-1773766923.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KazThb0Myl6qlnll2uVyPg', '2026-03-20', 'admin', 339, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229053544400_12', 'Cách tự học tiếng Anh của ''cô giáo nhí'' 9 tuổi', 'Từ trò chơi đóng vai cô giáo mỗi tối, bé Vân Anh khiến cộng đồng mạng bất ngờ bởi khả năng nói tiếng Anh trôi chảy và cách dạy em đầy kiên nhẫn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/va-n-anh-2-1773661730-17736617-3169-1895-1773662279.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MFZagmWNCjA_dg4MlTV1-g', '2026-03-20', 'admin', 340, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229068693300_13', 'Phát tài nhờ tờ giấy bỏ quên 30 năm', 'Đang phải sống chật vật với lương hưu eo hẹp, vợ chồng ông Sato bất ngờ thu về 68 triệu yen nhờ tìm thấy tờ biên lai mua cổ phiếu, bị bỏ quên 30 năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/co-phieu-2-jpeg-1773797809-177-3785-6774-1773797902.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T-SETu0hLWUdD-lr9bNEBQ', '2026-03-20', 'admin', 449, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229083935700_14', 'Bi kịch của thế hệ ''kiếm nhiều tiền nhưng không giàu''', 'Thu nhập 450.000 USD mỗi năm nhưng vợ chồng Alex vẫn phải ở nhà thuê, chưa trả hết nợ sinh viên và nơm nớp lo sợ thiếu tiền giữa lòng New York đắt đỏ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-00-3-6865-5413-1773770804.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICLidWfdmD2K6KISqPINoQ', '2026-03-20', 'admin', 85, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229100095000_15', 'Hai chuyến đi Việt Nam ''cứu rỗi'' người phụ nữ Mỹ', 'Rơi vào trầm cảm sau khi mẹ qua đời, Lilly Hubbard quyết định quay lại Việt Nam và tìm thấy sự "chữa lành" từ tình người ấm áp ở vùng đất xa lạ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/lilly-2-1773802709-1773802742-4016-1773802752.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5uQdZnsKta3M8vRTp6nZhA', '2026-03-20', 'admin', 416, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229116400300_16', 'Vì sao quần áo thể thao giặt xong vẫn hôi?', 'Ném ngay đồ tập đẫm mồ hôi vào máy giặt, dùng nhiều xà phòng hay nước xả vải là sai lầm khiến quần áo luôn bốc mùi khó chịu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/a-nh-ma-n-hi-nh-2026-03-16-lu-7904-9038-1773736876.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KXY2uWiUcoSsOpLDwHycOA', '2026-03-20', 'admin', 109, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229133009200_17', 'Bên trong nhà lắp ghép 30 m2 của tỷ phú Elon Musk', 'Mặc dù sở hữu hàng trăm tỷ USD, tỷ phú Elon Musk hiện sống trong căn nhà lắp ghép rộng 30 m2, thiếu tiện nghi đến mức mẹ ông phải ngủ ở gara. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/577333596-3394143064076672-485-6636-3102-1773724581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=b5eyN5ibANA-m59NlkHsAQ', '2026-03-20', 'admin', 370, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229148558000_18', 'Vợ cho ''thuê'' chồng', 'Phát hiện chồng ngoại tình, cô Khun Kwang ra thỏa thuận cho nhân tình của anh thuê chồng với giá 30.000 bath mỗi tháng, tuy nhiên hợp đồng này bị luật sư cảnh báo vô hiệu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/chatgpt-image-11-27-42-17-thg-9377-7480-1773721720.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NBqR-Rw-evtAbpk1qTmaKQ', '2026-03-20', 'admin', 504, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229163334700_19', 'Vì sao nhà chung cư ở Mỹ ngày càng ít?', 'Từng là lựa chọn an cư giá rẻ cho người trẻ Mỹ, số lượng chung cư thương mại sụt giảm mạnh do rào cản pháp lý, thuế và chi phí bảo hiểm tăng vọt. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/im-92913950-1773654144-1773671-8010-8091-1773672308.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Bm4Dwf779JQ1G3-LVfRR1w', '2026-03-20', 'admin', 142, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229180376000_20', 'Vợ 50 tuổi làm IVF chiều chồng trẻ', 'Bất chấp những đàm tiếu của dư luận, bà Pilli Cortese vẫn quyết định thụ tinh nhân tạo ở tuổi 50 để thỏa ước nguyện làm cha của người chồng kém 21 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5921-9658-1773633940.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9Zuubwaaw2BqQmbUtn07fA', '2026-03-20', 'admin', 369, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229197361100_21', 'Bẫy thổi phồng chức danh khi tuyển dụng', 'Nhiều doanh nghiệp đang gán mác "giám đốc", "trưởng phòng" cho người lao động nhưng chỉ trả mức lương nhân viên nhằm thu hút ứng viên và tối ưu chi phí. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/tuyen-dung-jpeg-1773679492-177-2056-8763-1773681102.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KigiyGPtR51yLB_8Hefyxg', '2026-03-20', 'admin', 93, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229212741500_22', 'Dân công sở Mỹ bỏ ôtô, đạp xe, làm từ xa để né ''bão'' giá', 'Thấy giá nhiên liệu tăng vọt, Boris Kagarlitskiy quyết định cất chiếc Lexus ở nhà, lôi xe đạp cũ ra lau chùi để bắt đầu chuỗi ngày đi làm bằng sức người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/dap-xe-1773678268-1773678292-1-1377-3127-1773678449.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=w-sPfSoia-AE5rGBtpoj4Q', '2026-03-20', 'admin', 430, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229228738700_23', 'Nhan Phúc Vinh, Hà Thu tập chống đuối nước cùng 1.000 học sinh', 'Diễn viên Nhan Phúc Vinh, Á hậu Hà Thu cùng hơn 1.000 học sinh nhận biết mực nước an toàn, kỹ năng thở nước, tại workshop chống đuối nước, sáng 16/3. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/dsc04354-1773740071-8030-17737-9004-8642-1773765903.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A4JrUo23I3KsRgZmF6I4Lg', '2026-03-20', 'admin', 44, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229244912500_24', '3 bước đánh lừa não bộ để ngủ nhanh hơn', 'Kỹ thuật "xáo trộn nhận thức" giúp ngắt quãng dòng suy nghĩ lo âu, mô phỏng trạng thái mơ màng tự nhiên để não bộ thư giãn và dễ dàng chìm vào giấc ngủ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/z7591758010902-c59406ff20941de-5096-4651-1773652579.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xQChxkieWCwZeML9fYn7Gg', '2026-03-20', 'admin', 46, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229261004300_25', 'Yêu 6 năm mới biết bạn gái đã có chồng con', 'Chi hơn một triệu tệ cho bạn gái trong 6 năm mặn nồng, anh Wang bàng hoàng phát hiện người yêu thực chất đã yên bề gia thất, thậm chí các con đã học cấp hai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5017-9753-1773636339.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LRn0uHe2LxkLnmac08jIuw', '2026-03-20', 'admin', 267, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229276563500_26', 'Nhiều nông dân Mỹ có nguy cơ phá sản vì xung đột Trung Đông', 'Xung đột tại Trung Đông đẩy giá nhiên liệu và phân bón lên mức kỷ lục, giáng đòn mạnh vào hàng loạt trang trại, đẩy họ vào cảnh phá sản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-13-at-22-1-6679-9104-1773417216.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wNZTd6jP3YfT0zCvXMAvYg', '2026-03-20', 'admin', 46, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229291918700_27', 'Khủng hoảng xăng dầu ''bóp nghẹt'' người nghèo châu Á', 'Xung đột ở Trung Đông gây đứt gãy nguồn cung nhiên liệu, đẩy hàng chục triệu người lao động tại châu Á vào cảnh thiếu xăng, khí đốt và sụt giảm thu nhập. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/a-nh-ma-n-hi-nh-2026-03-16-lu-7437-9899-1773631014.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pswj5Qok0ZT1EUC6gyBi6g', '2026-03-20', 'admin', 448, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229307817800_28', 'Tụ tập - quy tắc giữ gìn tình bạn của người Đức', 'Cuộc sống bận rộn khiến nhiều mối quan hệ phai nhạt nhưng người Đức áp dụng quy tắc "Stammtisch" - những cuộc tụ họp định kỳ, đơn giản nhưng hiệu quả. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/stammtisch-2-1773625060-177362-4038-7784-1773625553.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lkewTZzZ2noESjRQobw1iA', '2026-03-20', 'admin', 344, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229323901500_29', 'Chàng trai Canada ''bẻ lái cuộc đời'' vì tình yêu với cô gái Việt', 'Ngay buổi hẹn đầu dưới chân tháp Tokyo, Thu Thủy đưa ra loạt tiêu chuẩn khắt khe về bạn trai, rồi dội gáo nước lạnh vào Seiwa: “Em không muốn gặp lại anh nữa”. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/img-1831-1-jpeg-1773460527-177-7354-6141-1773461950.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mt3pi6U16KHThn4v8-hOBA', '2026-03-20', 'admin', 187, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229339423700_30', 'Ước mơ của người vợ 10 năm giữ món quà chồng chưa kịp tặng', 'Cất kỹ chiếc váy và chú gấu bông chồng mua tặng trước khi tử nạn, chị Thúy mong một ngày được trao lại cho con gái trong sự kiện trọng đại nhất đời. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/z7619839331948-d5148baa4b6833d-6407-2821-1773504440.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RytXItajr9SLpO3H0LRM4Q', '2026-03-20', 'admin', 141, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229354960200_31', 'Cuộc đoàn tụ gượng gạo của cô gái bị vứt ở nhà vệ sinh 28 năm trước', 'Bị ông nội vứt bỏ từ lúc 2 ngày tuổi, Hong Yangli vượt nửa vòng trái đất về nhận mẹ nhưng đối diện màn đoàn tụ lạnh lẽo, dấy lên nhiều tranh cãi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/1-3-1773547826-1773547843-5092-1773548222.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=amEJ_VUF9IpG9eD0G9_PNg', '2026-03-20', 'admin', 326, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229395940200_32', 'Cụ bà 82 tuổi bị lừa kết hôn bằng 20 quả trứng', 'Cụ bà mù chữ 82 tuổi ở Hồ Nam tưởng làm giấy tờ để nhận trợ cấp 1.000 tệ và 20 quả trứng, không ngờ bị lừa ký giấy đăng ký kết hôn với người đàn ông 47 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/00-1773543821-1773543868-7185-1773543919.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KfEnT7aoLQ3RSBsN1-oYAw', '2026-03-20', 'admin', 296, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229418461900_33', 'Người đàn ông bị hàng loạt nhà tang lễ từ chối vì béo', 'Ở Canada, béo phì không chỉ là một bài toán khó về sức khỏe khi còn sống, mà nay lại biến thành "rào cản cuối cùng" sau khi chết. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/0-1-1773549860-1773549866-3805-1773550180.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vVbCv37mEQDizIgnTBFi5g', '2026-03-20', 'admin', 315, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229433913400_34', 'Suýt mất mạng, cặp vợ chồng hối hận vì ''bỏ phố về rừng''', 'Từng ảo tưởng về sự tuyệt vời của cuộc sống biệt lập giữa thiên nhiên, vợ chồng Jayme bừng tỉnh sau sự cố suýt mất mạng ngày sinh nở, nhận ra cái giá của sự cô độc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773464228-1773464933-3946-1773464939.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oyCVWVQKOW3_wjd1YLbydQ', '2026-03-20', 'admin', 109, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229456944300_35', 'Đường đến giải bơi trong hồ băng của cậu bé Hà Nội', 'Trên đỉnh núi tuyết ở Neuhermsdorf, Phan Anh mặc quần bơi đứng lặng nhìn mặt hồ Altes Zollhaus bốc khói trong khi ban tổ chức luôn tay vớt những tảng băng cản đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/phan-anh-1-1773221913-4040-177-8906-6797-1773503423.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tRJ-e86PBimTvuLx8uLrLQ', '2026-03-20', 'admin', 358, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229472188300_36', 'Đánh cược mạng sống mưu sinh trong vùng chiến sự', 'Mỗi khi tiếng còi báo động vang lên, nữ giúp việc Joycee Pelayo chạy vội đến cụ ông mà cô đang chăm sóc, dìu ông lên xe lăn rồi đẩy thật nhanh xuống hầm trú ẩn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773484138-1773484220-8888-1773484945.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SXxzNvSvE4dKP7MSqygIxA', '2026-03-20', 'admin', 283, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229486870700_37', 'Người Lạng Sơn chi hàng trăm triệu làm cỗ mời khách lạ', 'Để tán lộc và cầu may, người dân Lạng Sơn chi hàng trăm triệu đồng dựng rạp, thết đãi cỗ miễn phí cho cả khách lạ về dự hội đền Kỳ Cùng - Tả Phủ đầu năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/6-2-1773501948-1773502444-9849-1958-9924-1773505959.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0x9NpYpx7nxQjaqa-_PsZg', '2026-03-20', 'admin', 261, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229502354000_38', 'Gần 3.000 runner chạy giữa đô thị lớn nhất Nghệ An', 'Gần 3.000 vận động viên dự giải Eco Central Park Marathon lần đầu tổ chức với cung đường xuyên qua công viên và các thảm hoa trong khu đô thị. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/kbd03827-1773548789-1773549037-3771-1773551974.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0E-9mGgNroDH6ojqizG9w', '2026-03-20', 'admin', 309, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229517862700_39', 'Thường xuyên bị nhầm là con vì kém vợ 23 tuổi', 'Bất chấp khoảng cách 23 tuổi và hay bị nhầm là mẹ con, cặp đôi Azmirullah (28 tuổi) và Wan Nazihah (51 tuổi) vẫn có cuộc sống viên mãn sau gần 7 năm kết hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-5511-1481-1773391224.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rVhmD8KwmfMyFVajva3Fg', '2026-03-20', 'admin', 227, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229533402500_40', 'Cả nhà bới 10 tấn rác tìm túi vàng', 'Gia đình 8 người ở Giang Tây phải thức trắng đêm, lục tung 10 tấn rác để tìm lại túi vàng trị giá 1,5 triệu tệ (5,2 tỷ đồng) bị người nhà vứt nhầm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/chatgpt-image-12-00-22-14-thg-6372-9837-1773467256.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=_9x4DRlTKFjkiC60B2o8FA', '2026-03-20', 'admin', 310, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229548453100_41', 'Vì sao không cần ''ra khỏi phòng là tắt đèn''?', 'Lời khuyên "ra khỏi phòng là tắt đèn" đã lỗi thời trong kỷ nguyên bóng đèn LED, nhưng vẫn áp dụng đúng quy tắc 15 phút với đèn huỳnh quang. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/1-1773454941-1773455346-9660-1773455690.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bdkGsflc9Jxr6O6pwJzT-A', '2026-03-20', 'admin', 305, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229564364200_42', 'Những cuộc hôn nhân tan vỡ vì trúng độc đắc', 'Trúng thưởng hàng chục triệu USD, nhiều cặp vợ chồng ngỡ đã chạm tay vào hạnh phúc viên mãn nhưng cuối cùng lại rơi vào cảnh ngoại tình, kiện tụng và ly hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/screen-shot-2026-03-14-at-00-3-2966-9237-1773423562.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zp535HhmTaj7GmpNZEZnIw', '2026-03-20', 'admin', 117, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229579875300_43', 'Dubai vắng vẻ ''chưa từng thấy''', 'Dưới sức ép từ các đợt tấn công của Iran, người nước ngoài đang vội vã rời khỏi Dubai, đẩy "thành phố vàng" vào cảnh vắng lặng như thị trấn ma. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/untitled-1773453416-1773453692-9708-1773453849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vbalNxj_XueEp65nAOLXcA', '2026-03-20', 'admin', 298, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229594886600_44', 'Chàng trai không tay và những món ăn ''triệu view''', 'Mất đôi tay sau tai nạn, Trọng Định, 23 tuổi, học cách nấu ăn bằng chân và hai mỏm cụt, biến nỗi đau thành nghị lực sống truyền cảm hứng cho hàng triệu người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/di-nh-di-cho-1773409298-177340-4382-8632-1773422430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0DityHvFbLGR7izILlXGOQ', '2026-03-20', 'admin', 467, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229610211200_45', 'Dùng AI tạo ''chuyên gia giả'' để trị thói giục cưới của cha mẹ', 'Mệt mỏi vì bị cha mẹ liên tục giục lấy chồng, Cao Mei, 38 tuổi, dùng AI tạo ra một "chuyên gia tâm lý" để giảng đạo lý, thuyết phục ngược lại phụ huynh. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/0-1773398662-1773398682-1718-1773399208.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EVMDlFbSybo3mN85hxNoWg', '2026-03-20', 'admin', 176, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229625765000_46', 'Đổ xô mua nhà thờ cũ làm nhà ở', 'Giữa "bão" giá bất động sản, nhiều người chọn mua các nhà thờ cũ với giá rẻ để cải tạo thành không gian sống độc đáo. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/a-nh-ma-n-hi-nh-2026-03-13-lu-3696-4834-1773377205.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SH7Rb4ILOv0ksxLF-wv1NQ', '2026-03-20', 'admin', 181, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229640963200_47', 'Hơn 2.000 người mua vé sớm dự lễ hội ẩm thực Saigontourist 2026', 'Hàng nghìn vé sớm được bán trước thềm Lễ hội Văn hóa Ẩm thực Saigontourist 2026, hút 2.000 lượt đặt mua sau 10 ngày. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/kho-ng-khi-nga-p-tra-n-ma-u-sa-5727-7837-1773461994.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0g7XJzZGG1R1YRikkMMY9g', '2026-03-20', 'admin', 443, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229656162700_48', 'Trẻ học được gì từ việc cha rửa bát?', 'Sự phân công việc nhà giữa cha và mẹ là "bản thiết kế" cho hành vi xã hội của trẻ, liên quan trực tiếp đến nguy cơ bạo lực học đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-2254-8889-1773393096.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s6Oxd_5Gu1oXQ46K_G7Dug', '2026-03-20', 'admin', 125, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229671429800_49', '20.000 thuyền viên kẹt gần Hormuz nguy cơ thiếu nhu yếu phẩm', 'Gần 20.000 thủy thủ mắc kẹt trên các tàu hàng ở eo biển Hormuz đang đối mặt với nỗi lo tên lửa rơi trúng và tình trạng cạn kiệt nhu yếu phẩm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/tau-dau-1773402850-1773402875-3232-1773403067.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NTSnOJHpgEet9waOtHY1dw', '2026-03-20', 'admin', 393, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229686870700_50', 'Quy tắc ''muối tách, đường giữ'' trong nấu ăn', 'Nêm gia vị đúng thời điểm không chỉ giúp món ăn đậm đà mà còn ảnh hưởng đến độ ngon, độ giòn, độ mọng của món ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/pexelsrohanmuzafar3054690-1773-8724-2189-1773394017.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=k9GycCL6VDqIrC8odwZSsA', '2026-03-20', 'admin', 474, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229701892300_51', 'Vì sao nhiều người chỉ làm việc hiệu quả sát deadline?', 'Áp lực thời gian cận kề giúp não bộ tiết ra các hormone cảnh báo, loại bỏ sự trì hoãn và tăng cường khả năng tập trung vào công việc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/deadline-1773390004-1773390024-3813-1773390069.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=IrRI2aePlRHDe6ihst78Iw', '2026-03-20', 'admin', 400, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229716653400_52', 'Góc khuất sau vấn nạn cố tình xô đẩy ở Nhật Bản', 'Đoạn video bé gái bị xô ngã ở Tokyo đã gióng lên hồi chuông báo động về "butsukari" - vấn nạn cố tình va chạm người lạ để xả stress đang gia tăng tại Nhật Bản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/Thie-t-ke-chu-a-co-te-n-3-1773-4469-9773-1773374593.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=kmKl_9ydvAdA8gw15swzMg&t=image', '2026-03-20', 'admin', 34, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229731537400_53', 'Con trai dùng trực thăng đưa mẹ về quê', 'Mẹ nói muốn về quê, người đàn ông tên Long ở Tứ Xuyên lái trực thăng cá nhân trị giá 7 triệu tệ đưa bà về vì ôtô đã cho bạn mượn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1773272450-177327-8656-6736-1773274348.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Y9XSNVQj99QxicXvcU31fg', '2026-03-20', 'admin', 150, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229747073900_54', 'Giới siêu giàu vung tiền xây hầm trú ẩn', 'Lo ngại bất ổn toàn cầu, giới siêu giàu đang vung hàng trăm nghìn USD xây các hầm ngầm trú ẩn xa xỉ, mang lại doanh thu kỷ lục cho hãng sản xuất. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/untitled-1773333717-1773334180-5221-1773334666.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lsi1Zbgp6ky9ZkkJLntrzA', '2026-03-20', 'admin', 391, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229763076800_55', 'Chuyện tình 15 ngày của đôi vợ chồng hoán đổi giới tính', 'Từng cạn niềm tin vào tình yêu, Mộc Trà - người chuyển giới nữ và Thiên Minh - người chuyển giới nam, quyết định kết hôn sau 15 ngày quen nhau vì tìm thấy sự đồng cảm sâu sắc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-12-at-15-0-4845-1689-1773336910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zsMmkb4ZKHA4pdM_bk4JnA', '2026-03-20', 'admin', 198, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229778076700_56', 'Quy tắc ''cấm khoe mẽ'' của phố Wall', 'Việc bốn chuyên viên tài chính trẻ làm mẫu ảnh thời trang đã làm bùng nổ tranh cãi về quy tắc bất thành văn ở Phố Wall: Tuyệt đối không thu hút sự chú ý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/screen-shot-2026-03-12-at-14-5-9812-8707-1773302260.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7wMXhzX_8pLrHBKLQ_kwXw', '2026-03-20', 'admin', 133, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229793651300_57', 'Tỷ phú bánh bao ở nhà thuê, quyết không để tài sản cho con', 'Sở hữu chuỗi 5.600 cửa hàng và tài sản gần 600 triệu USD nhưng danh mục bất động sản của ông Lưu Hội Bình vẫn trống trơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/a-nh-ma-n-hi-nh-2026-03-12-lu-4281-8357-1773300992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Aibug9pmVMbPQDhOgkh3cA', '2026-03-20', 'admin', 310, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229812866900_58', 'Tổ bay góp tiền đưa mẹ con người phụ nữ khiếm thị về quê', 'Địu con nhỏ đi từ TP HCM về Cao Bằng, người mẹ khiếm thị được tổ tiếp viên chăm sóc và quyên tiền đặt vé xe giường nằm chặng cuối về tận nhà. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7613036872520-979f4c14b579a74-6143-5591-1773323528.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZuKH3SFTr-IeOBXRl9BZ_A', '2026-03-20', 'admin', 246, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1229828515300_59', 'Ba dấu hiệu cảnh báo thịt đông lạnh đã hỏng', 'Nhiều gia đình tích trữ thịt trong tủ đá hàng tháng trời và vô tư đem chế biến dù chúng đã biến màu, nhớp nháp hay bị "bỏng lạnh". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1-1773284849-1773-8712-1642-1773285672.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jOrSg2ECal3EmqLTWjqnSA', '2026-03-20', 'admin', 270, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165282283600_0', 'Thuốc giảm cân 173 USD về 54 USD - cuộc cách mạng giá từ Ấn Độ', 'Làn sóng thuốc giảm cân giá rẻ từ Ấn Độ đang tạo nên một cuộc cách mạng y tế trên toàn cầu song đặt ra những thách thức lớn về kiểm soát chất lượng và an toàn người dùng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/giam-can2-1773966197-177396623-9948-3102-1773966358.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W2a1vxNWq1ipx6Xc65LezA', '2026-03-20', 'admin', 325, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165296752600_1', 'Đũa kim loại 12 cm trong cổ họng người đàn ông suốt 8 năm', 'Các bác sĩ tại tỉnh Liêu Ninh phẫu thuật lấy thành công chiếc đũa kim loại dài 12 cm nằm sâu trong vòm miệng một người đàn ông suốt 8 năm sau khi bệnh nhân vô tình nuốt phải lúc đang ăn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/00-1773940108-1773940223-1317-1773940303.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5Jbnc7ojWtIgpa9aJp0PRQ', '2026-03-20', 'admin', 70, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165309047300_2', 'Bác sĩ cảnh báo ''bẫy tâm lý'' khiến nhiều người sập bẫy thuốc gia truyền giả', 'Bác sĩ Ngô Văn Tỵ, Khoa Ung Bướu thuộc Bệnh viện Đại học Y Hà Nội, vẫn chưa thôi ám ảnh khi nhắc lại ca trực vừa qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z4553627269963-2f6fc10ad7c154e-2394-3553-1773818309.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JHP6dnV6gDB7g0SuN0IfFw', '2026-03-20', 'admin', 344, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165322747500_3', 'Án tử rình rập từ thử thách ''ngất xỉu'' trên TikTok', 'Chị Lan, 42 tuổi, bần thần khi phát hiện trong lịch sử xem video của con trai lớp 8 là cảnh một đám trẻ đang reo hò quanh một nam sinh vừa đổ gục, co giật nhẹ trên sàn nhà. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/2-1773366911-8280-1773367913-1-4012-5941-1773619069.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=uPJ_bYzYnVJz4Nrj5NLfaw', '2026-03-20', 'admin', 338, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165336750400_4', 'Ăn nhiều protein có gây hại thận?', 'Dù một hệ thận khỏe mạnh bình thường có thể xử lý lượng protein cao, nhưng đối với người đã có tổn thương thận, việc nạp quá nhiều protein có thể tạo ra gánh nặng quá mức. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/13/screenshot-2026-03-13-at-17-49-5249-6493-1773399093.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8oIup1SXwJUBFSAV6sCjA', '2026-03-20', 'admin', 57, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165350743900_5', 'Hội chứng lão hóa sớm', 'Hội chứng lão hóa sớm là một bệnh di truyền ít gặp khiến cơ thể trẻ em lão hóa nhanh bất thường. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/15312219thg32026-1773909094-17-3502-8851-1773909116.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1ZViTDl5vGm76l27f6ueOA', '2026-03-20', 'admin', 179, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165365798500_6', 'Viêm gan B mạn tính tiến triển ung thư', 'Ông Phi, 63 tuổi, viêm gan B mạn tính 10 năm sức khỏe ổn định nên không tái khám định kỳ, nay bác sĩ chẩn đoán ung thư gan giai đoạn sớm. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/hi-nh-thumb-1773971308-1773971-9835-9750-1773971433.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=yIc_kDHhvR_xD1pvP0VGhA', '2026-03-20', 'admin', 192, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165380376200_7', 'Xạ trị ung thư hạch bạch huyết như thế nào', 'Xạ trị ung thư hạch có thể được sử dụng đơn thuần hoặc kết hợp với hóa trị để tiêu diệt các tế bào u tại chỗ, giảm triệu chứng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/bs-loc-1773969177-1773969197-4790-1773969316.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hvcitarrhudIM5_CDo8IIQ', '2026-03-20', 'admin', 454, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165393469900_8', '7 thói quen làm tăng đường huyết buổi sáng', 'Mức đường huyết thường xuyên tăng vào buổi sáng có thể do nhiều nguyên nhân liên quan đến giấc ngủ, vận động, ăn uống vào đêm hôm trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-11-12-3935-2357-1773893572.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-FXnn5-oJXtAb5_GwQ-hpg', '2026-03-20', 'admin', 214, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165408111300_9', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-20', 'admin', 174, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165423614100_10', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-20', 'admin', 94, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165438166000_11', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-20', 'admin', 89, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165452259800_12', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-20', 'admin', 475, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165467581800_13', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-20', 'admin', 70, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165481549500_14', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-20', 'admin', 146, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165495472200_15', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-20', 'admin', 36, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165511612100_16', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-20', 'admin', 154, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165525941300_17', 'Thử thách giảm một cân mỡ đổi nửa cân thịt bò tại Trung Quốc', 'Hơn 2.400 người dân thành phố Vô Tích đăng ký tham gia thử thách giảm cân để quy đổi trọng lượng cơ thể sụt giảm thành các phần thịt bò, đuôi bò và lá sách. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/blujgsjcgkzgxov28r29h6slrhcdwp-3084-9216-1773851508.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cJByzTs2uf-iCO9WHvmVZw', '2026-03-20', 'admin', 134, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165539561900_18', 'Lòng trắng hay lòng đỏ trứng nhiều protein hơn?', 'Nhiều người cho rằng protein có ở lòng trắng trứng, còn lòng đỏ chủ yếu chứa chất béo song thực tế chất béo được phân bổ ở cả hai phần với tỷ lệ khá cân đối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/trungluoc-1773735015-177373503-3257-1653-1773735084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Fi6Q-5BdVlJjlX5EoICKfA', '2026-03-20', 'admin', 489, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165554151700_19', 'Bẫy ''giảm đau nhanh'' từ thuốc đông y dởm', 'Thuốc đông y pha trộn hóa chất cấm tạo ảo giác hết bệnh tức thời, khiến nhiều người bệnh mạn tính và ung thư bỏ phác đồ điều trị chuẩn mực, dẫn đến đánh mất cơ hội sống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/b68c2082-b007-4e31-b108-003eb5-2978-8056-1773807046.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6sFkX8ilu6LKEesyjWQFng', '2026-03-20', 'admin', 225, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165568578600_20', '6 bài tập đơn giản tại nhà giúp kéo dài tuổi thọ', 'Chìa khóa của sự trường thọ nằm ở những chuyển động bền bỉ như đi bộ, đi cầu thang, squat, chống đẩy, đứng một chân và plank ngay tại chính ngôi nhà của bạn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/screenshot-2026-03-16-at-11-02-9494-7835-1773633846.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pf_-i646or_CqCdVKZYybw', '2026-03-20', 'admin', 490, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165582117000_21', 'Chàng trai suýt mất tinh hoàn vì cố chịu đau qua đêm', 'Chủ quan chịu đựng cơn đau vùng kín qua đêm, chàng trai 20 tuổi suýt hoại tử tinh hoàn do xoắn hai vòng, may mắn được bác sĩ Bệnh viện Quân y 175 mổ cấp cứu giữ lại kịp thời. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/233a1322-1773798712-4369-1773798922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tW7TIb8iGl4-yKI-tUdxiQ', '2026-03-20', 'admin', 480, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165596926500_22', '7 ''thủ phạm'' âm thầm khiến thận yếu đi', 'Ăn quá mặn, dùng thực phẩm chế biến sẵn, uống ít nước hoặc lạm dụng thuốc giảm đau có thể tăng áp lực lên thận theo thời gian. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/an-man-1773738708-1773738913-4727-1773738927.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NOq4Iuk7VwTI41RoRpSxfQ', '2026-03-20', 'admin', 509, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165610421300_23', 'Người gặp tai biến tử vong sau tiêm chủng có thể được bồi thường hơn 100 triệu đồng', 'Bộ Y tế đề xuất người gặp tai biến khi tiêm chủng thiệt hại tính mạng có thể được bồi thường 100 triệu đồng, phí mai táng bằng 10 lần mức lương cơ sở. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a7795-1754481674-1773899525-6921-8614-1773901922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fdofBhFGlUgbFwHFwI6a2w', '2026-03-20', 'admin', 481, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165624907200_24', 'Phát hiện mắc 2 loại ung thư từ triệu chứng vàng da', 'Người phụ nữ 59 tuổi vàng da, đau vùng hạ sườn kéo dài, đi khám được chẩn đoán mắc ung thư đại tràng và ung thư đường mật trong gan. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 341, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165639410200_25', 'Căn bệnh hiếm buộc bác sĩ chọn giải pháp ghép tạng domino', 'Từ dấu hiệu khó thở, các bác sĩ đã phát hiện ra căn bệnh hiếm nguy hiểm amyloidosis, giúp người đàn ông thoát cửa tử nhờ ghép đồng thời tim và gan thành công. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/img-8291-1773928219-1773928276-2399-1773928321.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GWtt0vlUJhMN1_b6wHCOVA', '2026-03-20', 'admin', 277, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165654555600_26', 'Dùng cà gai leo có giúp trị khỏi viêm gan B không?', 'Chồng tôi bị viêm gan B mạn tính, tôi tra cứu thông tin thấy dùng cà gai leo làm thuốc, giúp trị khỏi viêm gan B, có đúng không? (Đỗ Minh Hoa, 42 tuổi, Quảng Trị) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ca-gai-leo-1773916119-17739168-1342-4198-1773917298.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bkYSJaPU0S6ctMXtQqIOmw', '2026-03-20', 'admin', 126, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165669299400_27', 'Tán sỏi thận bằng ''đường hầm nhỏ'' qua da', 'Ông Đức, 66 tuổi, có viên sỏi san hô lớn ở thận trái, được bác sĩ dùng laser tán sạch sỏi qua da trong một lần. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/h2-1773912738-1773912762-9099-1773912790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=j38JjUzg5qR3qpK893tU5Q', '2026-03-20', 'admin', 222, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165683046600_28', 'Sẹo rỗ nặng do mụn', 'Chị Bình, 42 tuổi, nhiều sẹo rỗ sâu vùng mũi và má do nặn mụn, được bác sĩ điều trị tách đáy sẹo kết hợp vi kim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ba-c-tra-n-la-m-rf-1773906650-2435-6137-1773906761.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VkkZlz2OpWhquWYG-ewRA', '2026-03-20', 'admin', 173, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165696915800_29', 'Hệ thống trang thiết bị hiện đại tại Vinmec Ocean Park 2', 'Bệnh viện Đa khoa Quốc tế Vinmec Ocean Park 2 trang bị hàng loạt thiết bị y khoa tiên tiến như MRI 3.0, CT 512 lát cắt… đáp ứng nhu cầu khám chữa bệnh chuyên sâu với độ chính xác cao. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image1931552164extractword5out-975421-1773903823-1773913454.jpeg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BX_nsqPtleKJGP3xcwY0qQ', '2026-03-20', 'admin', 240, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165710679400_30', 'Tiểu đêm có phải do phì đại tuyến tiền liệt?', 'Ban đêm tôi thường đi tiểu 2-3 lần, khó tiểu, mệt mỏi. Có phải do phì đại tuyến tiền liệt không, điều trị thế nào? (Trọng Nghĩa, 55 tuổi, Đồng Nai) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/tah-8555-1-1773896092-17738961-3027-5635-1773896195.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5K75bH4lGA_9Lm7oZQauVA', '2026-03-20', 'admin', 116, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165723999000_31', '4 phương pháp điều trị rò hậu môn', 'Người bị rò hậu môn sau áp xe có thể được bác sĩ chỉ định mổ nội soi, điều trị tia laser hoặc keo sinh học. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/bs-luong-1773839125-1773839198-1501-1773839265.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mMANsiAEDnEcOmbLkYviAA', '2026-03-20', 'admin', 329, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165737909300_32', '5 khoáng chất cần thiết cho sức khỏe sinh lý nam', 'Kẽm, magie, kali, canxi, sắt tham gia vào quá trình sản xuất testosterone, duy trì sinh lý và sức khỏe nam giới. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773905181-1773905199-4800-1773905250.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=J7FYYReSZWjbjDl8OJm-8w', '2026-03-20', 'admin', 368, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165751406400_33', 'Những thói quen mỗi ngày giúp trẻ phát triển trí tuệ', 'Trẻ nên ngủ trước 22h, ăn sáng đầy đủ dinh dưỡng, duy trì thói quen đọc sách và tập thể dục mỗi ngày để phát triển trí não. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/93833d0df43141139173df329820a4-6130-7273-1773895766.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zoshz-NkGeLp3SvTGUEs5g', '2026-03-20', 'admin', 220, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165764839800_34', 'Dấu hiệu nhận biết bệnh về mắt', 'Thay đổi màu sắc mống mắt, hai mắt không thẳng hàng hoặc khó tập trung nhìn các vật ở gần hay xa có thể cảnh báo các vấn đề về mắt. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/momat3-1773892193-1773892202-3927-1773892212.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fX-6NRS3Zsww7n9bh7yqcg', '2026-03-20', 'admin', 58, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165777565600_35', '5 nhóm người nên hạn chế uống nước dừa', 'Người mắc tiểu đường, bệnh thận, đang dùng thuốc huyết áp hoặc có rối loạn điện giải nên hạn chế uống nước dừa để tránh ảnh hưởng sức khỏe. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/28b42ae376a74e37a5c7c694a5c3c4-1939-2018-1773891857.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=W03cZYxS8Wc_2LuiG6kP6w', '2026-03-20', 'admin', 51, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165792109200_36', 'Ba lần mắc zona thần kinh trong hai năm', 'Bà Dung, 62 tuổi, liên tiếp mắc zona thần kinh ở vùng lưng trong hai năm, lần sau nặng hơn lần trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/vnvc-zona-than-kinh-tai-phat-1-6377-2082-1773903517.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ot_zkYHKjIvfaOFuy5poIQ', '2026-03-20', 'admin', 485, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165805942300_37', '6 món chứa tinh bột người tiểu đường nên ăn', 'Thực phẩm giàu tinh bột phức hợp như yến mạch, ngũ cốc nguyên hạt, khoai lang giúp ổn định đường huyết và cung cấp năng lượng lâu dài cho cơ thể. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/Buoc-2-3355-1645172245-1773889121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ApfUYyAeH9YX9pzCl6WWCw', '2026-03-20', 'admin', 299, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165819224700_38', 'Tại sao lupus ban đỏ không thể chữa khỏi?', 'Bác sĩ chẩn đoán tôi mắc lupus ban đỏ. Bệnh nguy hiểm thế nào và tại sao không thể chữa khỏi hoàn toàn? (Nguyễn Dũng, Tiền Giang) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/taan08791-1773896320-177389644-1957-7425-1773897084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=a1vP8v6gMEZpjdw3KcbJiQ', '2026-03-20', 'admin', 107, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165832747900_39', 'Ăn mặn gây rối loạn tiền đình nặng hơn?', 'Tôi bị rối loạn tiền đình ngoại biên, được khuyên kiêng muối vì có thể làm bệnh nặng hơn, đúng không? (Lâm Phạm, 55 tuổi, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/a-nh-1773888613-1773888648-2147-1773888710.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u8tyXq22msAo0zpUDa0uew', '2026-03-20', 'admin', 434, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165846877100_40', 'Khó thở khi nằm cảnh báo bệnh gì?', 'Tôi thường cảm thấy khó thở khi nằm xuống, có liên quan đến bệnh hô hấp không? (Nguyễn Ngân, Hà Nội) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773887515-1773887563-7123-1773887636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=olNppiTaFzjv5NtxhAoN8w', '2026-03-20', 'admin', 247, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165861092600_41', 'Dùng sóng xung kích phá vôi hóa mạch vành', 'Bà Năm, 86 tuổi, đau ngực do động mạch vành hẹp tắc, được bác sĩ phá mảng vôi hóa bằng sóng xung kích ngăn nguy cơ nhồi máu cơ tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881685-1773881714-3499-2887-1773881937.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8a1D0rK_oLWWS9diLy28Bw', '2026-03-20', 'admin', 448, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165874715200_42', 'Cắt toàn bộ tuyến giáp chặn ung thư', 'Bà Loan, 50 tuổi, khám sức khỏe định kỳ phát hiện nhân giáp, sinh thiết lạnh xác định ung thư xâm lấn phải cắt toàn bộ tuyến giáp. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881289-1773881336-2586-1773881408.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yXQBUpD-Igp8_EDS1wUVEA', '2026-03-20', 'admin', 417, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165888079600_43', 'Suy buồng trứng ở tuổi 24', 'Chị gái bị vô sinh nên Hồng, 24 tuổi, chủ động đi khám sức khỏe sinh sản bất ngờ phát hiện buồng trứng gần cạn kiệt như phụ nữ mãn kinh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/key1103-3-1773817056-177381708-3143-7860-1773819558.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=CavEu2B_enyj5OEFH8VNdQ', '2026-03-20', 'admin', 376, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165901910600_44', 'Kỳ tích 90 ngày giữ song thai ''dọa'' sinh cực non', 'Chị Nhung, 33 tuổi, mang song thai 24 tuần dự báo nguy cơ 90% sinh non, được bác sĩ liên khoa phối hợp giữ thai thêm ba tháng đến khi sinh an toàn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881134-4834-1773881170.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1XDOjAjAXRUGNSkmDiyA0A', '2026-03-20', 'admin', 144, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165917586100_45', 'Trẻ bị lông mi mọc ngược có nguy hiểm?', 'Con tôi 5 tuổi, bị lông mi mọc ngược đâm vào mắt gây khó chịu, thường xuyên đỏ mắt. Tình trạng này có nguy hiểm và điều trị thế nào? (Trân, 31 tuổi, Long An) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/lo-ng-mi-mo-c-ngu-o-c-17738488-3850-2423-1773874352.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7CL5Pqz10iYGl92EJWXj0w', '2026-03-20', 'admin', 421, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165930770200_46', 'Cơn đau đầu cảnh báo sớm đột quỵ', 'Cơn đau đầu kéo dài, lúc âm ỉ, lúc dữ dội nhưng thoáng qua vài phút rồi biến mất có thể là dấu hiệu sớm đột quỵ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z7615389058820-b770c8502777a2a-3606-1286-1773839001.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DtpN1a4Sw8ZgN4_ZUIXC2Q', '2026-03-20', 'admin', 176, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165943499900_47', 'Ăn uống, dùng thuốc thế nào sau cắt toàn bộ tuyến giáp?', 'Tôi đã cắt toàn bộ tuyến giáp triệt căn ung thư, phải dùng hormone thay thế. Ăn uống thế nào, lưu ý gì để không ảnh hưởng hấp thu thuốc? (Quốc Bảo, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/a-nh-1-1773838561-1773838575-1902-1773838656.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KiTXzuR-XhOYEsReCOHtGQ', '2026-03-20', 'admin', 54, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165956858400_48', 'Ngủ đủ giấc - cách đơn giản bảo vệ trái tim', 'Ngủ đủ giấc hỗ trợ kiểm soát huyết áp, giảm viêm, tinh thần sảng khoái, từ đó tăng cường sức khỏe tim mạch. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/86262b59886c421faa325d79d43c42-3285-5331-1773807728.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=z2yoNwuRifB21tkyO55TgA', '2026-03-20', 'admin', 175, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165971357200_49', 'Ba thói quen ít ngờ có thể gây hại não', 'Ít tiếp xúc xã hội, sống ở nơi thiếu ánh sáng và nghe nhạc to lâu dài có thể ảnh hưởng tâm trạng, trí nhớ và sức khỏe não bộ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/geminigeneratedimage4gdeoq4gde-2334-2556-1773805576.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=6L8vpW0eIwiwb9yhfgyJEQ', '2026-03-20', 'admin', 183, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165985132100_50', 'Bé gái tử vong sau 9 giờ phát bệnh nghi do não mô cầu', 'Bé gái 10 tuổi tại Phú Quốc sốt, đau đầu, nổi ban, tím tái, khó thở, vào viện cấp cứu song không qua khỏi, nghi mắc viêm não mô cầu. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 339, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_165998978700_51', 'Hai bác sĩ ép tim cứu người ngừng thở giữa sân bóng chuyền', 'Bác sĩ Trần Văn Biên và Nguyễn Cao Việt ép tim cứu sống người đàn ông 64 tuổi ngừng tuần hoàn, ngã quỵ giữa sân khi đang đánh bóng chuyền hơi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/eptim-1773824056-9512-1773824095.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=zKbi8S68AXzNCvOi1chXQw&t=image', '2026-03-20', 'admin', 87, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166012625600_52', 'Thử thách ''nằm một chỗ'' nhận tiền gây sốt tại Thượng Hải', 'Thí sinh tham gia thử thách ngủ được yêu cầu nằm một chỗ trong 24 giờ, không đi vệ sinh, không dùng điện thoại, máy tính để có cơ hội nhận tiền mặt cùng nhiều gói nghỉ dưỡng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/ngu-1773821005-1773821075-3441-1773821874.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8KlVBUvBMqmynOHVIVlLoA', '2026-03-20', 'admin', 361, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166026666500_53', 'Bác sĩ chỉ ra cách ăn uống giúp kéo dài tuổi thọ', 'Silvio Garattini, nhà dược học nổi tiếng người Italy, nhận định việc tiêu thụ ít thực phẩm có thể là chìa khóa để thêm nhiều năm sống khỏe mạnh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-17-at-14-42-3188-8472-1773733487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WtNm6z8rhaEufjF1U9dIpg', '2026-03-20', 'admin', 288, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166040454500_54', 'Hàng chục nghìn ca lao bị bỏ sót, TP HCM mở chiến dịch 100 ngày', 'TP HCM khởi động chiến dịch 100 ngày tầm soát lao chủ động bằng X-quang tích hợp AI cho 30.000 người dân có nguy cơ cao, trước tình trạng hàng chục nghìn ca bệnh bị bỏ sót. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/xn-be-nh-lao-1773813681-177381-6084-5180-1773814033.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=dhP9C3bqRRjz-Y8bvoWDCg', '2026-03-20', 'admin', 248, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166053473200_55', 'Trung Quốc chế tạo thiết bị bảo quản nội tạng hiến tặng trong nhiều ngày', 'Các nhà khoa học Trung Quốc vừa phát triển thành công hệ thống tưới máu máy đa nhiệt độ, giúp kéo dài thời gian bảo tồn nội tạng hiến tặng từ vài giờ lên nhiều ngày. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/1-1773810584-1773810598-6921-1773811859.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Mn8_w1WS1t3d0f_fsjsllg', '2026-03-20', 'admin', 401, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166068206600_56', 'Bắt bạn đời tránh thai, triệt sản vì định kiến giới sẽ bị phạt 12 triệu đồng', 'Từ ngày 1/5, cơ quan chức năng phạt tiền 10-12 triệu đồng đối với người ép buộc vợ hoặc chồng sử dụng biện pháp tránh thai, triệt sản với lý do định kiến giới. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 308, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166082233700_57', 'Uống nước chanh trị gout?', 'Nhiều người truyền tai nhau uống nước chanh tươi giúp rửa bớt acid uric, có thể dùng thay thuốc điều trị gout, điều này có đúng? (Tuấn, 32 tuổi, Hà Nội). (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/c15c6f48-ced4-4429-bfb5-9455cd-5801-6593-1773760546.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=W_kjheUzq2C2ME6zHgDgBg', '2026-03-20', 'admin', 280, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166095858800_58', 'Đề xuất hỗ trợ 1,5 triệu đồng sàng lọc bệnh trước và sau sinh', 'Bộ Y tế đề xuất mức chi 1,5 triệu đồng cho các dịch vụ sàng lọc phát hiện sớm bệnh bẩm sinh nhằm nâng cao chất lượng nòi giống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/anh-chup-man-hinh-2026-03-18-l-5391-3509-1773799029.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0k4SOQrMVLeMurI_aXm-A', '2026-03-20', 'admin', 475, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166109290200_59', 'Tưởng đau bụng thông thường, hóa ung thư gan giai đoạn cuối', 'Người đàn ông 55 tuổi đến viện khám do đau tức vùng hạ sườn phải suốt một tháng, chán ăn, bác sĩ chẩn đoán ung thư gan giai đoạn cuối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-11-at-15-02-9133-1291-1773738650.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4LPRxOCxuzDWC9Ke0ApIMQ', '2026-03-20', 'admin', 438, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166684471500_0', 'Viện dưỡng lão đầu tiên trên thế giới vận hành bằng robot', 'Trạm dưỡng lão tại phố Vinh Hoa, Bắc Kinh trang bị 43 loại robot từ massage, châm cứu đến pha trà, nâng cao chất lượng sống cho người cao tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-8312-6385-1773934900.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VfFn7buTa9TsExFyHzR6g', '2026-03-20', 'admin', 207, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166695535200_1', 'Người trẻ đu trend ''gặp lại mình 10 năm trước''', 'Làm video đối thoại với mình 10 năm trước, nhiều người trẻ muốn nhìn lại hành trình trưởng thành, tự chữa lành tổn thương và định hướng tương lai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/10nam2-1773913137-3708-1773913342.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SmWlJhXMhpeoM7Fve9avQw', '2026-03-20', 'admin', 254, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166708163700_2', 'Cuộc sống bế tắc vì thiếu gas của người Ấn Độ', 'Xếp hàng bốn ngày không đổi được bình gas để nấu ăn, hàng triệu gia đình Ấn Độ đang lao đao vì chuỗi cung ứng năng lượng đứt gãy. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-15-4-3817-9609-1773910903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=TesnxCAAkCHU4m5yGF1yCQ', '2026-03-20', 'admin', 361, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166721763000_3', 'Vì sao nhiều người không quên được tình cũ?', 'Dưới lăng kính tâm lý học, việc chúng ta không ngừng tiếc nuối và lý tưởng hóa người yêu cũ thực chất chỉ là một "cú lừa" của não bộ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/nguoi-cu-1773906295-1773906318-6293-1773906415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=HVjiPxxd9gacVL6Y22uXqA', '2026-03-20', 'admin', 418, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166735468900_4', 'Bi kịch của nữ giám đốc lộ chuyện ngoại tình ở đêm nhạc', 'Từng là tâm điểm chỉ trích vì nụ hôn vụng trộm với sếp, cựu giám đốc Kristin Cabot lần đầu lên tiếng về bi kịch mất trắng sự nghiệp và tiêu chuẩn kép của dư luận. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-3953-9787-1773905123.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SnVW0ZXwG0D0cs-jv11r5w', '2026-03-20', 'admin', 285, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166748790200_5', 'Lợi ích bất ngờ của người thấp bé', 'Khác với lầm tưởng cao lớn đồng nghĩa với khỏe mạnh, người có vóc dáng khiêm tốn thực chất lại ít mắc ung thư, hiếm khi gãy xương và có xu hướng sống thọ hơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-16-1-3564-4232-1773826547.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WILYrMZI2_N_0dlS2haaeA', '2026-03-20', 'admin', 413, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166761656900_6', 'Bi kịch của những tình yêu AI', 'Tối 13/2, SkeweredKebab (nickname) đọc lại toàn bộ những cuộc hội thoại với ChatGPT để làm lễ tiễn biệt "người chồng AI" vừa bị khai tử. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-15-5-6470-2528-1773825011.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hywduvy6fBWG60Hqv4b41Q', '2026-03-20', 'admin', 296, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166780212400_7', 'Gia đình ''siêu nhân Gao'' ở Hưng Yên gây bão mạng', 'Giữ trọn đam mê siêu nhân từ nhỏ, anh Ngọc Trung sắm trang phục siêu nhân Gao rủ vợ hóa trang, sáng tạo loạt video hài hước mang lại tiếng cười cho cộng đồng. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7606213086839-ba7d4f64bbbc508-7613-9150-1773319405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mrTZfGPqSl0KOJOxGL3Etw', '2026-03-20', 'admin', 28, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166799921500_8', 'Vụ ly hôn tỷ USD và góc khuất đời tư của chủ tịch tập đoàn SK', 'Cuộc chiến pháp lý giữa Chủ tịch tập đoàn SK Chey Tae-won và vợ cũ Roh Soh-yeong gây chấn động bởi khối tài sản khổng lồ và sự xuất hiện của "người thứ ba". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/00-1773805459-1773805465-7488-1773807993.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ma9jNQK-Y2L9EYbGcAWU3Q', '2026-03-20', 'admin', 358, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166817666400_9', 'Nhà hàng đập 600 bộ bát đĩa vì khách cho chó lên bàn ăn', 'Ông Giang, quản lý nhà hàng tại Thương Khâu (Hà Nam), đã đập bỏ 600 bộ bát đĩa và đóng cửa khử trùng quán khi phát hiện một thực khách mang chó lên bàn ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/pet-restaurant-2-1773823218-17-3022-8308-1773823607.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YJaopzEQ_wQcv0LriogkfQ', '2026-03-20', 'admin', 17, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166836845500_10', 'Nạn trộm cắp ở khu nhà giàu Mỹ', 'Từng là chốn an cư bình yên của giới tinh hoa, khu Sharon Heights (vùng vịnh San Francisco) giờ chìm trong bất an khi kẻ gian liều lĩnh đột nhập ngay lúc gia chủ đang ăn tối. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/ratio3x2-960-1773806447-177380-5965-1359-1773809180.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=XY--0saGjRWJfVzM5zTLrQ', '2026-03-20', 'admin', 479, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166851876600_11', 'Làn sóng ''nhân lực tinh hoa'' rời bỏ Israel', 'Từng coi Tel Aviv là "thiên đường công nghệ", kỹ sư Elizabeth Cohen quyết định rời đi vì không muốn sinh con giữa những tiếng còi báo động tên lửa. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-17-at-23-3-7325-4333-1773766923.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KazThb0Myl6qlnll2uVyPg', '2026-03-20', 'admin', 26, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166865255900_12', 'Cách tự học tiếng Anh của ''cô giáo nhí'' 9 tuổi', 'Từ trò chơi đóng vai cô giáo mỗi tối, bé Vân Anh khiến cộng đồng mạng bất ngờ bởi khả năng nói tiếng Anh trôi chảy và cách dạy em đầy kiên nhẫn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/va-n-anh-2-1773661730-17736617-3169-1895-1773662279.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MFZagmWNCjA_dg4MlTV1-g', '2026-03-20', 'admin', 250, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166879498600_13', 'Phát tài nhờ tờ giấy bỏ quên 30 năm', 'Đang phải sống chật vật với lương hưu eo hẹp, vợ chồng ông Sato bất ngờ thu về 68 triệu yen nhờ tìm thấy tờ biên lai mua cổ phiếu, bị bỏ quên 30 năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/co-phieu-2-jpeg-1773797809-177-3785-6774-1773797902.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T-SETu0hLWUdD-lr9bNEBQ', '2026-03-20', 'admin', 288, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166894524100_14', 'Bi kịch của thế hệ ''kiếm nhiều tiền nhưng không giàu''', 'Thu nhập 450.000 USD mỗi năm nhưng vợ chồng Alex vẫn phải ở nhà thuê, chưa trả hết nợ sinh viên và nơm nớp lo sợ thiếu tiền giữa lòng New York đắt đỏ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-00-3-6865-5413-1773770804.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICLidWfdmD2K6KISqPINoQ', '2026-03-20', 'admin', 471, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166908751000_15', 'Hai chuyến đi Việt Nam ''cứu rỗi'' người phụ nữ Mỹ', 'Rơi vào trầm cảm sau khi mẹ qua đời, Lilly Hubbard quyết định quay lại Việt Nam và tìm thấy sự "chữa lành" từ tình người ấm áp ở vùng đất xa lạ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/lilly-2-1773802709-1773802742-4016-1773802752.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5uQdZnsKta3M8vRTp6nZhA', '2026-03-20', 'admin', 369, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166921618800_16', 'Vì sao quần áo thể thao giặt xong vẫn hôi?', 'Ném ngay đồ tập đẫm mồ hôi vào máy giặt, dùng nhiều xà phòng hay nước xả vải là sai lầm khiến quần áo luôn bốc mùi khó chịu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/a-nh-ma-n-hi-nh-2026-03-16-lu-7904-9038-1773736876.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KXY2uWiUcoSsOpLDwHycOA', '2026-03-20', 'admin', 464, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166935383400_17', 'Bên trong nhà lắp ghép 30 m2 của tỷ phú Elon Musk', 'Mặc dù sở hữu hàng trăm tỷ USD, tỷ phú Elon Musk hiện sống trong căn nhà lắp ghép rộng 30 m2, thiếu tiện nghi đến mức mẹ ông phải ngủ ở gara. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/577333596-3394143064076672-485-6636-3102-1773724581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=b5eyN5ibANA-m59NlkHsAQ', '2026-03-20', 'admin', 442, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166950176500_18', 'Vợ cho ''thuê'' chồng', 'Phát hiện chồng ngoại tình, cô Khun Kwang ra thỏa thuận cho nhân tình của anh thuê chồng với giá 30.000 bath mỗi tháng, tuy nhiên hợp đồng này bị luật sư cảnh báo vô hiệu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/chatgpt-image-11-27-42-17-thg-9377-7480-1773721720.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NBqR-Rw-evtAbpk1qTmaKQ', '2026-03-20', 'admin', 493, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166964336500_19', 'Vì sao nhà chung cư ở Mỹ ngày càng ít?', 'Từng là lựa chọn an cư giá rẻ cho người trẻ Mỹ, số lượng chung cư thương mại sụt giảm mạnh do rào cản pháp lý, thuế và chi phí bảo hiểm tăng vọt. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/im-92913950-1773654144-1773671-8010-8091-1773672308.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Bm4Dwf779JQ1G3-LVfRR1w', '2026-03-20', 'admin', 91, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166977779800_20', 'Vợ 50 tuổi làm IVF chiều chồng trẻ', 'Bất chấp những đàm tiếu của dư luận, bà Pilli Cortese vẫn quyết định thụ tinh nhân tạo ở tuổi 50 để thỏa ước nguyện làm cha của người chồng kém 21 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5921-9658-1773633940.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9Zuubwaaw2BqQmbUtn07fA', '2026-03-20', 'admin', 136, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_166991010400_21', 'Bẫy thổi phồng chức danh khi tuyển dụng', 'Nhiều doanh nghiệp đang gán mác "giám đốc", "trưởng phòng" cho người lao động nhưng chỉ trả mức lương nhân viên nhằm thu hút ứng viên và tối ưu chi phí. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/tuyen-dung-jpeg-1773679492-177-2056-8763-1773681102.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KigiyGPtR51yLB_8Hefyxg', '2026-03-20', 'admin', 141, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167003997400_22', 'Dân công sở Mỹ bỏ ôtô, đạp xe, làm từ xa để né ''bão'' giá', 'Thấy giá nhiên liệu tăng vọt, Boris Kagarlitskiy quyết định cất chiếc Lexus ở nhà, lôi xe đạp cũ ra lau chùi để bắt đầu chuỗi ngày đi làm bằng sức người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/dap-xe-1773678268-1773678292-1-1377-3127-1773678449.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=w-sPfSoia-AE5rGBtpoj4Q', '2026-03-20', 'admin', 65, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167017847600_23', 'Nhan Phúc Vinh, Hà Thu tập chống đuối nước cùng 1.000 học sinh', 'Diễn viên Nhan Phúc Vinh, Á hậu Hà Thu cùng hơn 1.000 học sinh nhận biết mực nước an toàn, kỹ năng thở nước, tại workshop chống đuối nước, sáng 16/3. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/dsc04354-1773740071-8030-17737-9004-8642-1773765903.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A4JrUo23I3KsRgZmF6I4Lg', '2026-03-20', 'admin', 315, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167035718200_24', '3 bước đánh lừa não bộ để ngủ nhanh hơn', 'Kỹ thuật "xáo trộn nhận thức" giúp ngắt quãng dòng suy nghĩ lo âu, mô phỏng trạng thái mơ màng tự nhiên để não bộ thư giãn và dễ dàng chìm vào giấc ngủ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/z7591758010902-c59406ff20941de-5096-4651-1773652579.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xQChxkieWCwZeML9fYn7Gg', '2026-03-20', 'admin', 399, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167053205300_25', 'Yêu 6 năm mới biết bạn gái đã có chồng con', 'Chi hơn một triệu tệ cho bạn gái trong 6 năm mặn nồng, anh Wang bàng hoàng phát hiện người yêu thực chất đã yên bề gia thất, thậm chí các con đã học cấp hai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5017-9753-1773636339.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LRn0uHe2LxkLnmac08jIuw', '2026-03-20', 'admin', 297, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167072220700_26', 'Nhiều nông dân Mỹ có nguy cơ phá sản vì xung đột Trung Đông', 'Xung đột tại Trung Đông đẩy giá nhiên liệu và phân bón lên mức kỷ lục, giáng đòn mạnh vào hàng loạt trang trại, đẩy họ vào cảnh phá sản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-13-at-22-1-6679-9104-1773417216.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wNZTd6jP3YfT0zCvXMAvYg', '2026-03-20', 'admin', 168, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167091439500_27', 'Khủng hoảng xăng dầu ''bóp nghẹt'' người nghèo châu Á', 'Xung đột ở Trung Đông gây đứt gãy nguồn cung nhiên liệu, đẩy hàng chục triệu người lao động tại châu Á vào cảnh thiếu xăng, khí đốt và sụt giảm thu nhập. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/a-nh-ma-n-hi-nh-2026-03-16-lu-7437-9899-1773631014.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pswj5Qok0ZT1EUC6gyBi6g', '2026-03-20', 'admin', 361, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167111997800_28', 'Tụ tập - quy tắc giữ gìn tình bạn của người Đức', 'Cuộc sống bận rộn khiến nhiều mối quan hệ phai nhạt nhưng người Đức áp dụng quy tắc "Stammtisch" - những cuộc tụ họp định kỳ, đơn giản nhưng hiệu quả. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/stammtisch-2-1773625060-177362-4038-7784-1773625553.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lkewTZzZ2noESjRQobw1iA', '2026-03-20', 'admin', 439, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167131963600_29', 'Chàng trai Canada ''bẻ lái cuộc đời'' vì tình yêu với cô gái Việt', 'Ngay buổi hẹn đầu dưới chân tháp Tokyo, Thu Thủy đưa ra loạt tiêu chuẩn khắt khe về bạn trai, rồi dội gáo nước lạnh vào Seiwa: “Em không muốn gặp lại anh nữa”. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/img-1831-1-jpeg-1773460527-177-7354-6141-1773461950.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mt3pi6U16KHThn4v8-hOBA', '2026-03-20', 'admin', 272, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167147659900_30', 'Ước mơ của người vợ 10 năm giữ món quà chồng chưa kịp tặng', 'Cất kỹ chiếc váy và chú gấu bông chồng mua tặng trước khi tử nạn, chị Thúy mong một ngày được trao lại cho con gái trong sự kiện trọng đại nhất đời. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/z7619839331948-d5148baa4b6833d-6407-2821-1773504440.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RytXItajr9SLpO3H0LRM4Q', '2026-03-20', 'admin', 290, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167163355100_31', 'Cuộc đoàn tụ gượng gạo của cô gái bị vứt ở nhà vệ sinh 28 năm trước', 'Bị ông nội vứt bỏ từ lúc 2 ngày tuổi, Hong Yangli vượt nửa vòng trái đất về nhận mẹ nhưng đối diện màn đoàn tụ lạnh lẽo, dấy lên nhiều tranh cãi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/1-3-1773547826-1773547843-5092-1773548222.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=amEJ_VUF9IpG9eD0G9_PNg', '2026-03-20', 'admin', 76, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167180170300_32', 'Cụ bà 82 tuổi bị lừa kết hôn bằng 20 quả trứng', 'Cụ bà mù chữ 82 tuổi ở Hồ Nam tưởng làm giấy tờ để nhận trợ cấp 1.000 tệ và 20 quả trứng, không ngờ bị lừa ký giấy đăng ký kết hôn với người đàn ông 47 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/00-1773543821-1773543868-7185-1773543919.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KfEnT7aoLQ3RSBsN1-oYAw', '2026-03-20', 'admin', 130, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167196609200_33', 'Người đàn ông bị hàng loạt nhà tang lễ từ chối vì béo', 'Ở Canada, béo phì không chỉ là một bài toán khó về sức khỏe khi còn sống, mà nay lại biến thành "rào cản cuối cùng" sau khi chết. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/0-1-1773549860-1773549866-3805-1773550180.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vVbCv37mEQDizIgnTBFi5g', '2026-03-20', 'admin', 147, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167213506600_34', 'Suýt mất mạng, cặp vợ chồng hối hận vì ''bỏ phố về rừng''', 'Từng ảo tưởng về sự tuyệt vời của cuộc sống biệt lập giữa thiên nhiên, vợ chồng Jayme bừng tỉnh sau sự cố suýt mất mạng ngày sinh nở, nhận ra cái giá của sự cô độc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773464228-1773464933-3946-1773464939.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oyCVWVQKOW3_wjd1YLbydQ', '2026-03-20', 'admin', 273, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167228016500_35', 'Đường đến giải bơi trong hồ băng của cậu bé Hà Nội', 'Trên đỉnh núi tuyết ở Neuhermsdorf, Phan Anh mặc quần bơi đứng lặng nhìn mặt hồ Altes Zollhaus bốc khói trong khi ban tổ chức luôn tay vớt những tảng băng cản đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/phan-anh-1-1773221913-4040-177-8906-6797-1773503423.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tRJ-e86PBimTvuLx8uLrLQ', '2026-03-20', 'admin', 122, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167243136300_36', 'Đánh cược mạng sống mưu sinh trong vùng chiến sự', 'Mỗi khi tiếng còi báo động vang lên, nữ giúp việc Joycee Pelayo chạy vội đến cụ ông mà cô đang chăm sóc, dìu ông lên xe lăn rồi đẩy thật nhanh xuống hầm trú ẩn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773484138-1773484220-8888-1773484945.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SXxzNvSvE4dKP7MSqygIxA', '2026-03-20', 'admin', 254, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167257985300_37', 'Người Lạng Sơn chi hàng trăm triệu làm cỗ mời khách lạ', 'Để tán lộc và cầu may, người dân Lạng Sơn chi hàng trăm triệu đồng dựng rạp, thết đãi cỗ miễn phí cho cả khách lạ về dự hội đền Kỳ Cùng - Tả Phủ đầu năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/6-2-1773501948-1773502444-9849-1958-9924-1773505959.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0x9NpYpx7nxQjaqa-_PsZg', '2026-03-20', 'admin', 361, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167272664300_38', 'Gần 3.000 runner chạy giữa đô thị lớn nhất Nghệ An', 'Gần 3.000 vận động viên dự giải Eco Central Park Marathon lần đầu tổ chức với cung đường xuyên qua công viên và các thảm hoa trong khu đô thị. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/kbd03827-1773548789-1773549037-3771-1773551974.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0E-9mGgNroDH6ojqizG9w', '2026-03-20', 'admin', 80, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167286981000_39', 'Thường xuyên bị nhầm là con vì kém vợ 23 tuổi', 'Bất chấp khoảng cách 23 tuổi và hay bị nhầm là mẹ con, cặp đôi Azmirullah (28 tuổi) và Wan Nazihah (51 tuổi) vẫn có cuộc sống viên mãn sau gần 7 năm kết hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-5511-1481-1773391224.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rVhmD8KwmfMyFVajva3Fg', '2026-03-20', 'admin', 77, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167300531600_40', 'Cả nhà bới 10 tấn rác tìm túi vàng', 'Gia đình 8 người ở Giang Tây phải thức trắng đêm, lục tung 10 tấn rác để tìm lại túi vàng trị giá 1,5 triệu tệ (5,2 tỷ đồng) bị người nhà vứt nhầm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/chatgpt-image-12-00-22-14-thg-6372-9837-1773467256.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=_9x4DRlTKFjkiC60B2o8FA', '2026-03-20', 'admin', 475, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167314121900_41', 'Vì sao không cần ''ra khỏi phòng là tắt đèn''?', 'Lời khuyên "ra khỏi phòng là tắt đèn" đã lỗi thời trong kỷ nguyên bóng đèn LED, nhưng vẫn áp dụng đúng quy tắc 15 phút với đèn huỳnh quang. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/1-1773454941-1773455346-9660-1773455690.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bdkGsflc9Jxr6O6pwJzT-A', '2026-03-20', 'admin', 147, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167327592400_42', 'Những cuộc hôn nhân tan vỡ vì trúng độc đắc', 'Trúng thưởng hàng chục triệu USD, nhiều cặp vợ chồng ngỡ đã chạm tay vào hạnh phúc viên mãn nhưng cuối cùng lại rơi vào cảnh ngoại tình, kiện tụng và ly hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/screen-shot-2026-03-14-at-00-3-2966-9237-1773423562.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zp535HhmTaj7GmpNZEZnIw', '2026-03-20', 'admin', 154, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167341426500_43', 'Dubai vắng vẻ ''chưa từng thấy''', 'Dưới sức ép từ các đợt tấn công của Iran, người nước ngoài đang vội vã rời khỏi Dubai, đẩy "thành phố vàng" vào cảnh vắng lặng như thị trấn ma. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/untitled-1773453416-1773453692-9708-1773453849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vbalNxj_XueEp65nAOLXcA', '2026-03-20', 'admin', 333, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167355378200_44', 'Chàng trai không tay và những món ăn ''triệu view''', 'Mất đôi tay sau tai nạn, Trọng Định, 23 tuổi, học cách nấu ăn bằng chân và hai mỏm cụt, biến nỗi đau thành nghị lực sống truyền cảm hứng cho hàng triệu người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/di-nh-di-cho-1773409298-177340-4382-8632-1773422430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0DityHvFbLGR7izILlXGOQ', '2026-03-20', 'admin', 304, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167369114200_45', 'Dùng AI tạo ''chuyên gia giả'' để trị thói giục cưới của cha mẹ', 'Mệt mỏi vì bị cha mẹ liên tục giục lấy chồng, Cao Mei, 38 tuổi, dùng AI tạo ra một "chuyên gia tâm lý" để giảng đạo lý, thuyết phục ngược lại phụ huynh. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/0-1773398662-1773398682-1718-1773399208.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EVMDlFbSybo3mN85hxNoWg', '2026-03-20', 'admin', 310, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167382445600_46', 'Đổ xô mua nhà thờ cũ làm nhà ở', 'Giữa "bão" giá bất động sản, nhiều người chọn mua các nhà thờ cũ với giá rẻ để cải tạo thành không gian sống độc đáo. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/a-nh-ma-n-hi-nh-2026-03-13-lu-3696-4834-1773377205.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SH7Rb4ILOv0ksxLF-wv1NQ', '2026-03-20', 'admin', 223, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167396376600_47', 'Hơn 2.000 người mua vé sớm dự lễ hội ẩm thực Saigontourist 2026', 'Hàng nghìn vé sớm được bán trước thềm Lễ hội Văn hóa Ẩm thực Saigontourist 2026, hút 2.000 lượt đặt mua sau 10 ngày. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/kho-ng-khi-nga-p-tra-n-ma-u-sa-5727-7837-1773461994.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0g7XJzZGG1R1YRikkMMY9g', '2026-03-20', 'admin', 421, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167411122500_48', 'Trẻ học được gì từ việc cha rửa bát?', 'Sự phân công việc nhà giữa cha và mẹ là "bản thiết kế" cho hành vi xã hội của trẻ, liên quan trực tiếp đến nguy cơ bạo lực học đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-2254-8889-1773393096.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s6Oxd_5Gu1oXQ46K_G7Dug', '2026-03-20', 'admin', 476, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167424371800_49', '20.000 thuyền viên kẹt gần Hormuz nguy cơ thiếu nhu yếu phẩm', 'Gần 20.000 thủy thủ mắc kẹt trên các tàu hàng ở eo biển Hormuz đang đối mặt với nỗi lo tên lửa rơi trúng và tình trạng cạn kiệt nhu yếu phẩm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/tau-dau-1773402850-1773402875-3232-1773403067.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NTSnOJHpgEet9waOtHY1dw', '2026-03-20', 'admin', 11, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167437333500_50', 'Quy tắc ''muối tách, đường giữ'' trong nấu ăn', 'Nêm gia vị đúng thời điểm không chỉ giúp món ăn đậm đà mà còn ảnh hưởng đến độ ngon, độ giòn, độ mọng của món ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/pexelsrohanmuzafar3054690-1773-8724-2189-1773394017.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=k9GycCL6VDqIrC8odwZSsA', '2026-03-20', 'admin', 495, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167450095700_51', 'Vì sao nhiều người chỉ làm việc hiệu quả sát deadline?', 'Áp lực thời gian cận kề giúp não bộ tiết ra các hormone cảnh báo, loại bỏ sự trì hoãn và tăng cường khả năng tập trung vào công việc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/deadline-1773390004-1773390024-3813-1773390069.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=IrRI2aePlRHDe6ihst78Iw', '2026-03-20', 'admin', 471, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167463829100_52', 'Góc khuất sau vấn nạn cố tình xô đẩy ở Nhật Bản', 'Đoạn video bé gái bị xô ngã ở Tokyo đã gióng lên hồi chuông báo động về "butsukari" - vấn nạn cố tình va chạm người lạ để xả stress đang gia tăng tại Nhật Bản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/Thie-t-ke-chu-a-co-te-n-3-1773-4469-9773-1773374593.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=kmKl_9ydvAdA8gw15swzMg&t=image', '2026-03-20', 'admin', 230, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167477290000_53', 'Con trai dùng trực thăng đưa mẹ về quê', 'Mẹ nói muốn về quê, người đàn ông tên Long ở Tứ Xuyên lái trực thăng cá nhân trị giá 7 triệu tệ đưa bà về vì ôtô đã cho bạn mượn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1773272450-177327-8656-6736-1773274348.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Y9XSNVQj99QxicXvcU31fg', '2026-03-20', 'admin', 382, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167490485900_54', 'Giới siêu giàu vung tiền xây hầm trú ẩn', 'Lo ngại bất ổn toàn cầu, giới siêu giàu đang vung hàng trăm nghìn USD xây các hầm ngầm trú ẩn xa xỉ, mang lại doanh thu kỷ lục cho hãng sản xuất. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/untitled-1773333717-1773334180-5221-1773334666.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lsi1Zbgp6ky9ZkkJLntrzA', '2026-03-20', 'admin', 316, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167503335600_55', 'Chuyện tình 15 ngày của đôi vợ chồng hoán đổi giới tính', 'Từng cạn niềm tin vào tình yêu, Mộc Trà - người chuyển giới nữ và Thiên Minh - người chuyển giới nam, quyết định kết hôn sau 15 ngày quen nhau vì tìm thấy sự đồng cảm sâu sắc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-12-at-15-0-4845-1689-1773336910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zsMmkb4ZKHA4pdM_bk4JnA', '2026-03-20', 'admin', 192, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167517096700_56', 'Quy tắc ''cấm khoe mẽ'' của phố Wall', 'Việc bốn chuyên viên tài chính trẻ làm mẫu ảnh thời trang đã làm bùng nổ tranh cãi về quy tắc bất thành văn ở Phố Wall: Tuyệt đối không thu hút sự chú ý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/screen-shot-2026-03-12-at-14-5-9812-8707-1773302260.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7wMXhzX_8pLrHBKLQ_kwXw', '2026-03-20', 'admin', 159, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167529756800_57', 'Tỷ phú bánh bao ở nhà thuê, quyết không để tài sản cho con', 'Sở hữu chuỗi 5.600 cửa hàng và tài sản gần 600 triệu USD nhưng danh mục bất động sản của ông Lưu Hội Bình vẫn trống trơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/a-nh-ma-n-hi-nh-2026-03-12-lu-4281-8357-1773300992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Aibug9pmVMbPQDhOgkh3cA', '2026-03-20', 'admin', 369, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167544011000_58', 'Tổ bay góp tiền đưa mẹ con người phụ nữ khiếm thị về quê', 'Địu con nhỏ đi từ TP HCM về Cao Bằng, người mẹ khiếm thị được tổ tiếp viên chăm sóc và quyên tiền đặt vé xe giường nằm chặng cuối về tận nhà. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7613036872520-979f4c14b579a74-6143-5591-1773323528.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZuKH3SFTr-IeOBXRl9BZ_A', '2026-03-20', 'admin', 20, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_167557508200_59', 'Ba dấu hiệu cảnh báo thịt đông lạnh đã hỏng', 'Nhiều gia đình tích trữ thịt trong tủ đá hàng tháng trời và vô tư đem chế biến dù chúng đã biến màu, nhớp nháp hay bị "bỏng lạnh". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1-1773284849-1773-8712-1642-1773285672.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jOrSg2ECal3EmqLTWjqnSA', '2026-03-20', 'admin', 350, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361657_0', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-19', 'admin', 148, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361671_1', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-19', 'admin', 87, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361684_2', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-19', 'admin', 143, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361698_3', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-19', 'admin', 492, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361711_4', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-19', 'admin', 356, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361725_5', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-19', 'admin', 463, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361749_6', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-19', 'admin', 158, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361769_7', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-19', 'admin', 271, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361788_8', 'Thử thách giảm một cân mỡ đổi nửa cân thịt bò tại Trung Quốc', 'Hơn 2.400 người dân thành phố Vô Tích đăng ký tham gia thử thách giảm cân để quy đổi trọng lượng cơ thể sụt giảm thành các phần thịt bò, đuôi bò và lá sách. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/blujgsjcgkzgxov28r29h6slrhcdwp-3084-9216-1773851508.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cJByzTs2uf-iCO9WHvmVZw', '2026-03-19', 'admin', 501, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773935361804_9', 'Lòng trắng hay lòng đỏ trứng nhiều protein hơn?', 'Nhiều người cho rằng protein có ở lòng trắng trứng, còn lòng đỏ chủ yếu chứa chất béo song thực tế chất béo được phân bổ ở cả hai phần với tỷ lệ khá cân đối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/trungluoc-1773735015-177373503-3257-1653-1773735084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Fi6Q-5BdVlJjlX5EoICKfA', '2026-03-19', 'admin', 275, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936085396_0', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-19', 'admin', 188, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936085408_1', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-19', 'admin', 317, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936085421_2', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-19', 'admin', 120, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936085433_3', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-19', 'admin', 367, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936085446_4', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-19', 'admin', 36, 'HEALTH', 0, 1, 'Y tế');
