INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509573_0', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-19', 'admin', 351, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509587_1', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-19', 'admin', 506, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509606_2', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-19', 'admin', 32, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509625_3', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-19', 'admin', 112, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509643_4', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-19', 'admin', 502, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509660_5', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-19', 'admin', 187, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509676_6', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-19', 'admin', 216, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_1773936509693_7', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-19', 'admin', 292, 'HEALTH', 0, 1, 'Y tế');
