INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313149217900_3', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-19', 'admin', 484, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313161988600_4', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-19', 'admin', 151, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313174493500_5', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-19', 'admin', 148, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313187518500_6', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-19', 'admin', 121, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313200099200_7', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-19', 'admin', 312, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313212325400_8', 'Thử thách giảm một cân mỡ đổi nửa cân thịt bò tại Trung Quốc', 'Hơn 2.400 người dân thành phố Vô Tích đăng ký tham gia thử thách giảm cân để quy đổi trọng lượng cơ thể sụt giảm thành các phần thịt bò, đuôi bò và lá sách. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/blujgsjcgkzgxov28r29h6slrhcdwp-3084-9216-1773851508.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cJByzTs2uf-iCO9WHvmVZw', '2026-03-19', 'admin', 196, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313224899400_9', 'Lòng trắng hay lòng đỏ trứng nhiều protein hơn?', 'Nhiều người cho rằng protein có ở lòng trắng trứng, còn lòng đỏ chủ yếu chứa chất béo song thực tế chất béo được phân bổ ở cả hai phần với tỷ lệ khá cân đối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/trungluoc-1773735015-177373503-3257-1653-1773735084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Fi6Q-5BdVlJjlX5EoICKfA', '2026-03-19', 'admin', 411, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313238569200_10', 'Bẫy ''giảm đau nhanh'' từ thuốc đông y dởm', 'Thuốc đông y pha trộn hóa chất cấm tạo ảo giác hết bệnh tức thời, khiến nhiều người bệnh mạn tính và ung thư bỏ phác đồ điều trị chuẩn mực, dẫn đến đánh mất cơ hội sống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/b68c2082-b007-4e31-b108-003eb5-2978-8056-1773807046.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6sFkX8ilu6LKEesyjWQFng', '2026-03-19', 'admin', 469, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313254945200_11', '6 bài tập đơn giản tại nhà giúp kéo dài tuổi thọ', 'Chìa khóa của sự trường thọ nằm ở những chuyển động bền bỉ như đi bộ, đi cầu thang, squat, chống đẩy, đứng một chân và plank ngay tại chính ngôi nhà của bạn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/screenshot-2026-03-16-at-11-02-9494-7835-1773633846.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pf_-i646or_CqCdVKZYybw', '2026-03-19', 'admin', 426, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313269062500_12', 'Chàng trai suýt mất tinh hoàn vì cố chịu đau qua đêm', 'Chủ quan chịu đựng cơn đau vùng kín qua đêm, chàng trai 20 tuổi suýt hoại tử tinh hoàn do xoắn hai vòng, may mắn được bác sĩ Bệnh viện Quân y 175 mổ cấp cứu giữ lại kịp thời. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/233a1322-1773798712-4369-1773798922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tW7TIb8iGl4-yKI-tUdxiQ', '2026-03-19', 'admin', 62, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313282417800_13', '7 ''thủ phạm'' âm thầm khiến thận yếu đi', 'Ăn quá mặn, dùng thực phẩm chế biến sẵn, uống ít nước hoặc lạm dụng thuốc giảm đau có thể tăng áp lực lên thận theo thời gian. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/an-man-1773738708-1773738913-4727-1773738927.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NOq4Iuk7VwTI41RoRpSxfQ', '2026-03-19', 'admin', 207, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313294817400_14', 'Người gặp tai biến tử vong sau tiêm chủng có thể được bồi thường hơn 100 triệu đồng', 'Bộ Y tế đề xuất người gặp tai biến khi tiêm chủng thiệt hại tính mạng có thể được bồi thường 100 triệu đồng, phí mai táng bằng 10 lần mức lương cơ sở. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a7795-1754481674-1773899525-6921-8614-1773901922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fdofBhFGlUgbFwHFwI6a2w', '2026-03-19', 'admin', 180, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313307892300_15', 'Phát hiện mắc 2 loại ung thư từ triệu chứng vàng da', 'Người phụ nữ 59 tuổi vàng da, đau vùng hạ sườn kéo dài, đi khám được chẩn đoán mắc ung thư đại tràng và ung thư đường mật trong gan. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-19', 'admin', 379, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313320519100_16', 'Căn bệnh hiếm buộc bác sĩ chọn giải pháp ghép tạng domino', 'Từ dấu hiệu khó thở, các bác sĩ đã phát hiện ra căn bệnh hiếm nguy hiểm amyloidosis, giúp người đàn ông thoát cửa tử nhờ ghép đồng thời tim và gan thành công. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/img-8291-1773928219-1773928276-2399-1773928321.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GWtt0vlUJhMN1_b6wHCOVA', '2026-03-19', 'admin', 478, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313340079500_17', 'Dùng cà gai leo có giúp trị khỏi viêm gan B không?', 'Chồng tôi bị viêm gan B mạn tính, tôi tra cứu thông tin thấy dùng cà gai leo làm thuốc, giúp trị khỏi viêm gan B, có đúng không? (Đỗ Minh Hoa, 42 tuổi, Quảng Trị) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ca-gai-leo-1773916119-17739168-1342-4198-1773917298.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bkYSJaPU0S6ctMXtQqIOmw', '2026-03-19', 'admin', 403, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313358849000_18', 'Tán sỏi thận bằng ''đường hầm nhỏ'' qua da', 'Ông Đức, 66 tuổi, có viên sỏi san hô lớn ở thận trái, được bác sĩ dùng laser tán sạch sỏi qua da trong một lần. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/h2-1773912738-1773912762-9099-1773912790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=j38JjUzg5qR3qpK893tU5Q', '2026-03-19', 'admin', 467, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313377419200_19', 'Sẹo rỗ nặng do mụn', 'Chị Bình, 42 tuổi, nhiều sẹo rỗ sâu vùng mũi và má do nặn mụn, được bác sĩ điều trị tách đáy sẹo kết hợp vi kim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ba-c-tra-n-la-m-rf-1773906650-2435-6137-1773906761.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VkkZlz2OpWhquWYG-ewRA', '2026-03-19', 'admin', 99, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313394579100_20', 'Hệ thống trang thiết bị hiện đại tại Vinmec Ocean Park 2', 'Bệnh viện Đa khoa Quốc tế Vinmec Ocean Park 2 trang bị hàng loạt thiết bị y khoa tiên tiến như MRI 3.0, CT 512 lát cắt… đáp ứng nhu cầu khám chữa bệnh chuyên sâu với độ chính xác cao. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image1931552164extractword5out-975421-1773903823-1773913454.jpeg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BX_nsqPtleKJGP3xcwY0qQ', '2026-03-19', 'admin', 366, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313410598800_21', 'Tiểu đêm có phải do phì đại tuyến tiền liệt?', 'Ban đêm tôi thường đi tiểu 2-3 lần, khó tiểu, mệt mỏi. Có phải do phì đại tuyến tiền liệt không, điều trị thế nào? (Trọng Nghĩa, 55 tuổi, Đồng Nai) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/tah-8555-1-1773896092-17738961-3027-5635-1773896195.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5K75bH4lGA_9Lm7oZQauVA', '2026-03-19', 'admin', 164, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313426412400_22', '4 phương pháp điều trị rò hậu môn', 'Người bị rò hậu môn sau áp xe có thể được bác sĩ chỉ định mổ nội soi, điều trị tia laser hoặc keo sinh học. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/bs-luong-1773839125-1773839198-1501-1773839265.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mMANsiAEDnEcOmbLkYviAA', '2026-03-19', 'admin', 105, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313439963000_23', '5 khoáng chất cần thiết cho sức khỏe sinh lý nam', 'Kẽm, magie, kali, canxi, sắt tham gia vào quá trình sản xuất testosterone, duy trì sinh lý và sức khỏe nam giới. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773905181-1773905199-4800-1773905250.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=J7FYYReSZWjbjDl8OJm-8w', '2026-03-19', 'admin', 235, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313453540600_24', 'Những thói quen mỗi ngày giúp trẻ phát triển trí tuệ', 'Trẻ nên ngủ trước 22h, ăn sáng đầy đủ dinh dưỡng, duy trì thói quen đọc sách và tập thể dục mỗi ngày để phát triển trí não. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/93833d0df43141139173df329820a4-6130-7273-1773895766.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zoshz-NkGeLp3SvTGUEs5g', '2026-03-19', 'admin', 145, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313466231700_25', 'Dấu hiệu nhận biết bệnh về mắt', 'Thay đổi màu sắc mống mắt, hai mắt không thẳng hàng hoặc khó tập trung nhìn các vật ở gần hay xa có thể cảnh báo các vấn đề về mắt. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/momat3-1773892193-1773892202-3927-1773892212.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fX-6NRS3Zsww7n9bh7yqcg', '2026-03-19', 'admin', 33, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313478557700_26', '5 nhóm người nên hạn chế uống nước dừa', 'Người mắc tiểu đường, bệnh thận, đang dùng thuốc huyết áp hoặc có rối loạn điện giải nên hạn chế uống nước dừa để tránh ảnh hưởng sức khỏe. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/28b42ae376a74e37a5c7c694a5c3c4-1939-2018-1773891857.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=W03cZYxS8Wc_2LuiG6kP6w', '2026-03-19', 'admin', 336, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313491285700_27', 'Ba lần mắc zona thần kinh trong hai năm', 'Bà Dung, 62 tuổi, liên tiếp mắc zona thần kinh ở vùng lưng trong hai năm, lần sau nặng hơn lần trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/vnvc-zona-than-kinh-tai-phat-1-6377-2082-1773903517.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ot_zkYHKjIvfaOFuy5poIQ', '2026-03-19', 'admin', 453, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313503762500_28', '6 món chứa tinh bột người tiểu đường nên ăn', 'Thực phẩm giàu tinh bột phức hợp như yến mạch, ngũ cốc nguyên hạt, khoai lang giúp ổn định đường huyết và cung cấp năng lượng lâu dài cho cơ thể. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/Buoc-2-3355-1645172245-1773889121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ApfUYyAeH9YX9pzCl6WWCw', '2026-03-19', 'admin', 299, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313516762700_29', 'Tại sao lupus ban đỏ không thể chữa khỏi?', 'Bác sĩ chẩn đoán tôi mắc lupus ban đỏ. Bệnh nguy hiểm thế nào và tại sao không thể chữa khỏi hoàn toàn? (Nguyễn Dũng, Tiền Giang) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/taan08791-1773896320-177389644-1957-7425-1773897084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=a1vP8v6gMEZpjdw3KcbJiQ', '2026-03-19', 'admin', 201, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313529430300_30', 'Ăn mặn gây rối loạn tiền đình nặng hơn?', 'Tôi bị rối loạn tiền đình ngoại biên, được khuyên kiêng muối vì có thể làm bệnh nặng hơn, đúng không? (Lâm Phạm, 55 tuổi, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/a-nh-1773888613-1773888648-2147-1773888710.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u8tyXq22msAo0zpUDa0uew', '2026-03-19', 'admin', 158, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313542042200_31', 'Khó thở khi nằm cảnh báo bệnh gì?', 'Tôi thường cảm thấy khó thở khi nằm xuống, có liên quan đến bệnh hô hấp không? (Nguyễn Ngân, Hà Nội) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773887515-1773887563-7123-1773887636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=olNppiTaFzjv5NtxhAoN8w', '2026-03-19', 'admin', 199, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313554305100_32', 'Dùng sóng xung kích phá vôi hóa mạch vành', 'Bà Năm, 86 tuổi, đau ngực do động mạch vành hẹp tắc, được bác sĩ phá mảng vôi hóa bằng sóng xung kích ngăn nguy cơ nhồi máu cơ tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881685-1773881714-3499-2887-1773881937.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8a1D0rK_oLWWS9diLy28Bw', '2026-03-19', 'admin', 467, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313566853000_33', 'Cắt toàn bộ tuyến giáp chặn ung thư', 'Bà Loan, 50 tuổi, khám sức khỏe định kỳ phát hiện nhân giáp, sinh thiết lạnh xác định ung thư xâm lấn phải cắt toàn bộ tuyến giáp. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881289-1773881336-2586-1773881408.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yXQBUpD-Igp8_EDS1wUVEA', '2026-03-19', 'admin', 25, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313578710400_34', 'Suy buồng trứng ở tuổi 24', 'Chị gái bị vô sinh nên Hồng, 24 tuổi, chủ động đi khám sức khỏe sinh sản bất ngờ phát hiện buồng trứng gần cạn kiệt như phụ nữ mãn kinh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/key1103-3-1773817056-177381708-3143-7860-1773819558.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=CavEu2B_enyj5OEFH8VNdQ', '2026-03-19', 'admin', 325, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313591780500_35', 'Kỳ tích 90 ngày giữ song thai ''dọa'' sinh cực non', 'Chị Nhung, 33 tuổi, mang song thai 24 tuần dự báo nguy cơ 90% sinh non, được bác sĩ liên khoa phối hợp giữ thai thêm ba tháng đến khi sinh an toàn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881134-4834-1773881170.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1XDOjAjAXRUGNSkmDiyA0A', '2026-03-19', 'admin', 507, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313604434400_36', 'Trẻ bị lông mi mọc ngược có nguy hiểm?', 'Con tôi 5 tuổi, bị lông mi mọc ngược đâm vào mắt gây khó chịu, thường xuyên đỏ mắt. Tình trạng này có nguy hiểm và điều trị thế nào? (Trân, 31 tuổi, Long An) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/lo-ng-mi-mo-c-ngu-o-c-17738488-3850-2423-1773874352.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7CL5Pqz10iYGl92EJWXj0w', '2026-03-19', 'admin', 462, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313617311900_37', 'Cơn đau đầu cảnh báo sớm đột quỵ', 'Cơn đau đầu kéo dài, lúc âm ỉ, lúc dữ dội nhưng thoáng qua vài phút rồi biến mất có thể là dấu hiệu sớm đột quỵ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z7615389058820-b770c8502777a2a-3606-1286-1773839001.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DtpN1a4Sw8ZgN4_ZUIXC2Q', '2026-03-19', 'admin', 453, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313629483200_38', 'Ăn uống, dùng thuốc thế nào sau cắt toàn bộ tuyến giáp?', 'Tôi đã cắt toàn bộ tuyến giáp triệt căn ung thư, phải dùng hormone thay thế. Ăn uống thế nào, lưu ý gì để không ảnh hưởng hấp thu thuốc? (Quốc Bảo, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/a-nh-1-1773838561-1773838575-1902-1773838656.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KiTXzuR-XhOYEsReCOHtGQ', '2026-03-19', 'admin', 507, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313641858000_39', 'Ngủ đủ giấc - cách đơn giản bảo vệ trái tim', 'Ngủ đủ giấc hỗ trợ kiểm soát huyết áp, giảm viêm, tinh thần sảng khoái, từ đó tăng cường sức khỏe tim mạch. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/86262b59886c421faa325d79d43c42-3285-5331-1773807728.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=z2yoNwuRifB21tkyO55TgA', '2026-03-19', 'admin', 119, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313658100300_40', 'Ba thói quen ít ngờ có thể gây hại não', 'Ít tiếp xúc xã hội, sống ở nơi thiếu ánh sáng và nghe nhạc to lâu dài có thể ảnh hưởng tâm trạng, trí nhớ và sức khỏe não bộ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/geminigeneratedimage4gdeoq4gde-2334-2556-1773805576.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=6L8vpW0eIwiwb9yhfgyJEQ', '2026-03-19', 'admin', 224, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313676644800_41', 'Bé gái tử vong sau 9 giờ phát bệnh nghi do não mô cầu', 'Bé gái 10 tuổi tại Phú Quốc sốt, đau đầu, nổi ban, tím tái, khó thở, vào viện cấp cứu song không qua khỏi, nghi mắc viêm não mô cầu. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-19', 'admin', 166, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313696080800_42', 'Hai bác sĩ ép tim cứu người ngừng thở giữa sân bóng chuyền', 'Bác sĩ Trần Văn Biên và Nguyễn Cao Việt ép tim cứu sống người đàn ông 64 tuổi ngừng tuần hoàn, ngã quỵ giữa sân khi đang đánh bóng chuyền hơi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/eptim-1773824056-9512-1773824095.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=zKbi8S68AXzNCvOi1chXQw&t=image', '2026-03-19', 'admin', 204, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313714912100_43', 'Thử thách ''nằm một chỗ'' nhận tiền gây sốt tại Thượng Hải', 'Thí sinh tham gia thử thách ngủ được yêu cầu nằm một chỗ trong 24 giờ, không đi vệ sinh, không dùng điện thoại, máy tính để có cơ hội nhận tiền mặt cùng nhiều gói nghỉ dưỡng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/ngu-1773821005-1773821075-3441-1773821874.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8KlVBUvBMqmynOHVIVlLoA', '2026-03-19', 'admin', 257, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313730041000_44', 'Bác sĩ chỉ ra cách ăn uống giúp kéo dài tuổi thọ', 'Silvio Garattini, nhà dược học nổi tiếng người Italy, nhận định việc tiêu thụ ít thực phẩm có thể là chìa khóa để thêm nhiều năm sống khỏe mạnh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-17-at-14-42-3188-8472-1773733487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WtNm6z8rhaEufjF1U9dIpg', '2026-03-19', 'admin', 363, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313745877800_45', 'Hàng chục nghìn ca lao bị bỏ sót, TP HCM mở chiến dịch 100 ngày', 'TP HCM khởi động chiến dịch 100 ngày tầm soát lao chủ động bằng X-quang tích hợp AI cho 30.000 người dân có nguy cơ cao, trước tình trạng hàng chục nghìn ca bệnh bị bỏ sót. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/xn-be-nh-lao-1773813681-177381-6084-5180-1773814033.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=dhP9C3bqRRjz-Y8bvoWDCg', '2026-03-19', 'admin', 360, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313759904300_46', 'Trung Quốc chế tạo thiết bị bảo quản nội tạng hiến tặng trong nhiều ngày', 'Các nhà khoa học Trung Quốc vừa phát triển thành công hệ thống tưới máu máy đa nhiệt độ, giúp kéo dài thời gian bảo tồn nội tạng hiến tặng từ vài giờ lên nhiều ngày. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/1-1773810584-1773810598-6921-1773811859.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Mn8_w1WS1t3d0f_fsjsllg', '2026-03-19', 'admin', 97, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313772770700_47', 'Bắt bạn đời tránh thai, triệt sản vì định kiến giới sẽ bị phạt 12 triệu đồng', 'Từ ngày 1/5, cơ quan chức năng phạt tiền 10-12 triệu đồng đối với người ép buộc vợ hoặc chồng sử dụng biện pháp tránh thai, triệt sản với lý do định kiến giới. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-19', 'admin', 44, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313785297400_48', 'Uống nước chanh trị gout?', 'Nhiều người truyền tai nhau uống nước chanh tươi giúp rửa bớt acid uric, có thể dùng thay thuốc điều trị gout, điều này có đúng? (Tuấn, 32 tuổi, Hà Nội). (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/c15c6f48-ced4-4429-bfb5-9455cd-5801-6593-1773760546.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=W_kjheUzq2C2ME6zHgDgBg', '2026-03-19', 'admin', 40, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313797807700_49', 'Đề xuất hỗ trợ 1,5 triệu đồng sàng lọc bệnh trước và sau sinh', 'Bộ Y tế đề xuất mức chi 1,5 triệu đồng cho các dịch vụ sàng lọc phát hiện sớm bệnh bẩm sinh nhằm nâng cao chất lượng nòi giống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/anh-chup-man-hinh-2026-03-18-l-5391-3509-1773799029.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0k4SOQrMVLeMurI_aXm-A', '2026-03-19', 'admin', 203, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313810666700_50', 'Tưởng đau bụng thông thường, hóa ung thư gan giai đoạn cuối', 'Người đàn ông 55 tuổi đến viện khám do đau tức vùng hạ sườn phải suốt một tháng, chán ăn, bác sĩ chẩn đoán ung thư gan giai đoạn cuối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-11-at-15-02-9133-1291-1773738650.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4LPRxOCxuzDWC9Ke0ApIMQ', '2026-03-19', 'admin', 196, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313823283700_51', 'Từ 1/7, mẹ sinh con thứ 2 có thể nghỉ 7 tháng, cha nghỉ 10 ngày', 'Dự thảo mới cho phép người mẹ sinh con thứ hai nghỉ 7 tháng, thêm một tháng so với trước, giúp các gia đình có thêm thời gian chăm trẻ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/DSC9142-1773747953-7405-1773748019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kun5YDQOJ0Du1_kUlWGl1Q', '2026-03-19', 'admin', 180, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313835648400_52', 'Độc dược núp bóng ''thần y ba đời''', 'Núp bóng danh xưng "thần y" cùng lời cam kết "không khỏi không lấy tiền", nhiều đối tượng trục lợi tung ra hàng loạt bài thuốc Đông y kém chất lượng, gây họa cho người dùng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/thuo-c-tie-u-du-o-ng-2-1751378-1642-1585-1773790794.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=BM3PBuqDiOcxxKxu-FrLIA', '2026-03-19', 'admin', 99, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313849144400_53', 'Bí quyết giúp quý bà U70 sở hữu hình thể ''vạn người mê''', 'Ở tuổi 65, bà Lesley Maxwell vẫn khiến nhiều người phải ngoái nhìn nhờ thân hình săn chắc và cơ bụng sáu múi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/u701-1773719607-3703-177371969-8525-8146-1773732785.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xd0knGcn77T2SR_iKcJM9A', '2026-03-19', 'admin', 170, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313864271400_54', 'Có nên giặt quần áo mới trước khi mặc?', 'Làn da của tôi khá nhạy cảm, tôi có nên giặt quần áo mới trước khi mặc để hạn chế tình trạng ngứa, nổi mẩn hay không?(Tú, 23 tuổi, Hà Nội). (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/top-shape-2-1773628404-1773628-1443-7265-1773628558.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=eXIpocDyL3yIbtJ_LAMyqA', '2026-03-19', 'admin', 206, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313878669800_55', 'Điều gì xảy ra khi bạn ăn tinh bột?', 'Thực phẩm giàu tinh bột cung cấp năng lượng cùng với vitamin, khoáng chất, chất xơ cho cơ thể, là một phần quan trọng của chế độ ăn cân bằng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/chatgptimage15361116thg32026-1-5501-2960-1773650432.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=RgQJaKU6trcJdDWiX1-f7w', '2026-03-19', 'admin', 119, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313891912000_56', '9 sai lầm thường gặp âm thầm gây hỏng răng', 'Các nha sĩ cảnh báo rằng ngay cả những thói quen như nhai vật cứng, thở bằng miệng, lạm dụng sản phẩm làm trắng... có thể gây tổn thương nghiêm trọng đến răng và nướu theo thời gian. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/screenshot-2026-03-16-at-10-35-4738-7215-1773632213.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=4DK7hZkb0_1zX5EIsZIH8g', '2026-03-19', 'admin', 457, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313904519500_57', 'Vinmec Ocean Park 2 vận hành máy MRI 3.0', 'Hệ thống chụp cộng hưởng từ MRI 3.0 Tesla Magnetom Vida XT giúp rút ngắn thời gian chụp, giảm tiếng ồn, đồng thời nâng cao độ chính xác trong chẩn đoán. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/anh-1-17-1773829615-1773838403-1650-1773838419.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KJsDDD9ra4Zr_T0rLBhfSA', '2026-03-19', 'admin', 18, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313917356100_58', 'Nam giới hay nữ giới khó đào thải virus HPV hơn?', 'Nếu nhiễm virus HPV, nam giới hay nữ giới khó đào thải hơn, làm sao để nhanh đào thải? (Hoàng Lộc, 25 tuổi, Cần Thơ) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/medium-vecteezy-scientist-hold-1826-6893-1773830684.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NmJiQ03gv8AfPtQ1HIR-_Q', '2026-03-19', 'admin', 225, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313930107000_59', 'U bã đậu trên mặt bé gái 8 tuổi', 'Khối u ở tai trái của bé Thu, 8 tuổi, sưng to, đau, bác sĩ chẩn đoán u bã đậu có dấu hiệu nhiễm trùng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/image001-1773826220-1773826244-4276-1773826285.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=pLERXqlNXZRZ2Uy4I_wDIw', '2026-03-19', 'admin', 88, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21313999775600_0', 'Vì sao nhiều người không quên được tình cũ?', 'Dưới lăng kính tâm lý học, việc chúng ta không ngừng tiếc nuối và lý tưởng hóa người yêu cũ thực chất chỉ là một "cú lừa" của não bộ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/nguoi-cu-1773906295-1773906318-6293-1773906415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=HVjiPxxd9gacVL6Y22uXqA', '2026-03-19', 'admin', 399, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314013883300_1', 'Bi kịch của nữ giám đốc lộ chuyện ngoại tình ở đêm nhạc', 'Từng là tâm điểm chỉ trích vì nụ hôn vụng trộm với sếp, cựu giám đốc Kristin Cabot lần đầu lên tiếng về bi kịch mất trắng sự nghiệp và tiêu chuẩn kép của dư luận. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-3953-9787-1773905123.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SnVW0ZXwG0D0cs-jv11r5w', '2026-03-19', 'admin', 355, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314026262000_2', 'Lợi ích bất ngờ của người thấp bé', 'Khác với lầm tưởng cao lớn đồng nghĩa với khỏe mạnh, người có vóc dáng khiêm tốn thực chất lại ít mắc ung thư, hiếm khi gãy xương và có xu hướng sống thọ hơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-16-1-3564-4232-1773826547.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WILYrMZI2_N_0dlS2haaeA', '2026-03-19', 'admin', 445, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314038810500_3', 'Bi kịch của những tình yêu AI', 'Tối 13/2, SkeweredKebab (nickname) đọc lại toàn bộ những cuộc hội thoại với ChatGPT để làm lễ tiễn biệt "người chồng AI" vừa bị khai tử. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-15-5-6470-2528-1773825011.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hywduvy6fBWG60Hqv4b41Q', '2026-03-19', 'admin', 459, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314051827900_4', 'Gia đình ''siêu nhân Gao'' ở Hưng Yên gây bão mạng', 'Giữ trọn đam mê siêu nhân từ nhỏ, anh Ngọc Trung sắm trang phục siêu nhân Gao rủ vợ hóa trang, sáng tạo loạt video hài hước mang lại tiếng cười cho cộng đồng. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7606213086839-ba7d4f64bbbc508-7613-9150-1773319405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mrTZfGPqSl0KOJOxGL3Etw', '2026-03-19', 'admin', 31, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314069251700_5', 'Vụ ly hôn tỷ USD và góc khuất đời tư của chủ tịch tập đoàn SK', 'Cuộc chiến pháp lý giữa Chủ tịch tập đoàn SK Chey Tae-won và vợ cũ Roh Soh-yeong gây chấn động bởi khối tài sản khổng lồ và sự xuất hiện của "người thứ ba". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/00-1773805459-1773805465-7488-1773807993.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ma9jNQK-Y2L9EYbGcAWU3Q', '2026-03-19', 'admin', 339, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314088423600_6', 'Nhà hàng đập 600 bộ bát đĩa vì khách cho chó lên bàn ăn', 'Ông Giang, quản lý nhà hàng tại Thương Khâu (Hà Nam), đã đập bỏ 600 bộ bát đĩa và đóng cửa khử trùng quán khi phát hiện một thực khách mang chó lên bàn ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/pet-restaurant-2-1773823218-17-3022-8308-1773823607.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YJaopzEQ_wQcv0LriogkfQ', '2026-03-19', 'admin', 224, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314109206300_7', 'Nạn trộm cắp ở khu nhà giàu Mỹ', 'Từng là chốn an cư bình yên của giới tinh hoa, khu Sharon Heights (vùng vịnh San Francisco) giờ chìm trong bất an khi kẻ gian liều lĩnh đột nhập ngay lúc gia chủ đang ăn tối. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/ratio3x2-960-1773806447-177380-5965-1359-1773809180.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=XY--0saGjRWJfVzM5zTLrQ', '2026-03-19', 'admin', 70, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314127369100_8', 'Làn sóng ''nhân lực tinh hoa'' rời bỏ Israel', 'Từng coi Tel Aviv là "thiên đường công nghệ", kỹ sư Elizabeth Cohen quyết định rời đi vì không muốn sinh con giữa những tiếng còi báo động tên lửa. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-17-at-23-3-7325-4333-1773766923.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KazThb0Myl6qlnll2uVyPg', '2026-03-19', 'admin', 312, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314142834500_9', 'Cách tự học tiếng Anh của ''cô giáo nhí'' 9 tuổi', 'Từ trò chơi đóng vai cô giáo mỗi tối, bé Vân Anh khiến cộng đồng mạng bất ngờ bởi khả năng nói tiếng Anh trôi chảy và cách dạy em đầy kiên nhẫn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/va-n-anh-2-1773661730-17736617-3169-1895-1773662279.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MFZagmWNCjA_dg4MlTV1-g', '2026-03-19', 'admin', 180, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314162148000_10', 'Phát tài nhờ tờ giấy bỏ quên 30 năm', 'Đang phải sống chật vật với lương hưu eo hẹp, vợ chồng ông Sato bất ngờ thu về 68 triệu yen nhờ tìm thấy tờ biên lai mua cổ phiếu, bị bỏ quên 30 năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/co-phieu-2-jpeg-1773797809-177-3785-6774-1773797902.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T-SETu0hLWUdD-lr9bNEBQ', '2026-03-19', 'admin', 444, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314182455000_11', 'Bi kịch của thế hệ ''kiếm nhiều tiền nhưng không giàu''', 'Thu nhập 450.000 USD mỗi năm nhưng vợ chồng Alex vẫn phải ở nhà thuê, chưa trả hết nợ sinh viên và nơm nớp lo sợ thiếu tiền giữa lòng New York đắt đỏ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-00-3-6865-5413-1773770804.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICLidWfdmD2K6KISqPINoQ', '2026-03-19', 'admin', 231, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314194279500_12', 'Hai chuyến đi Việt Nam ''cứu rỗi'' người phụ nữ Mỹ', 'Rơi vào trầm cảm sau khi mẹ qua đời, Lilly Hubbard quyết định quay lại Việt Nam và tìm thấy sự "chữa lành" từ tình người ấm áp ở vùng đất xa lạ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/lilly-2-1773802709-1773802742-4016-1773802752.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5uQdZnsKta3M8vRTp6nZhA', '2026-03-19', 'admin', 156, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314206260200_13', 'Vì sao quần áo thể thao giặt xong vẫn hôi?', 'Ném ngay đồ tập đẫm mồ hôi vào máy giặt, dùng nhiều xà phòng hay nước xả vải là sai lầm khiến quần áo luôn bốc mùi khó chịu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/a-nh-ma-n-hi-nh-2026-03-16-lu-7904-9038-1773736876.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KXY2uWiUcoSsOpLDwHycOA', '2026-03-19', 'admin', 242, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314218555200_14', 'Bên trong nhà lắp ghép 30 m2 của tỷ phú Elon Musk', 'Mặc dù sở hữu hàng trăm tỷ USD, tỷ phú Elon Musk hiện sống trong căn nhà lắp ghép rộng 30 m2, thiếu tiện nghi đến mức mẹ ông phải ngủ ở gara. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/577333596-3394143064076672-485-6636-3102-1773724581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=b5eyN5ibANA-m59NlkHsAQ', '2026-03-19', 'admin', 267, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314230638400_15', 'Vợ cho ''thuê'' chồng', 'Phát hiện chồng ngoại tình, cô Khun Kwang ra thỏa thuận cho nhân tình của anh thuê chồng với giá 30.000 bath mỗi tháng, tuy nhiên hợp đồng này bị luật sư cảnh báo vô hiệu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/chatgpt-image-11-27-42-17-thg-9377-7480-1773721720.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NBqR-Rw-evtAbpk1qTmaKQ', '2026-03-19', 'admin', 287, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314243572700_16', 'Vì sao nhà chung cư ở Mỹ ngày càng ít?', 'Từng là lựa chọn an cư giá rẻ cho người trẻ Mỹ, số lượng chung cư thương mại sụt giảm mạnh do rào cản pháp lý, thuế và chi phí bảo hiểm tăng vọt. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/im-92913950-1773654144-1773671-8010-8091-1773672308.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Bm4Dwf779JQ1G3-LVfRR1w', '2026-03-19', 'admin', 257, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314256816500_17', 'Vợ 50 tuổi làm IVF chiều chồng trẻ', 'Bất chấp những đàm tiếu của dư luận, bà Pilli Cortese vẫn quyết định thụ tinh nhân tạo ở tuổi 50 để thỏa ước nguyện làm cha của người chồng kém 21 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5921-9658-1773633940.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9Zuubwaaw2BqQmbUtn07fA', '2026-03-19', 'admin', 185, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314270395300_18', 'Bẫy thổi phồng chức danh khi tuyển dụng', 'Nhiều doanh nghiệp đang gán mác "giám đốc", "trưởng phòng" cho người lao động nhưng chỉ trả mức lương nhân viên nhằm thu hút ứng viên và tối ưu chi phí. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/tuyen-dung-jpeg-1773679492-177-2056-8763-1773681102.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KigiyGPtR51yLB_8Hefyxg', '2026-03-19', 'admin', 478, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314282491600_19', 'Dân công sở Mỹ bỏ ôtô, đạp xe, làm từ xa để né ''bão'' giá', 'Thấy giá nhiên liệu tăng vọt, Boris Kagarlitskiy quyết định cất chiếc Lexus ở nhà, lôi xe đạp cũ ra lau chùi để bắt đầu chuỗi ngày đi làm bằng sức người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/dap-xe-1773678268-1773678292-1-1377-3127-1773678449.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=w-sPfSoia-AE5rGBtpoj4Q', '2026-03-19', 'admin', 214, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314295615200_20', 'Nhan Phúc Vinh, Hà Thu tập chống đuối nước cùng 1.000 học sinh', 'Diễn viên Nhan Phúc Vinh, Á hậu Hà Thu cùng hơn 1.000 học sinh nhận biết mực nước an toàn, kỹ năng thở nước, tại workshop chống đuối nước, sáng 16/3. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/dsc04354-1773740071-8030-17737-9004-8642-1773765903.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A4JrUo23I3KsRgZmF6I4Lg', '2026-03-19', 'admin', 411, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314310273900_21', '3 bước đánh lừa não bộ để ngủ nhanh hơn', 'Kỹ thuật "xáo trộn nhận thức" giúp ngắt quãng dòng suy nghĩ lo âu, mô phỏng trạng thái mơ màng tự nhiên để não bộ thư giãn và dễ dàng chìm vào giấc ngủ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/z7591758010902-c59406ff20941de-5096-4651-1773652579.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xQChxkieWCwZeML9fYn7Gg', '2026-03-19', 'admin', 170, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314323800100_22', 'Yêu 6 năm mới biết bạn gái đã có chồng con', 'Chi hơn một triệu tệ cho bạn gái trong 6 năm mặn nồng, anh Wang bàng hoàng phát hiện người yêu thực chất đã yên bề gia thất, thậm chí các con đã học cấp hai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5017-9753-1773636339.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LRn0uHe2LxkLnmac08jIuw', '2026-03-19', 'admin', 251, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314336685500_23', 'Nhiều nông dân Mỹ có nguy cơ phá sản vì xung đột Trung Đông', 'Xung đột tại Trung Đông đẩy giá nhiên liệu và phân bón lên mức kỷ lục, giáng đòn mạnh vào hàng loạt trang trại, đẩy họ vào cảnh phá sản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-13-at-22-1-6679-9104-1773417216.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wNZTd6jP3YfT0zCvXMAvYg', '2026-03-19', 'admin', 361, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314350859300_24', 'Khủng hoảng xăng dầu ''bóp nghẹt'' người nghèo châu Á', 'Xung đột ở Trung Đông gây đứt gãy nguồn cung nhiên liệu, đẩy hàng chục triệu người lao động tại châu Á vào cảnh thiếu xăng, khí đốt và sụt giảm thu nhập. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/a-nh-ma-n-hi-nh-2026-03-16-lu-7437-9899-1773631014.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pswj5Qok0ZT1EUC6gyBi6g', '2026-03-19', 'admin', 211, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314366167900_25', 'Tụ tập - quy tắc giữ gìn tình bạn của người Đức', 'Cuộc sống bận rộn khiến nhiều mối quan hệ phai nhạt nhưng người Đức áp dụng quy tắc "Stammtisch" - những cuộc tụ họp định kỳ, đơn giản nhưng hiệu quả. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/stammtisch-2-1773625060-177362-4038-7784-1773625553.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lkewTZzZ2noESjRQobw1iA', '2026-03-19', 'admin', 324, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314381791000_26', 'Chàng trai Canada ''bẻ lái cuộc đời'' vì tình yêu với cô gái Việt', 'Ngay buổi hẹn đầu dưới chân tháp Tokyo, Thu Thủy đưa ra loạt tiêu chuẩn khắt khe về bạn trai, rồi dội gáo nước lạnh vào Seiwa: “Em không muốn gặp lại anh nữa”. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/img-1831-1-jpeg-1773460527-177-7354-6141-1773461950.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mt3pi6U16KHThn4v8-hOBA', '2026-03-19', 'admin', 287, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314397241300_27', 'Ước mơ của người vợ 10 năm giữ món quà chồng chưa kịp tặng', 'Cất kỹ chiếc váy và chú gấu bông chồng mua tặng trước khi tử nạn, chị Thúy mong một ngày được trao lại cho con gái trong sự kiện trọng đại nhất đời. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/z7619839331948-d5148baa4b6833d-6407-2821-1773504440.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RytXItajr9SLpO3H0LRM4Q', '2026-03-19', 'admin', 82, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314410956800_28', 'Cuộc đoàn tụ gượng gạo của cô gái bị vứt ở nhà vệ sinh 28 năm trước', 'Bị ông nội vứt bỏ từ lúc 2 ngày tuổi, Hong Yangli vượt nửa vòng trái đất về nhận mẹ nhưng đối diện màn đoàn tụ lạnh lẽo, dấy lên nhiều tranh cãi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/1-3-1773547826-1773547843-5092-1773548222.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=amEJ_VUF9IpG9eD0G9_PNg', '2026-03-19', 'admin', 149, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314430365100_29', 'Cụ bà 82 tuổi bị lừa kết hôn bằng 20 quả trứng', 'Cụ bà mù chữ 82 tuổi ở Hồ Nam tưởng làm giấy tờ để nhận trợ cấp 1.000 tệ và 20 quả trứng, không ngờ bị lừa ký giấy đăng ký kết hôn với người đàn ông 47 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/00-1773543821-1773543868-7185-1773543919.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KfEnT7aoLQ3RSBsN1-oYAw', '2026-03-19', 'admin', 249, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314449722400_30', 'Người đàn ông bị hàng loạt nhà tang lễ từ chối vì béo', 'Ở Canada, béo phì không chỉ là một bài toán khó về sức khỏe khi còn sống, mà nay lại biến thành "rào cản cuối cùng" sau khi chết. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/0-1-1773549860-1773549866-3805-1773550180.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vVbCv37mEQDizIgnTBFi5g', '2026-03-19', 'admin', 411, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314469207100_31', 'Suýt mất mạng, cặp vợ chồng hối hận vì ''bỏ phố về rừng''', 'Từng ảo tưởng về sự tuyệt vời của cuộc sống biệt lập giữa thiên nhiên, vợ chồng Jayme bừng tỉnh sau sự cố suýt mất mạng ngày sinh nở, nhận ra cái giá của sự cô độc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773464228-1773464933-3946-1773464939.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oyCVWVQKOW3_wjd1YLbydQ', '2026-03-19', 'admin', 106, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314489387100_32', 'Đường đến giải bơi trong hồ băng của cậu bé Hà Nội', 'Trên đỉnh núi tuyết ở Neuhermsdorf, Phan Anh mặc quần bơi đứng lặng nhìn mặt hồ Altes Zollhaus bốc khói trong khi ban tổ chức luôn tay vớt những tảng băng cản đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/phan-anh-1-1773221913-4040-177-8906-6797-1773503423.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tRJ-e86PBimTvuLx8uLrLQ', '2026-03-19', 'admin', 263, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314505352800_33', 'Đánh cược mạng sống mưu sinh trong vùng chiến sự', 'Mỗi khi tiếng còi báo động vang lên, nữ giúp việc Joycee Pelayo chạy vội đến cụ ông mà cô đang chăm sóc, dìu ông lên xe lăn rồi đẩy thật nhanh xuống hầm trú ẩn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773484138-1773484220-8888-1773484945.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SXxzNvSvE4dKP7MSqygIxA', '2026-03-19', 'admin', 509, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314520656800_34', 'Người Lạng Sơn chi hàng trăm triệu làm cỗ mời khách lạ', 'Để tán lộc và cầu may, người dân Lạng Sơn chi hàng trăm triệu đồng dựng rạp, thết đãi cỗ miễn phí cho cả khách lạ về dự hội đền Kỳ Cùng - Tả Phủ đầu năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/6-2-1773501948-1773502444-9849-1958-9924-1773505959.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0x9NpYpx7nxQjaqa-_PsZg', '2026-03-19', 'admin', 328, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314537520900_35', 'Gần 3.000 runner chạy giữa đô thị lớn nhất Nghệ An', 'Gần 3.000 vận động viên dự giải Eco Central Park Marathon lần đầu tổ chức với cung đường xuyên qua công viên và các thảm hoa trong khu đô thị. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/kbd03827-1773548789-1773549037-3771-1773551974.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0E-9mGgNroDH6ojqizG9w', '2026-03-19', 'admin', 147, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314554184300_36', 'Thường xuyên bị nhầm là con vì kém vợ 23 tuổi', 'Bất chấp khoảng cách 23 tuổi và hay bị nhầm là mẹ con, cặp đôi Azmirullah (28 tuổi) và Wan Nazihah (51 tuổi) vẫn có cuộc sống viên mãn sau gần 7 năm kết hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-5511-1481-1773391224.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rVhmD8KwmfMyFVajva3Fg', '2026-03-19', 'admin', 85, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314567201400_37', 'Cả nhà bới 10 tấn rác tìm túi vàng', 'Gia đình 8 người ở Giang Tây phải thức trắng đêm, lục tung 10 tấn rác để tìm lại túi vàng trị giá 1,5 triệu tệ (5,2 tỷ đồng) bị người nhà vứt nhầm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/chatgpt-image-12-00-22-14-thg-6372-9837-1773467256.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=_9x4DRlTKFjkiC60B2o8FA', '2026-03-19', 'admin', 132, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314580281600_38', 'Vì sao không cần ''ra khỏi phòng là tắt đèn''?', 'Lời khuyên "ra khỏi phòng là tắt đèn" đã lỗi thời trong kỷ nguyên bóng đèn LED, nhưng vẫn áp dụng đúng quy tắc 15 phút với đèn huỳnh quang. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/1-1773454941-1773455346-9660-1773455690.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bdkGsflc9Jxr6O6pwJzT-A', '2026-03-19', 'admin', 378, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314593229400_39', 'Những cuộc hôn nhân tan vỡ vì trúng độc đắc', 'Trúng thưởng hàng chục triệu USD, nhiều cặp vợ chồng ngỡ đã chạm tay vào hạnh phúc viên mãn nhưng cuối cùng lại rơi vào cảnh ngoại tình, kiện tụng và ly hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/screen-shot-2026-03-14-at-00-3-2966-9237-1773423562.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zp535HhmTaj7GmpNZEZnIw', '2026-03-19', 'admin', 355, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314605658900_40', 'Dubai vắng vẻ ''chưa từng thấy''', 'Dưới sức ép từ các đợt tấn công của Iran, người nước ngoài đang vội vã rời khỏi Dubai, đẩy "thành phố vàng" vào cảnh vắng lặng như thị trấn ma. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/untitled-1773453416-1773453692-9708-1773453849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vbalNxj_XueEp65nAOLXcA', '2026-03-19', 'admin', 305, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314617502200_41', 'Chàng trai không tay và những món ăn ''triệu view''', 'Mất đôi tay sau tai nạn, Trọng Định, 23 tuổi, học cách nấu ăn bằng chân và hai mỏm cụt, biến nỗi đau thành nghị lực sống truyền cảm hứng cho hàng triệu người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/di-nh-di-cho-1773409298-177340-4382-8632-1773422430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0DityHvFbLGR7izILlXGOQ', '2026-03-19', 'admin', 317, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314629748700_42', 'Dùng AI tạo ''chuyên gia giả'' để trị thói giục cưới của cha mẹ', 'Mệt mỏi vì bị cha mẹ liên tục giục lấy chồng, Cao Mei, 38 tuổi, dùng AI tạo ra một "chuyên gia tâm lý" để giảng đạo lý, thuyết phục ngược lại phụ huynh. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/0-1773398662-1773398682-1718-1773399208.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EVMDlFbSybo3mN85hxNoWg', '2026-03-19', 'admin', 222, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314642277800_43', 'Đổ xô mua nhà thờ cũ làm nhà ở', 'Giữa "bão" giá bất động sản, nhiều người chọn mua các nhà thờ cũ với giá rẻ để cải tạo thành không gian sống độc đáo. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/a-nh-ma-n-hi-nh-2026-03-13-lu-3696-4834-1773377205.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SH7Rb4ILOv0ksxLF-wv1NQ', '2026-03-19', 'admin', 339, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314654109400_44', 'Hơn 2.000 người mua vé sớm dự lễ hội ẩm thực Saigontourist 2026', 'Hàng nghìn vé sớm được bán trước thềm Lễ hội Văn hóa Ẩm thực Saigontourist 2026, hút 2.000 lượt đặt mua sau 10 ngày. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/kho-ng-khi-nga-p-tra-n-ma-u-sa-5727-7837-1773461994.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0g7XJzZGG1R1YRikkMMY9g', '2026-03-19', 'admin', 144, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314665707200_45', 'Trẻ học được gì từ việc cha rửa bát?', 'Sự phân công việc nhà giữa cha và mẹ là "bản thiết kế" cho hành vi xã hội của trẻ, liên quan trực tiếp đến nguy cơ bạo lực học đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-2254-8889-1773393096.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s6Oxd_5Gu1oXQ46K_G7Dug', '2026-03-19', 'admin', 126, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314677197900_46', '20.000 thuyền viên kẹt gần Hormuz nguy cơ thiếu nhu yếu phẩm', 'Gần 20.000 thủy thủ mắc kẹt trên các tàu hàng ở eo biển Hormuz đang đối mặt với nỗi lo tên lửa rơi trúng và tình trạng cạn kiệt nhu yếu phẩm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/tau-dau-1773402850-1773402875-3232-1773403067.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NTSnOJHpgEet9waOtHY1dw', '2026-03-19', 'admin', 72, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314689380100_47', 'Quy tắc ''muối tách, đường giữ'' trong nấu ăn', 'Nêm gia vị đúng thời điểm không chỉ giúp món ăn đậm đà mà còn ảnh hưởng đến độ ngon, độ giòn, độ mọng của món ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/pexelsrohanmuzafar3054690-1773-8724-2189-1773394017.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=k9GycCL6VDqIrC8odwZSsA', '2026-03-19', 'admin', 143, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314701666400_48', 'Vì sao nhiều người chỉ làm việc hiệu quả sát deadline?', 'Áp lực thời gian cận kề giúp não bộ tiết ra các hormone cảnh báo, loại bỏ sự trì hoãn và tăng cường khả năng tập trung vào công việc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/deadline-1773390004-1773390024-3813-1773390069.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=IrRI2aePlRHDe6ihst78Iw', '2026-03-19', 'admin', 97, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314713398200_49', 'Góc khuất sau vấn nạn cố tình xô đẩy ở Nhật Bản', 'Đoạn video bé gái bị xô ngã ở Tokyo đã gióng lên hồi chuông báo động về "butsukari" - vấn nạn cố tình va chạm người lạ để xả stress đang gia tăng tại Nhật Bản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/Thie-t-ke-chu-a-co-te-n-3-1773-4469-9773-1773374593.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=kmKl_9ydvAdA8gw15swzMg&t=image', '2026-03-19', 'admin', 102, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314725364500_50', 'Con trai dùng trực thăng đưa mẹ về quê', 'Mẹ nói muốn về quê, người đàn ông tên Long ở Tứ Xuyên lái trực thăng cá nhân trị giá 7 triệu tệ đưa bà về vì ôtô đã cho bạn mượn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1773272450-177327-8656-6736-1773274348.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Y9XSNVQj99QxicXvcU31fg', '2026-03-19', 'admin', 138, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314737778900_51', 'Giới siêu giàu vung tiền xây hầm trú ẩn', 'Lo ngại bất ổn toàn cầu, giới siêu giàu đang vung hàng trăm nghìn USD xây các hầm ngầm trú ẩn xa xỉ, mang lại doanh thu kỷ lục cho hãng sản xuất. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/untitled-1773333717-1773334180-5221-1773334666.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lsi1Zbgp6ky9ZkkJLntrzA', '2026-03-19', 'admin', 139, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314750137500_52', 'Chuyện tình 15 ngày của đôi vợ chồng hoán đổi giới tính', 'Từng cạn niềm tin vào tình yêu, Mộc Trà - người chuyển giới nữ và Thiên Minh - người chuyển giới nam, quyết định kết hôn sau 15 ngày quen nhau vì tìm thấy sự đồng cảm sâu sắc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-12-at-15-0-4845-1689-1773336910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zsMmkb4ZKHA4pdM_bk4JnA', '2026-03-19', 'admin', 305, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314763014000_53', 'Quy tắc ''cấm khoe mẽ'' của phố Wall', 'Việc bốn chuyên viên tài chính trẻ làm mẫu ảnh thời trang đã làm bùng nổ tranh cãi về quy tắc bất thành văn ở Phố Wall: Tuyệt đối không thu hút sự chú ý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/screen-shot-2026-03-12-at-14-5-9812-8707-1773302260.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7wMXhzX_8pLrHBKLQ_kwXw', '2026-03-19', 'admin', 352, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314775804100_54', 'Tỷ phú bánh bao ở nhà thuê, quyết không để tài sản cho con', 'Sở hữu chuỗi 5.600 cửa hàng và tài sản gần 600 triệu USD nhưng danh mục bất động sản của ông Lưu Hội Bình vẫn trống trơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/a-nh-ma-n-hi-nh-2026-03-12-lu-4281-8357-1773300992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Aibug9pmVMbPQDhOgkh3cA', '2026-03-19', 'admin', 146, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314794047200_55', 'Tổ bay góp tiền đưa mẹ con người phụ nữ khiếm thị về quê', 'Địu con nhỏ đi từ TP HCM về Cao Bằng, người mẹ khiếm thị được tổ tiếp viên chăm sóc và quyên tiền đặt vé xe giường nằm chặng cuối về tận nhà. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7613036872520-979f4c14b579a74-6143-5591-1773323528.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZuKH3SFTr-IeOBXRl9BZ_A', '2026-03-19', 'admin', 468, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314811090700_56', 'Ba dấu hiệu cảnh báo thịt đông lạnh đã hỏng', 'Nhiều gia đình tích trữ thịt trong tủ đá hàng tháng trời và vô tư đem chế biến dù chúng đã biến màu, nhớp nháp hay bị "bỏng lạnh". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1-1773284849-1773-8712-1642-1773285672.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jOrSg2ECal3EmqLTWjqnSA', '2026-03-19', 'admin', 453, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314830540400_57', 'Nguy cơ lộ ảnh nhạy cảm khi xác thực khuôn mặt', 'Nhiều người lầm tưởng camera chỉ quét khuôn mặt (khung vòng tròn) khi xác thực sinh trắc học, nhưng thực tế, toàn bộ bối cảnh và nửa thân trên đều bị ghi lại. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/privacy-china-facial-recogniti-2318-1976-1773301226.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=muYXNO5HZuxuAbtU51scLg', '2026-03-19', 'admin', 267, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314847338600_58', 'Người dân châu Á chật vật vì giá gas, xăng dầu tăng vọt', 'Giá gas và xăng dầu tăng vọt do xung đột Trung Đông đang đe dọa trực tiếp đến sinh kế, buộc nhiều gia đình nghèo ở châu Á phải quay lại dùng củi đun nấu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/a-nh-ma-n-hi-nh-2026-03-12-lu-9395-2796-1773289912.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=q4U5mjEQL9diDyxLfc4zsQ', '2026-03-19', 'admin', 367, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_21314862616500_59', 'Cuộc đời ''em bé ống nghiệm'' đầu tiên ở nước Mỹ', 'Chào đời năm 1981, Elizabeth Carr - em bé thụ tinh ống nghiệm đầu tiên ở Mỹ - luôn nỗ lực sống chuẩn mực suốt 44 năm qua để xóa bỏ định kiến về phương pháp này. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7591758010902-c59406ff20941de-2155-7731-1773282846.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EvRg6g1Ns7JSi5xGeYGC3w', '2026-03-19', 'admin', 247, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312549183800_0', 'Thuốc giảm cân 173 USD về 54 USD - cuộc cách mạng giá từ Ấn Độ', 'Làn sóng thuốc giảm cân giá rẻ từ Ấn Độ đang tạo nên một cuộc cách mạng y tế trên toàn cầu song đặt ra những thách thức lớn về kiểm soát chất lượng và an toàn người dùng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/giam-can2-1773966197-177396623-9948-3102-1773966358.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W2a1vxNWq1ipx6Xc65LezA', '2026-03-20', 'admin', 204, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312566151900_1', 'Đũa kim loại 12 cm trong cổ họng người đàn ông suốt 8 năm', 'Các bác sĩ tại tỉnh Liêu Ninh phẫu thuật lấy thành công chiếc đũa kim loại dài 12 cm nằm sâu trong vòm miệng một người đàn ông suốt 8 năm sau khi bệnh nhân vô tình nuốt phải lúc đang ăn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/00-1773940108-1773940223-1317-1773940303.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5Jbnc7ojWtIgpa9aJp0PRQ', '2026-03-20', 'admin', 177, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312582327300_2', 'Bác sĩ cảnh báo ''bẫy tâm lý'' khiến nhiều người sập bẫy thuốc gia truyền giả', 'Bác sĩ Ngô Văn Tỵ, Khoa Ung Bướu thuộc Bệnh viện Đại học Y Hà Nội, vẫn chưa thôi ám ảnh khi nhắc lại ca trực vừa qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z4553627269963-2f6fc10ad7c154e-2394-3553-1773818309.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JHP6dnV6gDB7g0SuN0IfFw', '2026-03-20', 'admin', 264, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312598303000_3', 'Án tử rình rập từ thử thách ''ngất xỉu'' trên TikTok', 'Chị Lan, 42 tuổi, bần thần khi phát hiện trong lịch sử xem video của con trai lớp 8 là cảnh một đám trẻ đang reo hò quanh một nam sinh vừa đổ gục, co giật nhẹ trên sàn nhà. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/2-1773366911-8280-1773367913-1-4012-5941-1773619069.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=uPJ_bYzYnVJz4Nrj5NLfaw', '2026-03-20', 'admin', 177, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312614243600_4', 'Ăn nhiều protein có gây hại thận?', 'Dù một hệ thận khỏe mạnh bình thường có thể xử lý lượng protein cao, nhưng đối với người đã có tổn thương thận, việc nạp quá nhiều protein có thể tạo ra gánh nặng quá mức. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/13/screenshot-2026-03-13-at-17-49-5249-6493-1773399093.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8oIup1SXwJUBFSAV6sCjA', '2026-03-20', 'admin', 460, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312630701200_5', 'Hội chứng lão hóa sớm', 'Hội chứng lão hóa sớm là một bệnh di truyền ít gặp khiến cơ thể trẻ em lão hóa nhanh bất thường. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/15312219thg32026-1773909094-17-3502-8851-1773909116.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1ZViTDl5vGm76l27f6ueOA', '2026-03-20', 'admin', 344, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312647017200_6', 'Khám răng tình cờ phát hiện hẹp mạch máu não', 'Ông Tú, 66 tuổi, đi khám răng đo huyết áp lên đến 198/120 mmHg, nhập viện bác sĩ chẩn đoán mạch máu nuôi não hẹp nặng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/image001-1773969821-1773969840-9151-1773970140.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fXx1g4f8h2QLD3wA-sajjg', '2026-03-20', 'admin', 322, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312662814100_7', 'Tiêm botox có giúp giảm đau đầu mạn tính?', 'Tôi bị đau đầu gần như mỗi ngày, được chẩn đoán đau đầu mạn tính, dùng nhiều thuốc nhưng không giảm. Tiêm botox có giúp giảm đau đầu loại này? (Thanh Huyền, Cần Thơ) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/abc-1773970991-8969-1773971118-3274-4539-1773974532.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pKuq3CR1mT3CkkHqkFybXg', '2026-03-20', 'admin', 220, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312679293100_8', 'Viêm gan B mạn tính tiến triển ung thư', 'Ông Phi, 63 tuổi, viêm gan B mạn tính 10 năm sức khỏe ổn định nên không tái khám định kỳ, nay bác sĩ chẩn đoán ung thư gan giai đoạn sớm. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/hi-nh-thumb-1773971308-1773971-9835-9750-1773971433.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=yIc_kDHhvR_xD1pvP0VGhA', '2026-03-20', 'admin', 37, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312714608200_9', 'Xạ trị ung thư hạch bạch huyết như thế nào', 'Xạ trị ung thư hạch có thể được sử dụng đơn thuần hoặc kết hợp với hóa trị để tiêu diệt các tế bào u tại chỗ, giảm triệu chứng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/bs-loc-1773969177-1773969197-4790-1773969316.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hvcitarrhudIM5_CDo8IIQ', '2026-03-20', 'admin', 291, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312730436700_10', '7 thói quen làm tăng đường huyết buổi sáng', 'Mức đường huyết thường xuyên tăng vào buổi sáng có thể do nhiều nguyên nhân liên quan đến giấc ngủ, vận động, ăn uống vào đêm hôm trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-11-12-3935-2357-1773893572.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-FXnn5-oJXtAb5_GwQ-hpg', '2026-03-20', 'admin', 205, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312746121200_11', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-20', 'admin', 468, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312761922700_12', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-20', 'admin', 39, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312777486900_13', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-20', 'admin', 461, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312792883500_14', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-20', 'admin', 193, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312808327000_15', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-20', 'admin', 220, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312823371900_16', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-20', 'admin', 290, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312839086600_17', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-20', 'admin', 394, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312854769200_18', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-20', 'admin', 506, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312870565500_19', 'Thử thách giảm một cân mỡ đổi nửa cân thịt bò tại Trung Quốc', 'Hơn 2.400 người dân thành phố Vô Tích đăng ký tham gia thử thách giảm cân để quy đổi trọng lượng cơ thể sụt giảm thành các phần thịt bò, đuôi bò và lá sách. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/blujgsjcgkzgxov28r29h6slrhcdwp-3084-9216-1773851508.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cJByzTs2uf-iCO9WHvmVZw', '2026-03-20', 'admin', 193, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312885711100_20', 'Lòng trắng hay lòng đỏ trứng nhiều protein hơn?', 'Nhiều người cho rằng protein có ở lòng trắng trứng, còn lòng đỏ chủ yếu chứa chất béo song thực tế chất béo được phân bổ ở cả hai phần với tỷ lệ khá cân đối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/trungluoc-1773735015-177373503-3257-1653-1773735084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Fi6Q-5BdVlJjlX5EoICKfA', '2026-03-20', 'admin', 290, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312919272000_21', 'Bẫy ''giảm đau nhanh'' từ thuốc đông y dởm', 'Thuốc đông y pha trộn hóa chất cấm tạo ảo giác hết bệnh tức thời, khiến nhiều người bệnh mạn tính và ung thư bỏ phác đồ điều trị chuẩn mực, dẫn đến đánh mất cơ hội sống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/b68c2082-b007-4e31-b108-003eb5-2978-8056-1773807046.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6sFkX8ilu6LKEesyjWQFng', '2026-03-20', 'admin', 109, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312950139000_22', '6 bài tập đơn giản tại nhà giúp kéo dài tuổi thọ', 'Chìa khóa của sự trường thọ nằm ở những chuyển động bền bỉ như đi bộ, đi cầu thang, squat, chống đẩy, đứng một chân và plank ngay tại chính ngôi nhà của bạn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/screenshot-2026-03-16-at-11-02-9494-7835-1773633846.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pf_-i646or_CqCdVKZYybw', '2026-03-20', 'admin', 336, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312969750900_23', 'Chàng trai suýt mất tinh hoàn vì cố chịu đau qua đêm', 'Chủ quan chịu đựng cơn đau vùng kín qua đêm, chàng trai 20 tuổi suýt hoại tử tinh hoàn do xoắn hai vòng, may mắn được bác sĩ Bệnh viện Quân y 175 mổ cấp cứu giữ lại kịp thời. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/233a1322-1773798712-4369-1773798922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tW7TIb8iGl4-yKI-tUdxiQ', '2026-03-20', 'admin', 157, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3312987367500_24', '7 ''thủ phạm'' âm thầm khiến thận yếu đi', 'Ăn quá mặn, dùng thực phẩm chế biến sẵn, uống ít nước hoặc lạm dụng thuốc giảm đau có thể tăng áp lực lên thận theo thời gian. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/an-man-1773738708-1773738913-4727-1773738927.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NOq4Iuk7VwTI41RoRpSxfQ', '2026-03-20', 'admin', 425, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313002643700_25', 'Người gặp tai biến tử vong sau tiêm chủng có thể được bồi thường hơn 100 triệu đồng', 'Bộ Y tế đề xuất người gặp tai biến khi tiêm chủng thiệt hại tính mạng có thể được bồi thường 100 triệu đồng, phí mai táng bằng 10 lần mức lương cơ sở. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a7795-1754481674-1773899525-6921-8614-1773901922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fdofBhFGlUgbFwHFwI6a2w', '2026-03-20', 'admin', 164, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313019951700_26', 'Phát hiện mắc 2 loại ung thư từ triệu chứng vàng da', 'Người phụ nữ 59 tuổi vàng da, đau vùng hạ sườn kéo dài, đi khám được chẩn đoán mắc ung thư đại tràng và ung thư đường mật trong gan. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 105, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313035125700_27', 'Căn bệnh hiếm buộc bác sĩ chọn giải pháp ghép tạng domino', 'Từ dấu hiệu khó thở, các bác sĩ đã phát hiện ra căn bệnh hiếm nguy hiểm amyloidosis, giúp người đàn ông thoát cửa tử nhờ ghép đồng thời tim và gan thành công. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/img-8291-1773928219-1773928276-2399-1773928321.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GWtt0vlUJhMN1_b6wHCOVA', '2026-03-20', 'admin', 108, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313050628300_28', 'Dùng cà gai leo có giúp trị khỏi viêm gan B không?', 'Chồng tôi bị viêm gan B mạn tính, tôi tra cứu thông tin thấy dùng cà gai leo làm thuốc, giúp trị khỏi viêm gan B, có đúng không? (Đỗ Minh Hoa, 42 tuổi, Quảng Trị) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ca-gai-leo-1773916119-17739168-1342-4198-1773917298.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bkYSJaPU0S6ctMXtQqIOmw', '2026-03-20', 'admin', 414, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313065417100_29', 'Tán sỏi thận bằng ''đường hầm nhỏ'' qua da', 'Ông Đức, 66 tuổi, có viên sỏi san hô lớn ở thận trái, được bác sĩ dùng laser tán sạch sỏi qua da trong một lần. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/h2-1773912738-1773912762-9099-1773912790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=j38JjUzg5qR3qpK893tU5Q', '2026-03-20', 'admin', 157, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313080397500_30', 'Sẹo rỗ nặng do mụn', 'Chị Bình, 42 tuổi, nhiều sẹo rỗ sâu vùng mũi và má do nặn mụn, được bác sĩ điều trị tách đáy sẹo kết hợp vi kim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ba-c-tra-n-la-m-rf-1773906650-2435-6137-1773906761.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VkkZlz2OpWhquWYG-ewRA', '2026-03-20', 'admin', 11, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313096749400_31', 'Hệ thống trang thiết bị hiện đại tại Vinmec Ocean Park 2', 'Bệnh viện Đa khoa Quốc tế Vinmec Ocean Park 2 trang bị hàng loạt thiết bị y khoa tiên tiến như MRI 3.0, CT 512 lát cắt… đáp ứng nhu cầu khám chữa bệnh chuyên sâu với độ chính xác cao. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image1931552164extractword5out-975421-1773903823-1773913454.jpeg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BX_nsqPtleKJGP3xcwY0qQ', '2026-03-20', 'admin', 322, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313112712200_32', 'Tiểu đêm có phải do phì đại tuyến tiền liệt?', 'Ban đêm tôi thường đi tiểu 2-3 lần, khó tiểu, mệt mỏi. Có phải do phì đại tuyến tiền liệt không, điều trị thế nào? (Trọng Nghĩa, 55 tuổi, Đồng Nai) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/tah-8555-1-1773896092-17738961-3027-5635-1773896195.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5K75bH4lGA_9Lm7oZQauVA', '2026-03-20', 'admin', 110, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313127835000_33', '4 phương pháp điều trị rò hậu môn', 'Người bị rò hậu môn sau áp xe có thể được bác sĩ chỉ định mổ nội soi, điều trị tia laser hoặc keo sinh học. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/bs-luong-1773839125-1773839198-1501-1773839265.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mMANsiAEDnEcOmbLkYviAA', '2026-03-20', 'admin', 63, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313142492900_34', '5 khoáng chất cần thiết cho sức khỏe sinh lý nam', 'Kẽm, magie, kali, canxi, sắt tham gia vào quá trình sản xuất testosterone, duy trì sinh lý và sức khỏe nam giới. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773905181-1773905199-4800-1773905250.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=J7FYYReSZWjbjDl8OJm-8w', '2026-03-20', 'admin', 15, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313157889000_35', 'Những thói quen mỗi ngày giúp trẻ phát triển trí tuệ', 'Trẻ nên ngủ trước 22h, ăn sáng đầy đủ dinh dưỡng, duy trì thói quen đọc sách và tập thể dục mỗi ngày để phát triển trí não. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/93833d0df43141139173df329820a4-6130-7273-1773895766.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zoshz-NkGeLp3SvTGUEs5g', '2026-03-20', 'admin', 232, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313173109200_36', 'Dấu hiệu nhận biết bệnh về mắt', 'Thay đổi màu sắc mống mắt, hai mắt không thẳng hàng hoặc khó tập trung nhìn các vật ở gần hay xa có thể cảnh báo các vấn đề về mắt. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/momat3-1773892193-1773892202-3927-1773892212.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fX-6NRS3Zsww7n9bh7yqcg', '2026-03-20', 'admin', 391, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313187769100_37', '5 nhóm người nên hạn chế uống nước dừa', 'Người mắc tiểu đường, bệnh thận, đang dùng thuốc huyết áp hoặc có rối loạn điện giải nên hạn chế uống nước dừa để tránh ảnh hưởng sức khỏe. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/28b42ae376a74e37a5c7c694a5c3c4-1939-2018-1773891857.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=W03cZYxS8Wc_2LuiG6kP6w', '2026-03-20', 'admin', 430, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313202707500_38', 'Ba lần mắc zona thần kinh trong hai năm', 'Bà Dung, 62 tuổi, liên tiếp mắc zona thần kinh ở vùng lưng trong hai năm, lần sau nặng hơn lần trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/vnvc-zona-than-kinh-tai-phat-1-6377-2082-1773903517.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ot_zkYHKjIvfaOFuy5poIQ', '2026-03-20', 'admin', 94, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313217984900_39', '6 món chứa tinh bột người tiểu đường nên ăn', 'Thực phẩm giàu tinh bột phức hợp như yến mạch, ngũ cốc nguyên hạt, khoai lang giúp ổn định đường huyết và cung cấp năng lượng lâu dài cho cơ thể. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/Buoc-2-3355-1645172245-1773889121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ApfUYyAeH9YX9pzCl6WWCw', '2026-03-20', 'admin', 218, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313233335300_40', 'Tại sao lupus ban đỏ không thể chữa khỏi?', 'Bác sĩ chẩn đoán tôi mắc lupus ban đỏ. Bệnh nguy hiểm thế nào và tại sao không thể chữa khỏi hoàn toàn? (Nguyễn Dũng, Tiền Giang) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/taan08791-1773896320-177389644-1957-7425-1773897084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=a1vP8v6gMEZpjdw3KcbJiQ', '2026-03-20', 'admin', 491, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313248480700_41', 'Ăn mặn gây rối loạn tiền đình nặng hơn?', 'Tôi bị rối loạn tiền đình ngoại biên, được khuyên kiêng muối vì có thể làm bệnh nặng hơn, đúng không? (Lâm Phạm, 55 tuổi, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/a-nh-1773888613-1773888648-2147-1773888710.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u8tyXq22msAo0zpUDa0uew', '2026-03-20', 'admin', 59, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313263888200_42', 'Khó thở khi nằm cảnh báo bệnh gì?', 'Tôi thường cảm thấy khó thở khi nằm xuống, có liên quan đến bệnh hô hấp không? (Nguyễn Ngân, Hà Nội) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773887515-1773887563-7123-1773887636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=olNppiTaFzjv5NtxhAoN8w', '2026-03-20', 'admin', 160, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313279339000_43', 'Dùng sóng xung kích phá vôi hóa mạch vành', 'Bà Năm, 86 tuổi, đau ngực do động mạch vành hẹp tắc, được bác sĩ phá mảng vôi hóa bằng sóng xung kích ngăn nguy cơ nhồi máu cơ tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881685-1773881714-3499-2887-1773881937.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8a1D0rK_oLWWS9diLy28Bw', '2026-03-20', 'admin', 13, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313295422300_44', 'Cắt toàn bộ tuyến giáp chặn ung thư', 'Bà Loan, 50 tuổi, khám sức khỏe định kỳ phát hiện nhân giáp, sinh thiết lạnh xác định ung thư xâm lấn phải cắt toàn bộ tuyến giáp. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881289-1773881336-2586-1773881408.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yXQBUpD-Igp8_EDS1wUVEA', '2026-03-20', 'admin', 275, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313312979800_45', 'Suy buồng trứng ở tuổi 24', 'Chị gái bị vô sinh nên Hồng, 24 tuổi, chủ động đi khám sức khỏe sinh sản bất ngờ phát hiện buồng trứng gần cạn kiệt như phụ nữ mãn kinh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/key1103-3-1773817056-177381708-3143-7860-1773819558.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=CavEu2B_enyj5OEFH8VNdQ', '2026-03-20', 'admin', 465, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313328868800_46', 'Kỳ tích 90 ngày giữ song thai ''dọa'' sinh cực non', 'Chị Nhung, 33 tuổi, mang song thai 24 tuần dự báo nguy cơ 90% sinh non, được bác sĩ liên khoa phối hợp giữ thai thêm ba tháng đến khi sinh an toàn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881134-4834-1773881170.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1XDOjAjAXRUGNSkmDiyA0A', '2026-03-20', 'admin', 208, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313344914800_47', 'Trẻ bị lông mi mọc ngược có nguy hiểm?', 'Con tôi 5 tuổi, bị lông mi mọc ngược đâm vào mắt gây khó chịu, thường xuyên đỏ mắt. Tình trạng này có nguy hiểm và điều trị thế nào? (Trân, 31 tuổi, Long An) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/lo-ng-mi-mo-c-ngu-o-c-17738488-3850-2423-1773874352.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7CL5Pqz10iYGl92EJWXj0w', '2026-03-20', 'admin', 47, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313361476900_48', 'Cơn đau đầu cảnh báo sớm đột quỵ', 'Cơn đau đầu kéo dài, lúc âm ỉ, lúc dữ dội nhưng thoáng qua vài phút rồi biến mất có thể là dấu hiệu sớm đột quỵ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z7615389058820-b770c8502777a2a-3606-1286-1773839001.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DtpN1a4Sw8ZgN4_ZUIXC2Q', '2026-03-20', 'admin', 58, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313410334000_49', 'Ăn uống, dùng thuốc thế nào sau cắt toàn bộ tuyến giáp?', 'Tôi đã cắt toàn bộ tuyến giáp triệt căn ung thư, phải dùng hormone thay thế. Ăn uống thế nào, lưu ý gì để không ảnh hưởng hấp thu thuốc? (Quốc Bảo, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/a-nh-1-1773838561-1773838575-1902-1773838656.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KiTXzuR-XhOYEsReCOHtGQ', '2026-03-20', 'admin', 477, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313435544400_50', 'Ngủ đủ giấc - cách đơn giản bảo vệ trái tim', 'Ngủ đủ giấc hỗ trợ kiểm soát huyết áp, giảm viêm, tinh thần sảng khoái, từ đó tăng cường sức khỏe tim mạch. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/86262b59886c421faa325d79d43c42-3285-5331-1773807728.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=z2yoNwuRifB21tkyO55TgA', '2026-03-20', 'admin', 367, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313455934200_51', 'Ba thói quen ít ngờ có thể gây hại não', 'Ít tiếp xúc xã hội, sống ở nơi thiếu ánh sáng và nghe nhạc to lâu dài có thể ảnh hưởng tâm trạng, trí nhớ và sức khỏe não bộ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/geminigeneratedimage4gdeoq4gde-2334-2556-1773805576.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=6L8vpW0eIwiwb9yhfgyJEQ', '2026-03-20', 'admin', 195, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313475121100_52', 'Bé gái tử vong sau 9 giờ phát bệnh nghi do não mô cầu', 'Bé gái 10 tuổi tại Phú Quốc sốt, đau đầu, nổi ban, tím tái, khó thở, vào viện cấp cứu song không qua khỏi, nghi mắc viêm não mô cầu. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 203, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313493635700_53', 'Hai bác sĩ ép tim cứu người ngừng thở giữa sân bóng chuyền', 'Bác sĩ Trần Văn Biên và Nguyễn Cao Việt ép tim cứu sống người đàn ông 64 tuổi ngừng tuần hoàn, ngã quỵ giữa sân khi đang đánh bóng chuyền hơi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/eptim-1773824056-9512-1773824095.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=zKbi8S68AXzNCvOi1chXQw&t=image', '2026-03-20', 'admin', 22, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313510057300_54', 'Thử thách ''nằm một chỗ'' nhận tiền gây sốt tại Thượng Hải', 'Thí sinh tham gia thử thách ngủ được yêu cầu nằm một chỗ trong 24 giờ, không đi vệ sinh, không dùng điện thoại, máy tính để có cơ hội nhận tiền mặt cùng nhiều gói nghỉ dưỡng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/ngu-1773821005-1773821075-3441-1773821874.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8KlVBUvBMqmynOHVIVlLoA', '2026-03-20', 'admin', 139, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313525511700_55', 'Bác sĩ chỉ ra cách ăn uống giúp kéo dài tuổi thọ', 'Silvio Garattini, nhà dược học nổi tiếng người Italy, nhận định việc tiêu thụ ít thực phẩm có thể là chìa khóa để thêm nhiều năm sống khỏe mạnh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-17-at-14-42-3188-8472-1773733487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WtNm6z8rhaEufjF1U9dIpg', '2026-03-20', 'admin', 505, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313542564400_56', 'Hàng chục nghìn ca lao bị bỏ sót, TP HCM mở chiến dịch 100 ngày', 'TP HCM khởi động chiến dịch 100 ngày tầm soát lao chủ động bằng X-quang tích hợp AI cho 30.000 người dân có nguy cơ cao, trước tình trạng hàng chục nghìn ca bệnh bị bỏ sót. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/xn-be-nh-lao-1773813681-177381-6084-5180-1773814033.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=dhP9C3bqRRjz-Y8bvoWDCg', '2026-03-20', 'admin', 365, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313558151600_57', 'Trung Quốc chế tạo thiết bị bảo quản nội tạng hiến tặng trong nhiều ngày', 'Các nhà khoa học Trung Quốc vừa phát triển thành công hệ thống tưới máu máy đa nhiệt độ, giúp kéo dài thời gian bảo tồn nội tạng hiến tặng từ vài giờ lên nhiều ngày. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/1-1773810584-1773810598-6921-1773811859.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Mn8_w1WS1t3d0f_fsjsllg', '2026-03-20', 'admin', 226, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313573845300_58', 'Bắt bạn đời tránh thai, triệt sản vì định kiến giới sẽ bị phạt 12 triệu đồng', 'Từ ngày 1/5, cơ quan chức năng phạt tiền 10-12 triệu đồng đối với người ép buộc vợ hoặc chồng sử dụng biện pháp tránh thai, triệt sản với lý do định kiến giới. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 271, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3313589986500_59', 'Uống nước chanh trị gout?', 'Nhiều người truyền tai nhau uống nước chanh tươi giúp rửa bớt acid uric, có thể dùng thay thuốc điều trị gout, điều này có đúng? (Tuấn, 32 tuổi, Hà Nội). (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/c15c6f48-ced4-4429-bfb5-9455cd-5801-6593-1773760546.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=W_kjheUzq2C2ME6zHgDgBg', '2026-03-20', 'admin', 108, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314799309000_0', 'Làm giàu nhờ nghề mặc cả giá ôtô', 'Tomi Mikula kiếm 200.000 USD mỗi tháng nhờ dịch vụ đàm phán giá ôtô, giúp người mua tránh được các bẫy phụ phí từ đại lý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-5910-1846-1773937191.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=GyihZcdPr2Sfk_6yWjP9lw', '2026-03-20', 'admin', 371, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314815059400_1', 'Viện dưỡng lão đầu tiên trên thế giới vận hành bằng robot', 'Trạm dưỡng lão tại phố Vinh Hoa, Bắc Kinh trang bị 43 loại robot từ massage, châm cứu đến pha trà, nâng cao chất lượng sống cho người cao tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-8312-6385-1773934900.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VfFn7buTa9TsExFyHzR6g', '2026-03-20', 'admin', 92, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314829605900_2', 'Người trẻ đu trend ''gặp lại mình 10 năm trước''', 'Làm video đối thoại với mình 10 năm trước, nhiều người trẻ muốn nhìn lại hành trình trưởng thành, tự chữa lành tổn thương và định hướng tương lai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/10nam2-1773913137-3708-1773913342.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SmWlJhXMhpeoM7Fve9avQw', '2026-03-20', 'admin', 287, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314845047100_3', 'Cuộc sống bế tắc vì thiếu gas của người Ấn Độ', 'Xếp hàng bốn ngày không đổi được bình gas để nấu ăn, hàng triệu gia đình Ấn Độ đang lao đao vì chuỗi cung ứng năng lượng đứt gãy. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-15-4-3817-9609-1773910903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=TesnxCAAkCHU4m5yGF1yCQ', '2026-03-20', 'admin', 145, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314860813000_4', 'Vì sao nhiều người không quên được tình cũ?', 'Dưới lăng kính tâm lý học, việc chúng ta không ngừng tiếc nuối và lý tưởng hóa người yêu cũ thực chất chỉ là một "cú lừa" của não bộ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/nguoi-cu-1773906295-1773906318-6293-1773906415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=HVjiPxxd9gacVL6Y22uXqA', '2026-03-20', 'admin', 332, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314875899300_5', 'Bi kịch của nữ giám đốc lộ chuyện ngoại tình ở đêm nhạc', 'Từng là tâm điểm chỉ trích vì nụ hôn vụng trộm với sếp, cựu giám đốc Kristin Cabot lần đầu lên tiếng về bi kịch mất trắng sự nghiệp và tiêu chuẩn kép của dư luận. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-3953-9787-1773905123.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SnVW0ZXwG0D0cs-jv11r5w', '2026-03-20', 'admin', 159, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314891261700_6', 'Lợi ích bất ngờ của người thấp bé', 'Khác với lầm tưởng cao lớn đồng nghĩa với khỏe mạnh, người có vóc dáng khiêm tốn thực chất lại ít mắc ung thư, hiếm khi gãy xương và có xu hướng sống thọ hơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-16-1-3564-4232-1773826547.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WILYrMZI2_N_0dlS2haaeA', '2026-03-20', 'admin', 372, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314907103500_7', 'Bi kịch của những tình yêu AI', 'Tối 13/2, SkeweredKebab (nickname) đọc lại toàn bộ những cuộc hội thoại với ChatGPT để làm lễ tiễn biệt "người chồng AI" vừa bị khai tử. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-15-5-6470-2528-1773825011.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hywduvy6fBWG60Hqv4b41Q', '2026-03-20', 'admin', 162, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314922439800_8', 'Gia đình ''siêu nhân Gao'' ở Hưng Yên gây bão mạng', 'Giữ trọn đam mê siêu nhân từ nhỏ, anh Ngọc Trung sắm trang phục siêu nhân Gao rủ vợ hóa trang, sáng tạo loạt video hài hước mang lại tiếng cười cho cộng đồng. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7606213086839-ba7d4f64bbbc508-7613-9150-1773319405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mrTZfGPqSl0KOJOxGL3Etw', '2026-03-20', 'admin', 240, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314938150900_9', 'Vụ ly hôn tỷ USD và góc khuất đời tư của chủ tịch tập đoàn SK', 'Cuộc chiến pháp lý giữa Chủ tịch tập đoàn SK Chey Tae-won và vợ cũ Roh Soh-yeong gây chấn động bởi khối tài sản khổng lồ và sự xuất hiện của "người thứ ba". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/00-1773805459-1773805465-7488-1773807993.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ma9jNQK-Y2L9EYbGcAWU3Q', '2026-03-20', 'admin', 159, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314953716600_10', 'Nhà hàng đập 600 bộ bát đĩa vì khách cho chó lên bàn ăn', 'Ông Giang, quản lý nhà hàng tại Thương Khâu (Hà Nam), đã đập bỏ 600 bộ bát đĩa và đóng cửa khử trùng quán khi phát hiện một thực khách mang chó lên bàn ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/pet-restaurant-2-1773823218-17-3022-8308-1773823607.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YJaopzEQ_wQcv0LriogkfQ', '2026-03-20', 'admin', 397, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314968898500_11', 'Nạn trộm cắp ở khu nhà giàu Mỹ', 'Từng là chốn an cư bình yên của giới tinh hoa, khu Sharon Heights (vùng vịnh San Francisco) giờ chìm trong bất an khi kẻ gian liều lĩnh đột nhập ngay lúc gia chủ đang ăn tối. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/ratio3x2-960-1773806447-177380-5965-1359-1773809180.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=XY--0saGjRWJfVzM5zTLrQ', '2026-03-20', 'admin', 55, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314984485800_12', 'Làn sóng ''nhân lực tinh hoa'' rời bỏ Israel', 'Từng coi Tel Aviv là "thiên đường công nghệ", kỹ sư Elizabeth Cohen quyết định rời đi vì không muốn sinh con giữa những tiếng còi báo động tên lửa. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-17-at-23-3-7325-4333-1773766923.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KazThb0Myl6qlnll2uVyPg', '2026-03-20', 'admin', 405, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3314999507100_13', 'Cách tự học tiếng Anh của ''cô giáo nhí'' 9 tuổi', 'Từ trò chơi đóng vai cô giáo mỗi tối, bé Vân Anh khiến cộng đồng mạng bất ngờ bởi khả năng nói tiếng Anh trôi chảy và cách dạy em đầy kiên nhẫn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/va-n-anh-2-1773661730-17736617-3169-1895-1773662279.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MFZagmWNCjA_dg4MlTV1-g', '2026-03-20', 'admin', 299, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315014960300_14', 'Phát tài nhờ tờ giấy bỏ quên 30 năm', 'Đang phải sống chật vật với lương hưu eo hẹp, vợ chồng ông Sato bất ngờ thu về 68 triệu yen nhờ tìm thấy tờ biên lai mua cổ phiếu, bị bỏ quên 30 năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/co-phieu-2-jpeg-1773797809-177-3785-6774-1773797902.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T-SETu0hLWUdD-lr9bNEBQ', '2026-03-20', 'admin', 506, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315030497700_15', 'Bi kịch của thế hệ ''kiếm nhiều tiền nhưng không giàu''', 'Thu nhập 450.000 USD mỗi năm nhưng vợ chồng Alex vẫn phải ở nhà thuê, chưa trả hết nợ sinh viên và nơm nớp lo sợ thiếu tiền giữa lòng New York đắt đỏ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-00-3-6865-5413-1773770804.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICLidWfdmD2K6KISqPINoQ', '2026-03-20', 'admin', 273, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315070211700_16', 'Hai chuyến đi Việt Nam ''cứu rỗi'' người phụ nữ Mỹ', 'Rơi vào trầm cảm sau khi mẹ qua đời, Lilly Hubbard quyết định quay lại Việt Nam và tìm thấy sự "chữa lành" từ tình người ấm áp ở vùng đất xa lạ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/lilly-2-1773802709-1773802742-4016-1773802752.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5uQdZnsKta3M8vRTp6nZhA', '2026-03-20', 'admin', 209, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315098451500_17', 'Vì sao quần áo thể thao giặt xong vẫn hôi?', 'Ném ngay đồ tập đẫm mồ hôi vào máy giặt, dùng nhiều xà phòng hay nước xả vải là sai lầm khiến quần áo luôn bốc mùi khó chịu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/a-nh-ma-n-hi-nh-2026-03-16-lu-7904-9038-1773736876.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KXY2uWiUcoSsOpLDwHycOA', '2026-03-20', 'admin', 464, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315124340700_18', 'Bên trong nhà lắp ghép 30 m2 của tỷ phú Elon Musk', 'Mặc dù sở hữu hàng trăm tỷ USD, tỷ phú Elon Musk hiện sống trong căn nhà lắp ghép rộng 30 m2, thiếu tiện nghi đến mức mẹ ông phải ngủ ở gara. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/577333596-3394143064076672-485-6636-3102-1773724581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=b5eyN5ibANA-m59NlkHsAQ', '2026-03-20', 'admin', 329, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315139872300_19', 'Vợ cho ''thuê'' chồng', 'Phát hiện chồng ngoại tình, cô Khun Kwang ra thỏa thuận cho nhân tình của anh thuê chồng với giá 30.000 bath mỗi tháng, tuy nhiên hợp đồng này bị luật sư cảnh báo vô hiệu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/chatgpt-image-11-27-42-17-thg-9377-7480-1773721720.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NBqR-Rw-evtAbpk1qTmaKQ', '2026-03-20', 'admin', 98, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315154962600_20', 'Vì sao nhà chung cư ở Mỹ ngày càng ít?', 'Từng là lựa chọn an cư giá rẻ cho người trẻ Mỹ, số lượng chung cư thương mại sụt giảm mạnh do rào cản pháp lý, thuế và chi phí bảo hiểm tăng vọt. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/im-92913950-1773654144-1773671-8010-8091-1773672308.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Bm4Dwf779JQ1G3-LVfRR1w', '2026-03-20', 'admin', 309, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315170052000_21', 'Vợ 50 tuổi làm IVF chiều chồng trẻ', 'Bất chấp những đàm tiếu của dư luận, bà Pilli Cortese vẫn quyết định thụ tinh nhân tạo ở tuổi 50 để thỏa ước nguyện làm cha của người chồng kém 21 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5921-9658-1773633940.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9Zuubwaaw2BqQmbUtn07fA', '2026-03-20', 'admin', 200, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315185294900_22', 'Bẫy thổi phồng chức danh khi tuyển dụng', 'Nhiều doanh nghiệp đang gán mác "giám đốc", "trưởng phòng" cho người lao động nhưng chỉ trả mức lương nhân viên nhằm thu hút ứng viên và tối ưu chi phí. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/tuyen-dung-jpeg-1773679492-177-2056-8763-1773681102.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KigiyGPtR51yLB_8Hefyxg', '2026-03-20', 'admin', 471, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315201409000_23', 'Dân công sở Mỹ bỏ ôtô, đạp xe, làm từ xa để né ''bão'' giá', 'Thấy giá nhiên liệu tăng vọt, Boris Kagarlitskiy quyết định cất chiếc Lexus ở nhà, lôi xe đạp cũ ra lau chùi để bắt đầu chuỗi ngày đi làm bằng sức người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/dap-xe-1773678268-1773678292-1-1377-3127-1773678449.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=w-sPfSoia-AE5rGBtpoj4Q', '2026-03-20', 'admin', 479, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315220698100_24', 'Nhan Phúc Vinh, Hà Thu tập chống đuối nước cùng 1.000 học sinh', 'Diễn viên Nhan Phúc Vinh, Á hậu Hà Thu cùng hơn 1.000 học sinh nhận biết mực nước an toàn, kỹ năng thở nước, tại workshop chống đuối nước, sáng 16/3. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/dsc04354-1773740071-8030-17737-9004-8642-1773765903.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A4JrUo23I3KsRgZmF6I4Lg', '2026-03-20', 'admin', 503, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315237532700_25', '3 bước đánh lừa não bộ để ngủ nhanh hơn', 'Kỹ thuật "xáo trộn nhận thức" giúp ngắt quãng dòng suy nghĩ lo âu, mô phỏng trạng thái mơ màng tự nhiên để não bộ thư giãn và dễ dàng chìm vào giấc ngủ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/z7591758010902-c59406ff20941de-5096-4651-1773652579.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xQChxkieWCwZeML9fYn7Gg', '2026-03-20', 'admin', 23, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315253265300_26', 'Yêu 6 năm mới biết bạn gái đã có chồng con', 'Chi hơn một triệu tệ cho bạn gái trong 6 năm mặn nồng, anh Wang bàng hoàng phát hiện người yêu thực chất đã yên bề gia thất, thậm chí các con đã học cấp hai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5017-9753-1773636339.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LRn0uHe2LxkLnmac08jIuw', '2026-03-20', 'admin', 103, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315268416300_27', 'Nhiều nông dân Mỹ có nguy cơ phá sản vì xung đột Trung Đông', 'Xung đột tại Trung Đông đẩy giá nhiên liệu và phân bón lên mức kỷ lục, giáng đòn mạnh vào hàng loạt trang trại, đẩy họ vào cảnh phá sản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-13-at-22-1-6679-9104-1773417216.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wNZTd6jP3YfT0zCvXMAvYg', '2026-03-20', 'admin', 468, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315283662800_28', 'Khủng hoảng xăng dầu ''bóp nghẹt'' người nghèo châu Á', 'Xung đột ở Trung Đông gây đứt gãy nguồn cung nhiên liệu, đẩy hàng chục triệu người lao động tại châu Á vào cảnh thiếu xăng, khí đốt và sụt giảm thu nhập. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/a-nh-ma-n-hi-nh-2026-03-16-lu-7437-9899-1773631014.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pswj5Qok0ZT1EUC6gyBi6g', '2026-03-20', 'admin', 138, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315298797300_29', 'Tụ tập - quy tắc giữ gìn tình bạn của người Đức', 'Cuộc sống bận rộn khiến nhiều mối quan hệ phai nhạt nhưng người Đức áp dụng quy tắc "Stammtisch" - những cuộc tụ họp định kỳ, đơn giản nhưng hiệu quả. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/stammtisch-2-1773625060-177362-4038-7784-1773625553.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lkewTZzZ2noESjRQobw1iA', '2026-03-20', 'admin', 182, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315313594400_30', 'Chàng trai Canada ''bẻ lái cuộc đời'' vì tình yêu với cô gái Việt', 'Ngay buổi hẹn đầu dưới chân tháp Tokyo, Thu Thủy đưa ra loạt tiêu chuẩn khắt khe về bạn trai, rồi dội gáo nước lạnh vào Seiwa: “Em không muốn gặp lại anh nữa”. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/img-1831-1-jpeg-1773460527-177-7354-6141-1773461950.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mt3pi6U16KHThn4v8-hOBA', '2026-03-20', 'admin', 58, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315328709300_31', 'Ước mơ của người vợ 10 năm giữ món quà chồng chưa kịp tặng', 'Cất kỹ chiếc váy và chú gấu bông chồng mua tặng trước khi tử nạn, chị Thúy mong một ngày được trao lại cho con gái trong sự kiện trọng đại nhất đời. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/z7619839331948-d5148baa4b6833d-6407-2821-1773504440.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RytXItajr9SLpO3H0LRM4Q', '2026-03-20', 'admin', 498, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315343970500_32', 'Cuộc đoàn tụ gượng gạo của cô gái bị vứt ở nhà vệ sinh 28 năm trước', 'Bị ông nội vứt bỏ từ lúc 2 ngày tuổi, Hong Yangli vượt nửa vòng trái đất về nhận mẹ nhưng đối diện màn đoàn tụ lạnh lẽo, dấy lên nhiều tranh cãi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/1-3-1773547826-1773547843-5092-1773548222.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=amEJ_VUF9IpG9eD0G9_PNg', '2026-03-20', 'admin', 38, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315359718500_33', 'Cụ bà 82 tuổi bị lừa kết hôn bằng 20 quả trứng', 'Cụ bà mù chữ 82 tuổi ở Hồ Nam tưởng làm giấy tờ để nhận trợ cấp 1.000 tệ và 20 quả trứng, không ngờ bị lừa ký giấy đăng ký kết hôn với người đàn ông 47 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/00-1773543821-1773543868-7185-1773543919.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KfEnT7aoLQ3RSBsN1-oYAw', '2026-03-20', 'admin', 143, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315375098400_34', 'Người đàn ông bị hàng loạt nhà tang lễ từ chối vì béo', 'Ở Canada, béo phì không chỉ là một bài toán khó về sức khỏe khi còn sống, mà nay lại biến thành "rào cản cuối cùng" sau khi chết. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/0-1-1773549860-1773549866-3805-1773550180.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vVbCv37mEQDizIgnTBFi5g', '2026-03-20', 'admin', 486, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315390334100_35', 'Suýt mất mạng, cặp vợ chồng hối hận vì ''bỏ phố về rừng''', 'Từng ảo tưởng về sự tuyệt vời của cuộc sống biệt lập giữa thiên nhiên, vợ chồng Jayme bừng tỉnh sau sự cố suýt mất mạng ngày sinh nở, nhận ra cái giá của sự cô độc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773464228-1773464933-3946-1773464939.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oyCVWVQKOW3_wjd1YLbydQ', '2026-03-20', 'admin', 308, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315405856800_36', 'Đường đến giải bơi trong hồ băng của cậu bé Hà Nội', 'Trên đỉnh núi tuyết ở Neuhermsdorf, Phan Anh mặc quần bơi đứng lặng nhìn mặt hồ Altes Zollhaus bốc khói trong khi ban tổ chức luôn tay vớt những tảng băng cản đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/phan-anh-1-1773221913-4040-177-8906-6797-1773503423.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tRJ-e86PBimTvuLx8uLrLQ', '2026-03-20', 'admin', 56, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315421205200_37', 'Đánh cược mạng sống mưu sinh trong vùng chiến sự', 'Mỗi khi tiếng còi báo động vang lên, nữ giúp việc Joycee Pelayo chạy vội đến cụ ông mà cô đang chăm sóc, dìu ông lên xe lăn rồi đẩy thật nhanh xuống hầm trú ẩn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773484138-1773484220-8888-1773484945.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SXxzNvSvE4dKP7MSqygIxA', '2026-03-20', 'admin', 197, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315436482900_38', 'Người Lạng Sơn chi hàng trăm triệu làm cỗ mời khách lạ', 'Để tán lộc và cầu may, người dân Lạng Sơn chi hàng trăm triệu đồng dựng rạp, thết đãi cỗ miễn phí cho cả khách lạ về dự hội đền Kỳ Cùng - Tả Phủ đầu năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/6-2-1773501948-1773502444-9849-1958-9924-1773505959.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0x9NpYpx7nxQjaqa-_PsZg', '2026-03-20', 'admin', 250, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315451626300_39', 'Gần 3.000 runner chạy giữa đô thị lớn nhất Nghệ An', 'Gần 3.000 vận động viên dự giải Eco Central Park Marathon lần đầu tổ chức với cung đường xuyên qua công viên và các thảm hoa trong khu đô thị. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/kbd03827-1773548789-1773549037-3771-1773551974.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0E-9mGgNroDH6ojqizG9w', '2026-03-20', 'admin', 475, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315466980300_40', 'Thường xuyên bị nhầm là con vì kém vợ 23 tuổi', 'Bất chấp khoảng cách 23 tuổi và hay bị nhầm là mẹ con, cặp đôi Azmirullah (28 tuổi) và Wan Nazihah (51 tuổi) vẫn có cuộc sống viên mãn sau gần 7 năm kết hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-5511-1481-1773391224.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rVhmD8KwmfMyFVajva3Fg', '2026-03-20', 'admin', 507, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315481204200_41', 'Cả nhà bới 10 tấn rác tìm túi vàng', 'Gia đình 8 người ở Giang Tây phải thức trắng đêm, lục tung 10 tấn rác để tìm lại túi vàng trị giá 1,5 triệu tệ (5,2 tỷ đồng) bị người nhà vứt nhầm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/chatgpt-image-12-00-22-14-thg-6372-9837-1773467256.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=_9x4DRlTKFjkiC60B2o8FA', '2026-03-20', 'admin', 193, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315496140100_42', 'Vì sao không cần ''ra khỏi phòng là tắt đèn''?', 'Lời khuyên "ra khỏi phòng là tắt đèn" đã lỗi thời trong kỷ nguyên bóng đèn LED, nhưng vẫn áp dụng đúng quy tắc 15 phút với đèn huỳnh quang. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/1-1773454941-1773455346-9660-1773455690.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bdkGsflc9Jxr6O6pwJzT-A', '2026-03-20', 'admin', 354, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315511222500_43', 'Những cuộc hôn nhân tan vỡ vì trúng độc đắc', 'Trúng thưởng hàng chục triệu USD, nhiều cặp vợ chồng ngỡ đã chạm tay vào hạnh phúc viên mãn nhưng cuối cùng lại rơi vào cảnh ngoại tình, kiện tụng và ly hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/screen-shot-2026-03-14-at-00-3-2966-9237-1773423562.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zp535HhmTaj7GmpNZEZnIw', '2026-03-20', 'admin', 147, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315550939500_44', 'Dubai vắng vẻ ''chưa từng thấy''', 'Dưới sức ép từ các đợt tấn công của Iran, người nước ngoài đang vội vã rời khỏi Dubai, đẩy "thành phố vàng" vào cảnh vắng lặng như thị trấn ma. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/untitled-1773453416-1773453692-9708-1773453849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vbalNxj_XueEp65nAOLXcA', '2026-03-20', 'admin', 326, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315583119300_45', 'Chàng trai không tay và những món ăn ''triệu view''', 'Mất đôi tay sau tai nạn, Trọng Định, 23 tuổi, học cách nấu ăn bằng chân và hai mỏm cụt, biến nỗi đau thành nghị lực sống truyền cảm hứng cho hàng triệu người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/di-nh-di-cho-1773409298-177340-4382-8632-1773422430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0DityHvFbLGR7izILlXGOQ', '2026-03-20', 'admin', 63, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315601563400_46', 'Dùng AI tạo ''chuyên gia giả'' để trị thói giục cưới của cha mẹ', 'Mệt mỏi vì bị cha mẹ liên tục giục lấy chồng, Cao Mei, 38 tuổi, dùng AI tạo ra một "chuyên gia tâm lý" để giảng đạo lý, thuyết phục ngược lại phụ huynh. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/0-1773398662-1773398682-1718-1773399208.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EVMDlFbSybo3mN85hxNoWg', '2026-03-20', 'admin', 321, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315619714200_47', 'Đổ xô mua nhà thờ cũ làm nhà ở', 'Giữa "bão" giá bất động sản, nhiều người chọn mua các nhà thờ cũ với giá rẻ để cải tạo thành không gian sống độc đáo. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/a-nh-ma-n-hi-nh-2026-03-13-lu-3696-4834-1773377205.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SH7Rb4ILOv0ksxLF-wv1NQ', '2026-03-20', 'admin', 162, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315634958300_48', 'Hơn 2.000 người mua vé sớm dự lễ hội ẩm thực Saigontourist 2026', 'Hàng nghìn vé sớm được bán trước thềm Lễ hội Văn hóa Ẩm thực Saigontourist 2026, hút 2.000 lượt đặt mua sau 10 ngày. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/kho-ng-khi-nga-p-tra-n-ma-u-sa-5727-7837-1773461994.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0g7XJzZGG1R1YRikkMMY9g', '2026-03-20', 'admin', 435, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315649950200_49', 'Trẻ học được gì từ việc cha rửa bát?', 'Sự phân công việc nhà giữa cha và mẹ là "bản thiết kế" cho hành vi xã hội của trẻ, liên quan trực tiếp đến nguy cơ bạo lực học đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-2254-8889-1773393096.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s6Oxd_5Gu1oXQ46K_G7Dug', '2026-03-20', 'admin', 374, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315666113400_50', '20.000 thuyền viên kẹt gần Hormuz nguy cơ thiếu nhu yếu phẩm', 'Gần 20.000 thủy thủ mắc kẹt trên các tàu hàng ở eo biển Hormuz đang đối mặt với nỗi lo tên lửa rơi trúng và tình trạng cạn kiệt nhu yếu phẩm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/tau-dau-1773402850-1773402875-3232-1773403067.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NTSnOJHpgEet9waOtHY1dw', '2026-03-20', 'admin', 93, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315686574900_51', 'Quy tắc ''muối tách, đường giữ'' trong nấu ăn', 'Nêm gia vị đúng thời điểm không chỉ giúp món ăn đậm đà mà còn ảnh hưởng đến độ ngon, độ giòn, độ mọng của món ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/pexelsrohanmuzafar3054690-1773-8724-2189-1773394017.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=k9GycCL6VDqIrC8odwZSsA', '2026-03-20', 'admin', 398, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315705491900_52', 'Vì sao nhiều người chỉ làm việc hiệu quả sát deadline?', 'Áp lực thời gian cận kề giúp não bộ tiết ra các hormone cảnh báo, loại bỏ sự trì hoãn và tăng cường khả năng tập trung vào công việc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/deadline-1773390004-1773390024-3813-1773390069.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=IrRI2aePlRHDe6ihst78Iw', '2026-03-20', 'admin', 453, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315721364200_53', 'Góc khuất sau vấn nạn cố tình xô đẩy ở Nhật Bản', 'Đoạn video bé gái bị xô ngã ở Tokyo đã gióng lên hồi chuông báo động về "butsukari" - vấn nạn cố tình va chạm người lạ để xả stress đang gia tăng tại Nhật Bản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/Thie-t-ke-chu-a-co-te-n-3-1773-4469-9773-1773374593.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=kmKl_9ydvAdA8gw15swzMg&t=image', '2026-03-20', 'admin', 335, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315746996800_54', 'Con trai dùng trực thăng đưa mẹ về quê', 'Mẹ nói muốn về quê, người đàn ông tên Long ở Tứ Xuyên lái trực thăng cá nhân trị giá 7 triệu tệ đưa bà về vì ôtô đã cho bạn mượn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1773272450-177327-8656-6736-1773274348.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Y9XSNVQj99QxicXvcU31fg', '2026-03-20', 'admin', 94, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315763974500_55', 'Giới siêu giàu vung tiền xây hầm trú ẩn', 'Lo ngại bất ổn toàn cầu, giới siêu giàu đang vung hàng trăm nghìn USD xây các hầm ngầm trú ẩn xa xỉ, mang lại doanh thu kỷ lục cho hãng sản xuất. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/untitled-1773333717-1773334180-5221-1773334666.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lsi1Zbgp6ky9ZkkJLntrzA', '2026-03-20', 'admin', 300, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315779501900_56', 'Chuyện tình 15 ngày của đôi vợ chồng hoán đổi giới tính', 'Từng cạn niềm tin vào tình yêu, Mộc Trà - người chuyển giới nữ và Thiên Minh - người chuyển giới nam, quyết định kết hôn sau 15 ngày quen nhau vì tìm thấy sự đồng cảm sâu sắc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-12-at-15-0-4845-1689-1773336910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zsMmkb4ZKHA4pdM_bk4JnA', '2026-03-20', 'admin', 452, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315794409700_57', 'Quy tắc ''cấm khoe mẽ'' của phố Wall', 'Việc bốn chuyên viên tài chính trẻ làm mẫu ảnh thời trang đã làm bùng nổ tranh cãi về quy tắc bất thành văn ở Phố Wall: Tuyệt đối không thu hút sự chú ý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/screen-shot-2026-03-12-at-14-5-9812-8707-1773302260.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7wMXhzX_8pLrHBKLQ_kwXw', '2026-03-20', 'admin', 245, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315809495800_58', 'Tỷ phú bánh bao ở nhà thuê, quyết không để tài sản cho con', 'Sở hữu chuỗi 5.600 cửa hàng và tài sản gần 600 triệu USD nhưng danh mục bất động sản của ông Lưu Hội Bình vẫn trống trơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/a-nh-ma-n-hi-nh-2026-03-12-lu-4281-8357-1773300992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Aibug9pmVMbPQDhOgkh3cA', '2026-03-20', 'admin', 283, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3315824329900_59', 'Tổ bay góp tiền đưa mẹ con người phụ nữ khiếm thị về quê', 'Địu con nhỏ đi từ TP HCM về Cao Bằng, người mẹ khiếm thị được tổ tiếp viên chăm sóc và quyên tiền đặt vé xe giường nằm chặng cuối về tận nhà. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7613036872520-979f4c14b579a74-6143-5591-1773323528.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZuKH3SFTr-IeOBXRl9BZ_A', '2026-03-20', 'admin', 172, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611761346200_0', 'Thuốc giảm cân 173 USD về 54 USD - cuộc cách mạng giá từ Ấn Độ', 'Làn sóng thuốc giảm cân giá rẻ từ Ấn Độ đang tạo nên một cuộc cách mạng y tế trên toàn cầu song đặt ra những thách thức lớn về kiểm soát chất lượng và an toàn người dùng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/giam-can2-1773966197-177396623-9948-3102-1773966358.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W2a1vxNWq1ipx6Xc65LezA', '2026-03-20', 'admin', 148, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611789232700_1', 'Đũa kim loại 12 cm trong cổ họng người đàn ông suốt 8 năm', 'Các bác sĩ tại tỉnh Liêu Ninh phẫu thuật lấy thành công chiếc đũa kim loại dài 12 cm nằm sâu trong vòm miệng một người đàn ông suốt 8 năm sau khi bệnh nhân vô tình nuốt phải lúc đang ăn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/00-1773940108-1773940223-1317-1773940303.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5Jbnc7ojWtIgpa9aJp0PRQ', '2026-03-20', 'admin', 261, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611817527100_2', 'Bác sĩ cảnh báo ''bẫy tâm lý'' khiến nhiều người sập bẫy thuốc gia truyền giả', 'Bác sĩ Ngô Văn Tỵ, Khoa Ung Bướu thuộc Bệnh viện Đại học Y Hà Nội, vẫn chưa thôi ám ảnh khi nhắc lại ca trực vừa qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z4553627269963-2f6fc10ad7c154e-2394-3553-1773818309.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JHP6dnV6gDB7g0SuN0IfFw', '2026-03-20', 'admin', 281, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611844382100_3', 'Án tử rình rập từ thử thách ''ngất xỉu'' trên TikTok', 'Chị Lan, 42 tuổi, bần thần khi phát hiện trong lịch sử xem video của con trai lớp 8 là cảnh một đám trẻ đang reo hò quanh một nam sinh vừa đổ gục, co giật nhẹ trên sàn nhà. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/2-1773366911-8280-1773367913-1-4012-5941-1773619069.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=uPJ_bYzYnVJz4Nrj5NLfaw', '2026-03-20', 'admin', 237, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611871348000_4', 'Ăn nhiều protein có gây hại thận?', 'Dù một hệ thận khỏe mạnh bình thường có thể xử lý lượng protein cao, nhưng đối với người đã có tổn thương thận, việc nạp quá nhiều protein có thể tạo ra gánh nặng quá mức. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/13/screenshot-2026-03-13-at-17-49-5249-6493-1773399093.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8oIup1SXwJUBFSAV6sCjA', '2026-03-20', 'admin', 259, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611897341400_5', 'Hội chứng lão hóa sớm', 'Hội chứng lão hóa sớm là một bệnh di truyền ít gặp khiến cơ thể trẻ em lão hóa nhanh bất thường. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/15312219thg32026-1773909094-17-3502-8851-1773909116.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1ZViTDl5vGm76l27f6ueOA', '2026-03-20', 'admin', 174, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611924890700_6', 'Tiêm botox có giúp giảm đau đầu mạn tính?', 'Tôi bị đau đầu gần như mỗi ngày, được chẩn đoán đau đầu mạn tính, dùng nhiều thuốc nhưng không giảm. Tiêm botox có giúp giảm đau đầu loại này? (Thanh Huyền, Cần Thơ) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/abc-1773970991-8969-1773971118-3274-4539-1773974532.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pKuq3CR1mT3CkkHqkFybXg', '2026-03-20', 'admin', 202, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611951200800_7', 'Viêm gan B mạn tính tiến triển ung thư', 'Ông Phi, 63 tuổi, viêm gan B mạn tính 10 năm sức khỏe ổn định nên không tái khám định kỳ, nay bác sĩ chẩn đoán ung thư gan giai đoạn sớm. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/hi-nh-thumb-1773971308-1773971-9835-9750-1773971433.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=yIc_kDHhvR_xD1pvP0VGhA', '2026-03-20', 'admin', 277, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3611977263000_8', 'Xạ trị ung thư hạch bạch huyết như thế nào', 'Xạ trị ung thư hạch có thể được sử dụng đơn thuần hoặc kết hợp với hóa trị để tiêu diệt các tế bào u tại chỗ, giảm triệu chứng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/bs-loc-1773969177-1773969197-4790-1773969316.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hvcitarrhudIM5_CDo8IIQ', '2026-03-20', 'admin', 230, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612005155200_9', '7 thói quen làm tăng đường huyết buổi sáng', 'Mức đường huyết thường xuyên tăng vào buổi sáng có thể do nhiều nguyên nhân liên quan đến giấc ngủ, vận động, ăn uống vào đêm hôm trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-11-12-3935-2357-1773893572.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-FXnn5-oJXtAb5_GwQ-hpg', '2026-03-20', 'admin', 456, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612029139700_10', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-20', 'admin', 180, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612056987100_11', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-20', 'admin', 120, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612086069900_12', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-20', 'admin', 105, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612110269600_13', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-20', 'admin', 203, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612128540800_14', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-20', 'admin', 443, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612145699200_15', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-20', 'admin', 110, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612165804000_16', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-20', 'admin', 498, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612183886500_17', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-20', 'admin', 389, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612201612600_18', 'Thử thách giảm một cân mỡ đổi nửa cân thịt bò tại Trung Quốc', 'Hơn 2.400 người dân thành phố Vô Tích đăng ký tham gia thử thách giảm cân để quy đổi trọng lượng cơ thể sụt giảm thành các phần thịt bò, đuôi bò và lá sách. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/blujgsjcgkzgxov28r29h6slrhcdwp-3084-9216-1773851508.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cJByzTs2uf-iCO9WHvmVZw', '2026-03-20', 'admin', 505, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612222314300_19', 'Lòng trắng hay lòng đỏ trứng nhiều protein hơn?', 'Nhiều người cho rằng protein có ở lòng trắng trứng, còn lòng đỏ chủ yếu chứa chất béo song thực tế chất béo được phân bổ ở cả hai phần với tỷ lệ khá cân đối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/trungluoc-1773735015-177373503-3257-1653-1773735084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Fi6Q-5BdVlJjlX5EoICKfA', '2026-03-20', 'admin', 222, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612244244900_20', 'Bẫy ''giảm đau nhanh'' từ thuốc đông y dởm', 'Thuốc đông y pha trộn hóa chất cấm tạo ảo giác hết bệnh tức thời, khiến nhiều người bệnh mạn tính và ung thư bỏ phác đồ điều trị chuẩn mực, dẫn đến đánh mất cơ hội sống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/b68c2082-b007-4e31-b108-003eb5-2978-8056-1773807046.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6sFkX8ilu6LKEesyjWQFng', '2026-03-20', 'admin', 97, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612265105100_21', '6 bài tập đơn giản tại nhà giúp kéo dài tuổi thọ', 'Chìa khóa của sự trường thọ nằm ở những chuyển động bền bỉ như đi bộ, đi cầu thang, squat, chống đẩy, đứng một chân và plank ngay tại chính ngôi nhà của bạn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/screenshot-2026-03-16-at-11-02-9494-7835-1773633846.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pf_-i646or_CqCdVKZYybw', '2026-03-20', 'admin', 248, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612291098500_22', 'Chàng trai suýt mất tinh hoàn vì cố chịu đau qua đêm', 'Chủ quan chịu đựng cơn đau vùng kín qua đêm, chàng trai 20 tuổi suýt hoại tử tinh hoàn do xoắn hai vòng, may mắn được bác sĩ Bệnh viện Quân y 175 mổ cấp cứu giữ lại kịp thời. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/233a1322-1773798712-4369-1773798922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tW7TIb8iGl4-yKI-tUdxiQ', '2026-03-20', 'admin', 408, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612323257800_23', '7 ''thủ phạm'' âm thầm khiến thận yếu đi', 'Ăn quá mặn, dùng thực phẩm chế biến sẵn, uống ít nước hoặc lạm dụng thuốc giảm đau có thể tăng áp lực lên thận theo thời gian. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/an-man-1773738708-1773738913-4727-1773738927.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NOq4Iuk7VwTI41RoRpSxfQ', '2026-03-20', 'admin', 267, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612350115400_24', 'Người gặp tai biến tử vong sau tiêm chủng có thể được bồi thường hơn 100 triệu đồng', 'Bộ Y tế đề xuất người gặp tai biến khi tiêm chủng thiệt hại tính mạng có thể được bồi thường 100 triệu đồng, phí mai táng bằng 10 lần mức lương cơ sở. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a7795-1754481674-1773899525-6921-8614-1773901922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fdofBhFGlUgbFwHFwI6a2w', '2026-03-20', 'admin', 346, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612371723300_25', 'Phát hiện mắc 2 loại ung thư từ triệu chứng vàng da', 'Người phụ nữ 59 tuổi vàng da, đau vùng hạ sườn kéo dài, đi khám được chẩn đoán mắc ung thư đại tràng và ung thư đường mật trong gan. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 90, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612388188900_26', 'Căn bệnh hiếm buộc bác sĩ chọn giải pháp ghép tạng domino', 'Từ dấu hiệu khó thở, các bác sĩ đã phát hiện ra căn bệnh hiếm nguy hiểm amyloidosis, giúp người đàn ông thoát cửa tử nhờ ghép đồng thời tim và gan thành công. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/img-8291-1773928219-1773928276-2399-1773928321.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GWtt0vlUJhMN1_b6wHCOVA', '2026-03-20', 'admin', 309, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612404627300_27', 'Dùng cà gai leo có giúp trị khỏi viêm gan B không?', 'Chồng tôi bị viêm gan B mạn tính, tôi tra cứu thông tin thấy dùng cà gai leo làm thuốc, giúp trị khỏi viêm gan B, có đúng không? (Đỗ Minh Hoa, 42 tuổi, Quảng Trị) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ca-gai-leo-1773916119-17739168-1342-4198-1773917298.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bkYSJaPU0S6ctMXtQqIOmw', '2026-03-20', 'admin', 114, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612420781600_28', 'Tán sỏi thận bằng ''đường hầm nhỏ'' qua da', 'Ông Đức, 66 tuổi, có viên sỏi san hô lớn ở thận trái, được bác sĩ dùng laser tán sạch sỏi qua da trong một lần. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/h2-1773912738-1773912762-9099-1773912790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=j38JjUzg5qR3qpK893tU5Q', '2026-03-20', 'admin', 166, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612436564900_29', 'Sẹo rỗ nặng do mụn', 'Chị Bình, 42 tuổi, nhiều sẹo rỗ sâu vùng mũi và má do nặn mụn, được bác sĩ điều trị tách đáy sẹo kết hợp vi kim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ba-c-tra-n-la-m-rf-1773906650-2435-6137-1773906761.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VkkZlz2OpWhquWYG-ewRA', '2026-03-20', 'admin', 214, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612452330100_30', 'Hệ thống trang thiết bị hiện đại tại Vinmec Ocean Park 2', 'Bệnh viện Đa khoa Quốc tế Vinmec Ocean Park 2 trang bị hàng loạt thiết bị y khoa tiên tiến như MRI 3.0, CT 512 lát cắt… đáp ứng nhu cầu khám chữa bệnh chuyên sâu với độ chính xác cao. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image1931552164extractword5out-975421-1773903823-1773913454.jpeg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BX_nsqPtleKJGP3xcwY0qQ', '2026-03-20', 'admin', 340, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612466665100_31', 'Tiểu đêm có phải do phì đại tuyến tiền liệt?', 'Ban đêm tôi thường đi tiểu 2-3 lần, khó tiểu, mệt mỏi. Có phải do phì đại tuyến tiền liệt không, điều trị thế nào? (Trọng Nghĩa, 55 tuổi, Đồng Nai) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/tah-8555-1-1773896092-17738961-3027-5635-1773896195.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5K75bH4lGA_9Lm7oZQauVA', '2026-03-20', 'admin', 111, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612482071200_32', '4 phương pháp điều trị rò hậu môn', 'Người bị rò hậu môn sau áp xe có thể được bác sĩ chỉ định mổ nội soi, điều trị tia laser hoặc keo sinh học. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/bs-luong-1773839125-1773839198-1501-1773839265.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mMANsiAEDnEcOmbLkYviAA', '2026-03-20', 'admin', 211, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612497566300_33', '5 khoáng chất cần thiết cho sức khỏe sinh lý nam', 'Kẽm, magie, kali, canxi, sắt tham gia vào quá trình sản xuất testosterone, duy trì sinh lý và sức khỏe nam giới. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773905181-1773905199-4800-1773905250.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=J7FYYReSZWjbjDl8OJm-8w', '2026-03-20', 'admin', 181, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612512747000_34', 'Những thói quen mỗi ngày giúp trẻ phát triển trí tuệ', 'Trẻ nên ngủ trước 22h, ăn sáng đầy đủ dinh dưỡng, duy trì thói quen đọc sách và tập thể dục mỗi ngày để phát triển trí não. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/93833d0df43141139173df329820a4-6130-7273-1773895766.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zoshz-NkGeLp3SvTGUEs5g', '2026-03-20', 'admin', 282, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612527938400_35', 'Dấu hiệu nhận biết bệnh về mắt', 'Thay đổi màu sắc mống mắt, hai mắt không thẳng hàng hoặc khó tập trung nhìn các vật ở gần hay xa có thể cảnh báo các vấn đề về mắt. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/momat3-1773892193-1773892202-3927-1773892212.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fX-6NRS3Zsww7n9bh7yqcg', '2026-03-20', 'admin', 48, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612543788700_36', '5 nhóm người nên hạn chế uống nước dừa', 'Người mắc tiểu đường, bệnh thận, đang dùng thuốc huyết áp hoặc có rối loạn điện giải nên hạn chế uống nước dừa để tránh ảnh hưởng sức khỏe. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/28b42ae376a74e37a5c7c694a5c3c4-1939-2018-1773891857.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=W03cZYxS8Wc_2LuiG6kP6w', '2026-03-20', 'admin', 264, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612559660900_37', 'Ba lần mắc zona thần kinh trong hai năm', 'Bà Dung, 62 tuổi, liên tiếp mắc zona thần kinh ở vùng lưng trong hai năm, lần sau nặng hơn lần trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/vnvc-zona-than-kinh-tai-phat-1-6377-2082-1773903517.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ot_zkYHKjIvfaOFuy5poIQ', '2026-03-20', 'admin', 330, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612576379700_38', '6 món chứa tinh bột người tiểu đường nên ăn', 'Thực phẩm giàu tinh bột phức hợp như yến mạch, ngũ cốc nguyên hạt, khoai lang giúp ổn định đường huyết và cung cấp năng lượng lâu dài cho cơ thể. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/Buoc-2-3355-1645172245-1773889121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ApfUYyAeH9YX9pzCl6WWCw', '2026-03-20', 'admin', 236, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612593479000_39', 'Tại sao lupus ban đỏ không thể chữa khỏi?', 'Bác sĩ chẩn đoán tôi mắc lupus ban đỏ. Bệnh nguy hiểm thế nào và tại sao không thể chữa khỏi hoàn toàn? (Nguyễn Dũng, Tiền Giang) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/taan08791-1773896320-177389644-1957-7425-1773897084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=a1vP8v6gMEZpjdw3KcbJiQ', '2026-03-20', 'admin', 117, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612608764900_40', 'Ăn mặn gây rối loạn tiền đình nặng hơn?', 'Tôi bị rối loạn tiền đình ngoại biên, được khuyên kiêng muối vì có thể làm bệnh nặng hơn, đúng không? (Lâm Phạm, 55 tuổi, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/a-nh-1773888613-1773888648-2147-1773888710.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u8tyXq22msAo0zpUDa0uew', '2026-03-20', 'admin', 502, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612625994700_41', 'Khó thở khi nằm cảnh báo bệnh gì?', 'Tôi thường cảm thấy khó thở khi nằm xuống, có liên quan đến bệnh hô hấp không? (Nguyễn Ngân, Hà Nội) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773887515-1773887563-7123-1773887636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=olNppiTaFzjv5NtxhAoN8w', '2026-03-20', 'admin', 63, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612641512500_42', 'Dùng sóng xung kích phá vôi hóa mạch vành', 'Bà Năm, 86 tuổi, đau ngực do động mạch vành hẹp tắc, được bác sĩ phá mảng vôi hóa bằng sóng xung kích ngăn nguy cơ nhồi máu cơ tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881685-1773881714-3499-2887-1773881937.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8a1D0rK_oLWWS9diLy28Bw', '2026-03-20', 'admin', 84, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612658497500_43', 'Cắt toàn bộ tuyến giáp chặn ung thư', 'Bà Loan, 50 tuổi, khám sức khỏe định kỳ phát hiện nhân giáp, sinh thiết lạnh xác định ung thư xâm lấn phải cắt toàn bộ tuyến giáp. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881289-1773881336-2586-1773881408.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yXQBUpD-Igp8_EDS1wUVEA', '2026-03-20', 'admin', 432, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612674757100_44', 'Suy buồng trứng ở tuổi 24', 'Chị gái bị vô sinh nên Hồng, 24 tuổi, chủ động đi khám sức khỏe sinh sản bất ngờ phát hiện buồng trứng gần cạn kiệt như phụ nữ mãn kinh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/key1103-3-1773817056-177381708-3143-7860-1773819558.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=CavEu2B_enyj5OEFH8VNdQ', '2026-03-20', 'admin', 509, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612689791700_45', 'Kỳ tích 90 ngày giữ song thai ''dọa'' sinh cực non', 'Chị Nhung, 33 tuổi, mang song thai 24 tuần dự báo nguy cơ 90% sinh non, được bác sĩ liên khoa phối hợp giữ thai thêm ba tháng đến khi sinh an toàn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881134-4834-1773881170.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1XDOjAjAXRUGNSkmDiyA0A', '2026-03-20', 'admin', 48, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612705587800_46', 'Trẻ bị lông mi mọc ngược có nguy hiểm?', 'Con tôi 5 tuổi, bị lông mi mọc ngược đâm vào mắt gây khó chịu, thường xuyên đỏ mắt. Tình trạng này có nguy hiểm và điều trị thế nào? (Trân, 31 tuổi, Long An) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/lo-ng-mi-mo-c-ngu-o-c-17738488-3850-2423-1773874352.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7CL5Pqz10iYGl92EJWXj0w', '2026-03-20', 'admin', 166, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612724395300_47', 'Cơn đau đầu cảnh báo sớm đột quỵ', 'Cơn đau đầu kéo dài, lúc âm ỉ, lúc dữ dội nhưng thoáng qua vài phút rồi biến mất có thể là dấu hiệu sớm đột quỵ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z7615389058820-b770c8502777a2a-3606-1286-1773839001.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DtpN1a4Sw8ZgN4_ZUIXC2Q', '2026-03-20', 'admin', 346, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612740246500_48', 'Ăn uống, dùng thuốc thế nào sau cắt toàn bộ tuyến giáp?', 'Tôi đã cắt toàn bộ tuyến giáp triệt căn ung thư, phải dùng hormone thay thế. Ăn uống thế nào, lưu ý gì để không ảnh hưởng hấp thu thuốc? (Quốc Bảo, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/a-nh-1-1773838561-1773838575-1902-1773838656.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KiTXzuR-XhOYEsReCOHtGQ', '2026-03-20', 'admin', 503, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612755914000_49', 'Ngủ đủ giấc - cách đơn giản bảo vệ trái tim', 'Ngủ đủ giấc hỗ trợ kiểm soát huyết áp, giảm viêm, tinh thần sảng khoái, từ đó tăng cường sức khỏe tim mạch. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/86262b59886c421faa325d79d43c42-3285-5331-1773807728.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=z2yoNwuRifB21tkyO55TgA', '2026-03-20', 'admin', 89, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612772248500_50', 'Ba thói quen ít ngờ có thể gây hại não', 'Ít tiếp xúc xã hội, sống ở nơi thiếu ánh sáng và nghe nhạc to lâu dài có thể ảnh hưởng tâm trạng, trí nhớ và sức khỏe não bộ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/geminigeneratedimage4gdeoq4gde-2334-2556-1773805576.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=6L8vpW0eIwiwb9yhfgyJEQ', '2026-03-20', 'admin', 220, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612788037300_51', 'Bé gái tử vong sau 9 giờ phát bệnh nghi do não mô cầu', 'Bé gái 10 tuổi tại Phú Quốc sốt, đau đầu, nổi ban, tím tái, khó thở, vào viện cấp cứu song không qua khỏi, nghi mắc viêm não mô cầu. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 360, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612810092400_52', 'Hai bác sĩ ép tim cứu người ngừng thở giữa sân bóng chuyền', 'Bác sĩ Trần Văn Biên và Nguyễn Cao Việt ép tim cứu sống người đàn ông 64 tuổi ngừng tuần hoàn, ngã quỵ giữa sân khi đang đánh bóng chuyền hơi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/eptim-1773824056-9512-1773824095.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=zKbi8S68AXzNCvOi1chXQw&t=image', '2026-03-20', 'admin', 409, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612832703500_53', 'Thử thách ''nằm một chỗ'' nhận tiền gây sốt tại Thượng Hải', 'Thí sinh tham gia thử thách ngủ được yêu cầu nằm một chỗ trong 24 giờ, không đi vệ sinh, không dùng điện thoại, máy tính để có cơ hội nhận tiền mặt cùng nhiều gói nghỉ dưỡng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/ngu-1773821005-1773821075-3441-1773821874.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8KlVBUvBMqmynOHVIVlLoA', '2026-03-20', 'admin', 74, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612855534900_54', 'Bác sĩ chỉ ra cách ăn uống giúp kéo dài tuổi thọ', 'Silvio Garattini, nhà dược học nổi tiếng người Italy, nhận định việc tiêu thụ ít thực phẩm có thể là chìa khóa để thêm nhiều năm sống khỏe mạnh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-17-at-14-42-3188-8472-1773733487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WtNm6z8rhaEufjF1U9dIpg', '2026-03-20', 'admin', 260, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612879308600_55', 'Hàng chục nghìn ca lao bị bỏ sót, TP HCM mở chiến dịch 100 ngày', 'TP HCM khởi động chiến dịch 100 ngày tầm soát lao chủ động bằng X-quang tích hợp AI cho 30.000 người dân có nguy cơ cao, trước tình trạng hàng chục nghìn ca bệnh bị bỏ sót. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/xn-be-nh-lao-1773813681-177381-6084-5180-1773814033.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=dhP9C3bqRRjz-Y8bvoWDCg', '2026-03-20', 'admin', 104, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612902066900_56', 'Trung Quốc chế tạo thiết bị bảo quản nội tạng hiến tặng trong nhiều ngày', 'Các nhà khoa học Trung Quốc vừa phát triển thành công hệ thống tưới máu máy đa nhiệt độ, giúp kéo dài thời gian bảo tồn nội tạng hiến tặng từ vài giờ lên nhiều ngày. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/1-1773810584-1773810598-6921-1773811859.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Mn8_w1WS1t3d0f_fsjsllg', '2026-03-20', 'admin', 496, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612926440900_57', 'Bắt bạn đời tránh thai, triệt sản vì định kiến giới sẽ bị phạt 12 triệu đồng', 'Từ ngày 1/5, cơ quan chức năng phạt tiền 10-12 triệu đồng đối với người ép buộc vợ hoặc chồng sử dụng biện pháp tránh thai, triệt sản với lý do định kiến giới. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 505, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612947963900_58', 'Uống nước chanh trị gout?', 'Nhiều người truyền tai nhau uống nước chanh tươi giúp rửa bớt acid uric, có thể dùng thay thuốc điều trị gout, điều này có đúng? (Tuấn, 32 tuổi, Hà Nội). (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/c15c6f48-ced4-4429-bfb5-9455cd-5801-6593-1773760546.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=W_kjheUzq2C2ME6zHgDgBg', '2026-03-20', 'admin', 194, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3612971532500_59', 'Đề xuất hỗ trợ 1,5 triệu đồng sàng lọc bệnh trước và sau sinh', 'Bộ Y tế đề xuất mức chi 1,5 triệu đồng cho các dịch vụ sàng lọc phát hiện sớm bệnh bẩm sinh nhằm nâng cao chất lượng nòi giống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/anh-chup-man-hinh-2026-03-18-l-5391-3509-1773799029.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0k4SOQrMVLeMurI_aXm-A', '2026-03-20', 'admin', 462, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632513765300_0', 'Làm giàu nhờ nghề mặc cả giá ôtô', 'Tomi Mikula kiếm 200.000 USD mỗi tháng nhờ dịch vụ đàm phán giá ôtô, giúp người mua tránh được các bẫy phụ phí từ đại lý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-5910-1846-1773937191.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=GyihZcdPr2Sfk_6yWjP9lw', '2026-03-20', 'admin', 448, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632538313500_1', 'Viện dưỡng lão đầu tiên trên thế giới vận hành bằng robot', 'Trạm dưỡng lão tại phố Vinh Hoa, Bắc Kinh trang bị 43 loại robot từ massage, châm cứu đến pha trà, nâng cao chất lượng sống cho người cao tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-8312-6385-1773934900.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VfFn7buTa9TsExFyHzR6g', '2026-03-20', 'admin', 267, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632552352500_2', 'Người trẻ đu trend ''gặp lại mình 10 năm trước''', 'Làm video đối thoại với mình 10 năm trước, nhiều người trẻ muốn nhìn lại hành trình trưởng thành, tự chữa lành tổn thương và định hướng tương lai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/10nam2-1773913137-3708-1773913342.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SmWlJhXMhpeoM7Fve9avQw', '2026-03-20', 'admin', 97, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632566534600_3', 'Cuộc sống bế tắc vì thiếu gas của người Ấn Độ', 'Xếp hàng bốn ngày không đổi được bình gas để nấu ăn, hàng triệu gia đình Ấn Độ đang lao đao vì chuỗi cung ứng năng lượng đứt gãy. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-15-4-3817-9609-1773910903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=TesnxCAAkCHU4m5yGF1yCQ', '2026-03-20', 'admin', 40, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632578963700_4', 'Vì sao nhiều người không quên được tình cũ?', 'Dưới lăng kính tâm lý học, việc chúng ta không ngừng tiếc nuối và lý tưởng hóa người yêu cũ thực chất chỉ là một "cú lừa" của não bộ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/nguoi-cu-1773906295-1773906318-6293-1773906415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=HVjiPxxd9gacVL6Y22uXqA', '2026-03-20', 'admin', 357, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632592880400_5', 'Bi kịch của nữ giám đốc lộ chuyện ngoại tình ở đêm nhạc', 'Từng là tâm điểm chỉ trích vì nụ hôn vụng trộm với sếp, cựu giám đốc Kristin Cabot lần đầu lên tiếng về bi kịch mất trắng sự nghiệp và tiêu chuẩn kép của dư luận. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-3953-9787-1773905123.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SnVW0ZXwG0D0cs-jv11r5w', '2026-03-20', 'admin', 383, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632605776200_6', 'Lợi ích bất ngờ của người thấp bé', 'Khác với lầm tưởng cao lớn đồng nghĩa với khỏe mạnh, người có vóc dáng khiêm tốn thực chất lại ít mắc ung thư, hiếm khi gãy xương và có xu hướng sống thọ hơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-16-1-3564-4232-1773826547.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WILYrMZI2_N_0dlS2haaeA', '2026-03-20', 'admin', 198, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632618190800_7', 'Bi kịch của những tình yêu AI', 'Tối 13/2, SkeweredKebab (nickname) đọc lại toàn bộ những cuộc hội thoại với ChatGPT để làm lễ tiễn biệt "người chồng AI" vừa bị khai tử. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-15-5-6470-2528-1773825011.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hywduvy6fBWG60Hqv4b41Q', '2026-03-20', 'admin', 319, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632629987100_8', 'Gia đình ''siêu nhân Gao'' ở Hưng Yên gây bão mạng', 'Giữ trọn đam mê siêu nhân từ nhỏ, anh Ngọc Trung sắm trang phục siêu nhân Gao rủ vợ hóa trang, sáng tạo loạt video hài hước mang lại tiếng cười cho cộng đồng. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7606213086839-ba7d4f64bbbc508-7613-9150-1773319405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mrTZfGPqSl0KOJOxGL3Etw', '2026-03-20', 'admin', 248, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632642486000_9', 'Vụ ly hôn tỷ USD và góc khuất đời tư của chủ tịch tập đoàn SK', 'Cuộc chiến pháp lý giữa Chủ tịch tập đoàn SK Chey Tae-won và vợ cũ Roh Soh-yeong gây chấn động bởi khối tài sản khổng lồ và sự xuất hiện của "người thứ ba". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/00-1773805459-1773805465-7488-1773807993.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ma9jNQK-Y2L9EYbGcAWU3Q', '2026-03-20', 'admin', 172, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632654870800_10', 'Nhà hàng đập 600 bộ bát đĩa vì khách cho chó lên bàn ăn', 'Ông Giang, quản lý nhà hàng tại Thương Khâu (Hà Nam), đã đập bỏ 600 bộ bát đĩa và đóng cửa khử trùng quán khi phát hiện một thực khách mang chó lên bàn ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/pet-restaurant-2-1773823218-17-3022-8308-1773823607.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YJaopzEQ_wQcv0LriogkfQ', '2026-03-20', 'admin', 251, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632668014600_11', 'Nạn trộm cắp ở khu nhà giàu Mỹ', 'Từng là chốn an cư bình yên của giới tinh hoa, khu Sharon Heights (vùng vịnh San Francisco) giờ chìm trong bất an khi kẻ gian liều lĩnh đột nhập ngay lúc gia chủ đang ăn tối. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/ratio3x2-960-1773806447-177380-5965-1359-1773809180.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=XY--0saGjRWJfVzM5zTLrQ', '2026-03-20', 'admin', 438, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632679601600_12', 'Làn sóng ''nhân lực tinh hoa'' rời bỏ Israel', 'Từng coi Tel Aviv là "thiên đường công nghệ", kỹ sư Elizabeth Cohen quyết định rời đi vì không muốn sinh con giữa những tiếng còi báo động tên lửa. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-17-at-23-3-7325-4333-1773766923.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KazThb0Myl6qlnll2uVyPg', '2026-03-20', 'admin', 366, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632691636000_13', 'Cách tự học tiếng Anh của ''cô giáo nhí'' 9 tuổi', 'Từ trò chơi đóng vai cô giáo mỗi tối, bé Vân Anh khiến cộng đồng mạng bất ngờ bởi khả năng nói tiếng Anh trôi chảy và cách dạy em đầy kiên nhẫn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/va-n-anh-2-1773661730-17736617-3169-1895-1773662279.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MFZagmWNCjA_dg4MlTV1-g', '2026-03-20', 'admin', 308, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632704475400_14', 'Phát tài nhờ tờ giấy bỏ quên 30 năm', 'Đang phải sống chật vật với lương hưu eo hẹp, vợ chồng ông Sato bất ngờ thu về 68 triệu yen nhờ tìm thấy tờ biên lai mua cổ phiếu, bị bỏ quên 30 năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/co-phieu-2-jpeg-1773797809-177-3785-6774-1773797902.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T-SETu0hLWUdD-lr9bNEBQ', '2026-03-20', 'admin', 83, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632716538300_15', 'Bi kịch của thế hệ ''kiếm nhiều tiền nhưng không giàu''', 'Thu nhập 450.000 USD mỗi năm nhưng vợ chồng Alex vẫn phải ở nhà thuê, chưa trả hết nợ sinh viên và nơm nớp lo sợ thiếu tiền giữa lòng New York đắt đỏ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-00-3-6865-5413-1773770804.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICLidWfdmD2K6KISqPINoQ', '2026-03-20', 'admin', 189, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632728737900_16', 'Hai chuyến đi Việt Nam ''cứu rỗi'' người phụ nữ Mỹ', 'Rơi vào trầm cảm sau khi mẹ qua đời, Lilly Hubbard quyết định quay lại Việt Nam và tìm thấy sự "chữa lành" từ tình người ấm áp ở vùng đất xa lạ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/lilly-2-1773802709-1773802742-4016-1773802752.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5uQdZnsKta3M8vRTp6nZhA', '2026-03-20', 'admin', 97, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632740460300_17', 'Vì sao quần áo thể thao giặt xong vẫn hôi?', 'Ném ngay đồ tập đẫm mồ hôi vào máy giặt, dùng nhiều xà phòng hay nước xả vải là sai lầm khiến quần áo luôn bốc mùi khó chịu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/a-nh-ma-n-hi-nh-2026-03-16-lu-7904-9038-1773736876.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KXY2uWiUcoSsOpLDwHycOA', '2026-03-20', 'admin', 428, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632751825200_18', 'Bên trong nhà lắp ghép 30 m2 của tỷ phú Elon Musk', 'Mặc dù sở hữu hàng trăm tỷ USD, tỷ phú Elon Musk hiện sống trong căn nhà lắp ghép rộng 30 m2, thiếu tiện nghi đến mức mẹ ông phải ngủ ở gara. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/577333596-3394143064076672-485-6636-3102-1773724581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=b5eyN5ibANA-m59NlkHsAQ', '2026-03-20', 'admin', 253, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632764300300_19', 'Vợ cho ''thuê'' chồng', 'Phát hiện chồng ngoại tình, cô Khun Kwang ra thỏa thuận cho nhân tình của anh thuê chồng với giá 30.000 bath mỗi tháng, tuy nhiên hợp đồng này bị luật sư cảnh báo vô hiệu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/chatgpt-image-11-27-42-17-thg-9377-7480-1773721720.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NBqR-Rw-evtAbpk1qTmaKQ', '2026-03-20', 'admin', 440, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632775781200_20', 'Vì sao nhà chung cư ở Mỹ ngày càng ít?', 'Từng là lựa chọn an cư giá rẻ cho người trẻ Mỹ, số lượng chung cư thương mại sụt giảm mạnh do rào cản pháp lý, thuế và chi phí bảo hiểm tăng vọt. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/im-92913950-1773654144-1773671-8010-8091-1773672308.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Bm4Dwf779JQ1G3-LVfRR1w', '2026-03-20', 'admin', 498, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632787697300_21', 'Vợ 50 tuổi làm IVF chiều chồng trẻ', 'Bất chấp những đàm tiếu của dư luận, bà Pilli Cortese vẫn quyết định thụ tinh nhân tạo ở tuổi 50 để thỏa ước nguyện làm cha của người chồng kém 21 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5921-9658-1773633940.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9Zuubwaaw2BqQmbUtn07fA', '2026-03-20', 'admin', 69, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632799816300_22', 'Bẫy thổi phồng chức danh khi tuyển dụng', 'Nhiều doanh nghiệp đang gán mác "giám đốc", "trưởng phòng" cho người lao động nhưng chỉ trả mức lương nhân viên nhằm thu hút ứng viên và tối ưu chi phí. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/tuyen-dung-jpeg-1773679492-177-2056-8763-1773681102.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KigiyGPtR51yLB_8Hefyxg', '2026-03-20', 'admin', 362, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632811555900_23', 'Dân công sở Mỹ bỏ ôtô, đạp xe, làm từ xa để né ''bão'' giá', 'Thấy giá nhiên liệu tăng vọt, Boris Kagarlitskiy quyết định cất chiếc Lexus ở nhà, lôi xe đạp cũ ra lau chùi để bắt đầu chuỗi ngày đi làm bằng sức người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/dap-xe-1773678268-1773678292-1-1377-3127-1773678449.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=w-sPfSoia-AE5rGBtpoj4Q', '2026-03-20', 'admin', 296, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632823657100_24', 'Nhan Phúc Vinh, Hà Thu tập chống đuối nước cùng 1.000 học sinh', 'Diễn viên Nhan Phúc Vinh, Á hậu Hà Thu cùng hơn 1.000 học sinh nhận biết mực nước an toàn, kỹ năng thở nước, tại workshop chống đuối nước, sáng 16/3. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/dsc04354-1773740071-8030-17737-9004-8642-1773765903.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A4JrUo23I3KsRgZmF6I4Lg', '2026-03-20', 'admin', 59, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632836121100_25', '3 bước đánh lừa não bộ để ngủ nhanh hơn', 'Kỹ thuật "xáo trộn nhận thức" giúp ngắt quãng dòng suy nghĩ lo âu, mô phỏng trạng thái mơ màng tự nhiên để não bộ thư giãn và dễ dàng chìm vào giấc ngủ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/z7591758010902-c59406ff20941de-5096-4651-1773652579.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xQChxkieWCwZeML9fYn7Gg', '2026-03-20', 'admin', 302, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632848414200_26', 'Yêu 6 năm mới biết bạn gái đã có chồng con', 'Chi hơn một triệu tệ cho bạn gái trong 6 năm mặn nồng, anh Wang bàng hoàng phát hiện người yêu thực chất đã yên bề gia thất, thậm chí các con đã học cấp hai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5017-9753-1773636339.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LRn0uHe2LxkLnmac08jIuw', '2026-03-20', 'admin', 198, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632868530200_27', 'Nhiều nông dân Mỹ có nguy cơ phá sản vì xung đột Trung Đông', 'Xung đột tại Trung Đông đẩy giá nhiên liệu và phân bón lên mức kỷ lục, giáng đòn mạnh vào hàng loạt trang trại, đẩy họ vào cảnh phá sản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-13-at-22-1-6679-9104-1773417216.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wNZTd6jP3YfT0zCvXMAvYg', '2026-03-20', 'admin', 471, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632886262300_28', 'Khủng hoảng xăng dầu ''bóp nghẹt'' người nghèo châu Á', 'Xung đột ở Trung Đông gây đứt gãy nguồn cung nhiên liệu, đẩy hàng chục triệu người lao động tại châu Á vào cảnh thiếu xăng, khí đốt và sụt giảm thu nhập. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/a-nh-ma-n-hi-nh-2026-03-16-lu-7437-9899-1773631014.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pswj5Qok0ZT1EUC6gyBi6g', '2026-03-20', 'admin', 424, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632901900300_29', 'Tụ tập - quy tắc giữ gìn tình bạn của người Đức', 'Cuộc sống bận rộn khiến nhiều mối quan hệ phai nhạt nhưng người Đức áp dụng quy tắc "Stammtisch" - những cuộc tụ họp định kỳ, đơn giản nhưng hiệu quả. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/stammtisch-2-1773625060-177362-4038-7784-1773625553.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lkewTZzZ2noESjRQobw1iA', '2026-03-20', 'admin', 103, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632917465400_30', 'Chàng trai Canada ''bẻ lái cuộc đời'' vì tình yêu với cô gái Việt', 'Ngay buổi hẹn đầu dưới chân tháp Tokyo, Thu Thủy đưa ra loạt tiêu chuẩn khắt khe về bạn trai, rồi dội gáo nước lạnh vào Seiwa: “Em không muốn gặp lại anh nữa”. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/img-1831-1-jpeg-1773460527-177-7354-6141-1773461950.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mt3pi6U16KHThn4v8-hOBA', '2026-03-20', 'admin', 499, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632931946400_31', 'Ước mơ của người vợ 10 năm giữ món quà chồng chưa kịp tặng', 'Cất kỹ chiếc váy và chú gấu bông chồng mua tặng trước khi tử nạn, chị Thúy mong một ngày được trao lại cho con gái trong sự kiện trọng đại nhất đời. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/z7619839331948-d5148baa4b6833d-6407-2821-1773504440.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RytXItajr9SLpO3H0LRM4Q', '2026-03-20', 'admin', 441, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632944308000_32', 'Cuộc đoàn tụ gượng gạo của cô gái bị vứt ở nhà vệ sinh 28 năm trước', 'Bị ông nội vứt bỏ từ lúc 2 ngày tuổi, Hong Yangli vượt nửa vòng trái đất về nhận mẹ nhưng đối diện màn đoàn tụ lạnh lẽo, dấy lên nhiều tranh cãi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/1-3-1773547826-1773547843-5092-1773548222.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=amEJ_VUF9IpG9eD0G9_PNg', '2026-03-20', 'admin', 436, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632958070400_33', 'Cụ bà 82 tuổi bị lừa kết hôn bằng 20 quả trứng', 'Cụ bà mù chữ 82 tuổi ở Hồ Nam tưởng làm giấy tờ để nhận trợ cấp 1.000 tệ và 20 quả trứng, không ngờ bị lừa ký giấy đăng ký kết hôn với người đàn ông 47 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/00-1773543821-1773543868-7185-1773543919.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KfEnT7aoLQ3RSBsN1-oYAw', '2026-03-20', 'admin', 97, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632971181600_34', 'Người đàn ông bị hàng loạt nhà tang lễ từ chối vì béo', 'Ở Canada, béo phì không chỉ là một bài toán khó về sức khỏe khi còn sống, mà nay lại biến thành "rào cản cuối cùng" sau khi chết. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/0-1-1773549860-1773549866-3805-1773550180.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vVbCv37mEQDizIgnTBFi5g', '2026-03-20', 'admin', 276, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632983929100_35', 'Suýt mất mạng, cặp vợ chồng hối hận vì ''bỏ phố về rừng''', 'Từng ảo tưởng về sự tuyệt vời của cuộc sống biệt lập giữa thiên nhiên, vợ chồng Jayme bừng tỉnh sau sự cố suýt mất mạng ngày sinh nở, nhận ra cái giá của sự cô độc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773464228-1773464933-3946-1773464939.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oyCVWVQKOW3_wjd1YLbydQ', '2026-03-20', 'admin', 90, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3632999590100_36', 'Đường đến giải bơi trong hồ băng của cậu bé Hà Nội', 'Trên đỉnh núi tuyết ở Neuhermsdorf, Phan Anh mặc quần bơi đứng lặng nhìn mặt hồ Altes Zollhaus bốc khói trong khi ban tổ chức luôn tay vớt những tảng băng cản đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/phan-anh-1-1773221913-4040-177-8906-6797-1773503423.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tRJ-e86PBimTvuLx8uLrLQ', '2026-03-20', 'admin', 491, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633014377500_37', 'Đánh cược mạng sống mưu sinh trong vùng chiến sự', 'Mỗi khi tiếng còi báo động vang lên, nữ giúp việc Joycee Pelayo chạy vội đến cụ ông mà cô đang chăm sóc, dìu ông lên xe lăn rồi đẩy thật nhanh xuống hầm trú ẩn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773484138-1773484220-8888-1773484945.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SXxzNvSvE4dKP7MSqygIxA', '2026-03-20', 'admin', 434, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633027769300_38', 'Người Lạng Sơn chi hàng trăm triệu làm cỗ mời khách lạ', 'Để tán lộc và cầu may, người dân Lạng Sơn chi hàng trăm triệu đồng dựng rạp, thết đãi cỗ miễn phí cho cả khách lạ về dự hội đền Kỳ Cùng - Tả Phủ đầu năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/6-2-1773501948-1773502444-9849-1958-9924-1773505959.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0x9NpYpx7nxQjaqa-_PsZg', '2026-03-20', 'admin', 231, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633039924400_39', 'Gần 3.000 runner chạy giữa đô thị lớn nhất Nghệ An', 'Gần 3.000 vận động viên dự giải Eco Central Park Marathon lần đầu tổ chức với cung đường xuyên qua công viên và các thảm hoa trong khu đô thị. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/kbd03827-1773548789-1773549037-3771-1773551974.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0E-9mGgNroDH6ojqizG9w', '2026-03-20', 'admin', 170, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633051775800_40', 'Thường xuyên bị nhầm là con vì kém vợ 23 tuổi', 'Bất chấp khoảng cách 23 tuổi và hay bị nhầm là mẹ con, cặp đôi Azmirullah (28 tuổi) và Wan Nazihah (51 tuổi) vẫn có cuộc sống viên mãn sau gần 7 năm kết hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-5511-1481-1773391224.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rVhmD8KwmfMyFVajva3Fg', '2026-03-20', 'admin', 321, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633063614500_41', 'Cả nhà bới 10 tấn rác tìm túi vàng', 'Gia đình 8 người ở Giang Tây phải thức trắng đêm, lục tung 10 tấn rác để tìm lại túi vàng trị giá 1,5 triệu tệ (5,2 tỷ đồng) bị người nhà vứt nhầm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/chatgpt-image-12-00-22-14-thg-6372-9837-1773467256.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=_9x4DRlTKFjkiC60B2o8FA', '2026-03-20', 'admin', 199, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633076741800_42', 'Vì sao không cần ''ra khỏi phòng là tắt đèn''?', 'Lời khuyên "ra khỏi phòng là tắt đèn" đã lỗi thời trong kỷ nguyên bóng đèn LED, nhưng vẫn áp dụng đúng quy tắc 15 phút với đèn huỳnh quang. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/1-1773454941-1773455346-9660-1773455690.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bdkGsflc9Jxr6O6pwJzT-A', '2026-03-20', 'admin', 450, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633089650200_43', 'Những cuộc hôn nhân tan vỡ vì trúng độc đắc', 'Trúng thưởng hàng chục triệu USD, nhiều cặp vợ chồng ngỡ đã chạm tay vào hạnh phúc viên mãn nhưng cuối cùng lại rơi vào cảnh ngoại tình, kiện tụng và ly hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/screen-shot-2026-03-14-at-00-3-2966-9237-1773423562.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zp535HhmTaj7GmpNZEZnIw', '2026-03-20', 'admin', 40, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633102311200_44', 'Dubai vắng vẻ ''chưa từng thấy''', 'Dưới sức ép từ các đợt tấn công của Iran, người nước ngoài đang vội vã rời khỏi Dubai, đẩy "thành phố vàng" vào cảnh vắng lặng như thị trấn ma. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/untitled-1773453416-1773453692-9708-1773453849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vbalNxj_XueEp65nAOLXcA', '2026-03-20', 'admin', 419, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633114513200_45', 'Chàng trai không tay và những món ăn ''triệu view''', 'Mất đôi tay sau tai nạn, Trọng Định, 23 tuổi, học cách nấu ăn bằng chân và hai mỏm cụt, biến nỗi đau thành nghị lực sống truyền cảm hứng cho hàng triệu người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/di-nh-di-cho-1773409298-177340-4382-8632-1773422430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0DityHvFbLGR7izILlXGOQ', '2026-03-20', 'admin', 373, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633126849000_46', 'Dùng AI tạo ''chuyên gia giả'' để trị thói giục cưới của cha mẹ', 'Mệt mỏi vì bị cha mẹ liên tục giục lấy chồng, Cao Mei, 38 tuổi, dùng AI tạo ra một "chuyên gia tâm lý" để giảng đạo lý, thuyết phục ngược lại phụ huynh. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/0-1773398662-1773398682-1718-1773399208.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EVMDlFbSybo3mN85hxNoWg', '2026-03-20', 'admin', 170, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633138452200_47', 'Đổ xô mua nhà thờ cũ làm nhà ở', 'Giữa "bão" giá bất động sản, nhiều người chọn mua các nhà thờ cũ với giá rẻ để cải tạo thành không gian sống độc đáo. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/a-nh-ma-n-hi-nh-2026-03-13-lu-3696-4834-1773377205.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SH7Rb4ILOv0ksxLF-wv1NQ', '2026-03-20', 'admin', 259, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633150235700_48', 'Hơn 2.000 người mua vé sớm dự lễ hội ẩm thực Saigontourist 2026', 'Hàng nghìn vé sớm được bán trước thềm Lễ hội Văn hóa Ẩm thực Saigontourist 2026, hút 2.000 lượt đặt mua sau 10 ngày. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/kho-ng-khi-nga-p-tra-n-ma-u-sa-5727-7837-1773461994.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0g7XJzZGG1R1YRikkMMY9g', '2026-03-20', 'admin', 503, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633162110200_49', 'Trẻ học được gì từ việc cha rửa bát?', 'Sự phân công việc nhà giữa cha và mẹ là "bản thiết kế" cho hành vi xã hội của trẻ, liên quan trực tiếp đến nguy cơ bạo lực học đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-2254-8889-1773393096.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s6Oxd_5Gu1oXQ46K_G7Dug', '2026-03-20', 'admin', 484, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633173730700_50', '20.000 thuyền viên kẹt gần Hormuz nguy cơ thiếu nhu yếu phẩm', 'Gần 20.000 thủy thủ mắc kẹt trên các tàu hàng ở eo biển Hormuz đang đối mặt với nỗi lo tên lửa rơi trúng và tình trạng cạn kiệt nhu yếu phẩm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/tau-dau-1773402850-1773402875-3232-1773403067.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NTSnOJHpgEet9waOtHY1dw', '2026-03-20', 'admin', 42, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633185771800_51', 'Quy tắc ''muối tách, đường giữ'' trong nấu ăn', 'Nêm gia vị đúng thời điểm không chỉ giúp món ăn đậm đà mà còn ảnh hưởng đến độ ngon, độ giòn, độ mọng của món ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/pexelsrohanmuzafar3054690-1773-8724-2189-1773394017.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=k9GycCL6VDqIrC8odwZSsA', '2026-03-20', 'admin', 236, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633197414400_52', 'Vì sao nhiều người chỉ làm việc hiệu quả sát deadline?', 'Áp lực thời gian cận kề giúp não bộ tiết ra các hormone cảnh báo, loại bỏ sự trì hoãn và tăng cường khả năng tập trung vào công việc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/deadline-1773390004-1773390024-3813-1773390069.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=IrRI2aePlRHDe6ihst78Iw', '2026-03-20', 'admin', 467, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633209781700_53', 'Góc khuất sau vấn nạn cố tình xô đẩy ở Nhật Bản', 'Đoạn video bé gái bị xô ngã ở Tokyo đã gióng lên hồi chuông báo động về "butsukari" - vấn nạn cố tình va chạm người lạ để xả stress đang gia tăng tại Nhật Bản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/Thie-t-ke-chu-a-co-te-n-3-1773-4469-9773-1773374593.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=kmKl_9ydvAdA8gw15swzMg&t=image', '2026-03-20', 'admin', 213, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633223574000_54', 'Con trai dùng trực thăng đưa mẹ về quê', 'Mẹ nói muốn về quê, người đàn ông tên Long ở Tứ Xuyên lái trực thăng cá nhân trị giá 7 triệu tệ đưa bà về vì ôtô đã cho bạn mượn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1773272450-177327-8656-6736-1773274348.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Y9XSNVQj99QxicXvcU31fg', '2026-03-20', 'admin', 441, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633239360600_55', 'Giới siêu giàu vung tiền xây hầm trú ẩn', 'Lo ngại bất ổn toàn cầu, giới siêu giàu đang vung hàng trăm nghìn USD xây các hầm ngầm trú ẩn xa xỉ, mang lại doanh thu kỷ lục cho hãng sản xuất. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/untitled-1773333717-1773334180-5221-1773334666.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lsi1Zbgp6ky9ZkkJLntrzA', '2026-03-20', 'admin', 268, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633256150200_56', 'Chuyện tình 15 ngày của đôi vợ chồng hoán đổi giới tính', 'Từng cạn niềm tin vào tình yêu, Mộc Trà - người chuyển giới nữ và Thiên Minh - người chuyển giới nam, quyết định kết hôn sau 15 ngày quen nhau vì tìm thấy sự đồng cảm sâu sắc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-12-at-15-0-4845-1689-1773336910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zsMmkb4ZKHA4pdM_bk4JnA', '2026-03-20', 'admin', 461, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633274711100_57', 'Quy tắc ''cấm khoe mẽ'' của phố Wall', 'Việc bốn chuyên viên tài chính trẻ làm mẫu ảnh thời trang đã làm bùng nổ tranh cãi về quy tắc bất thành văn ở Phố Wall: Tuyệt đối không thu hút sự chú ý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/screen-shot-2026-03-12-at-14-5-9812-8707-1773302260.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7wMXhzX_8pLrHBKLQ_kwXw', '2026-03-20', 'admin', 363, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633292962300_58', 'Tỷ phú bánh bao ở nhà thuê, quyết không để tài sản cho con', 'Sở hữu chuỗi 5.600 cửa hàng và tài sản gần 600 triệu USD nhưng danh mục bất động sản của ông Lưu Hội Bình vẫn trống trơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/a-nh-ma-n-hi-nh-2026-03-12-lu-4281-8357-1773300992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Aibug9pmVMbPQDhOgkh3cA', '2026-03-20', 'admin', 489, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_3633311599700_59', 'Tổ bay góp tiền đưa mẹ con người phụ nữ khiếm thị về quê', 'Địu con nhỏ đi từ TP HCM về Cao Bằng, người mẹ khiếm thị được tổ tiếp viên chăm sóc và quyên tiền đặt vé xe giường nằm chặng cuối về tận nhà. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7613036872520-979f4c14b579a74-6143-5591-1773323528.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZuKH3SFTr-IeOBXRl9BZ_A', '2026-03-20', 'admin', 434, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777671124500_0', 'Thuốc giảm cân 173 USD về 54 USD - cuộc cách mạng giá từ Ấn Độ', 'Làn sóng thuốc giảm cân giá rẻ từ Ấn Độ đang tạo nên một cuộc cách mạng y tế trên toàn cầu song đặt ra những thách thức lớn về kiểm soát chất lượng và an toàn người dùng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/giam-can2-1773966197-177396623-9948-3102-1773966358.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W2a1vxNWq1ipx6Xc65LezA', '2026-03-20', 'admin', 365, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777703346800_1', 'Đũa kim loại 12 cm trong cổ họng người đàn ông suốt 8 năm', 'Các bác sĩ tại tỉnh Liêu Ninh phẫu thuật lấy thành công chiếc đũa kim loại dài 12 cm nằm sâu trong vòm miệng một người đàn ông suốt 8 năm sau khi bệnh nhân vô tình nuốt phải lúc đang ăn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/00-1773940108-1773940223-1317-1773940303.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5Jbnc7ojWtIgpa9aJp0PRQ', '2026-03-20', 'admin', 440, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777720914500_2', 'Bác sĩ cảnh báo ''bẫy tâm lý'' khiến nhiều người sập bẫy thuốc gia truyền giả', 'Bác sĩ Ngô Văn Tỵ, Khoa Ung Bướu thuộc Bệnh viện Đại học Y Hà Nội, vẫn chưa thôi ám ảnh khi nhắc lại ca trực vừa qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z4553627269963-2f6fc10ad7c154e-2394-3553-1773818309.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JHP6dnV6gDB7g0SuN0IfFw', '2026-03-20', 'admin', 144, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777741905000_3', 'Án tử rình rập từ thử thách ''ngất xỉu'' trên TikTok', 'Chị Lan, 42 tuổi, bần thần khi phát hiện trong lịch sử xem video của con trai lớp 8 là cảnh một đám trẻ đang reo hò quanh một nam sinh vừa đổ gục, co giật nhẹ trên sàn nhà. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/2-1773366911-8280-1773367913-1-4012-5941-1773619069.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=uPJ_bYzYnVJz4Nrj5NLfaw', '2026-03-20', 'admin', 160, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777766003700_4', 'Ăn nhiều protein có gây hại thận?', 'Dù một hệ thận khỏe mạnh bình thường có thể xử lý lượng protein cao, nhưng đối với người đã có tổn thương thận, việc nạp quá nhiều protein có thể tạo ra gánh nặng quá mức. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/13/screenshot-2026-03-13-at-17-49-5249-6493-1773399093.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8oIup1SXwJUBFSAV6sCjA', '2026-03-20', 'admin', 364, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777782979700_5', 'Hội chứng lão hóa sớm', 'Hội chứng lão hóa sớm là một bệnh di truyền ít gặp khiến cơ thể trẻ em lão hóa nhanh bất thường. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/15312219thg32026-1773909094-17-3502-8851-1773909116.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1ZViTDl5vGm76l27f6ueOA', '2026-03-20', 'admin', 326, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777800462600_6', 'Viêm gan B mạn tính tiến triển ung thư', 'Ông Phi, 63 tuổi, viêm gan B mạn tính 10 năm sức khỏe ổn định nên không tái khám định kỳ, nay bác sĩ chẩn đoán ung thư gan giai đoạn sớm. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/hi-nh-thumb-1773971308-1773971-9835-9750-1773971433.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=yIc_kDHhvR_xD1pvP0VGhA', '2026-03-20', 'admin', 123, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777819484600_7', 'Xạ trị ung thư hạch bạch huyết như thế nào', 'Xạ trị ung thư hạch có thể được sử dụng đơn thuần hoặc kết hợp với hóa trị để tiêu diệt các tế bào u tại chỗ, giảm triệu chứng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/20/bs-loc-1773969177-1773969197-4790-1773969316.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hvcitarrhudIM5_CDo8IIQ', '2026-03-20', 'admin', 479, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777836240700_8', '7 thói quen làm tăng đường huyết buổi sáng', 'Mức đường huyết thường xuyên tăng vào buổi sáng có thể do nhiều nguyên nhân liên quan đến giấc ngủ, vận động, ăn uống vào đêm hôm trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/screenshot-2026-03-19-at-11-12-3935-2357-1773893572.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-FXnn5-oJXtAb5_GwQ-hpg', '2026-03-20', 'admin', 408, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777855106400_9', 'Mỗi ngày hút một bao thuốc, người đàn ông đột ngột ngưng tim', 'Người đàn ông 54 tuổi, hút một gói thuốc mỗi ngày suốt 35 năm, đột ngột ngưng tim, ngưng thở sau cơn đau ngực dữ dội kéo dài 30 phút. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/can-thie-p-jpeg-1773909778-177-4989-9465-1773909960.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5EnKZgISUioE91smt6Udwg', '2026-03-20', 'admin', 166, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777934046300_10', 'Những lá thư gửi từ tương lai cho con gái của người mẹ u não', 'Mỗi sáng, khi cô con gái 4 tuổi đã đến trường, ngôi nhà trở nên yên tĩnh, Laura Mahon, 33 tuổi, lại ngồi vào bàn ăn, nén đau để viết sẵn những tấm thiệp sinh nhật cho con gái đến năm 21 tuổi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/my4-1773894972-1773895405-7175-1773895818.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=00eLQni3Lqc522YT3wqo9A', '2026-03-20', 'admin', 301, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_777960775800_11', 'Bác sĩ Trung Quốc cảnh báo 5 dấu hiệu bệnh thận giai đoạn muộn', 'Nước tiểu nhiều bọt dai dẳng, cơ thể phù nề, huyết áp tăng cao, thiếu máu và mệt mỏi kéo dài là 5 dấu hiệu cảnh báo bệnh thận đã bước sang giai đoạn muộn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/9-1773905367-1773905376-3413-1773906043.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XtIcrheZsVefXkLBNUmUpA', '2026-03-20', 'admin', 124, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778015570300_12', 'Đề xuất mở điểm chăm sóc người già ban ngày ở nhà văn hóa', 'Bộ Y tế đề xuất phát triển mô hình chăm sóc người cao tuổi tại nhà và cộng đồng, mở điểm chăm sóc ban ngày tận dụng cơ sở vật chất sẵn có như nhà văn hóa, khu thể thao thôn, tổ dân phố. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a8498-1773897410-1773897452-6863-1773897602.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MCcATBXaEiqtdXGqoxLE2w', '2026-03-20', 'admin', 77, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778040081300_13', 'Sai lầm khiến người béo phì càng nhịn ăn càng tăng cân', 'Nhiều người thừa cân tự ép xác bằng các chế độ nhịn ăn kham khổ, vô tình kích hoạt cơ chế "tiết kiệm năng lượng" của cơ thể, dẫn đến thèm ăn dữ dội và tăng trọng lượng nhanh hơn trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/15/233a1705-1773547491-2148-1773547814.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=QNa8fsyxOQ1Zn-ytkx6fKg', '2026-03-20', 'admin', 239, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778061327700_14', 'Ca ghép tạng domino đầu tiên ở Việt Nam', 'Bệnh viện Việt Đức công bố thực hiện thành công ca ghép gan domino đầu tiên tại Việt Nam, khi các bác sĩ lấy gan của người vừa nhận tạng để tiếp tục ghép cho một người khác. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/anh-chup-man-hinh-2026-03-19-l-5953-9803-1773889955.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=uE5raiv6zy9Vgo9CbNXKpw', '2026-03-20', 'admin', 392, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778083046900_15', 'Chạy thận từ tuổi 26', 'Đi khám vì mệt mỏi, chị Thi điếng người khi bác sĩ thông báo suy thận giai đoạn cuối ở tuổi 26 và bước vào hành trình vừa chống chọi với những ca lọc máu, vừa buôn bán nuôi con suốt 12 năm qua. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/dsc03583-jpg-1773831613-177383-8776-5305-1773832307.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5ymZf82fKYzb63fWdsNVjA', '2026-03-20', 'admin', 508, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778106761500_16', 'Bác sĩ Mỹ khuyến cáo 7 thói quen cần tránh sau 19h để bảo vệ trái tim', 'Chuyên gia tim mạch Sanjay Bhojraj cảnh báo những thói quen sai lầm sau 19h có thể gây tích tụ tổn thương hệ tuần hoàn, đồng thời đưa ra các giải pháp giúp bảo vệ trái tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/adobestock-276718589-1200x800-4588-9432-1773827761.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=gQUmxjLSJObZbe2Iu1H0wg', '2026-03-20', 'admin', 141, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778126542200_17', 'Thử thách giảm một cân mỡ đổi nửa cân thịt bò tại Trung Quốc', 'Hơn 2.400 người dân thành phố Vô Tích đăng ký tham gia thử thách giảm cân để quy đổi trọng lượng cơ thể sụt giảm thành các phần thịt bò, đuôi bò và lá sách. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/blujgsjcgkzgxov28r29h6slrhcdwp-3084-9216-1773851508.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cJByzTs2uf-iCO9WHvmVZw', '2026-03-20', 'admin', 309, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778145243000_18', 'Lòng trắng hay lòng đỏ trứng nhiều protein hơn?', 'Nhiều người cho rằng protein có ở lòng trắng trứng, còn lòng đỏ chủ yếu chứa chất béo song thực tế chất béo được phân bổ ở cả hai phần với tỷ lệ khá cân đối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/trungluoc-1773735015-177373503-3257-1653-1773735084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Fi6Q-5BdVlJjlX5EoICKfA', '2026-03-20', 'admin', 509, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778165049600_19', 'Bẫy ''giảm đau nhanh'' từ thuốc đông y dởm', 'Thuốc đông y pha trộn hóa chất cấm tạo ảo giác hết bệnh tức thời, khiến nhiều người bệnh mạn tính và ung thư bỏ phác đồ điều trị chuẩn mực, dẫn đến đánh mất cơ hội sống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/b68c2082-b007-4e31-b108-003eb5-2978-8056-1773807046.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6sFkX8ilu6LKEesyjWQFng', '2026-03-20', 'admin', 289, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778182405600_20', '6 bài tập đơn giản tại nhà giúp kéo dài tuổi thọ', 'Chìa khóa của sự trường thọ nằm ở những chuyển động bền bỉ như đi bộ, đi cầu thang, squat, chống đẩy, đứng một chân và plank ngay tại chính ngôi nhà của bạn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/16/screenshot-2026-03-16-at-11-02-9494-7835-1773633846.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pf_-i646or_CqCdVKZYybw', '2026-03-20', 'admin', 389, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778200513700_21', 'Chàng trai suýt mất tinh hoàn vì cố chịu đau qua đêm', 'Chủ quan chịu đựng cơn đau vùng kín qua đêm, chàng trai 20 tuổi suýt hoại tử tinh hoàn do xoắn hai vòng, may mắn được bác sĩ Bệnh viện Quân y 175 mổ cấp cứu giữ lại kịp thời. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/233a1322-1773798712-4369-1773798922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tW7TIb8iGl4-yKI-tUdxiQ', '2026-03-20', 'admin', 22, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778219587800_22', '7 ''thủ phạm'' âm thầm khiến thận yếu đi', 'Ăn quá mặn, dùng thực phẩm chế biến sẵn, uống ít nước hoặc lạm dụng thuốc giảm đau có thể tăng áp lực lên thận theo thời gian. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/an-man-1773738708-1773738913-4727-1773738927.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NOq4Iuk7VwTI41RoRpSxfQ', '2026-03-20', 'admin', 56, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778239714800_23', 'Người gặp tai biến tử vong sau tiêm chủng có thể được bồi thường hơn 100 triệu đồng', 'Bộ Y tế đề xuất người gặp tai biến khi tiêm chủng thiệt hại tính mạng có thể được bồi thường 100 triệu đồng, phí mai táng bằng 10 lần mức lương cơ sở. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/233a7795-1754481674-1773899525-6921-8614-1773901922.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fdofBhFGlUgbFwHFwI6a2w', '2026-03-20', 'admin', 406, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778265431300_24', 'Phát hiện mắc 2 loại ung thư từ triệu chứng vàng da', 'Người phụ nữ 59 tuổi vàng da, đau vùng hạ sườn kéo dài, đi khám được chẩn đoán mắc ung thư đại tràng và ung thư đường mật trong gan. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 437, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778287899600_25', 'Căn bệnh hiếm buộc bác sĩ chọn giải pháp ghép tạng domino', 'Từ dấu hiệu khó thở, các bác sĩ đã phát hiện ra căn bệnh hiếm nguy hiểm amyloidosis, giúp người đàn ông thoát cửa tử nhờ ghép đồng thời tim và gan thành công. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/img-8291-1773928219-1773928276-2399-1773928321.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GWtt0vlUJhMN1_b6wHCOVA', '2026-03-20', 'admin', 371, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778317155600_26', 'Dùng cà gai leo có giúp trị khỏi viêm gan B không?', 'Chồng tôi bị viêm gan B mạn tính, tôi tra cứu thông tin thấy dùng cà gai leo làm thuốc, giúp trị khỏi viêm gan B, có đúng không? (Đỗ Minh Hoa, 42 tuổi, Quảng Trị) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ca-gai-leo-1773916119-17739168-1342-4198-1773917298.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bkYSJaPU0S6ctMXtQqIOmw', '2026-03-20', 'admin', 307, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778347784100_27', 'Tán sỏi thận bằng ''đường hầm nhỏ'' qua da', 'Ông Đức, 66 tuổi, có viên sỏi san hô lớn ở thận trái, được bác sĩ dùng laser tán sạch sỏi qua da trong một lần. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/h2-1773912738-1773912762-9099-1773912790.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=j38JjUzg5qR3qpK893tU5Q', '2026-03-20', 'admin', 47, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778386729600_28', 'Sẹo rỗ nặng do mụn', 'Chị Bình, 42 tuổi, nhiều sẹo rỗ sâu vùng mũi và má do nặn mụn, được bác sĩ điều trị tách đáy sẹo kết hợp vi kim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/ba-c-tra-n-la-m-rf-1773906650-2435-6137-1773906761.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=0VkkZlz2OpWhquWYG-ewRA', '2026-03-20', 'admin', 460, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778413741500_29', 'Hệ thống trang thiết bị hiện đại tại Vinmec Ocean Park 2', 'Bệnh viện Đa khoa Quốc tế Vinmec Ocean Park 2 trang bị hàng loạt thiết bị y khoa tiên tiến như MRI 3.0, CT 512 lát cắt… đáp ứng nhu cầu khám chữa bệnh chuyên sâu với độ chính xác cao. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image1931552164extractword5out-975421-1773903823-1773913454.jpeg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BX_nsqPtleKJGP3xcwY0qQ', '2026-03-20', 'admin', 488, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778442056000_30', 'Tiểu đêm có phải do phì đại tuyến tiền liệt?', 'Ban đêm tôi thường đi tiểu 2-3 lần, khó tiểu, mệt mỏi. Có phải do phì đại tuyến tiền liệt không, điều trị thế nào? (Trọng Nghĩa, 55 tuổi, Đồng Nai) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/tah-8555-1-1773896092-17738961-3027-5635-1773896195.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5K75bH4lGA_9Lm7oZQauVA', '2026-03-20', 'admin', 195, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778483989600_31', '4 phương pháp điều trị rò hậu môn', 'Người bị rò hậu môn sau áp xe có thể được bác sĩ chỉ định mổ nội soi, điều trị tia laser hoặc keo sinh học. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/bs-luong-1773839125-1773839198-1501-1773839265.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mMANsiAEDnEcOmbLkYviAA', '2026-03-20', 'admin', 338, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778514107700_32', '5 khoáng chất cần thiết cho sức khỏe sinh lý nam', 'Kẽm, magie, kali, canxi, sắt tham gia vào quá trình sản xuất testosterone, duy trì sinh lý và sức khỏe nam giới. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773905181-1773905199-4800-1773905250.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=J7FYYReSZWjbjDl8OJm-8w', '2026-03-20', 'admin', 443, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778559842000_33', 'Những thói quen mỗi ngày giúp trẻ phát triển trí tuệ', 'Trẻ nên ngủ trước 22h, ăn sáng đầy đủ dinh dưỡng, duy trì thói quen đọc sách và tập thể dục mỗi ngày để phát triển trí não. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/93833d0df43141139173df329820a4-6130-7273-1773895766.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Zoshz-NkGeLp3SvTGUEs5g', '2026-03-20', 'admin', 98, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778581596000_34', 'Dấu hiệu nhận biết bệnh về mắt', 'Thay đổi màu sắc mống mắt, hai mắt không thẳng hàng hoặc khó tập trung nhìn các vật ở gần hay xa có thể cảnh báo các vấn đề về mắt. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/momat3-1773892193-1773892202-3927-1773892212.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=fX-6NRS3Zsww7n9bh7yqcg', '2026-03-20', 'admin', 443, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778625112300_35', '5 nhóm người nên hạn chế uống nước dừa', 'Người mắc tiểu đường, bệnh thận, đang dùng thuốc huyết áp hoặc có rối loạn điện giải nên hạn chế uống nước dừa để tránh ảnh hưởng sức khỏe. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/28b42ae376a74e37a5c7c694a5c3c4-1939-2018-1773891857.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=W03cZYxS8Wc_2LuiG6kP6w', '2026-03-20', 'admin', 196, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778671942000_36', 'Ba lần mắc zona thần kinh trong hai năm', 'Bà Dung, 62 tuổi, liên tiếp mắc zona thần kinh ở vùng lưng trong hai năm, lần sau nặng hơn lần trước. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/vnvc-zona-than-kinh-tai-phat-1-6377-2082-1773903517.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ot_zkYHKjIvfaOFuy5poIQ', '2026-03-20', 'admin', 138, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778695983900_37', '6 món chứa tinh bột người tiểu đường nên ăn', 'Thực phẩm giàu tinh bột phức hợp như yến mạch, ngũ cốc nguyên hạt, khoai lang giúp ổn định đường huyết và cung cấp năng lượng lâu dài cho cơ thể. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/Buoc-2-3355-1645172245-1773889121.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ApfUYyAeH9YX9pzCl6WWCw', '2026-03-20', 'admin', 144, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778721858700_38', 'Tại sao lupus ban đỏ không thể chữa khỏi?', 'Bác sĩ chẩn đoán tôi mắc lupus ban đỏ. Bệnh nguy hiểm thế nào và tại sao không thể chữa khỏi hoàn toàn? (Nguyễn Dũng, Tiền Giang) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/taan08791-1773896320-177389644-1957-7425-1773897084.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=a1vP8v6gMEZpjdw3KcbJiQ', '2026-03-20', 'admin', 315, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778747601600_39', 'Ăn mặn gây rối loạn tiền đình nặng hơn?', 'Tôi bị rối loạn tiền đình ngoại biên, được khuyên kiêng muối vì có thể làm bệnh nặng hơn, đúng không? (Lâm Phạm, 55 tuổi, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/a-nh-1773888613-1773888648-2147-1773888710.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=u8tyXq22msAo0zpUDa0uew', '2026-03-20', 'admin', 373, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778774224000_40', 'Khó thở khi nằm cảnh báo bệnh gì?', 'Tôi thường cảm thấy khó thở khi nằm xuống, có liên quan đến bệnh hô hấp không? (Nguyễn Ngân, Hà Nội) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773887515-1773887563-7123-1773887636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=olNppiTaFzjv5NtxhAoN8w', '2026-03-20', 'admin', 78, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778797449500_41', 'Dùng sóng xung kích phá vôi hóa mạch vành', 'Bà Năm, 86 tuổi, đau ngực do động mạch vành hẹp tắc, được bác sĩ phá mảng vôi hóa bằng sóng xung kích ngăn nguy cơ nhồi máu cơ tim. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881685-1773881714-3499-2887-1773881937.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8a1D0rK_oLWWS9diLy28Bw', '2026-03-20', 'admin', 182, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778826062600_42', 'Cắt toàn bộ tuyến giáp chặn ung thư', 'Bà Loan, 50 tuổi, khám sức khỏe định kỳ phát hiện nhân giáp, sinh thiết lạnh xác định ung thư xâm lấn phải cắt toàn bộ tuyến giáp. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881289-1773881336-2586-1773881408.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yXQBUpD-Igp8_EDS1wUVEA', '2026-03-20', 'admin', 371, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778843418900_43', 'Suy buồng trứng ở tuổi 24', 'Chị gái bị vô sinh nên Hồng, 24 tuổi, chủ động đi khám sức khỏe sinh sản bất ngờ phát hiện buồng trứng gần cạn kiệt như phụ nữ mãn kinh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/key1103-3-1773817056-177381708-3143-7860-1773819558.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=CavEu2B_enyj5OEFH8VNdQ', '2026-03-20', 'admin', 384, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778862357700_44', 'Kỳ tích 90 ngày giữ song thai ''dọa'' sinh cực non', 'Chị Nhung, 33 tuổi, mang song thai 24 tuần dự báo nguy cơ 90% sinh non, được bác sĩ liên khoa phối hợp giữ thai thêm ba tháng đến khi sinh an toàn. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/image001-1773881134-4834-1773881170.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1XDOjAjAXRUGNSkmDiyA0A', '2026-03-20', 'admin', 85, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778888123100_45', 'Trẻ bị lông mi mọc ngược có nguy hiểm?', 'Con tôi 5 tuổi, bị lông mi mọc ngược đâm vào mắt gây khó chịu, thường xuyên đỏ mắt. Tình trạng này có nguy hiểm và điều trị thế nào? (Trân, 31 tuổi, Long An) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/19/lo-ng-mi-mo-c-ngu-o-c-17738488-3850-2423-1773874352.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7CL5Pqz10iYGl92EJWXj0w', '2026-03-20', 'admin', 283, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778904610100_46', 'Cơn đau đầu cảnh báo sớm đột quỵ', 'Cơn đau đầu kéo dài, lúc âm ỉ, lúc dữ dội nhưng thoáng qua vài phút rồi biến mất có thể là dấu hiệu sớm đột quỵ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/z7615389058820-b770c8502777a2a-3606-1286-1773839001.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=DtpN1a4Sw8ZgN4_ZUIXC2Q', '2026-03-20', 'admin', 251, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778921992100_47', 'Ăn uống, dùng thuốc thế nào sau cắt toàn bộ tuyến giáp?', 'Tôi đã cắt toàn bộ tuyến giáp triệt căn ung thư, phải dùng hormone thay thế. Ăn uống thế nào, lưu ý gì để không ảnh hưởng hấp thu thuốc? (Quốc Bảo, TP HCM) (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/a-nh-1-1773838561-1773838575-1902-1773838656.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KiTXzuR-XhOYEsReCOHtGQ', '2026-03-20', 'admin', 105, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778937591400_48', 'Ngủ đủ giấc - cách đơn giản bảo vệ trái tim', 'Ngủ đủ giấc hỗ trợ kiểm soát huyết áp, giảm viêm, tinh thần sảng khoái, từ đó tăng cường sức khỏe tim mạch. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/86262b59886c421faa325d79d43c42-3285-5331-1773807728.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=z2yoNwuRifB21tkyO55TgA', '2026-03-20', 'admin', 358, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778953862400_49', 'Ba thói quen ít ngờ có thể gây hại não', 'Ít tiếp xúc xã hội, sống ở nơi thiếu ánh sáng và nghe nhạc to lâu dài có thể ảnh hưởng tâm trạng, trí nhớ và sức khỏe não bộ. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/geminigeneratedimage4gdeoq4gde-2334-2556-1773805576.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=6L8vpW0eIwiwb9yhfgyJEQ', '2026-03-20', 'admin', 309, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778969417300_50', 'Bé gái tử vong sau 9 giờ phát bệnh nghi do não mô cầu', 'Bé gái 10 tuổi tại Phú Quốc sốt, đau đầu, nổi ban, tím tái, khó thở, vào viện cấp cứu song không qua khỏi, nghi mắc viêm não mô cầu. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 123, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_778985700100_51', 'Hai bác sĩ ép tim cứu người ngừng thở giữa sân bóng chuyền', 'Bác sĩ Trần Văn Biên và Nguyễn Cao Việt ép tim cứu sống người đàn ông 64 tuổi ngừng tuần hoàn, ngã quỵ giữa sân khi đang đánh bóng chuyền hơi. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/eptim-1773824056-9512-1773824095.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=zKbi8S68AXzNCvOi1chXQw&t=image', '2026-03-20', 'admin', 472, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779001952800_52', 'Thử thách ''nằm một chỗ'' nhận tiền gây sốt tại Thượng Hải', 'Thí sinh tham gia thử thách ngủ được yêu cầu nằm một chỗ trong 24 giờ, không đi vệ sinh, không dùng điện thoại, máy tính để có cơ hội nhận tiền mặt cùng nhiều gói nghỉ dưỡng. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/ngu-1773821005-1773821075-3441-1773821874.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8KlVBUvBMqmynOHVIVlLoA', '2026-03-20', 'admin', 352, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779024843600_53', 'Bác sĩ chỉ ra cách ăn uống giúp kéo dài tuổi thọ', 'Silvio Garattini, nhà dược học nổi tiếng người Italy, nhận định việc tiêu thụ ít thực phẩm có thể là chìa khóa để thêm nhiều năm sống khỏe mạnh. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-17-at-14-42-3188-8472-1773733487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WtNm6z8rhaEufjF1U9dIpg', '2026-03-20', 'admin', 46, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779044995400_54', 'Hàng chục nghìn ca lao bị bỏ sót, TP HCM mở chiến dịch 100 ngày', 'TP HCM khởi động chiến dịch 100 ngày tầm soát lao chủ động bằng X-quang tích hợp AI cho 30.000 người dân có nguy cơ cao, trước tình trạng hàng chục nghìn ca bệnh bị bỏ sót. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/xn-be-nh-lao-1773813681-177381-6084-5180-1773814033.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=dhP9C3bqRRjz-Y8bvoWDCg', '2026-03-20', 'admin', 73, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779064903700_55', 'Trung Quốc chế tạo thiết bị bảo quản nội tạng hiến tặng trong nhiều ngày', 'Các nhà khoa học Trung Quốc vừa phát triển thành công hệ thống tưới máu máy đa nhiệt độ, giúp kéo dài thời gian bảo tồn nội tạng hiến tặng từ vài giờ lên nhiều ngày. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/1-1773810584-1773810598-6921-1773811859.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Mn8_w1WS1t3d0f_fsjsllg', '2026-03-20', 'admin', 319, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779085894200_56', 'Bắt bạn đời tránh thai, triệt sản vì định kiến giới sẽ bị phạt 12 triệu đồng', 'Từ ngày 1/5, cơ quan chức năng phạt tiền 10-12 triệu đồng đối với người ép buộc vợ hoặc chồng sử dụng biện pháp tránh thai, triệt sản với lý do định kiến giới. (Nguồn: VNExpress)', 'https://s1.vnecdn.net/vnexpress/restruct/i/v914/v2_2019/pc/graphics/logo.svg', '2026-03-20', 'admin', 270, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779105725800_57', 'Uống nước chanh trị gout?', 'Nhiều người truyền tai nhau uống nước chanh tươi giúp rửa bớt acid uric, có thể dùng thay thuốc điều trị gout, điều này có đúng? (Tuấn, 32 tuổi, Hà Nội). (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/c15c6f48-ced4-4429-bfb5-9455cd-5801-6593-1773760546.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=W_kjheUzq2C2ME6zHgDgBg', '2026-03-20', 'admin', 298, 'HEALTH', 1, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779124587100_58', 'Đề xuất hỗ trợ 1,5 triệu đồng sàng lọc bệnh trước và sau sinh', 'Bộ Y tế đề xuất mức chi 1,5 triệu đồng cho các dịch vụ sàng lọc phát hiện sớm bệnh bẩm sinh nhằm nâng cao chất lượng nòi giống. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/18/anh-chup-man-hinh-2026-03-18-l-5391-3509-1773799029.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0k4SOQrMVLeMurI_aXm-A', '2026-03-20', 'admin', 312, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_779143263300_59', 'Tưởng đau bụng thông thường, hóa ung thư gan giai đoạn cuối', 'Người đàn ông 55 tuổi đến viện khám do đau tức vùng hạ sườn phải suốt một tháng, chán ăn, bác sĩ chẩn đoán ung thư gan giai đoạn cuối. (Nguồn: VNExpress)', 'https://i1-suckhoe.vnecdn.net/2026/03/17/screenshot-2026-03-11-at-15-02-9133-1291-1773738650.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4LPRxOCxuzDWC9Ke0ApIMQ', '2026-03-20', 'admin', 50, 'HEALTH', 0, 1, 'Y tế');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780247526000_0', 'Viện dưỡng lão đầu tiên trên thế giới vận hành bằng robot', 'Trạm dưỡng lão tại phố Vinh Hoa, Bắc Kinh trang bị 43 loại robot từ massage, châm cứu đến pha trà, nâng cao chất lượng sống cho người cao tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-8312-6385-1773934900.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VfFn7buTa9TsExFyHzR6g', '2026-03-20', 'admin', 129, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780266829900_1', 'Người trẻ đu trend ''gặp lại mình 10 năm trước''', 'Làm video đối thoại với mình 10 năm trước, nhiều người trẻ muốn nhìn lại hành trình trưởng thành, tự chữa lành tổn thương và định hướng tương lai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/10nam2-1773913137-3708-1773913342.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SmWlJhXMhpeoM7Fve9avQw', '2026-03-20', 'admin', 202, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780288267000_2', 'Cuộc sống bế tắc vì thiếu gas của người Ấn Độ', 'Xếp hàng bốn ngày không đổi được bình gas để nấu ăn, hàng triệu gia đình Ấn Độ đang lao đao vì chuỗi cung ứng năng lượng đứt gãy. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/screen-shot-2026-03-19-at-15-4-3817-9609-1773910903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=TesnxCAAkCHU4m5yGF1yCQ', '2026-03-20', 'admin', 242, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780311470200_3', 'Vì sao nhiều người không quên được tình cũ?', 'Dưới lăng kính tâm lý học, việc chúng ta không ngừng tiếc nuối và lý tưởng hóa người yêu cũ thực chất chỉ là một "cú lừa" của não bộ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/nguoi-cu-1773906295-1773906318-6293-1773906415.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=HVjiPxxd9gacVL6Y22uXqA', '2026-03-20', 'admin', 420, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780337583000_4', 'Bi kịch của nữ giám đốc lộ chuyện ngoại tình ở đêm nhạc', 'Từng là tâm điểm chỉ trích vì nụ hôn vụng trộm với sếp, cựu giám đốc Kristin Cabot lần đầu lên tiếng về bi kịch mất trắng sự nghiệp và tiêu chuẩn kép của dư luận. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/19/a-nh-ma-n-hi-nh-2026-03-19-lu-3953-9787-1773905123.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SnVW0ZXwG0D0cs-jv11r5w', '2026-03-20', 'admin', 473, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780365511000_5', 'Lợi ích bất ngờ của người thấp bé', 'Khác với lầm tưởng cao lớn đồng nghĩa với khỏe mạnh, người có vóc dáng khiêm tốn thực chất lại ít mắc ung thư, hiếm khi gãy xương và có xu hướng sống thọ hơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-16-1-3564-4232-1773826547.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=WILYrMZI2_N_0dlS2haaeA', '2026-03-20', 'admin', 89, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780394158600_6', 'Bi kịch của những tình yêu AI', 'Tối 13/2, SkeweredKebab (nickname) đọc lại toàn bộ những cuộc hội thoại với ChatGPT để làm lễ tiễn biệt "người chồng AI" vừa bị khai tử. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-15-5-6470-2528-1773825011.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=hywduvy6fBWG60Hqv4b41Q', '2026-03-20', 'admin', 501, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780422959800_7', 'Gia đình ''siêu nhân Gao'' ở Hưng Yên gây bão mạng', 'Giữ trọn đam mê siêu nhân từ nhỏ, anh Ngọc Trung sắm trang phục siêu nhân Gao rủ vợ hóa trang, sáng tạo loạt video hài hước mang lại tiếng cười cho cộng đồng. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7606213086839-ba7d4f64bbbc508-7613-9150-1773319405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mrTZfGPqSl0KOJOxGL3Etw', '2026-03-20', 'admin', 363, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780449543000_8', 'Vụ ly hôn tỷ USD và góc khuất đời tư của chủ tịch tập đoàn SK', 'Cuộc chiến pháp lý giữa Chủ tịch tập đoàn SK Chey Tae-won và vợ cũ Roh Soh-yeong gây chấn động bởi khối tài sản khổng lồ và sự xuất hiện của "người thứ ba". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/00-1773805459-1773805465-7488-1773807993.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ma9jNQK-Y2L9EYbGcAWU3Q', '2026-03-20', 'admin', 447, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780476617500_9', 'Nhà hàng đập 600 bộ bát đĩa vì khách cho chó lên bàn ăn', 'Ông Giang, quản lý nhà hàng tại Thương Khâu (Hà Nam), đã đập bỏ 600 bộ bát đĩa và đóng cửa khử trùng quán khi phát hiện một thực khách mang chó lên bàn ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/pet-restaurant-2-1773823218-17-3022-8308-1773823607.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YJaopzEQ_wQcv0LriogkfQ', '2026-03-20', 'admin', 411, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780505414200_10', 'Nạn trộm cắp ở khu nhà giàu Mỹ', 'Từng là chốn an cư bình yên của giới tinh hoa, khu Sharon Heights (vùng vịnh San Francisco) giờ chìm trong bất an khi kẻ gian liều lĩnh đột nhập ngay lúc gia chủ đang ăn tối. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/ratio3x2-960-1773806447-177380-5965-1359-1773809180.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=XY--0saGjRWJfVzM5zTLrQ', '2026-03-20', 'admin', 268, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780534473600_11', 'Làn sóng ''nhân lực tinh hoa'' rời bỏ Israel', 'Từng coi Tel Aviv là "thiên đường công nghệ", kỹ sư Elizabeth Cohen quyết định rời đi vì không muốn sinh con giữa những tiếng còi báo động tên lửa. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-17-at-23-3-7325-4333-1773766923.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KazThb0Myl6qlnll2uVyPg', '2026-03-20', 'admin', 413, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780561582700_12', 'Cách tự học tiếng Anh của ''cô giáo nhí'' 9 tuổi', 'Từ trò chơi đóng vai cô giáo mỗi tối, bé Vân Anh khiến cộng đồng mạng bất ngờ bởi khả năng nói tiếng Anh trôi chảy và cách dạy em đầy kiên nhẫn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/va-n-anh-2-1773661730-17736617-3169-1895-1773662279.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MFZagmWNCjA_dg4MlTV1-g', '2026-03-20', 'admin', 57, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780590058800_13', 'Phát tài nhờ tờ giấy bỏ quên 30 năm', 'Đang phải sống chật vật với lương hưu eo hẹp, vợ chồng ông Sato bất ngờ thu về 68 triệu yen nhờ tìm thấy tờ biên lai mua cổ phiếu, bị bỏ quên 30 năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/co-phieu-2-jpeg-1773797809-177-3785-6774-1773797902.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T-SETu0hLWUdD-lr9bNEBQ', '2026-03-20', 'admin', 326, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780617000900_14', 'Bi kịch của thế hệ ''kiếm nhiều tiền nhưng không giàu''', 'Thu nhập 450.000 USD mỗi năm nhưng vợ chồng Alex vẫn phải ở nhà thuê, chưa trả hết nợ sinh viên và nơm nớp lo sợ thiếu tiền giữa lòng New York đắt đỏ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/screen-shot-2026-03-18-at-00-3-6865-5413-1773770804.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICLidWfdmD2K6KISqPINoQ', '2026-03-20', 'admin', 215, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780644497200_15', 'Hai chuyến đi Việt Nam ''cứu rỗi'' người phụ nữ Mỹ', 'Rơi vào trầm cảm sau khi mẹ qua đời, Lilly Hubbard quyết định quay lại Việt Nam và tìm thấy sự "chữa lành" từ tình người ấm áp ở vùng đất xa lạ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/18/lilly-2-1773802709-1773802742-4016-1773802752.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=5uQdZnsKta3M8vRTp6nZhA', '2026-03-20', 'admin', 393, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780672384700_16', 'Vì sao quần áo thể thao giặt xong vẫn hôi?', 'Ném ngay đồ tập đẫm mồ hôi vào máy giặt, dùng nhiều xà phòng hay nước xả vải là sai lầm khiến quần áo luôn bốc mùi khó chịu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/a-nh-ma-n-hi-nh-2026-03-16-lu-7904-9038-1773736876.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KXY2uWiUcoSsOpLDwHycOA', '2026-03-20', 'admin', 65, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780697308100_17', 'Bên trong nhà lắp ghép 30 m2 của tỷ phú Elon Musk', 'Mặc dù sở hữu hàng trăm tỷ USD, tỷ phú Elon Musk hiện sống trong căn nhà lắp ghép rộng 30 m2, thiếu tiện nghi đến mức mẹ ông phải ngủ ở gara. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/577333596-3394143064076672-485-6636-3102-1773724581.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=b5eyN5ibANA-m59NlkHsAQ', '2026-03-20', 'admin', 187, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780722907500_18', 'Vợ cho ''thuê'' chồng', 'Phát hiện chồng ngoại tình, cô Khun Kwang ra thỏa thuận cho nhân tình của anh thuê chồng với giá 30.000 bath mỗi tháng, tuy nhiên hợp đồng này bị luật sư cảnh báo vô hiệu. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/chatgpt-image-11-27-42-17-thg-9377-7480-1773721720.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NBqR-Rw-evtAbpk1qTmaKQ', '2026-03-20', 'admin', 122, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780753035700_19', 'Vì sao nhà chung cư ở Mỹ ngày càng ít?', 'Từng là lựa chọn an cư giá rẻ cho người trẻ Mỹ, số lượng chung cư thương mại sụt giảm mạnh do rào cản pháp lý, thuế và chi phí bảo hiểm tăng vọt. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/im-92913950-1773654144-1773671-8010-8091-1773672308.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Bm4Dwf779JQ1G3-LVfRR1w', '2026-03-20', 'admin', 161, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780809449500_20', 'Vợ 50 tuổi làm IVF chiều chồng trẻ', 'Bất chấp những đàm tiếu của dư luận, bà Pilli Cortese vẫn quyết định thụ tinh nhân tạo ở tuổi 50 để thỏa ước nguyện làm cha của người chồng kém 21 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5921-9658-1773633940.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=9Zuubwaaw2BqQmbUtn07fA', '2026-03-20', 'admin', 118, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780839696600_21', 'Bẫy thổi phồng chức danh khi tuyển dụng', 'Nhiều doanh nghiệp đang gán mác "giám đốc", "trưởng phòng" cho người lao động nhưng chỉ trả mức lương nhân viên nhằm thu hút ứng viên và tối ưu chi phí. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/tuyen-dung-jpeg-1773679492-177-2056-8763-1773681102.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KigiyGPtR51yLB_8Hefyxg', '2026-03-20', 'admin', 287, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780872914600_22', 'Dân công sở Mỹ bỏ ôtô, đạp xe, làm từ xa để né ''bão'' giá', 'Thấy giá nhiên liệu tăng vọt, Boris Kagarlitskiy quyết định cất chiếc Lexus ở nhà, lôi xe đạp cũ ra lau chùi để bắt đầu chuỗi ngày đi làm bằng sức người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/dap-xe-1773678268-1773678292-1-1377-3127-1773678449.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=w-sPfSoia-AE5rGBtpoj4Q', '2026-03-20', 'admin', 312, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780898622500_23', 'Nhan Phúc Vinh, Hà Thu tập chống đuối nước cùng 1.000 học sinh', 'Diễn viên Nhan Phúc Vinh, Á hậu Hà Thu cùng hơn 1.000 học sinh nhận biết mực nước an toàn, kỹ năng thở nước, tại workshop chống đuối nước, sáng 16/3. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/17/dsc04354-1773740071-8030-17737-9004-8642-1773765903.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A4JrUo23I3KsRgZmF6I4Lg', '2026-03-20', 'admin', 354, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780931378400_24', '3 bước đánh lừa não bộ để ngủ nhanh hơn', 'Kỹ thuật "xáo trộn nhận thức" giúp ngắt quãng dòng suy nghĩ lo âu, mô phỏng trạng thái mơ màng tự nhiên để não bộ thư giãn và dễ dàng chìm vào giấc ngủ. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/z7591758010902-c59406ff20941de-5096-4651-1773652579.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xQChxkieWCwZeML9fYn7Gg', '2026-03-20', 'admin', 291, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780955464600_25', 'Yêu 6 năm mới biết bạn gái đã có chồng con', 'Chi hơn một triệu tệ cho bạn gái trong 6 năm mặn nồng, anh Wang bàng hoàng phát hiện người yêu thực chất đã yên bề gia thất, thậm chí các con đã học cấp hai. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/577333596-3394143064076672-485-5017-9753-1773636339.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LRn0uHe2LxkLnmac08jIuw', '2026-03-20', 'admin', 354, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780975147600_26', 'Nhiều nông dân Mỹ có nguy cơ phá sản vì xung đột Trung Đông', 'Xung đột tại Trung Đông đẩy giá nhiên liệu và phân bón lên mức kỷ lục, giáng đòn mạnh vào hàng loạt trang trại, đẩy họ vào cảnh phá sản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-13-at-22-1-6679-9104-1773417216.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wNZTd6jP3YfT0zCvXMAvYg', '2026-03-20', 'admin', 147, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_780995956600_27', 'Khủng hoảng xăng dầu ''bóp nghẹt'' người nghèo châu Á', 'Xung đột ở Trung Đông gây đứt gãy nguồn cung nhiên liệu, đẩy hàng chục triệu người lao động tại châu Á vào cảnh thiếu xăng, khí đốt và sụt giảm thu nhập. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/a-nh-ma-n-hi-nh-2026-03-16-lu-7437-9899-1773631014.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=pswj5Qok0ZT1EUC6gyBi6g', '2026-03-20', 'admin', 167, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781016730400_28', 'Tụ tập - quy tắc giữ gìn tình bạn của người Đức', 'Cuộc sống bận rộn khiến nhiều mối quan hệ phai nhạt nhưng người Đức áp dụng quy tắc "Stammtisch" - những cuộc tụ họp định kỳ, đơn giản nhưng hiệu quả. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/16/stammtisch-2-1773625060-177362-4038-7784-1773625553.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lkewTZzZ2noESjRQobw1iA', '2026-03-20', 'admin', 398, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781036112900_29', 'Chàng trai Canada ''bẻ lái cuộc đời'' vì tình yêu với cô gái Việt', 'Ngay buổi hẹn đầu dưới chân tháp Tokyo, Thu Thủy đưa ra loạt tiêu chuẩn khắt khe về bạn trai, rồi dội gáo nước lạnh vào Seiwa: “Em không muốn gặp lại anh nữa”. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/img-1831-1-jpeg-1773460527-177-7354-6141-1773461950.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=mt3pi6U16KHThn4v8-hOBA', '2026-03-20', 'admin', 407, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781055704100_30', 'Ước mơ của người vợ 10 năm giữ món quà chồng chưa kịp tặng', 'Cất kỹ chiếc váy và chú gấu bông chồng mua tặng trước khi tử nạn, chị Thúy mong một ngày được trao lại cho con gái trong sự kiện trọng đại nhất đời. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/z7619839331948-d5148baa4b6833d-6407-2821-1773504440.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=RytXItajr9SLpO3H0LRM4Q', '2026-03-20', 'admin', 501, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781078237900_31', 'Cuộc đoàn tụ gượng gạo của cô gái bị vứt ở nhà vệ sinh 28 năm trước', 'Bị ông nội vứt bỏ từ lúc 2 ngày tuổi, Hong Yangli vượt nửa vòng trái đất về nhận mẹ nhưng đối diện màn đoàn tụ lạnh lẽo, dấy lên nhiều tranh cãi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/1-3-1773547826-1773547843-5092-1773548222.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=amEJ_VUF9IpG9eD0G9_PNg', '2026-03-20', 'admin', 339, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781097673500_32', 'Cụ bà 82 tuổi bị lừa kết hôn bằng 20 quả trứng', 'Cụ bà mù chữ 82 tuổi ở Hồ Nam tưởng làm giấy tờ để nhận trợ cấp 1.000 tệ và 20 quả trứng, không ngờ bị lừa ký giấy đăng ký kết hôn với người đàn ông 47 tuổi. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/00-1773543821-1773543868-7185-1773543919.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=KfEnT7aoLQ3RSBsN1-oYAw', '2026-03-20', 'admin', 504, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781118520000_33', 'Người đàn ông bị hàng loạt nhà tang lễ từ chối vì béo', 'Ở Canada, béo phì không chỉ là một bài toán khó về sức khỏe khi còn sống, mà nay lại biến thành "rào cản cuối cùng" sau khi chết. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/0-1-1773549860-1773549866-3805-1773550180.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vVbCv37mEQDizIgnTBFi5g', '2026-03-20', 'admin', 205, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781141631700_34', 'Suýt mất mạng, cặp vợ chồng hối hận vì ''bỏ phố về rừng''', 'Từng ảo tưởng về sự tuyệt vời của cuộc sống biệt lập giữa thiên nhiên, vợ chồng Jayme bừng tỉnh sau sự cố suýt mất mạng ngày sinh nở, nhận ra cái giá của sự cô độc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773464228-1773464933-3946-1773464939.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=oyCVWVQKOW3_wjd1YLbydQ', '2026-03-20', 'admin', 221, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781163694300_35', 'Đường đến giải bơi trong hồ băng của cậu bé Hà Nội', 'Trên đỉnh núi tuyết ở Neuhermsdorf, Phan Anh mặc quần bơi đứng lặng nhìn mặt hồ Altes Zollhaus bốc khói trong khi ban tổ chức luôn tay vớt những tảng băng cản đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/phan-anh-1-1773221913-4040-177-8906-6797-1773503423.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tRJ-e86PBimTvuLx8uLrLQ', '2026-03-20', 'admin', 154, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781186137600_36', 'Đánh cược mạng sống mưu sinh trong vùng chiến sự', 'Mỗi khi tiếng còi báo động vang lên, nữ giúp việc Joycee Pelayo chạy vội đến cụ ông mà cô đang chăm sóc, dìu ông lên xe lăn rồi đẩy thật nhanh xuống hầm trú ẩn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/s-1773484138-1773484220-8888-1773484945.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=SXxzNvSvE4dKP7MSqygIxA', '2026-03-20', 'admin', 240, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781208152900_37', 'Người Lạng Sơn chi hàng trăm triệu làm cỗ mời khách lạ', 'Để tán lộc và cầu may, người dân Lạng Sơn chi hàng trăm triệu đồng dựng rạp, thết đãi cỗ miễn phí cho cả khách lạ về dự hội đền Kỳ Cùng - Tả Phủ đầu năm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/6-2-1773501948-1773502444-9849-1958-9924-1773505959.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0x9NpYpx7nxQjaqa-_PsZg', '2026-03-20', 'admin', 151, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781229449500_38', 'Gần 3.000 runner chạy giữa đô thị lớn nhất Nghệ An', 'Gần 3.000 vận động viên dự giải Eco Central Park Marathon lần đầu tổ chức với cung đường xuyên qua công viên và các thảm hoa trong khu đô thị. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/15/kbd03827-1773548789-1773549037-3771-1773551974.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=F0E-9mGgNroDH6ojqizG9w', '2026-03-20', 'admin', 214, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781252617100_39', 'Thường xuyên bị nhầm là con vì kém vợ 23 tuổi', 'Bất chấp khoảng cách 23 tuổi và hay bị nhầm là mẹ con, cặp đôi Azmirullah (28 tuổi) và Wan Nazihah (51 tuổi) vẫn có cuộc sống viên mãn sau gần 7 năm kết hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-5511-1481-1773391224.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rVhmD8KwmfMyFVajva3Fg', '2026-03-20', 'admin', 378, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781270714800_40', 'Cả nhà bới 10 tấn rác tìm túi vàng', 'Gia đình 8 người ở Giang Tây phải thức trắng đêm, lục tung 10 tấn rác để tìm lại túi vàng trị giá 1,5 triệu tệ (5,2 tỷ đồng) bị người nhà vứt nhầm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/chatgpt-image-12-00-22-14-thg-6372-9837-1773467256.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=_9x4DRlTKFjkiC60B2o8FA', '2026-03-20', 'admin', 105, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781288159700_41', 'Vì sao không cần ''ra khỏi phòng là tắt đèn''?', 'Lời khuyên "ra khỏi phòng là tắt đèn" đã lỗi thời trong kỷ nguyên bóng đèn LED, nhưng vẫn áp dụng đúng quy tắc 15 phút với đèn huỳnh quang. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/1-1773454941-1773455346-9660-1773455690.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bdkGsflc9Jxr6O6pwJzT-A', '2026-03-20', 'admin', 142, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781305705900_42', 'Những cuộc hôn nhân tan vỡ vì trúng độc đắc', 'Trúng thưởng hàng chục triệu USD, nhiều cặp vợ chồng ngỡ đã chạm tay vào hạnh phúc viên mãn nhưng cuối cùng lại rơi vào cảnh ngoại tình, kiện tụng và ly hôn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/screen-shot-2026-03-14-at-00-3-2966-9237-1773423562.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zp535HhmTaj7GmpNZEZnIw', '2026-03-20', 'admin', 429, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781324781500_43', 'Dubai vắng vẻ ''chưa từng thấy''', 'Dưới sức ép từ các đợt tấn công của Iran, người nước ngoài đang vội vã rời khỏi Dubai, đẩy "thành phố vàng" vào cảnh vắng lặng như thị trấn ma. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/untitled-1773453416-1773453692-9708-1773453849.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vbalNxj_XueEp65nAOLXcA', '2026-03-20', 'admin', 169, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781340431000_44', 'Chàng trai không tay và những món ăn ''triệu view''', 'Mất đôi tay sau tai nạn, Trọng Định, 23 tuổi, học cách nấu ăn bằng chân và hai mỏm cụt, biến nỗi đau thành nghị lực sống truyền cảm hứng cho hàng triệu người. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/di-nh-di-cho-1773409298-177340-4382-8632-1773422430.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0DityHvFbLGR7izILlXGOQ', '2026-03-20', 'admin', 104, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781358277900_45', 'Dùng AI tạo ''chuyên gia giả'' để trị thói giục cưới của cha mẹ', 'Mệt mỏi vì bị cha mẹ liên tục giục lấy chồng, Cao Mei, 38 tuổi, dùng AI tạo ra một "chuyên gia tâm lý" để giảng đạo lý, thuyết phục ngược lại phụ huynh. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/0-1773398662-1773398682-1718-1773399208.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EVMDlFbSybo3mN85hxNoWg', '2026-03-20', 'admin', 475, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781374836700_46', 'Đổ xô mua nhà thờ cũ làm nhà ở', 'Giữa "bão" giá bất động sản, nhiều người chọn mua các nhà thờ cũ với giá rẻ để cải tạo thành không gian sống độc đáo. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/a-nh-ma-n-hi-nh-2026-03-13-lu-3696-4834-1773377205.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SH7Rb4ILOv0ksxLF-wv1NQ', '2026-03-20', 'admin', 129, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781392948400_47', 'Hơn 2.000 người mua vé sớm dự lễ hội ẩm thực Saigontourist 2026', 'Hàng nghìn vé sớm được bán trước thềm Lễ hội Văn hóa Ẩm thực Saigontourist 2026, hút 2.000 lượt đặt mua sau 10 ngày. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/14/kho-ng-khi-nga-p-tra-n-ma-u-sa-5727-7837-1773461994.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0g7XJzZGG1R1YRikkMMY9g', '2026-03-20', 'admin', 158, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781410072100_48', 'Trẻ học được gì từ việc cha rửa bát?', 'Sự phân công việc nhà giữa cha và mẹ là "bản thiết kế" cho hành vi xã hội của trẻ, liên quan trực tiếp đến nguy cơ bạo lực học đường. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/577333596-3394143064076672-485-2254-8889-1773393096.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=s6Oxd_5Gu1oXQ46K_G7Dug', '2026-03-20', 'admin', 161, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781428611500_49', '20.000 thuyền viên kẹt gần Hormuz nguy cơ thiếu nhu yếu phẩm', 'Gần 20.000 thủy thủ mắc kẹt trên các tàu hàng ở eo biển Hormuz đang đối mặt với nỗi lo tên lửa rơi trúng và tình trạng cạn kiệt nhu yếu phẩm. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/tau-dau-1773402850-1773402875-3232-1773403067.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=NTSnOJHpgEet9waOtHY1dw', '2026-03-20', 'admin', 35, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781445096400_50', 'Quy tắc ''muối tách, đường giữ'' trong nấu ăn', 'Nêm gia vị đúng thời điểm không chỉ giúp món ăn đậm đà mà còn ảnh hưởng đến độ ngon, độ giòn, độ mọng của món ăn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/pexelsrohanmuzafar3054690-1773-8724-2189-1773394017.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=k9GycCL6VDqIrC8odwZSsA', '2026-03-20', 'admin', 475, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781464165100_51', 'Vì sao nhiều người chỉ làm việc hiệu quả sát deadline?', 'Áp lực thời gian cận kề giúp não bộ tiết ra các hormone cảnh báo, loại bỏ sự trì hoãn và tăng cường khả năng tập trung vào công việc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/deadline-1773390004-1773390024-3813-1773390069.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=IrRI2aePlRHDe6ihst78Iw', '2026-03-20', 'admin', 472, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781480009100_52', 'Góc khuất sau vấn nạn cố tình xô đẩy ở Nhật Bản', 'Đoạn video bé gái bị xô ngã ở Tokyo đã gióng lên hồi chuông báo động về "butsukari" - vấn nạn cố tình va chạm người lạ để xả stress đang gia tăng tại Nhật Bản. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/Thie-t-ke-chu-a-co-te-n-3-1773-4469-9773-1773374593.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=kmKl_9ydvAdA8gw15swzMg&t=image', '2026-03-20', 'admin', 401, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781499495300_53', 'Con trai dùng trực thăng đưa mẹ về quê', 'Mẹ nói muốn về quê, người đàn ông tên Long ở Tứ Xuyên lái trực thăng cá nhân trị giá 7 triệu tệ đưa bà về vì ôtô đã cho bạn mượn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1773272450-177327-8656-6736-1773274348.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Y9XSNVQj99QxicXvcU31fg', '2026-03-20', 'admin', 143, 'HEALTH', 1, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781517506700_54', 'Giới siêu giàu vung tiền xây hầm trú ẩn', 'Lo ngại bất ổn toàn cầu, giới siêu giàu đang vung hàng trăm nghìn USD xây các hầm ngầm trú ẩn xa xỉ, mang lại doanh thu kỷ lục cho hãng sản xuất. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/untitled-1773333717-1773334180-5221-1773334666.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lsi1Zbgp6ky9ZkkJLntrzA', '2026-03-20', 'admin', 49, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781533658100_55', 'Chuyện tình 15 ngày của đôi vợ chồng hoán đổi giới tính', 'Từng cạn niềm tin vào tình yêu, Mộc Trà - người chuyển giới nữ và Thiên Minh - người chuyển giới nam, quyết định kết hôn sau 15 ngày quen nhau vì tìm thấy sự đồng cảm sâu sắc. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/13/screen-shot-2026-03-12-at-15-0-4845-1689-1773336910.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zsMmkb4ZKHA4pdM_bk4JnA', '2026-03-20', 'admin', 145, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781550465100_56', 'Quy tắc ''cấm khoe mẽ'' của phố Wall', 'Việc bốn chuyên viên tài chính trẻ làm mẫu ảnh thời trang đã làm bùng nổ tranh cãi về quy tắc bất thành văn ở Phố Wall: Tuyệt đối không thu hút sự chú ý. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/screen-shot-2026-03-12-at-14-5-9812-8707-1773302260.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7wMXhzX_8pLrHBKLQ_kwXw', '2026-03-20', 'admin', 492, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781568262600_57', 'Tỷ phú bánh bao ở nhà thuê, quyết không để tài sản cho con', 'Sở hữu chuỗi 5.600 cửa hàng và tài sản gần 600 triệu USD nhưng danh mục bất động sản của ông Lưu Hội Bình vẫn trống trơn. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/a-nh-ma-n-hi-nh-2026-03-12-lu-4281-8357-1773300992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Aibug9pmVMbPQDhOgkh3cA', '2026-03-20', 'admin', 44, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781584342800_58', 'Tổ bay góp tiền đưa mẹ con người phụ nữ khiếm thị về quê', 'Địu con nhỏ đi từ TP HCM về Cao Bằng, người mẹ khiếm thị được tổ tiếp viên chăm sóc và quyên tiền đặt vé xe giường nằm chặng cuối về tận nhà. (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/z7613036872520-979f4c14b579a74-6143-5591-1773323528.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZuKH3SFTr-IeOBXRl9BZ_A', '2026-03-20', 'admin', 105, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_HEALTH_781603369600_59', 'Ba dấu hiệu cảnh báo thịt đông lạnh đã hỏng', 'Nhiều gia đình tích trữ thịt trong tủ đá hàng tháng trời và vô tư đem chế biến dù chúng đã biến màu, nhớp nháp hay bị "bỏng lạnh". (Nguồn: VNExpress)', 'https://i1-giadinh.vnecdn.net/2026/03/12/w700d1q75cms-1-1773284849-1773-8712-1642-1773285672.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jOrSg2ECal3EmqLTWjqnSA', '2026-03-20', 'admin', 456, 'HEALTH', 0, 1, 'Dinh dưỡng');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219525433000_0', 'Ấn định thời gian tổ chức FIFA ASEAN Cup', 'Liên đoàn Bóng đá Thế giới (FIFA) đã phê duyệt kế hoạch tổ chức FIFA ASEAN Cup từ tháng 9-10/2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/AN-MUNG-VOI-CUP-VO-DICH57-2363-1773969526.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JidnBWJIvqfl2Dv9bvKkVQ', '2026-03-20', 'admin', 67, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219537458100_1', 'Cầu thủ Bayern từ chối phỏng vấn vì hết giờ làm việc', 'Filip Pavic và Deniz Ofli không trả lời phỏng vấn sau trận thắng Atalanta 4-1 ở lượt về vòng 1/8 Champions League tối 19/3 vì quá giới hạn giờ làm việc theo luật Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/image-1773967945398-1773967962-1222-8032-1773968011.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OAbrLeaaF4YcCa7BDbrymw', '2026-03-20', 'admin', 268, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219550461200_2', 'Thùy Linh vào tứ kết ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh chỉ mất 36 phút để thắng Lo Sin Yan Happy 21-12, 21-14, vào tứ kết giải cầu lông Orleans Masters, tối 19/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/thuy-linh-vo-dich10-jpg-177396-2060-5273-1773960838.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WC1v2qFlvAKogW4s3KTmlg', '2026-03-20', 'admin', 198, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219563595900_3', 'Tuyển Iran tẩy chay Mỹ nhưng vẫn dự World Cup', 'Chủ tịch LĐBĐ Iran (FFIRI) Mehdi Taj khẳng định đội tuyển nước này vẫn tham dự World Cup 2026 nhưng không muốn thi đấu tại Mỹ, khiến lịch thi đấu có thể xáo trộn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-png-1773924012-1773924022-2141-1773924048.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8T67oMfZFJdDkEG28y_uw', '2026-03-20', 'admin', 63, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219578277100_4', 'Tuyển nữ Iran được vinh danh ngày về nước', 'Đội tuyển bóng đá nữ Iran, ngoại trừ hai cầu thủ, đã về nước sau khi quá cảnh ở nhiều quốc gia, khép lại vụ việc gây chú ý tại Asian Cup nữ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-1773919073-1773919081-7375-1773919159.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vHBTQCcZgQ23NsODfnyjhA', '2026-03-20', 'admin', 363, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219591556800_5', 'Neymar ''rất buồn'' vì quyết định của Ancelotti', 'Neymar bày tỏ sự thất vọng sau khi tiếp tục bị HLV Carlo Ancelotti từ chối cho trở lại tuyển Brazil. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t081833527-1-5964-1473-1773796972.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=AtSAIHhqEbf5SswZ44u2Ng', '2026-03-20', 'admin', 28, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219605276900_6', 'WADA lùi quyết định, tránh đối đầu ông Trump trước World Cup', 'Cơ quan Phòng chống Doping Thế giới (WADA) hoãn xem xét quy định có thể dẫn tới việc cấm Tổng thống Donald Trump tham dự các sự kiện thể thao lớn, qua đó tạm tránh nguy cơ đối đầu Mỹ trước thềm World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/trump-png-1773922699-177392270-5580-2360-1773922717.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tPI61WljNUU7JS-nfrvVbg', '2026-03-20', 'admin', 246, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219618938600_7', 'Thầy cũ làm cố vấn cho Van Persie', 'HLV lừng danh Dick Advocaat sẽ làm cố vấn cho Robin Van Persie, người đang gặp thách thức trên cương vị thuyền trưởng của Feyenoord. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t123143546-1-2315-7842-1773898604.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EGRmKUov_VUr9RywpY2_YA', '2026-03-20', 'admin', 23, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219632791600_8', 'Từ chối chung bục với nhà vô địch điền kinh Mỹ vì nghi vấn doping', '14 VĐV từ chối đứng chung bục với nhà vô địch các nội dung chạy 3.000m và 5.000m nam Seth Clevenger tại giải điền kinh sinh viên Mỹ, gây tranh cãi về quyền thi đấu của anh. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdv-png-1773826186-1773826265-6895-1773826290.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=3dlRyQmZif8TQv2oOJyjFg', '2026-03-20', 'admin', 87, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219646210600_9', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-20', 'admin', 249, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219659450900_10', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-20', 'admin', 391, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219672540700_11', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-20', 'admin', 506, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219687480500_12', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-20', 'admin', 239, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219702770000_13', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-20', 'admin', 24, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219718048100_14', 'VĐV Esports Hoa Tranh: ''Ngày trở về từ SEA Games là lần đầu tiên tôi thấy bố khóc''', 'Trước khi giành HC vàng SEA Games 33, Bùi Nguyễn Hoa Tranh (1S RuuRuu) từng nghĩ đến khả năng từ bỏ con đường VĐV thể thao điện tử chuyên nghiệp vì bị bố mẹ phản đối. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/anh-4-1773897015-5035-17738994-5898-6381-1773899533.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XlTU1AR6fUvNI4kafT6cqA', '2026-03-20', 'admin', 446, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219732963500_15', 'Xuân Son: ''Tôi muốn thắng, không cần biết Malaysia bị xử thua thế nào''', 'Trước ngày hội quân cùng tuyển Việt Nam, tiền đạo nhập tịch Nguyễn Xuân Son thể hiện quyết tâm cùng đồng đội đánh bại Malaysia ở lượt về vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/nam-dinh-vo-dich-v-league-2023-1951-6365-1773892546.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Og1tfVvmaRUSNkjUexYb-A', '2026-03-20', 'admin', 114, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219747613200_16', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-20', 'admin', 97, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219760597500_17', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-20', 'admin', 266, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219773057400_18', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-20', 'admin', 121, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219785965800_19', 'Vì sao các đội bóng Anh rơi rụng ở Champions League?', 'Ngoại hạng Anh có tới sáu đội vào vòng 1/8 ở Champions League, nhưng chỉ còn Arsenal và Liverpool vào tứ kết. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/1773710180948mancityrealmadrid-2653-6959-1773757914.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=p1eLBPPG0hP-iPNgzdpC1Q', '2026-03-20', 'admin', 390, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219798776000_20', 'Messi chạm mốc 900 bàn, vẫn không cứu nổi Inter Miami', 'Đội trưởng Lionel Messi sớm ghi bàn nhưng chủ nhà Inter Miami chỉ hòa Nashville 1-1 ở lượt về vòng 1/8 CONCACAF Champions Cup, và bị loại bởi luật ghi bàn sân khách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/messi-jpeg-1773881744-17738817-5037-1960-1773882092.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hwHF05gvNVSC4Ef0nGjKNg', '2026-03-20', 'admin', 136, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219811047200_21', 'Lewandowski phá một kỷ lục của Messi', 'Robert Lewandowski trở thành cầu thủ ghi bàn vào lưới nhiều đội bóng khác nhau nhất tại Champion League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t074116697-1-5000-1174-1773881038.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2ngI4cwv3baoRsJpP6Nbpg', '2026-03-20', 'admin', 59, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219823751600_22', 'Xác định 4 cặp tứ kết Champions League', 'ĐKVĐ PSG đại chiến Liverpool, trong khi Real Madrid đấu Bayern Munich là những cặp đấu được chờ đợi ở tứ kết Champions League mùa 2025-2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/arsenal-png-1773874075-1773874-8366-3595-1773874264.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=YpF-4_ge5FhXJnWMzGNsuA', '2026-03-20', 'admin', 217, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219836033200_23', 'Kane chạm mốc 50 bàn ở Champions League', 'Lập cú đúp trong trận Bayern thắng Atalanta 4-1 ở lượt về vòng 1/8, Harry Kane trở thành cầu thủ người Anh đầu tiên chạm mốc 50 bàn ở Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/kane1-png-1773870859-177387087-1321-5328-1773871258.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lrF0ArtaeTryRxVftXmeYA', '2026-03-20', 'admin', 419, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219849925500_24', 'Hai nữ cầu thủ Iran không đội hijab khi tập luyện tại Australia', 'Fatemeh Pasandideh và Atefeh Ramezanisadeh, hai cầu thủ xin tị nạn tại Australia, tham gia buổi tập cùng CLB Brisbane Roar mà không đội hijab - trang phục che kín từ cổ đến chân vốn bị bắt buộc theo quy định của Cộng hòa Hồi giáo Iran. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/iranPNG-1773840815-5081-1773840989.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=4fIEt2Y3tfrEr8P1tun_lw', '2026-03-20', 'admin', 84, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219863236800_25', 'Bố ''Thiên thần băng'' Alysa Liu thừa nhận sai lầm khi dạy con', 'Người cha của "Thiên thần băng" Alysa Liu thừa nhận những sai lầm trong quá khứ, khi nhìn lại hành trình đưa con gái tới đỉnh cao Olympic mùa Đông. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arthur-liu-alysa-liu-177382629-4892-6962-1773826652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W3u-0xRdIjAZBIJ5QJrzZQ', '2026-03-20', 'admin', 436, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219876929200_26', 'YouTube bắt tay FIFA phát sóng World Cup 2026', 'Thỏa thuận giữa YouTube và FIFA mở ra cách tiếp cận mới cho người hâm mộ khi cho phép phát trực tiếp một phần trận đấu, cùng nhiều nội dung độc quyền trên nền tảng video lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/fifa-png-1773775939-1773775960-2114-1773775973.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mTLltq3Bja2F22bFYvpfeg', '2026-03-20', 'admin', 404, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219890169000_27', 'Flick tránh nói khả năng Barca vô địch Champions League', 'HLV Hansi Flick duy trì thận trọng dù Barca đại thắng Newcastle 7-2 ở lượt về vòng 1/8 Champions League, tối 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/NewProject20260319T060911579-1-1339-6481-1773875561.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kHoAQi7TDUXFcr6h89ZyQg', '2026-03-20', 'admin', 196, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219904457800_28', 'Tottenham bị Atletico loại khỏi Champions League', 'Thắng 3-2 ở lượt về tối 18/3, Tottenham vẫn dừng bước ở vòng 1/8 Champions League vì thua Atletico Madrid chung cuộc 5-7. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773874559636-1773874569-6754-8611-1773874805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WXigzq_XHtDG2K8l9lNCZA', '2026-03-20', 'admin', 40, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219917941200_29', 'Liverpool đấu PSG ở tứ kết Champions League', 'Thắng Galatasaray 4-0 ở lượt về vòng 1/8, Liverpool đi tiếp tại Champions League với tổng tỷ số 4-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773872898601-1773872921-9151-5872-1773873066.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VPoCGTfzNrIzO40T4XdRA', '2026-03-20', 'admin', 271, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219931158900_30', 'Barca thắng Newcastle 7-2 ở Champions League', 'Barca thắng đội khách Newcastle 7-2 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 8-3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/barca-png-1773868979-177386900-2805-1625-1773869128.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Vsem5oeB9FuV0jTuy2_2DQ', '2026-03-20', 'admin', 58, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219944634700_31', 'Rakitic: ''Barca thời tôi lẽ ra phải giành thêm ba Champions League''', 'Trả lời phỏng vấn kênh radio Catalonia Cadena SER, cựu tiền vệ Croatia Ivan Rakitic nhìn lại thời kỳ vàng son của Barca, tiếc nuối về những cơ hội bị bỏ lỡ ở Champions League và phân tích tình hình hiện tại của thầy trò Hansi Flick. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/top-1773834422-9056-1773834524.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BjNtzP_sflZqa-6YmD-Mjg', '2026-03-20', 'admin', 505, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219958237800_32', 'Vợ chạy 10 km tưởng nhớ Diogo Jota', 'Rute Cardoso hoàn thành cuộc đua 10 km tại Porto với số áo 20, trong Ngày của Cha đầu tiên kể từ khi cố tiền đạo Liverpool Diogo Jota tử nạn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/rutePNG-1773826559-2930-1773826561.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7s8TcEYo0ktvOznkvcFIqg', '2026-03-20', 'admin', 195, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219971496200_33', 'Senegal khiếu nại khi bị tước chức vô địch châu Phi', 'Senegal tuyên bố kiện lên Tòa Trọng tài Thể thao (CAS) về việc bị tước chức vô địch châu Phi 2025, hai tháng sau khi đăng quang ở Morocco. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/senegal-sadio-mane-1773831398-9470-4714-1773831475.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7UQcAQYUPCumgb9DXiwMgQ', '2026-03-20', 'admin', 124, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1219984365800_34', 'Tốc độ - điểm tựa để Duplantis định nghĩa lại nhảy sào', 'Qua nhiều năm, Armand Duplantis tập trung tối đa vào tốc độ, tạo nên cơ chế vận động đặc biệt để 15 lần phá kỷ lục thế giới với mốc mới nhất là 6,31 m thiết lập hôm 12/3 tại Uppsala, Thụy Điển. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image-1773820570531-1773820590-6075-3474-1773821051.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=49kqAoW8YXRKEskZTYDonA', '2026-03-20', 'admin', 291, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220000000800_35', 'Chuyên gia Malaysia: ''Không được buông xuôi khi tái đấu Việt Nam''', 'Đã mất vé dự Asian Cup 2027 vì bê bối nhập tịch, nhưng chuyên gia Zulakbal Abdul Karim cho rằng Malaysia nên xem trận đấu sắp tới với Việt Nam là cơ hội gỡ gạc thể diện. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/559442709-122153351474803027-6-6606-4056-1773807723.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=w_jBT4_2sv3DRmpLwsBwAQ', '2026-03-20', 'admin', 224, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220016131600_36', 'Henry: ''CĐV trung lập không muốn Arsenal vô địch''', 'Huyền thoại Thierry Henry cảm thấy khó hiểu khi nhiều CĐV trung lập không muốn Arsenal đăng quang Ngoại hạng Anh, đồng thời lên tiếng bảo vệ lối chơi thực dụng của đội bóng dưới thời HLV Mikel Arteta. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/arsenal-png-1773750496-1773750-9517-8995-1773750527.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5eRI7k-GSroryTc-98-Txg', '2026-03-20', 'admin', 339, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220029517100_37', 'Carragher: ''Liverpool đang đánh mất bản sắc và niềm tin CĐV dưới thời Slot''', 'Cựu hậu vệ Jamie Carragher cho rằng Liverpool không chỉ đánh mất lối chơi pressing từng làm nên thương hiệu dưới thời Jurgen Klopp mà còn dần đánh mất sự ủng hộ từ khán giả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tottenham-png-1773752395-17737-1382-6361-1773752445.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tBvdxo8jIKctwoKedMDx-Q', '2026-03-20', 'admin', 501, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220042625100_38', 'AFC được đánh giá cao khi không nương tay với Malaysia', 'Nhiều tờ báo trong khu vực khen ngợi Liên đoàn bóng đá châu Á vì thẳng tay xử thua Malaysia ở vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/img-3473-1773740118-3722-1773740123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bVLAgWv6TX4y-ZOuQjnB4w', '2026-03-20', 'admin', 382, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220055292200_39', 'Thùy Linh thắng nghẹt thở ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh hạ đối thủ được đánh giá cao hơn Lin Hsiang-ti 2-1 ở trận ra quân giải cầu lông Orleans Masters, chiều 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/11-jpg-1773830995-1186-1773831360.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JfNGXkiE-GdJF-YVUI1xIA', '2026-03-20', 'admin', 47, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220068695600_40', 'Enrique bất ngờ khi PSG thắng đậm Chelsea', 'HLV Luis Enrique thừa nhận chưa từng nghĩ PSG có thể đè bẹp Chelsea với tổng tỷ số 8-2 ở vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/enrique-png-1773811580-1773811-5639-2995-1773811650.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=po-EQiJAXJnHV1MIbhu0vA', '2026-03-20', 'admin', 443, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220089305100_41', 'Flick sẽ giải nghệ sau khi rời Barca', 'HLV Hansi Flick phủ nhận đồng ý gia hạn với Barca, nhưng khẳng định đội bóng xứ Catalonia sẽ là bến đỗ cuối cùng trong sự nghiệp cầm quân. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/flick1-png-1773778564-17737786-8387-6182-1773778660.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=UV3lPCVahzoE3Zt9PxbbEA', '2026-03-20', 'admin', 87, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220103286900_42', 'Guardiola: ''Ai cũng muốn tôi bị sa thải''', 'HLV Pep Guardiola bác bỏ khả năng chia tay Man City dù bị Real Madrid loại khỏi Champions League, đồng thời tin tưởng vào triển vọng tích cực mùa tới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/pep-png-1773798800-1773798815-7191-1773798881.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=rtxOlOuaZAhTncoH24ReRg', '2026-03-20', 'admin', 496, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220121502200_43', 'Vinícius giả vờ khóc để châm chọc CĐV Man City', 'Tiền đạo Vinicius cho biết những màn mừng bàn thắng trong trận hạ Man City 2-1 ở lượt về vòng 1/8 Champions League là lời đáp trả tấm banner chế giễu anh từ mùa trước. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-png-1773792039-1773792047-1924-1773793390.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=2plZZ9Z-BT5gzPf8L3aT1w', '2026-03-20', 'admin', 297, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220140265100_44', 'Senegal bị tước chức vô địch Cup châu Phi 2026', 'Kết quả trận chung kết Cup châu Phi (AFCON) 2026 bị đảo ngược, khi chủ nhà Morocco được xử thắng 3-0 trước Senegal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773790138504-1773790163-8054-1773790485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=e5EhHcs6VXNKBStFraLlbw', '2026-03-20', 'admin', 255, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220157265500_45', 'CĐV Malaysia: ''Vụ gian lận nhập tịch là nỗi hổ thẹn quốc gia''', 'Làn sóng phẫn nộ bùng lên sau khi LĐBĐ châu Á (AFC) xử thua Malaysia 0-3 ở trận gặp Nepal và Việt Nam vì dùng cầu thủ nhập tịch không đủ tư cách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/malaysia-bi-xu-thua-1773745350-8129-9070-1773745502.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=61ulTsK_fGL0qbEZOxtOKQ', '2026-03-20', 'admin', 188, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220172139000_46', 'Siêu sao bóng bàn Trung Quốc tạo cơn sốt chuyển nhượng tại Đức', 'Fan Zhendong sẽ rời 1. FC Saarbrucken TT sau mùa giải này để gia nhập kình địch Borussia Dusseldorf, tạo nên một trong những thương vụ gây chú ý nhất của Bundesliga bóng bàn Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/zhendong-1773720139-1773720150-9937-1773720478.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KixJarScZbvUNkyUJgurtA', '2026-03-20', 'admin', 157, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220187792700_47', 'Real hạ Man City, vào tứ kết Champions League', 'Vinicius lập cú đúp giúp Real Madrid thắng 2-1 trên sân của Man City, đội phải đá thiếu người từ hiệp một ở lượt về vòng 1/8 Champions League, để đi tiếp với kết quả chung cuộc 5-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-1773788393-1773788421-8762-1773788445.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fOykQp0zSx7XL-euN6VMfw', '2026-03-20', 'admin', 63, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220200711100_48', 'PSG vùi dập Chelsea ở Champions League', 'Sau trận thắng 5-2 ở lượt đi, ĐKVĐ PSG tiếp tục đè bẹp Chelsea 3-0 ngay tại Stamford Bridge ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/psg1-png-1773787486-1773787582-5228-1773787664.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NNYls03Jvo3QkKWark4Qtg', '2026-03-20', 'admin', 438, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220213481100_49', 'Arsenal vào tứ kết Champions League', 'Arsenal thắng đội khách Leverkusen 2-0 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 3-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arsenal2-png-1773785414-177378-5607-7238-1773785517.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ws_yDnDrbPSZ6RSu3aJyuQ', '2026-03-20', 'admin', 181, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220226947700_50', '''Ngựa ô'' Bodo/Glimt bị loại khỏi Champions League', 'Thắng 3-0 từ lượt đi, nhưng Bodo/Glimt vẫn bị loại khi thua Sporting Lisbon 0-5 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773782561242-1773782577-8615-1345-1773782755.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T6CIsrQnBsmht0o3buqKWQ', '2026-03-20', 'admin', 108, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220240563300_51', 'Runner Trung Quốc bị chặn ngay trước vạch đích khi đang dẫn đầu', 'Xueji Sheng bất ngờ bị trọng tài ngăn cản ngay trước vạch đích do nhầm với người chạy half marathon, phải "về đích lại" để hoàn tất thủ tục ghi nhận kết quả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdvPNG-1773791774-1248-1773791779.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=md9z0cz3Co2j-wIP4EWpjA', '2026-03-20', 'admin', 87, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220252984800_52', 'Iran muốn dời các trận World Cup 2026 từ Mỹ sang Mexico', 'LĐBĐ Iran (FFIRI) đang bàn với FIFA chuyển các trận của đội tuyển nước này ở World Cup 2026 từ Mỹ sang quốc gia đồng chủ nhà Mexico, do những lo ngại về an toàn của các cầu thủ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/image-1773751920118-1773751934-4946-8771-1773752024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=g06qKBljyPM39QVRjhwpIA', '2026-03-20', 'admin', 443, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220265328300_53', 'Enrique: ''Câu đùa về Ngoại hạng Anh theo tôi khắp nơi''', 'HLV Luis Enrique nói câu đùa của ông về việc đánh bại các CLB Ngoại hạng Anh bị nhắc lại ở khắp nơi, khi PSG chuẩn bị tái đấu Chelsea ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/enrique-1773716464-1773716640-3320-1773716649.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=JuRfLttCMERhjkDaYEbmMA', '2026-03-20', 'admin', 453, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220277521200_54', 'Guardiola nói về ''văn hóa đón nhận thất bại'' trước thềm đại chiến Real', 'Pep Guardiola đã có những phân tích trước thềm trận lượt về Man City - Real Madrid ở vòng 1/8 Champions League, đồng thời đưa ra những chiêm nghiệm về "văn hóa đón nhận thất bại" trong thể thao. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/idjv5irrtfitraeiaqouzqasri-177-8609-2353-1773752110.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GHaNqqdTA3lETSjOvwg2vw', '2026-03-20', 'admin', 267, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220289760400_55', 'Leverkusen ra sức châm chọc Arsenal', 'Trước trận lượt đi lẫn lượt về vòng 1/8 Champions League, trang mạng xã hội chính thức của Bayer Leverkusen liên tục đăng tải các bài viết mang tính hài hước, trêu đùa đối thủ Arsenal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7629011609378-12196e04c788300-4265-4771-1773751277.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xcRrq5P1zJMGGLlmFQ7jGA', '2026-03-20', 'admin', 394, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220302176500_56', 'David Silva: ''Nếu Real thủng lưới trong 25 phút đầu, Man City sẽ có cơ hội''', 'Theo cựu danh thủ Man City David Silva, nếu chọc thủng lưới Real Madrid sớm, Man City sẽ có cơ hội lật ngược thế cờ sau khi thua 0-3 ở lượt đi vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/courtois-1773750600-1773750655-7749-1871-1773750912.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zOs8AH1FGSS7W7yjXb4GJA', '2026-03-20', 'admin', 407, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220314752200_57', 'Hai tuyển thủ eSports Thái Lan bị giam 3 tháng vì gian lận tại SEA Games', 'Sáng 17/3, tòa án quận Pathum Wan, Bangkok tuyên 6 tháng tù với Tokyogurl và Cheerio vì gian lận thi đấu tại SEA Games 33, nhưng giảm còn 3 tháng giam giữ do nhận tội. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tokyogurl-png-1773741329-17737-9236-3266-1773741471.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1xskZ9TIuyxAg2hn8Nzjkw', '2026-03-20', 'admin', 389, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220326981100_58', 'Việt kiều Croatia được đôn lên U23 Việt Nam', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, được đôn từ đội tuyển U19 lên U23 Việt Nam để ban huấn luyện đánh giá khả năng. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7630059415036-96db7a349004a0d-6837-4270-1773745617.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-g6RkAXzhB_htlIhsyapCw', '2026-03-20', 'admin', 166, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1220339888400_59', 'Ancelotti: ''Real thời Mbappe cần thời gian để tạo nên di sản riêng''', 'Trả lời Radio Marca, cựu HLV Real Madrid Carlo Ancelotti kể về những tháng đầu dẫn dắt tuyển Brazil, quan hệ với đội bóng cũ, sự tiến hóa của bóng đá và cái nhìn về những học trò cũ như Mbappe, Vinicius hay Fede Valverde. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/download-11-1773738753-1773738-2303-4952-1773738784.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eZdhblJJcYn-9YBYl1v4nA', '2026-03-20', 'admin', 319, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156405131600_0', 'Ấn định thời gian tổ chức FIFA ASEAN Cup', 'Liên đoàn Bóng đá Thế giới (FIFA) đã phê duyệt kế hoạch tổ chức FIFA ASEAN Cup từ tháng 9-10/2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/AN-MUNG-VOI-CUP-VO-DICH57-2363-1773969526.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JidnBWJIvqfl2Dv9bvKkVQ', '2026-03-20', 'admin', 301, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156419136800_1', 'Cầu thủ Bayern từ chối phỏng vấn vì hết giờ làm việc', 'Filip Pavic và Deniz Ofli không trả lời phỏng vấn sau trận thắng Atalanta 4-1 ở lượt về vòng 1/8 Champions League tối 19/3 vì quá giới hạn giờ làm việc theo luật Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/image-1773967945398-1773967962-1222-8032-1773968011.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OAbrLeaaF4YcCa7BDbrymw', '2026-03-20', 'admin', 179, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156438061000_2', 'Thùy Linh vào tứ kết ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh chỉ mất 36 phút để thắng Lo Sin Yan Happy 21-12, 21-14, vào tứ kết giải cầu lông Orleans Masters, tối 19/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/thuy-linh-vo-dich10-jpg-177396-2060-5273-1773960838.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WC1v2qFlvAKogW4s3KTmlg', '2026-03-20', 'admin', 271, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156451807300_3', 'Tuyển Iran tẩy chay Mỹ nhưng vẫn dự World Cup', 'Chủ tịch LĐBĐ Iran (FFIRI) Mehdi Taj khẳng định đội tuyển nước này vẫn tham dự World Cup 2026 nhưng không muốn thi đấu tại Mỹ, khiến lịch thi đấu có thể xáo trộn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-png-1773924012-1773924022-2141-1773924048.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8T67oMfZFJdDkEG28y_uw', '2026-03-20', 'admin', 426, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156465475000_4', 'Tuyển nữ Iran được vinh danh ngày về nước', 'Đội tuyển bóng đá nữ Iran, ngoại trừ hai cầu thủ, đã về nước sau khi quá cảnh ở nhiều quốc gia, khép lại vụ việc gây chú ý tại Asian Cup nữ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-1773919073-1773919081-7375-1773919159.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vHBTQCcZgQ23NsODfnyjhA', '2026-03-20', 'admin', 385, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156479684300_5', 'Neymar ''rất buồn'' vì quyết định của Ancelotti', 'Neymar bày tỏ sự thất vọng sau khi tiếp tục bị HLV Carlo Ancelotti từ chối cho trở lại tuyển Brazil. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t081833527-1-5964-1473-1773796972.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=AtSAIHhqEbf5SswZ44u2Ng', '2026-03-20', 'admin', 476, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156493457800_6', 'WADA lùi quyết định, tránh đối đầu ông Trump trước World Cup', 'Cơ quan Phòng chống Doping Thế giới (WADA) hoãn xem xét quy định có thể dẫn tới việc cấm Tổng thống Donald Trump tham dự các sự kiện thể thao lớn, qua đó tạm tránh nguy cơ đối đầu Mỹ trước thềm World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/trump-png-1773922699-177392270-5580-2360-1773922717.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tPI61WljNUU7JS-nfrvVbg', '2026-03-20', 'admin', 80, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156507492800_7', 'Thầy cũ làm cố vấn cho Van Persie', 'HLV lừng danh Dick Advocaat sẽ làm cố vấn cho Robin Van Persie, người đang gặp thách thức trên cương vị thuyền trưởng của Feyenoord. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t123143546-1-2315-7842-1773898604.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EGRmKUov_VUr9RywpY2_YA', '2026-03-20', 'admin', 123, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156521962600_8', 'Từ chối chung bục với nhà vô địch điền kinh Mỹ vì nghi vấn doping', '14 VĐV từ chối đứng chung bục với nhà vô địch các nội dung chạy 3.000m và 5.000m nam Seth Clevenger tại giải điền kinh sinh viên Mỹ, gây tranh cãi về quyền thi đấu của anh. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdv-png-1773826186-1773826265-6895-1773826290.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=3dlRyQmZif8TQv2oOJyjFg', '2026-03-20', 'admin', 365, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156535402900_9', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-20', 'admin', 318, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156549271600_10', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-20', 'admin', 396, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156563050600_11', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-20', 'admin', 32, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156578524800_12', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-20', 'admin', 200, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156592231000_13', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-20', 'admin', 109, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156605956500_14', 'VĐV Esports Hoa Tranh: ''Ngày trở về từ SEA Games là lần đầu tiên tôi thấy bố khóc''', 'Trước khi giành HC vàng SEA Games 33, Bùi Nguyễn Hoa Tranh (1S RuuRuu) từng nghĩ đến khả năng từ bỏ con đường VĐV thể thao điện tử chuyên nghiệp vì bị bố mẹ phản đối. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/anh-4-1773897015-5035-17738994-5898-6381-1773899533.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XlTU1AR6fUvNI4kafT6cqA', '2026-03-20', 'admin', 175, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156619930700_15', 'Xuân Son: ''Tôi muốn thắng, không cần biết Malaysia bị xử thua thế nào''', 'Trước ngày hội quân cùng tuyển Việt Nam, tiền đạo nhập tịch Nguyễn Xuân Son thể hiện quyết tâm cùng đồng đội đánh bại Malaysia ở lượt về vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/nam-dinh-vo-dich-v-league-2023-1951-6365-1773892546.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Og1tfVvmaRUSNkjUexYb-A', '2026-03-20', 'admin', 122, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156634016700_16', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-20', 'admin', 278, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156648255400_17', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-20', 'admin', 89, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156663463200_18', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-20', 'admin', 275, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156678107900_19', 'Vì sao các đội bóng Anh rơi rụng ở Champions League?', 'Ngoại hạng Anh có tới sáu đội vào vòng 1/8 ở Champions League, nhưng chỉ còn Arsenal và Liverpool vào tứ kết. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/1773710180948mancityrealmadrid-2653-6959-1773757914.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=p1eLBPPG0hP-iPNgzdpC1Q', '2026-03-20', 'admin', 71, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156691005400_20', 'Messi chạm mốc 900 bàn, vẫn không cứu nổi Inter Miami', 'Đội trưởng Lionel Messi sớm ghi bàn nhưng chủ nhà Inter Miami chỉ hòa Nashville 1-1 ở lượt về vòng 1/8 CONCACAF Champions Cup, và bị loại bởi luật ghi bàn sân khách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/messi-jpeg-1773881744-17738817-5037-1960-1773882092.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hwHF05gvNVSC4Ef0nGjKNg', '2026-03-20', 'admin', 456, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156705336500_21', 'Lewandowski phá một kỷ lục của Messi', 'Robert Lewandowski trở thành cầu thủ ghi bàn vào lưới nhiều đội bóng khác nhau nhất tại Champion League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t074116697-1-5000-1174-1773881038.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2ngI4cwv3baoRsJpP6Nbpg', '2026-03-20', 'admin', 253, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156720036000_22', 'Xác định 4 cặp tứ kết Champions League', 'ĐKVĐ PSG đại chiến Liverpool, trong khi Real Madrid đấu Bayern Munich là những cặp đấu được chờ đợi ở tứ kết Champions League mùa 2025-2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/arsenal-png-1773874075-1773874-8366-3595-1773874264.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=YpF-4_ge5FhXJnWMzGNsuA', '2026-03-20', 'admin', 462, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156741461500_23', 'Kane chạm mốc 50 bàn ở Champions League', 'Lập cú đúp trong trận Bayern thắng Atalanta 4-1 ở lượt về vòng 1/8, Harry Kane trở thành cầu thủ người Anh đầu tiên chạm mốc 50 bàn ở Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/kane1-png-1773870859-177387087-1321-5328-1773871258.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lrF0ArtaeTryRxVftXmeYA', '2026-03-20', 'admin', 87, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156762747900_24', 'Hai nữ cầu thủ Iran không đội hijab khi tập luyện tại Australia', 'Fatemeh Pasandideh và Atefeh Ramezanisadeh, hai cầu thủ xin tị nạn tại Australia, tham gia buổi tập cùng CLB Brisbane Roar mà không đội hijab - trang phục che kín từ cổ đến chân vốn bị bắt buộc theo quy định của Cộng hòa Hồi giáo Iran. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/iranPNG-1773840815-5081-1773840989.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=4fIEt2Y3tfrEr8P1tun_lw', '2026-03-20', 'admin', 210, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156783839800_25', 'Bố ''Thiên thần băng'' Alysa Liu thừa nhận sai lầm khi dạy con', 'Người cha của "Thiên thần băng" Alysa Liu thừa nhận những sai lầm trong quá khứ, khi nhìn lại hành trình đưa con gái tới đỉnh cao Olympic mùa Đông. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arthur-liu-alysa-liu-177382629-4892-6962-1773826652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W3u-0xRdIjAZBIJ5QJrzZQ', '2026-03-20', 'admin', 436, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156798786800_26', 'YouTube bắt tay FIFA phát sóng World Cup 2026', 'Thỏa thuận giữa YouTube và FIFA mở ra cách tiếp cận mới cho người hâm mộ khi cho phép phát trực tiếp một phần trận đấu, cùng nhiều nội dung độc quyền trên nền tảng video lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/fifa-png-1773775939-1773775960-2114-1773775973.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mTLltq3Bja2F22bFYvpfeg', '2026-03-20', 'admin', 393, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156812750700_27', 'Flick tránh nói khả năng Barca vô địch Champions League', 'HLV Hansi Flick duy trì thận trọng dù Barca đại thắng Newcastle 7-2 ở lượt về vòng 1/8 Champions League, tối 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/NewProject20260319T060911579-1-1339-6481-1773875561.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kHoAQi7TDUXFcr6h89ZyQg', '2026-03-20', 'admin', 397, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156827828700_28', 'Tottenham bị Atletico loại khỏi Champions League', 'Thắng 3-2 ở lượt về tối 18/3, Tottenham vẫn dừng bước ở vòng 1/8 Champions League vì thua Atletico Madrid chung cuộc 5-7. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773874559636-1773874569-6754-8611-1773874805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WXigzq_XHtDG2K8l9lNCZA', '2026-03-20', 'admin', 169, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156841311600_29', 'Liverpool đấu PSG ở tứ kết Champions League', 'Thắng Galatasaray 4-0 ở lượt về vòng 1/8, Liverpool đi tiếp tại Champions League với tổng tỷ số 4-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773872898601-1773872921-9151-5872-1773873066.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VPoCGTfzNrIzO40T4XdRA', '2026-03-20', 'admin', 126, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156854871700_30', 'Barca thắng Newcastle 7-2 ở Champions League', 'Barca thắng đội khách Newcastle 7-2 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 8-3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/barca-png-1773868979-177386900-2805-1625-1773869128.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Vsem5oeB9FuV0jTuy2_2DQ', '2026-03-20', 'admin', 425, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156868421000_31', 'Rakitic: ''Barca thời tôi lẽ ra phải giành thêm ba Champions League''', 'Trả lời phỏng vấn kênh radio Catalonia Cadena SER, cựu tiền vệ Croatia Ivan Rakitic nhìn lại thời kỳ vàng son của Barca, tiếc nuối về những cơ hội bị bỏ lỡ ở Champions League và phân tích tình hình hiện tại của thầy trò Hansi Flick. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/top-1773834422-9056-1773834524.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BjNtzP_sflZqa-6YmD-Mjg', '2026-03-20', 'admin', 38, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156881640500_32', 'Vợ chạy 10 km tưởng nhớ Diogo Jota', 'Rute Cardoso hoàn thành cuộc đua 10 km tại Porto với số áo 20, trong Ngày của Cha đầu tiên kể từ khi cố tiền đạo Liverpool Diogo Jota tử nạn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/rutePNG-1773826559-2930-1773826561.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7s8TcEYo0ktvOznkvcFIqg', '2026-03-20', 'admin', 420, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156895610500_33', 'Senegal khiếu nại khi bị tước chức vô địch châu Phi', 'Senegal tuyên bố kiện lên Tòa Trọng tài Thể thao (CAS) về việc bị tước chức vô địch châu Phi 2025, hai tháng sau khi đăng quang ở Morocco. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/senegal-sadio-mane-1773831398-9470-4714-1773831475.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7UQcAQYUPCumgb9DXiwMgQ', '2026-03-20', 'admin', 150, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156909419200_34', 'Tốc độ - điểm tựa để Duplantis định nghĩa lại nhảy sào', 'Qua nhiều năm, Armand Duplantis tập trung tối đa vào tốc độ, tạo nên cơ chế vận động đặc biệt để 15 lần phá kỷ lục thế giới với mốc mới nhất là 6,31 m thiết lập hôm 12/3 tại Uppsala, Thụy Điển. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image-1773820570531-1773820590-6075-3474-1773821051.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=49kqAoW8YXRKEskZTYDonA', '2026-03-20', 'admin', 170, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156922656500_35', 'Chuyên gia Malaysia: ''Không được buông xuôi khi tái đấu Việt Nam''', 'Đã mất vé dự Asian Cup 2027 vì bê bối nhập tịch, nhưng chuyên gia Zulakbal Abdul Karim cho rằng Malaysia nên xem trận đấu sắp tới với Việt Nam là cơ hội gỡ gạc thể diện. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/559442709-122153351474803027-6-6606-4056-1773807723.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=w_jBT4_2sv3DRmpLwsBwAQ', '2026-03-20', 'admin', 159, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156936002500_36', 'Henry: ''CĐV trung lập không muốn Arsenal vô địch''', 'Huyền thoại Thierry Henry cảm thấy khó hiểu khi nhiều CĐV trung lập không muốn Arsenal đăng quang Ngoại hạng Anh, đồng thời lên tiếng bảo vệ lối chơi thực dụng của đội bóng dưới thời HLV Mikel Arteta. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/arsenal-png-1773750496-1773750-9517-8995-1773750527.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5eRI7k-GSroryTc-98-Txg', '2026-03-20', 'admin', 106, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156949293200_37', 'Carragher: ''Liverpool đang đánh mất bản sắc và niềm tin CĐV dưới thời Slot''', 'Cựu hậu vệ Jamie Carragher cho rằng Liverpool không chỉ đánh mất lối chơi pressing từng làm nên thương hiệu dưới thời Jurgen Klopp mà còn dần đánh mất sự ủng hộ từ khán giả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tottenham-png-1773752395-17737-1382-6361-1773752445.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tBvdxo8jIKctwoKedMDx-Q', '2026-03-20', 'admin', 67, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156962888900_38', 'AFC được đánh giá cao khi không nương tay với Malaysia', 'Nhiều tờ báo trong khu vực khen ngợi Liên đoàn bóng đá châu Á vì thẳng tay xử thua Malaysia ở vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/img-3473-1773740118-3722-1773740123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bVLAgWv6TX4y-ZOuQjnB4w', '2026-03-20', 'admin', 419, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156975916900_39', 'Thùy Linh thắng nghẹt thở ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh hạ đối thủ được đánh giá cao hơn Lin Hsiang-ti 2-1 ở trận ra quân giải cầu lông Orleans Masters, chiều 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/11-jpg-1773830995-1186-1773831360.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JfNGXkiE-GdJF-YVUI1xIA', '2026-03-20', 'admin', 221, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_156989512600_40', 'Enrique bất ngờ khi PSG thắng đậm Chelsea', 'HLV Luis Enrique thừa nhận chưa từng nghĩ PSG có thể đè bẹp Chelsea với tổng tỷ số 8-2 ở vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/enrique-png-1773811580-1773811-5639-2995-1773811650.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=po-EQiJAXJnHV1MIbhu0vA', '2026-03-20', 'admin', 451, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157002112500_41', 'Flick sẽ giải nghệ sau khi rời Barca', 'HLV Hansi Flick phủ nhận đồng ý gia hạn với Barca, nhưng khẳng định đội bóng xứ Catalonia sẽ là bến đỗ cuối cùng trong sự nghiệp cầm quân. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/flick1-png-1773778564-17737786-8387-6182-1773778660.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=UV3lPCVahzoE3Zt9PxbbEA', '2026-03-20', 'admin', 168, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157015107800_42', 'Guardiola: ''Ai cũng muốn tôi bị sa thải''', 'HLV Pep Guardiola bác bỏ khả năng chia tay Man City dù bị Real Madrid loại khỏi Champions League, đồng thời tin tưởng vào triển vọng tích cực mùa tới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/pep-png-1773798800-1773798815-7191-1773798881.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=rtxOlOuaZAhTncoH24ReRg', '2026-03-20', 'admin', 100, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157029330900_43', 'Vinícius giả vờ khóc để châm chọc CĐV Man City', 'Tiền đạo Vinicius cho biết những màn mừng bàn thắng trong trận hạ Man City 2-1 ở lượt về vòng 1/8 Champions League là lời đáp trả tấm banner chế giễu anh từ mùa trước. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-png-1773792039-1773792047-1924-1773793390.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=2plZZ9Z-BT5gzPf8L3aT1w', '2026-03-20', 'admin', 61, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157043444400_44', 'Senegal bị tước chức vô địch Cup châu Phi 2026', 'Kết quả trận chung kết Cup châu Phi (AFCON) 2026 bị đảo ngược, khi chủ nhà Morocco được xử thắng 3-0 trước Senegal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773790138504-1773790163-8054-1773790485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=e5EhHcs6VXNKBStFraLlbw', '2026-03-20', 'admin', 503, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157057432800_45', 'CĐV Malaysia: ''Vụ gian lận nhập tịch là nỗi hổ thẹn quốc gia''', 'Làn sóng phẫn nộ bùng lên sau khi LĐBĐ châu Á (AFC) xử thua Malaysia 0-3 ở trận gặp Nepal và Việt Nam vì dùng cầu thủ nhập tịch không đủ tư cách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/malaysia-bi-xu-thua-1773745350-8129-9070-1773745502.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=61ulTsK_fGL0qbEZOxtOKQ', '2026-03-20', 'admin', 136, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157071633000_46', 'Siêu sao bóng bàn Trung Quốc tạo cơn sốt chuyển nhượng tại Đức', 'Fan Zhendong sẽ rời 1. FC Saarbrucken TT sau mùa giải này để gia nhập kình địch Borussia Dusseldorf, tạo nên một trong những thương vụ gây chú ý nhất của Bundesliga bóng bàn Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/zhendong-1773720139-1773720150-9937-1773720478.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KixJarScZbvUNkyUJgurtA', '2026-03-20', 'admin', 126, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157087780300_47', 'Real hạ Man City, vào tứ kết Champions League', 'Vinicius lập cú đúp giúp Real Madrid thắng 2-1 trên sân của Man City, đội phải đá thiếu người từ hiệp một ở lượt về vòng 1/8 Champions League, để đi tiếp với kết quả chung cuộc 5-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-1773788393-1773788421-8762-1773788445.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fOykQp0zSx7XL-euN6VMfw', '2026-03-20', 'admin', 444, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157102701300_48', 'PSG vùi dập Chelsea ở Champions League', 'Sau trận thắng 5-2 ở lượt đi, ĐKVĐ PSG tiếp tục đè bẹp Chelsea 3-0 ngay tại Stamford Bridge ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/psg1-png-1773787486-1773787582-5228-1773787664.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NNYls03Jvo3QkKWark4Qtg', '2026-03-20', 'admin', 446, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157117262800_49', 'Arsenal vào tứ kết Champions League', 'Arsenal thắng đội khách Leverkusen 2-0 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 3-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arsenal2-png-1773785414-177378-5607-7238-1773785517.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ws_yDnDrbPSZ6RSu3aJyuQ', '2026-03-20', 'admin', 46, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157132347900_50', '''Ngựa ô'' Bodo/Glimt bị loại khỏi Champions League', 'Thắng 3-0 từ lượt đi, nhưng Bodo/Glimt vẫn bị loại khi thua Sporting Lisbon 0-5 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773782561242-1773782577-8615-1345-1773782755.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T6CIsrQnBsmht0o3buqKWQ', '2026-03-20', 'admin', 80, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157147270400_51', 'Runner Trung Quốc bị chặn ngay trước vạch đích khi đang dẫn đầu', 'Xueji Sheng bất ngờ bị trọng tài ngăn cản ngay trước vạch đích do nhầm với người chạy half marathon, phải "về đích lại" để hoàn tất thủ tục ghi nhận kết quả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdvPNG-1773791774-1248-1773791779.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=md9z0cz3Co2j-wIP4EWpjA', '2026-03-20', 'admin', 337, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157162658400_52', 'Iran muốn dời các trận World Cup 2026 từ Mỹ sang Mexico', 'LĐBĐ Iran (FFIRI) đang bàn với FIFA chuyển các trận của đội tuyển nước này ở World Cup 2026 từ Mỹ sang quốc gia đồng chủ nhà Mexico, do những lo ngại về an toàn của các cầu thủ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/image-1773751920118-1773751934-4946-8771-1773752024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=g06qKBljyPM39QVRjhwpIA', '2026-03-20', 'admin', 48, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157177350200_53', 'Enrique: ''Câu đùa về Ngoại hạng Anh theo tôi khắp nơi''', 'HLV Luis Enrique nói câu đùa của ông về việc đánh bại các CLB Ngoại hạng Anh bị nhắc lại ở khắp nơi, khi PSG chuẩn bị tái đấu Chelsea ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/enrique-1773716464-1773716640-3320-1773716649.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=JuRfLttCMERhjkDaYEbmMA', '2026-03-20', 'admin', 499, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157191211700_54', 'Guardiola nói về ''văn hóa đón nhận thất bại'' trước thềm đại chiến Real', 'Pep Guardiola đã có những phân tích trước thềm trận lượt về Man City - Real Madrid ở vòng 1/8 Champions League, đồng thời đưa ra những chiêm nghiệm về "văn hóa đón nhận thất bại" trong thể thao. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/idjv5irrtfitraeiaqouzqasri-177-8609-2353-1773752110.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GHaNqqdTA3lETSjOvwg2vw', '2026-03-20', 'admin', 314, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157204720800_55', 'Leverkusen ra sức châm chọc Arsenal', 'Trước trận lượt đi lẫn lượt về vòng 1/8 Champions League, trang mạng xã hội chính thức của Bayer Leverkusen liên tục đăng tải các bài viết mang tính hài hước, trêu đùa đối thủ Arsenal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7629011609378-12196e04c788300-4265-4771-1773751277.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xcRrq5P1zJMGGLlmFQ7jGA', '2026-03-20', 'admin', 261, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157217893200_56', 'David Silva: ''Nếu Real thủng lưới trong 25 phút đầu, Man City sẽ có cơ hội''', 'Theo cựu danh thủ Man City David Silva, nếu chọc thủng lưới Real Madrid sớm, Man City sẽ có cơ hội lật ngược thế cờ sau khi thua 0-3 ở lượt đi vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/courtois-1773750600-1773750655-7749-1871-1773750912.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zOs8AH1FGSS7W7yjXb4GJA', '2026-03-20', 'admin', 345, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157231189100_57', 'Hai tuyển thủ eSports Thái Lan bị giam 3 tháng vì gian lận tại SEA Games', 'Sáng 17/3, tòa án quận Pathum Wan, Bangkok tuyên 6 tháng tù với Tokyogurl và Cheerio vì gian lận thi đấu tại SEA Games 33, nhưng giảm còn 3 tháng giam giữ do nhận tội. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tokyogurl-png-1773741329-17737-9236-3266-1773741471.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1xskZ9TIuyxAg2hn8Nzjkw', '2026-03-20', 'admin', 318, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157245384500_58', 'Việt kiều Croatia được đôn lên U23 Việt Nam', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, được đôn từ đội tuyển U19 lên U23 Việt Nam để ban huấn luyện đánh giá khả năng. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7630059415036-96db7a349004a0d-6837-4270-1773745617.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-g6RkAXzhB_htlIhsyapCw', '2026-03-20', 'admin', 175, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_157258299300_59', 'Ancelotti: ''Real thời Mbappe cần thời gian để tạo nên di sản riêng''', 'Trả lời Radio Marca, cựu HLV Real Madrid Carlo Ancelotti kể về những tháng đầu dẫn dắt tuyển Brazil, quan hệ với đội bóng cũ, sự tiến hóa của bóng đá và cái nhìn về những học trò cũ như Mbappe, Vinicius hay Fede Valverde. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/download-11-1773738753-1773738-2303-4952-1773738784.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eZdhblJJcYn-9YBYl1v4nA', '2026-03-20', 'admin', 207, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360320_0', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-19', 'admin', 205, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360339_1', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-19', 'admin', 468, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360358_2', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-19', 'admin', 264, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360378_3', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-19', 'admin', 222, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360396_4', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-19', 'admin', 420, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360415_5', 'VĐV Esports Hoa Tranh: ''Ngày trở về từ SEA Games là lần đầu tiên tôi thấy bố khóc''', 'Trước khi giành HC vàng SEA Games 33, Bùi Nguyễn Hoa Tranh (1S RuuRuu) từng nghĩ đến khả năng từ bỏ con đường VĐV thể thao điện tử chuyên nghiệp vì bị bố mẹ phản đối. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/anh-4-1773897015-5035-17738994-5898-6381-1773899533.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XlTU1AR6fUvNI4kafT6cqA', '2026-03-19', 'admin', 354, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360434_6', 'Xuân Son: ''Tôi muốn thắng, không cần biết Malaysia bị xử thua thế nào''', 'Trước ngày hội quân cùng tuyển Việt Nam, tiền đạo nhập tịch Nguyễn Xuân Son thể hiện quyết tâm cùng đồng đội đánh bại Malaysia ở lượt về vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/nam-dinh-vo-dich-v-league-2023-1951-6365-1773892546.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Og1tfVvmaRUSNkjUexYb-A', '2026-03-19', 'admin', 474, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360453_7', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-19', 'admin', 327, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360486_8', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-19', 'admin', 426, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773935360502_9', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-19', 'admin', 379, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085002_0', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-19', 'admin', 129, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085017_1', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-19', 'admin', 76, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085033_2', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-19', 'admin', 382, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085051_3', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-19', 'admin', 298, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085067_4', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-19', 'admin', 90, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085084_5', 'VĐV Esports Hoa Tranh: ''Ngày trở về từ SEA Games là lần đầu tiên tôi thấy bố khóc''', 'Trước khi giành HC vàng SEA Games 33, Bùi Nguyễn Hoa Tranh (1S RuuRuu) từng nghĩ đến khả năng từ bỏ con đường VĐV thể thao điện tử chuyên nghiệp vì bị bố mẹ phản đối. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/anh-4-1773897015-5035-17738994-5898-6381-1773899533.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XlTU1AR6fUvNI4kafT6cqA', '2026-03-19', 'admin', 169, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085101_6', 'Xuân Son: ''Tôi muốn thắng, không cần biết Malaysia bị xử thua thế nào''', 'Trước ngày hội quân cùng tuyển Việt Nam, tiền đạo nhập tịch Nguyễn Xuân Son thể hiện quyết tâm cùng đồng đội đánh bại Malaysia ở lượt về vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/nam-dinh-vo-dich-v-league-2023-1951-6365-1773892546.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Og1tfVvmaRUSNkjUexYb-A', '2026-03-19', 'admin', 54, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085115_7', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-19', 'admin', 508, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085129_8', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-19', 'admin', 50, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936085144_9', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-19', 'admin', 392, 'SPORT', 0, 1, 'Bóng đá');
