INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936509305_7', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-19', 'admin', 331, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936509319_8', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-19', 'admin', 447, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936509343_9', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-19', 'admin', 401, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936729627_0', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-19', 'admin', 269, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936729652_1', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-19', 'admin', 400, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936729674_2', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-19', 'admin', 469, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936729697_3', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-19', 'admin', 247, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_1773936729723_4', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-19', 'admin', 439, 'SPORT', 0, 1, 'Bóng đá');
