INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309059124400_11', 'Messi chạm mốc 900 bàn, vẫn không cứu nổi Inter Miami', 'Đội trưởng Lionel Messi sớm ghi bàn nhưng chủ nhà Inter Miami chỉ hòa Nashville 1-1 ở lượt về vòng 1/8 CONCACAF Champions Cup, và bị loại bởi luật ghi bàn sân khách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/messi-jpeg-1773881744-17738817-5037-1960-1773882092.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hwHF05gvNVSC4Ef0nGjKNg', '2026-03-19', 'admin', 127, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309073581800_12', 'Lewandowski phá một kỷ lục của Messi', 'Robert Lewandowski trở thành cầu thủ ghi bàn vào lưới nhiều đội bóng khác nhau nhất tại Champion League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t074116697-1-5000-1174-1773881038.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2ngI4cwv3baoRsJpP6Nbpg', '2026-03-19', 'admin', 432, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309089318300_13', 'Xác định 4 cặp tứ kết Champions League', 'ĐKVĐ PSG đại chiến Liverpool, trong khi Real Madrid đấu Bayern Munich là những cặp đấu được chờ đợi ở tứ kết Champions League mùa 2025-2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/arsenal-png-1773874075-1773874-8366-3595-1773874264.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=YpF-4_ge5FhXJnWMzGNsuA', '2026-03-19', 'admin', 104, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309105759000_14', 'Kane chạm mốc 50 bàn ở Champions League', 'Lập cú đúp trong trận Bayern thắng Atalanta 4-1 ở lượt về vòng 1/8, Harry Kane trở thành cầu thủ người Anh đầu tiên chạm mốc 50 bàn ở Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/kane1-png-1773870859-177387087-1321-5328-1773871258.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lrF0ArtaeTryRxVftXmeYA', '2026-03-19', 'admin', 487, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309120458900_15', 'Hai nữ cầu thủ Iran không đội hijab khi tập luyện tại Australia', 'Fatemeh Pasandideh và Atefeh Ramezanisadeh, hai cầu thủ xin tị nạn tại Australia, tham gia buổi tập cùng CLB Brisbane Roar mà không đội hijab - trang phục che kín từ cổ đến chân vốn bị bắt buộc theo quy định của Cộng hòa Hồi giáo Iran. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/iranPNG-1773840815-5081-1773840989.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=4fIEt2Y3tfrEr8P1tun_lw', '2026-03-19', 'admin', 123, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309135695600_16', 'Bố ''Thiên thần băng'' Alysa Liu thừa nhận sai lầm khi dạy con', 'Người cha của "Thiên thần băng" Alysa Liu thừa nhận những sai lầm trong quá khứ, khi nhìn lại hành trình đưa con gái tới đỉnh cao Olympic mùa Đông. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arthur-liu-alysa-liu-177382629-4892-6962-1773826652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W3u-0xRdIjAZBIJ5QJrzZQ', '2026-03-19', 'admin', 52, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309150078600_17', 'YouTube bắt tay FIFA phát sóng World Cup 2026', 'Thỏa thuận giữa YouTube và FIFA mở ra cách tiếp cận mới cho người hâm mộ khi cho phép phát trực tiếp một phần trận đấu, cùng nhiều nội dung độc quyền trên nền tảng video lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/fifa-png-1773775939-1773775960-2114-1773775973.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mTLltq3Bja2F22bFYvpfeg', '2026-03-19', 'admin', 119, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309164098600_18', 'Flick tránh nói khả năng Barca vô địch Champions League', 'HLV Hansi Flick duy trì thận trọng dù Barca đại thắng Newcastle 7-2 ở lượt về vòng 1/8 Champions League, tối 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/NewProject20260319T060911579-1-1339-6481-1773875561.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kHoAQi7TDUXFcr6h89ZyQg', '2026-03-19', 'admin', 481, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309178544900_19', 'Tottenham bị Atletico loại khỏi Champions League', 'Thắng 3-2 ở lượt về tối 18/3, Tottenham vẫn dừng bước ở vòng 1/8 Champions League vì thua Atletico Madrid chung cuộc 5-7. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773874559636-1773874569-6754-8611-1773874805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WXigzq_XHtDG2K8l9lNCZA', '2026-03-19', 'admin', 65, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309191881500_20', 'Liverpool đấu PSG ở tứ kết Champions League', 'Thắng Galatasaray 4-0 ở lượt về vòng 1/8, Liverpool đi tiếp tại Champions League với tổng tỷ số 4-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773872898601-1773872921-9151-5872-1773873066.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VPoCGTfzNrIzO40T4XdRA', '2026-03-19', 'admin', 466, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309204987700_21', 'Barca thắng Newcastle 7-2 ở Champions League', 'Barca thắng đội khách Newcastle 7-2 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 8-3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/barca-png-1773868979-177386900-2805-1625-1773869128.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Vsem5oeB9FuV0jTuy2_2DQ', '2026-03-19', 'admin', 256, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309218080700_22', 'Rakitic: ''Barca thời tôi lẽ ra phải giành thêm ba Champions League''', 'Trả lời phỏng vấn kênh radio Catalonia Cadena SER, cựu tiền vệ Croatia Ivan Rakitic nhìn lại thời kỳ vàng son của Barca, tiếc nuối về những cơ hội bị bỏ lỡ ở Champions League và phân tích tình hình hiện tại của thầy trò Hansi Flick. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/top-1773834422-9056-1773834524.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BjNtzP_sflZqa-6YmD-Mjg', '2026-03-19', 'admin', 322, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309231428200_23', 'Vợ chạy 10 km tưởng nhớ Diogo Jota', 'Rute Cardoso hoàn thành cuộc đua 10 km tại Porto với số áo 20, trong Ngày của Cha đầu tiên kể từ khi cố tiền đạo Liverpool Diogo Jota tử nạn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/rutePNG-1773826559-2930-1773826561.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7s8TcEYo0ktvOznkvcFIqg', '2026-03-19', 'admin', 495, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309254084200_24', 'Senegal khiếu nại khi bị tước chức vô địch châu Phi', 'Senegal tuyên bố kiện lên Tòa Trọng tài Thể thao (CAS) về việc bị tước chức vô địch châu Phi 2025, hai tháng sau khi đăng quang ở Morocco. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/senegal-sadio-mane-1773831398-9470-4714-1773831475.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7UQcAQYUPCumgb9DXiwMgQ', '2026-03-19', 'admin', 495, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309278238800_25', 'Tốc độ - điểm tựa để Duplantis định nghĩa lại nhảy sào', 'Qua nhiều năm, Armand Duplantis tập trung tối đa vào tốc độ, tạo nên cơ chế vận động đặc biệt để 15 lần phá kỷ lục thế giới với mốc mới nhất là 6,31 m thiết lập hôm 12/3 tại Uppsala, Thụy Điển. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image-1773820570531-1773820590-6075-3474-1773821051.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=49kqAoW8YXRKEskZTYDonA', '2026-03-19', 'admin', 331, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309300760700_26', 'Chuyên gia Malaysia: ''Không được buông xuôi khi tái đấu Việt Nam''', 'Đã mất vé dự Asian Cup 2027 vì bê bối nhập tịch, nhưng chuyên gia Zulakbal Abdul Karim cho rằng Malaysia nên xem trận đấu sắp tới với Việt Nam là cơ hội gỡ gạc thể diện. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/559442709-122153351474803027-6-6606-4056-1773807723.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=w_jBT4_2sv3DRmpLwsBwAQ', '2026-03-19', 'admin', 490, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309319103500_27', 'Henry: ''CĐV trung lập không muốn Arsenal vô địch''', 'Huyền thoại Thierry Henry cảm thấy khó hiểu khi nhiều CĐV trung lập không muốn Arsenal đăng quang Ngoại hạng Anh, đồng thời lên tiếng bảo vệ lối chơi thực dụng của đội bóng dưới thời HLV Mikel Arteta. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/arsenal-png-1773750496-1773750-9517-8995-1773750527.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5eRI7k-GSroryTc-98-Txg', '2026-03-19', 'admin', 186, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309336832500_28', 'Carragher: ''Liverpool đang đánh mất bản sắc và niềm tin CĐV dưới thời Slot''', 'Cựu hậu vệ Jamie Carragher cho rằng Liverpool không chỉ đánh mất lối chơi pressing từng làm nên thương hiệu dưới thời Jurgen Klopp mà còn dần đánh mất sự ủng hộ từ khán giả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tottenham-png-1773752395-17737-1382-6361-1773752445.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tBvdxo8jIKctwoKedMDx-Q', '2026-03-19', 'admin', 423, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309355515000_29', 'AFC được đánh giá cao khi không nương tay với Malaysia', 'Nhiều tờ báo trong khu vực khen ngợi Liên đoàn bóng đá châu Á vì thẳng tay xử thua Malaysia ở vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/img-3473-1773740118-3722-1773740123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bVLAgWv6TX4y-ZOuQjnB4w', '2026-03-19', 'admin', 294, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309370728300_30', 'Thùy Linh thắng nghẹt thở ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh hạ đối thủ được đánh giá cao hơn Lin Hsiang-ti 2-1 ở trận ra quân giải cầu lông Orleans Masters, chiều 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/11-jpg-1773830995-1186-1773831360.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JfNGXkiE-GdJF-YVUI1xIA', '2026-03-19', 'admin', 176, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309384399300_31', 'Enrique bất ngờ khi PSG thắng đậm Chelsea', 'HLV Luis Enrique thừa nhận chưa từng nghĩ PSG có thể đè bẹp Chelsea với tổng tỷ số 8-2 ở vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/enrique-png-1773811580-1773811-5639-2995-1773811650.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=po-EQiJAXJnHV1MIbhu0vA', '2026-03-19', 'admin', 332, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309397445000_32', 'Flick sẽ giải nghệ sau khi rời Barca', 'HLV Hansi Flick phủ nhận đồng ý gia hạn với Barca, nhưng khẳng định đội bóng xứ Catalonia sẽ là bến đỗ cuối cùng trong sự nghiệp cầm quân. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/flick1-png-1773778564-17737786-8387-6182-1773778660.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=UV3lPCVahzoE3Zt9PxbbEA', '2026-03-19', 'admin', 425, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309410983200_33', 'Guardiola: ''Ai cũng muốn tôi bị sa thải''', 'HLV Pep Guardiola bác bỏ khả năng chia tay Man City dù bị Real Madrid loại khỏi Champions League, đồng thời tin tưởng vào triển vọng tích cực mùa tới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/pep-png-1773798800-1773798815-7191-1773798881.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=rtxOlOuaZAhTncoH24ReRg', '2026-03-19', 'admin', 501, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309424912900_34', 'Vinícius giả vờ khóc để châm chọc CĐV Man City', 'Tiền đạo Vinicius cho biết những màn mừng bàn thắng trong trận hạ Man City 2-1 ở lượt về vòng 1/8 Champions League là lời đáp trả tấm banner chế giễu anh từ mùa trước. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-png-1773792039-1773792047-1924-1773793390.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=2plZZ9Z-BT5gzPf8L3aT1w', '2026-03-19', 'admin', 359, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309438919300_35', 'Senegal bị tước chức vô địch Cup châu Phi 2026', 'Kết quả trận chung kết Cup châu Phi (AFCON) 2026 bị đảo ngược, khi chủ nhà Morocco được xử thắng 3-0 trước Senegal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773790138504-1773790163-8054-1773790485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=e5EhHcs6VXNKBStFraLlbw', '2026-03-19', 'admin', 39, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309455003700_36', 'CĐV Malaysia: ''Vụ gian lận nhập tịch là nỗi hổ thẹn quốc gia''', 'Làn sóng phẫn nộ bùng lên sau khi LĐBĐ châu Á (AFC) xử thua Malaysia 0-3 ở trận gặp Nepal và Việt Nam vì dùng cầu thủ nhập tịch không đủ tư cách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/malaysia-bi-xu-thua-1773745350-8129-9070-1773745502.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=61ulTsK_fGL0qbEZOxtOKQ', '2026-03-19', 'admin', 498, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309471141200_37', 'Siêu sao bóng bàn Trung Quốc tạo cơn sốt chuyển nhượng tại Đức', 'Fan Zhendong sẽ rời 1. FC Saarbrucken TT sau mùa giải này để gia nhập kình địch Borussia Dusseldorf, tạo nên một trong những thương vụ gây chú ý nhất của Bundesliga bóng bàn Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/zhendong-1773720139-1773720150-9937-1773720478.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KixJarScZbvUNkyUJgurtA', '2026-03-19', 'admin', 325, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309485998900_38', 'Real hạ Man City, vào tứ kết Champions League', 'Vinicius lập cú đúp giúp Real Madrid thắng 2-1 trên sân của Man City, đội phải đá thiếu người từ hiệp một ở lượt về vòng 1/8 Champions League, để đi tiếp với kết quả chung cuộc 5-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-1773788393-1773788421-8762-1773788445.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fOykQp0zSx7XL-euN6VMfw', '2026-03-19', 'admin', 318, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309500562300_39', 'PSG vùi dập Chelsea ở Champions League', 'Sau trận thắng 5-2 ở lượt đi, ĐKVĐ PSG tiếp tục đè bẹp Chelsea 3-0 ngay tại Stamford Bridge ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/psg1-png-1773787486-1773787582-5228-1773787664.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NNYls03Jvo3QkKWark4Qtg', '2026-03-19', 'admin', 224, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309515295800_40', 'Arsenal vào tứ kết Champions League', 'Arsenal thắng đội khách Leverkusen 2-0 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 3-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arsenal2-png-1773785414-177378-5607-7238-1773785517.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ws_yDnDrbPSZ6RSu3aJyuQ', '2026-03-19', 'admin', 295, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309529624800_41', '''Ngựa ô'' Bodo/Glimt bị loại khỏi Champions League', 'Thắng 3-0 từ lượt đi, nhưng Bodo/Glimt vẫn bị loại khi thua Sporting Lisbon 0-5 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773782561242-1773782577-8615-1345-1773782755.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T6CIsrQnBsmht0o3buqKWQ', '2026-03-19', 'admin', 283, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309543307300_42', 'Runner Trung Quốc bị chặn ngay trước vạch đích khi đang dẫn đầu', 'Xueji Sheng bất ngờ bị trọng tài ngăn cản ngay trước vạch đích do nhầm với người chạy half marathon, phải "về đích lại" để hoàn tất thủ tục ghi nhận kết quả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdvPNG-1773791774-1248-1773791779.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=md9z0cz3Co2j-wIP4EWpjA', '2026-03-19', 'admin', 37, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309556885700_43', 'Iran muốn dời các trận World Cup 2026 từ Mỹ sang Mexico', 'LĐBĐ Iran (FFIRI) đang bàn với FIFA chuyển các trận của đội tuyển nước này ở World Cup 2026 từ Mỹ sang quốc gia đồng chủ nhà Mexico, do những lo ngại về an toàn của các cầu thủ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/image-1773751920118-1773751934-4946-8771-1773752024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=g06qKBljyPM39QVRjhwpIA', '2026-03-19', 'admin', 170, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309570270300_44', 'Enrique: ''Câu đùa về Ngoại hạng Anh theo tôi khắp nơi''', 'HLV Luis Enrique nói câu đùa của ông về việc đánh bại các CLB Ngoại hạng Anh bị nhắc lại ở khắp nơi, khi PSG chuẩn bị tái đấu Chelsea ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/enrique-1773716464-1773716640-3320-1773716649.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=JuRfLttCMERhjkDaYEbmMA', '2026-03-19', 'admin', 370, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309584388200_45', 'Guardiola nói về ''văn hóa đón nhận thất bại'' trước thềm đại chiến Real', 'Pep Guardiola đã có những phân tích trước thềm trận lượt về Man City - Real Madrid ở vòng 1/8 Champions League, đồng thời đưa ra những chiêm nghiệm về "văn hóa đón nhận thất bại" trong thể thao. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/idjv5irrtfitraeiaqouzqasri-177-8609-2353-1773752110.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GHaNqqdTA3lETSjOvwg2vw', '2026-03-19', 'admin', 478, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309596918300_46', 'Leverkusen ra sức châm chọc Arsenal', 'Trước trận lượt đi lẫn lượt về vòng 1/8 Champions League, trang mạng xã hội chính thức của Bayer Leverkusen liên tục đăng tải các bài viết mang tính hài hước, trêu đùa đối thủ Arsenal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7629011609378-12196e04c788300-4265-4771-1773751277.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xcRrq5P1zJMGGLlmFQ7jGA', '2026-03-19', 'admin', 79, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309610018100_47', 'David Silva: ''Nếu Real thủng lưới trong 25 phút đầu, Man City sẽ có cơ hội''', 'Theo cựu danh thủ Man City David Silva, nếu chọc thủng lưới Real Madrid sớm, Man City sẽ có cơ hội lật ngược thế cờ sau khi thua 0-3 ở lượt đi vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/courtois-1773750600-1773750655-7749-1871-1773750912.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zOs8AH1FGSS7W7yjXb4GJA', '2026-03-19', 'admin', 89, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309633125600_48', 'Hai tuyển thủ eSports Thái Lan bị giam 3 tháng vì gian lận tại SEA Games', 'Sáng 17/3, tòa án quận Pathum Wan, Bangkok tuyên 6 tháng tù với Tokyogurl và Cheerio vì gian lận thi đấu tại SEA Games 33, nhưng giảm còn 3 tháng giam giữ do nhận tội. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tokyogurl-png-1773741329-17737-9236-3266-1773741471.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1xskZ9TIuyxAg2hn8Nzjkw', '2026-03-19', 'admin', 484, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309653189700_49', 'Việt kiều Croatia được đôn lên U23 Việt Nam', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, được đôn từ đội tuyển U19 lên U23 Việt Nam để ban huấn luyện đánh giá khả năng. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7630059415036-96db7a349004a0d-6837-4270-1773745617.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-g6RkAXzhB_htlIhsyapCw', '2026-03-19', 'admin', 285, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309674170900_50', 'Ancelotti: ''Real thời Mbappe cần thời gian để tạo nên di sản riêng''', 'Trả lời Radio Marca, cựu HLV Real Madrid Carlo Ancelotti kể về những tháng đầu dẫn dắt tuyển Brazil, quan hệ với đội bóng cũ, sự tiến hóa của bóng đá và cái nhìn về những học trò cũ như Mbappe, Vinicius hay Fede Valverde. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/download-11-1773738753-1773738-2303-4952-1773738784.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eZdhblJJcYn-9YBYl1v4nA', '2026-03-19', 'admin', 143, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309690895700_51', 'Việt Nam áp sát Top 100 FIFA sau khi được xử thắng Malaysia', 'Việt Nam sẽ tăng 5 bậc FIFA, lên vị trí 103 thế giới, sau khi được xử thắng Malaysia 3-0 ở vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/vie-t-nam-malaysia-1773738448-3601-2582-1773738513.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1s2wBGw1HaMbsp1s6XE_AQ', '2026-03-19', 'admin', 185, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309709782300_52', 'Arteta: ''Arsenal biết phải làm gì để vào tứ kết Champions League''', 'HLV Mikel Arteta muốn Arsenal cải thiện khả năng tấn công và tận dụng lợi thế sân nhà khi tiếp Leverkusen ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/arteta-1773718113-1773718147-2755-1773718188.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=kmmlguggTeKANzeglN_XnA', '2026-03-19', 'admin', 240, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309724833400_53', 'Việt Nam giành vé sớm dự Asian Cup 2027', 'Do Malaysia bị xử thua hai trận, Việt Nam chắc chắn đứng đầu bảng F vòng loại cuối, đồng nghĩa với suất dự vòng chung kết Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/nguyen-hai-long-viet-nam-lao-v-2837-1972-1773732393.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=SAuRaBFY5ANbAkdivtrZGA', '2026-03-19', 'admin', 316, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309737582600_54', 'Malaysia bị xử thua Việt Nam 0-3', 'Malaysia bị xử thua ở các trận đã đấu với Việt Nam và Nepal ở vòng loại cuối Asian Cup 2027, do sử dụng 7 cầu thủ nhập tịch giả mạo hồ sơ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/img-3311-1773729675-3856-1773729704.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0ipL4mVGAS47Jy7AwkHa3w', '2026-03-19', 'admin', 117, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309750537100_55', 'Tiến Linh bị loại, Hoàng Hên lần đầu lên tuyển Việt Nam', 'HLV Kim Sang-sik gạch tên Nguyễn Tiến Linh và lần đầu triệu tập tiền vệ nhập tịch Đỗ Hoàng Hên, để chuẩn bị cho trận gặp Malaysia tại vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/download7-1773730769-1381-1773730774.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XBk4_7cl5aPBTLXQJsJm5Q', '2026-03-19', 'admin', 324, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309764897300_56', 'Rayan Cherki: ''Tôi muốn đưa bóng đá kiểu cũ trở lại thành xu hướng''', 'Trả lời phỏng vấn tạp chí Pháp France Football, ngôi sao Man City Rayan Cherki tự nhận là người kế thừa của bóng đá kiểu cũ, của những nghệ sĩ, biết cách tạo ra tính giải trí và những khoảnh khắc khó lường. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/Cherki117737216596012177372330-8747-1654-1773749376.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=MaFkQZBnLn-3bP0Kd0hXvQ', '2026-03-19', 'admin', 428, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309779470000_57', 'Jorge Valdano: ''Đừng bao giờ xem thường Real ở Champions League''', 'Trên mục góc nhìn của báo Tây Ban Nha El Pais, cựu HLV và CEO Real Madrid Jorge Valdano cảnh báo bất kỳ đội bóng nào cũng không thể xem thường thầy trò Alvaro Arbeloa, nhất là ở sân chơi Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/val-verde-2-1773711449-1773711-4480-4032-1773711757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=end54HewtsejqpCF1344PQ', '2026-03-19', 'admin', 351, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309796944000_58', 'Rudiger thích tranh chấp sức mạnh với Haaland', 'Trung vệ Antonio Rudiger mong chờ màn đối đầu tiền đạo Erling Haaland khi Real Madrid làm khách của Man City ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/rudiger-1773714139-1773714155-5681-1773714347.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=sU8hD9et6icAqg6BNFhgKQ', '2026-03-19', 'admin', 106, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_21309811153300_59', 'CĐV Malaysia biểu tình phản đối vụ gian lận nhập tịch', 'Khoảng 70 người hâm mộ đã biểu tình ôn hòa trước trụ sở Liên đoàn bóng đá Malaysia hôm nay, để phản đối vụ 7 cầu thủ nhập tịch gian lận. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/screenshot20260317at122726-177-5427-6659-1773725416.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=wF__THlCbbCVaCETt6IEBQ', '2026-03-19', 'admin', 49, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235315227600_0', 'Ấn định thời gian tổ chức FIFA ASEAN Cup', 'Liên đoàn Bóng đá Thế giới (FIFA) đã phê duyệt kế hoạch tổ chức FIFA ASEAN Cup từ tháng 9-10/2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/AN-MUNG-VOI-CUP-VO-DICH57-2363-1773969526.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JidnBWJIvqfl2Dv9bvKkVQ', '2026-03-20', 'admin', 279, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235332375300_1', 'Cầu thủ Bayern từ chối phỏng vấn vì hết giờ làm việc', 'Filip Pavic và Deniz Ofli không trả lời phỏng vấn sau trận thắng Atalanta 4-1 ở lượt về vòng 1/8 Champions League tối 19/3 vì quá giới hạn giờ làm việc theo luật Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/image-1773967945398-1773967962-1222-8032-1773968011.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OAbrLeaaF4YcCa7BDbrymw', '2026-03-20', 'admin', 246, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235349165300_2', 'Thùy Linh vào tứ kết ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh chỉ mất 36 phút để thắng Lo Sin Yan Happy 21-12, 21-14, vào tứ kết giải cầu lông Orleans Masters, tối 19/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/thuy-linh-vo-dich10-jpg-177396-2060-5273-1773960838.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WC1v2qFlvAKogW4s3KTmlg', '2026-03-20', 'admin', 397, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235365517100_3', 'Tuyển Iran tẩy chay Mỹ nhưng vẫn dự World Cup', 'Chủ tịch LĐBĐ Iran (FFIRI) Mehdi Taj khẳng định đội tuyển nước này vẫn tham dự World Cup 2026 nhưng không muốn thi đấu tại Mỹ, khiến lịch thi đấu có thể xáo trộn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-png-1773924012-1773924022-2141-1773924048.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8T67oMfZFJdDkEG28y_uw', '2026-03-20', 'admin', 38, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235383008100_4', 'Tuyển nữ Iran được vinh danh ngày về nước', 'Đội tuyển bóng đá nữ Iran, ngoại trừ hai cầu thủ, đã về nước sau khi quá cảnh ở nhiều quốc gia, khép lại vụ việc gây chú ý tại Asian Cup nữ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-1773919073-1773919081-7375-1773919159.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vHBTQCcZgQ23NsODfnyjhA', '2026-03-20', 'admin', 405, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235400323200_5', 'Neymar ''rất buồn'' vì quyết định của Ancelotti', 'Neymar bày tỏ sự thất vọng sau khi tiếp tục bị HLV Carlo Ancelotti từ chối cho trở lại tuyển Brazil. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t081833527-1-5964-1473-1773796972.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=AtSAIHhqEbf5SswZ44u2Ng', '2026-03-20', 'admin', 159, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235419554400_6', 'WADA lùi quyết định, tránh đối đầu ông Trump trước World Cup', 'Cơ quan Phòng chống Doping Thế giới (WADA) hoãn xem xét quy định có thể dẫn tới việc cấm Tổng thống Donald Trump tham dự các sự kiện thể thao lớn, qua đó tạm tránh nguy cơ đối đầu Mỹ trước thềm World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/trump-png-1773922699-177392270-5580-2360-1773922717.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tPI61WljNUU7JS-nfrvVbg', '2026-03-20', 'admin', 414, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235435918800_7', 'Thầy cũ làm cố vấn cho Van Persie', 'HLV lừng danh Dick Advocaat sẽ làm cố vấn cho Robin Van Persie, người đang gặp thách thức trên cương vị thuyền trưởng của Feyenoord. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t123143546-1-2315-7842-1773898604.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EGRmKUov_VUr9RywpY2_YA', '2026-03-20', 'admin', 396, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235453735700_8', 'Từ chối chung bục với nhà vô địch điền kinh Mỹ vì nghi vấn doping', '14 VĐV từ chối đứng chung bục với nhà vô địch các nội dung chạy 3.000m và 5.000m nam Seth Clevenger tại giải điền kinh sinh viên Mỹ, gây tranh cãi về quyền thi đấu của anh. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdv-png-1773826186-1773826265-6895-1773826290.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=3dlRyQmZif8TQv2oOJyjFg', '2026-03-20', 'admin', 29, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235471108300_9', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-20', 'admin', 94, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235489704400_10', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-20', 'admin', 178, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235505674500_11', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-20', 'admin', 466, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235522536400_12', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-20', 'admin', 337, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235539097700_13', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-20', 'admin', 17, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235557251800_14', 'VĐV Esports Hoa Tranh: ''Ngày trở về từ SEA Games là lần đầu tiên tôi thấy bố khóc''', 'Trước khi giành HC vàng SEA Games 33, Bùi Nguyễn Hoa Tranh (1S RuuRuu) từng nghĩ đến khả năng từ bỏ con đường VĐV thể thao điện tử chuyên nghiệp vì bị bố mẹ phản đối. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/anh-4-1773897015-5035-17738994-5898-6381-1773899533.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XlTU1AR6fUvNI4kafT6cqA', '2026-03-20', 'admin', 349, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235573592800_15', 'Xuân Son: ''Tôi muốn thắng, không cần biết Malaysia bị xử thua thế nào''', 'Trước ngày hội quân cùng tuyển Việt Nam, tiền đạo nhập tịch Nguyễn Xuân Son thể hiện quyết tâm cùng đồng đội đánh bại Malaysia ở lượt về vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/nam-dinh-vo-dich-v-league-2023-1951-6365-1773892546.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Og1tfVvmaRUSNkjUexYb-A', '2026-03-20', 'admin', 65, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235590574000_16', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-20', 'admin', 225, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235607382500_17', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-20', 'admin', 443, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235624140400_18', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-20', 'admin', 14, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235641355400_19', 'Vì sao các đội bóng Anh rơi rụng ở Champions League?', 'Ngoại hạng Anh có tới sáu đội vào vòng 1/8 ở Champions League, nhưng chỉ còn Arsenal và Liverpool vào tứ kết. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/1773710180948mancityrealmadrid-2653-6959-1773757914.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=p1eLBPPG0hP-iPNgzdpC1Q', '2026-03-20', 'admin', 257, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235657806100_20', 'Messi chạm mốc 900 bàn, vẫn không cứu nổi Inter Miami', 'Đội trưởng Lionel Messi sớm ghi bàn nhưng chủ nhà Inter Miami chỉ hòa Nashville 1-1 ở lượt về vòng 1/8 CONCACAF Champions Cup, và bị loại bởi luật ghi bàn sân khách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/messi-jpeg-1773881744-17738817-5037-1960-1773882092.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hwHF05gvNVSC4Ef0nGjKNg', '2026-03-20', 'admin', 322, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235674196600_21', 'Lewandowski phá một kỷ lục của Messi', 'Robert Lewandowski trở thành cầu thủ ghi bàn vào lưới nhiều đội bóng khác nhau nhất tại Champion League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t074116697-1-5000-1174-1773881038.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2ngI4cwv3baoRsJpP6Nbpg', '2026-03-20', 'admin', 483, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235690134200_22', 'Xác định 4 cặp tứ kết Champions League', 'ĐKVĐ PSG đại chiến Liverpool, trong khi Real Madrid đấu Bayern Munich là những cặp đấu được chờ đợi ở tứ kết Champions League mùa 2025-2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/arsenal-png-1773874075-1773874-8366-3595-1773874264.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=YpF-4_ge5FhXJnWMzGNsuA', '2026-03-20', 'admin', 488, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235706286900_23', 'Kane chạm mốc 50 bàn ở Champions League', 'Lập cú đúp trong trận Bayern thắng Atalanta 4-1 ở lượt về vòng 1/8, Harry Kane trở thành cầu thủ người Anh đầu tiên chạm mốc 50 bàn ở Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/kane1-png-1773870859-177387087-1321-5328-1773871258.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lrF0ArtaeTryRxVftXmeYA', '2026-03-20', 'admin', 259, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235723408600_24', 'Hai nữ cầu thủ Iran không đội hijab khi tập luyện tại Australia', 'Fatemeh Pasandideh và Atefeh Ramezanisadeh, hai cầu thủ xin tị nạn tại Australia, tham gia buổi tập cùng CLB Brisbane Roar mà không đội hijab - trang phục che kín từ cổ đến chân vốn bị bắt buộc theo quy định của Cộng hòa Hồi giáo Iran. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/iranPNG-1773840815-5081-1773840989.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=4fIEt2Y3tfrEr8P1tun_lw', '2026-03-20', 'admin', 266, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235739692100_25', 'Bố ''Thiên thần băng'' Alysa Liu thừa nhận sai lầm khi dạy con', 'Người cha của "Thiên thần băng" Alysa Liu thừa nhận những sai lầm trong quá khứ, khi nhìn lại hành trình đưa con gái tới đỉnh cao Olympic mùa Đông. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arthur-liu-alysa-liu-177382629-4892-6962-1773826652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W3u-0xRdIjAZBIJ5QJrzZQ', '2026-03-20', 'admin', 385, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235756186200_26', 'YouTube bắt tay FIFA phát sóng World Cup 2026', 'Thỏa thuận giữa YouTube và FIFA mở ra cách tiếp cận mới cho người hâm mộ khi cho phép phát trực tiếp một phần trận đấu, cùng nhiều nội dung độc quyền trên nền tảng video lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/fifa-png-1773775939-1773775960-2114-1773775973.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mTLltq3Bja2F22bFYvpfeg', '2026-03-20', 'admin', 18, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235773062200_27', 'Flick tránh nói khả năng Barca vô địch Champions League', 'HLV Hansi Flick duy trì thận trọng dù Barca đại thắng Newcastle 7-2 ở lượt về vòng 1/8 Champions League, tối 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/NewProject20260319T060911579-1-1339-6481-1773875561.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kHoAQi7TDUXFcr6h89ZyQg', '2026-03-20', 'admin', 423, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235789298100_28', 'Tottenham bị Atletico loại khỏi Champions League', 'Thắng 3-2 ở lượt về tối 18/3, Tottenham vẫn dừng bước ở vòng 1/8 Champions League vì thua Atletico Madrid chung cuộc 5-7. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773874559636-1773874569-6754-8611-1773874805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WXigzq_XHtDG2K8l9lNCZA', '2026-03-20', 'admin', 71, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235805480400_29', 'Liverpool đấu PSG ở tứ kết Champions League', 'Thắng Galatasaray 4-0 ở lượt về vòng 1/8, Liverpool đi tiếp tại Champions League với tổng tỷ số 4-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773872898601-1773872921-9151-5872-1773873066.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VPoCGTfzNrIzO40T4XdRA', '2026-03-20', 'admin', 242, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235822742200_30', 'Barca thắng Newcastle 7-2 ở Champions League', 'Barca thắng đội khách Newcastle 7-2 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 8-3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/barca-png-1773868979-177386900-2805-1625-1773869128.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Vsem5oeB9FuV0jTuy2_2DQ', '2026-03-20', 'admin', 323, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235839908900_31', 'Rakitic: ''Barca thời tôi lẽ ra phải giành thêm ba Champions League''', 'Trả lời phỏng vấn kênh radio Catalonia Cadena SER, cựu tiền vệ Croatia Ivan Rakitic nhìn lại thời kỳ vàng son của Barca, tiếc nuối về những cơ hội bị bỏ lỡ ở Champions League và phân tích tình hình hiện tại của thầy trò Hansi Flick. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/top-1773834422-9056-1773834524.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BjNtzP_sflZqa-6YmD-Mjg', '2026-03-20', 'admin', 475, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235856937900_32', 'Vợ chạy 10 km tưởng nhớ Diogo Jota', 'Rute Cardoso hoàn thành cuộc đua 10 km tại Porto với số áo 20, trong Ngày của Cha đầu tiên kể từ khi cố tiền đạo Liverpool Diogo Jota tử nạn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/rutePNG-1773826559-2930-1773826561.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7s8TcEYo0ktvOznkvcFIqg', '2026-03-20', 'admin', 99, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235874158300_33', 'Senegal khiếu nại khi bị tước chức vô địch châu Phi', 'Senegal tuyên bố kiện lên Tòa Trọng tài Thể thao (CAS) về việc bị tước chức vô địch châu Phi 2025, hai tháng sau khi đăng quang ở Morocco. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/senegal-sadio-mane-1773831398-9470-4714-1773831475.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7UQcAQYUPCumgb9DXiwMgQ', '2026-03-20', 'admin', 112, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235890725600_34', 'Tốc độ - điểm tựa để Duplantis định nghĩa lại nhảy sào', 'Qua nhiều năm, Armand Duplantis tập trung tối đa vào tốc độ, tạo nên cơ chế vận động đặc biệt để 15 lần phá kỷ lục thế giới với mốc mới nhất là 6,31 m thiết lập hôm 12/3 tại Uppsala, Thụy Điển. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image-1773820570531-1773820590-6075-3474-1773821051.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=49kqAoW8YXRKEskZTYDonA', '2026-03-20', 'admin', 11, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235906842700_35', 'Chuyên gia Malaysia: ''Không được buông xuôi khi tái đấu Việt Nam''', 'Đã mất vé dự Asian Cup 2027 vì bê bối nhập tịch, nhưng chuyên gia Zulakbal Abdul Karim cho rằng Malaysia nên xem trận đấu sắp tới với Việt Nam là cơ hội gỡ gạc thể diện. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/559442709-122153351474803027-6-6606-4056-1773807723.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=w_jBT4_2sv3DRmpLwsBwAQ', '2026-03-20', 'admin', 364, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235923731100_36', 'Henry: ''CĐV trung lập không muốn Arsenal vô địch''', 'Huyền thoại Thierry Henry cảm thấy khó hiểu khi nhiều CĐV trung lập không muốn Arsenal đăng quang Ngoại hạng Anh, đồng thời lên tiếng bảo vệ lối chơi thực dụng của đội bóng dưới thời HLV Mikel Arteta. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/arsenal-png-1773750496-1773750-9517-8995-1773750527.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5eRI7k-GSroryTc-98-Txg', '2026-03-20', 'admin', 220, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235940018900_37', 'Carragher: ''Liverpool đang đánh mất bản sắc và niềm tin CĐV dưới thời Slot''', 'Cựu hậu vệ Jamie Carragher cho rằng Liverpool không chỉ đánh mất lối chơi pressing từng làm nên thương hiệu dưới thời Jurgen Klopp mà còn dần đánh mất sự ủng hộ từ khán giả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tottenham-png-1773752395-17737-1382-6361-1773752445.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tBvdxo8jIKctwoKedMDx-Q', '2026-03-20', 'admin', 451, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235955529700_38', 'AFC được đánh giá cao khi không nương tay với Malaysia', 'Nhiều tờ báo trong khu vực khen ngợi Liên đoàn bóng đá châu Á vì thẳng tay xử thua Malaysia ở vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/img-3473-1773740118-3722-1773740123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bVLAgWv6TX4y-ZOuQjnB4w', '2026-03-20', 'admin', 61, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235972596700_39', 'Thùy Linh thắng nghẹt thở ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh hạ đối thủ được đánh giá cao hơn Lin Hsiang-ti 2-1 ở trận ra quân giải cầu lông Orleans Masters, chiều 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/11-jpg-1773830995-1186-1773831360.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JfNGXkiE-GdJF-YVUI1xIA', '2026-03-20', 'admin', 166, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3235989496500_40', 'Enrique bất ngờ khi PSG thắng đậm Chelsea', 'HLV Luis Enrique thừa nhận chưa từng nghĩ PSG có thể đè bẹp Chelsea với tổng tỷ số 8-2 ở vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/enrique-png-1773811580-1773811-5639-2995-1773811650.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=po-EQiJAXJnHV1MIbhu0vA', '2026-03-20', 'admin', 428, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236006597600_41', 'Flick sẽ giải nghệ sau khi rời Barca', 'HLV Hansi Flick phủ nhận đồng ý gia hạn với Barca, nhưng khẳng định đội bóng xứ Catalonia sẽ là bến đỗ cuối cùng trong sự nghiệp cầm quân. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/flick1-png-1773778564-17737786-8387-6182-1773778660.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=UV3lPCVahzoE3Zt9PxbbEA', '2026-03-20', 'admin', 381, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236023652800_42', 'Guardiola: ''Ai cũng muốn tôi bị sa thải''', 'HLV Pep Guardiola bác bỏ khả năng chia tay Man City dù bị Real Madrid loại khỏi Champions League, đồng thời tin tưởng vào triển vọng tích cực mùa tới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/pep-png-1773798800-1773798815-7191-1773798881.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=rtxOlOuaZAhTncoH24ReRg', '2026-03-20', 'admin', 143, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236040252300_43', 'Vinícius giả vờ khóc để châm chọc CĐV Man City', 'Tiền đạo Vinicius cho biết những màn mừng bàn thắng trong trận hạ Man City 2-1 ở lượt về vòng 1/8 Champions League là lời đáp trả tấm banner chế giễu anh từ mùa trước. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-png-1773792039-1773792047-1924-1773793390.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=2plZZ9Z-BT5gzPf8L3aT1w', '2026-03-20', 'admin', 119, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236057862100_44', 'Senegal bị tước chức vô địch Cup châu Phi 2026', 'Kết quả trận chung kết Cup châu Phi (AFCON) 2026 bị đảo ngược, khi chủ nhà Morocco được xử thắng 3-0 trước Senegal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773790138504-1773790163-8054-1773790485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=e5EhHcs6VXNKBStFraLlbw', '2026-03-20', 'admin', 241, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236073956900_45', 'CĐV Malaysia: ''Vụ gian lận nhập tịch là nỗi hổ thẹn quốc gia''', 'Làn sóng phẫn nộ bùng lên sau khi LĐBĐ châu Á (AFC) xử thua Malaysia 0-3 ở trận gặp Nepal và Việt Nam vì dùng cầu thủ nhập tịch không đủ tư cách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/malaysia-bi-xu-thua-1773745350-8129-9070-1773745502.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=61ulTsK_fGL0qbEZOxtOKQ', '2026-03-20', 'admin', 423, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236090301500_46', 'Siêu sao bóng bàn Trung Quốc tạo cơn sốt chuyển nhượng tại Đức', 'Fan Zhendong sẽ rời 1. FC Saarbrucken TT sau mùa giải này để gia nhập kình địch Borussia Dusseldorf, tạo nên một trong những thương vụ gây chú ý nhất của Bundesliga bóng bàn Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/zhendong-1773720139-1773720150-9937-1773720478.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KixJarScZbvUNkyUJgurtA', '2026-03-20', 'admin', 234, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236107317600_47', 'Real hạ Man City, vào tứ kết Champions League', 'Vinicius lập cú đúp giúp Real Madrid thắng 2-1 trên sân của Man City, đội phải đá thiếu người từ hiệp một ở lượt về vòng 1/8 Champions League, để đi tiếp với kết quả chung cuộc 5-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-1773788393-1773788421-8762-1773788445.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fOykQp0zSx7XL-euN6VMfw', '2026-03-20', 'admin', 499, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236123315000_48', 'PSG vùi dập Chelsea ở Champions League', 'Sau trận thắng 5-2 ở lượt đi, ĐKVĐ PSG tiếp tục đè bẹp Chelsea 3-0 ngay tại Stamford Bridge ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/psg1-png-1773787486-1773787582-5228-1773787664.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NNYls03Jvo3QkKWark4Qtg', '2026-03-20', 'admin', 399, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236139686000_49', 'Arsenal vào tứ kết Champions League', 'Arsenal thắng đội khách Leverkusen 2-0 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 3-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arsenal2-png-1773785414-177378-5607-7238-1773785517.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ws_yDnDrbPSZ6RSu3aJyuQ', '2026-03-20', 'admin', 477, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236155625900_50', '''Ngựa ô'' Bodo/Glimt bị loại khỏi Champions League', 'Thắng 3-0 từ lượt đi, nhưng Bodo/Glimt vẫn bị loại khi thua Sporting Lisbon 0-5 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773782561242-1773782577-8615-1345-1773782755.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T6CIsrQnBsmht0o3buqKWQ', '2026-03-20', 'admin', 44, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236172567900_51', 'Runner Trung Quốc bị chặn ngay trước vạch đích khi đang dẫn đầu', 'Xueji Sheng bất ngờ bị trọng tài ngăn cản ngay trước vạch đích do nhầm với người chạy half marathon, phải "về đích lại" để hoàn tất thủ tục ghi nhận kết quả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdvPNG-1773791774-1248-1773791779.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=md9z0cz3Co2j-wIP4EWpjA', '2026-03-20', 'admin', 178, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236188899300_52', 'Iran muốn dời các trận World Cup 2026 từ Mỹ sang Mexico', 'LĐBĐ Iran (FFIRI) đang bàn với FIFA chuyển các trận của đội tuyển nước này ở World Cup 2026 từ Mỹ sang quốc gia đồng chủ nhà Mexico, do những lo ngại về an toàn của các cầu thủ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/image-1773751920118-1773751934-4946-8771-1773752024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=g06qKBljyPM39QVRjhwpIA', '2026-03-20', 'admin', 457, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236205773400_53', 'Enrique: ''Câu đùa về Ngoại hạng Anh theo tôi khắp nơi''', 'HLV Luis Enrique nói câu đùa của ông về việc đánh bại các CLB Ngoại hạng Anh bị nhắc lại ở khắp nơi, khi PSG chuẩn bị tái đấu Chelsea ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/enrique-1773716464-1773716640-3320-1773716649.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=JuRfLttCMERhjkDaYEbmMA', '2026-03-20', 'admin', 431, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236262697400_54', 'Guardiola nói về ''văn hóa đón nhận thất bại'' trước thềm đại chiến Real', 'Pep Guardiola đã có những phân tích trước thềm trận lượt về Man City - Real Madrid ở vòng 1/8 Champions League, đồng thời đưa ra những chiêm nghiệm về "văn hóa đón nhận thất bại" trong thể thao. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/idjv5irrtfitraeiaqouzqasri-177-8609-2353-1773752110.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GHaNqqdTA3lETSjOvwg2vw', '2026-03-20', 'admin', 458, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236286731900_55', 'Leverkusen ra sức châm chọc Arsenal', 'Trước trận lượt đi lẫn lượt về vòng 1/8 Champions League, trang mạng xã hội chính thức của Bayer Leverkusen liên tục đăng tải các bài viết mang tính hài hước, trêu đùa đối thủ Arsenal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7629011609378-12196e04c788300-4265-4771-1773751277.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xcRrq5P1zJMGGLlmFQ7jGA', '2026-03-20', 'admin', 289, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236310423500_56', 'David Silva: ''Nếu Real thủng lưới trong 25 phút đầu, Man City sẽ có cơ hội''', 'Theo cựu danh thủ Man City David Silva, nếu chọc thủng lưới Real Madrid sớm, Man City sẽ có cơ hội lật ngược thế cờ sau khi thua 0-3 ở lượt đi vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/courtois-1773750600-1773750655-7749-1871-1773750912.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zOs8AH1FGSS7W7yjXb4GJA', '2026-03-20', 'admin', 505, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236327586400_57', 'Hai tuyển thủ eSports Thái Lan bị giam 3 tháng vì gian lận tại SEA Games', 'Sáng 17/3, tòa án quận Pathum Wan, Bangkok tuyên 6 tháng tù với Tokyogurl và Cheerio vì gian lận thi đấu tại SEA Games 33, nhưng giảm còn 3 tháng giam giữ do nhận tội. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tokyogurl-png-1773741329-17737-9236-3266-1773741471.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1xskZ9TIuyxAg2hn8Nzjkw', '2026-03-20', 'admin', 425, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236343984500_58', 'Việt kiều Croatia được đôn lên U23 Việt Nam', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, được đôn từ đội tuyển U19 lên U23 Việt Nam để ban huấn luyện đánh giá khả năng. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7630059415036-96db7a349004a0d-6837-4270-1773745617.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-g6RkAXzhB_htlIhsyapCw', '2026-03-20', 'admin', 263, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3236361261000_59', 'Ancelotti: ''Real thời Mbappe cần thời gian để tạo nên di sản riêng''', 'Trả lời Radio Marca, cựu HLV Real Madrid Carlo Ancelotti kể về những tháng đầu dẫn dắt tuyển Brazil, quan hệ với đội bóng cũ, sự tiến hóa của bóng đá và cái nhìn về những học trò cũ như Mbappe, Vinicius hay Fede Valverde. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/download-11-1773738753-1773738-2303-4952-1773738784.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eZdhblJJcYn-9YBYl1v4nA', '2026-03-20', 'admin', 116, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527285119700_0', 'Ấn định thời gian tổ chức FIFA ASEAN Cup', 'Liên đoàn Bóng đá Thế giới (FIFA) đã phê duyệt kế hoạch tổ chức FIFA ASEAN Cup từ tháng 9-10/2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/AN-MUNG-VOI-CUP-VO-DICH57-2363-1773969526.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JidnBWJIvqfl2Dv9bvKkVQ', '2026-03-20', 'admin', 392, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527301094700_1', 'Cầu thủ Bayern từ chối phỏng vấn vì hết giờ làm việc', 'Filip Pavic và Deniz Ofli không trả lời phỏng vấn sau trận thắng Atalanta 4-1 ở lượt về vòng 1/8 Champions League tối 19/3 vì quá giới hạn giờ làm việc theo luật Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/image-1773967945398-1773967962-1222-8032-1773968011.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OAbrLeaaF4YcCa7BDbrymw', '2026-03-20', 'admin', 150, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527317304400_2', 'Thùy Linh vào tứ kết ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh chỉ mất 36 phút để thắng Lo Sin Yan Happy 21-12, 21-14, vào tứ kết giải cầu lông Orleans Masters, tối 19/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/thuy-linh-vo-dich10-jpg-177396-2060-5273-1773960838.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WC1v2qFlvAKogW4s3KTmlg', '2026-03-20', 'admin', 157, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527333421800_3', 'Tuyển Iran tẩy chay Mỹ nhưng vẫn dự World Cup', 'Chủ tịch LĐBĐ Iran (FFIRI) Mehdi Taj khẳng định đội tuyển nước này vẫn tham dự World Cup 2026 nhưng không muốn thi đấu tại Mỹ, khiến lịch thi đấu có thể xáo trộn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-png-1773924012-1773924022-2141-1773924048.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8T67oMfZFJdDkEG28y_uw', '2026-03-20', 'admin', 470, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527350994300_4', 'Tuyển nữ Iran được vinh danh ngày về nước', 'Đội tuyển bóng đá nữ Iran, ngoại trừ hai cầu thủ, đã về nước sau khi quá cảnh ở nhiều quốc gia, khép lại vụ việc gây chú ý tại Asian Cup nữ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-1773919073-1773919081-7375-1773919159.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vHBTQCcZgQ23NsODfnyjhA', '2026-03-20', 'admin', 33, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527367886300_5', 'Neymar ''rất buồn'' vì quyết định của Ancelotti', 'Neymar bày tỏ sự thất vọng sau khi tiếp tục bị HLV Carlo Ancelotti từ chối cho trở lại tuyển Brazil. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t081833527-1-5964-1473-1773796972.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=AtSAIHhqEbf5SswZ44u2Ng', '2026-03-20', 'admin', 189, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527384570500_6', 'WADA lùi quyết định, tránh đối đầu ông Trump trước World Cup', 'Cơ quan Phòng chống Doping Thế giới (WADA) hoãn xem xét quy định có thể dẫn tới việc cấm Tổng thống Donald Trump tham dự các sự kiện thể thao lớn, qua đó tạm tránh nguy cơ đối đầu Mỹ trước thềm World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/trump-png-1773922699-177392270-5580-2360-1773922717.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tPI61WljNUU7JS-nfrvVbg', '2026-03-20', 'admin', 31, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527401109900_7', 'Thầy cũ làm cố vấn cho Van Persie', 'HLV lừng danh Dick Advocaat sẽ làm cố vấn cho Robin Van Persie, người đang gặp thách thức trên cương vị thuyền trưởng của Feyenoord. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t123143546-1-2315-7842-1773898604.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EGRmKUov_VUr9RywpY2_YA', '2026-03-20', 'admin', 258, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527418507500_8', 'Từ chối chung bục với nhà vô địch điền kinh Mỹ vì nghi vấn doping', '14 VĐV từ chối đứng chung bục với nhà vô địch các nội dung chạy 3.000m và 5.000m nam Seth Clevenger tại giải điền kinh sinh viên Mỹ, gây tranh cãi về quyền thi đấu của anh. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdv-png-1773826186-1773826265-6895-1773826290.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=3dlRyQmZif8TQv2oOJyjFg', '2026-03-20', 'admin', 289, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527437692600_9', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-20', 'admin', 474, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527458461800_10', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-20', 'admin', 173, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527475148600_11', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-20', 'admin', 145, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527491343100_12', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-20', 'admin', 326, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527507845000_13', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-20', 'admin', 184, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527524378800_14', 'VĐV Esports Hoa Tranh: ''Ngày trở về từ SEA Games là lần đầu tiên tôi thấy bố khóc''', 'Trước khi giành HC vàng SEA Games 33, Bùi Nguyễn Hoa Tranh (1S RuuRuu) từng nghĩ đến khả năng từ bỏ con đường VĐV thể thao điện tử chuyên nghiệp vì bị bố mẹ phản đối. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/anh-4-1773897015-5035-17738994-5898-6381-1773899533.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XlTU1AR6fUvNI4kafT6cqA', '2026-03-20', 'admin', 97, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527540835400_15', 'Xuân Son: ''Tôi muốn thắng, không cần biết Malaysia bị xử thua thế nào''', 'Trước ngày hội quân cùng tuyển Việt Nam, tiền đạo nhập tịch Nguyễn Xuân Son thể hiện quyết tâm cùng đồng đội đánh bại Malaysia ở lượt về vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/nam-dinh-vo-dich-v-league-2023-1951-6365-1773892546.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Og1tfVvmaRUSNkjUexYb-A', '2026-03-20', 'admin', 194, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527557909500_16', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-20', 'admin', 427, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527574272800_17', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-20', 'admin', 65, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527590720700_18', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-20', 'admin', 192, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527607890300_19', 'Vì sao các đội bóng Anh rơi rụng ở Champions League?', 'Ngoại hạng Anh có tới sáu đội vào vòng 1/8 ở Champions League, nhưng chỉ còn Arsenal và Liverpool vào tứ kết. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/1773710180948mancityrealmadrid-2653-6959-1773757914.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=p1eLBPPG0hP-iPNgzdpC1Q', '2026-03-20', 'admin', 213, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527624941400_20', 'Messi chạm mốc 900 bàn, vẫn không cứu nổi Inter Miami', 'Đội trưởng Lionel Messi sớm ghi bàn nhưng chủ nhà Inter Miami chỉ hòa Nashville 1-1 ở lượt về vòng 1/8 CONCACAF Champions Cup, và bị loại bởi luật ghi bàn sân khách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/messi-jpeg-1773881744-17738817-5037-1960-1773882092.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hwHF05gvNVSC4Ef0nGjKNg', '2026-03-20', 'admin', 440, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527641918500_21', 'Lewandowski phá một kỷ lục của Messi', 'Robert Lewandowski trở thành cầu thủ ghi bàn vào lưới nhiều đội bóng khác nhau nhất tại Champion League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t074116697-1-5000-1174-1773881038.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2ngI4cwv3baoRsJpP6Nbpg', '2026-03-20', 'admin', 371, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527659809800_22', 'Xác định 4 cặp tứ kết Champions League', 'ĐKVĐ PSG đại chiến Liverpool, trong khi Real Madrid đấu Bayern Munich là những cặp đấu được chờ đợi ở tứ kết Champions League mùa 2025-2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/arsenal-png-1773874075-1773874-8366-3595-1773874264.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=YpF-4_ge5FhXJnWMzGNsuA', '2026-03-20', 'admin', 173, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527678689400_23', 'Kane chạm mốc 50 bàn ở Champions League', 'Lập cú đúp trong trận Bayern thắng Atalanta 4-1 ở lượt về vòng 1/8, Harry Kane trở thành cầu thủ người Anh đầu tiên chạm mốc 50 bàn ở Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/kane1-png-1773870859-177387087-1321-5328-1773871258.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lrF0ArtaeTryRxVftXmeYA', '2026-03-20', 'admin', 221, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527697236700_24', 'Hai nữ cầu thủ Iran không đội hijab khi tập luyện tại Australia', 'Fatemeh Pasandideh và Atefeh Ramezanisadeh, hai cầu thủ xin tị nạn tại Australia, tham gia buổi tập cùng CLB Brisbane Roar mà không đội hijab - trang phục che kín từ cổ đến chân vốn bị bắt buộc theo quy định của Cộng hòa Hồi giáo Iran. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/iranPNG-1773840815-5081-1773840989.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=4fIEt2Y3tfrEr8P1tun_lw', '2026-03-20', 'admin', 21, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527714138800_25', 'Bố ''Thiên thần băng'' Alysa Liu thừa nhận sai lầm khi dạy con', 'Người cha của "Thiên thần băng" Alysa Liu thừa nhận những sai lầm trong quá khứ, khi nhìn lại hành trình đưa con gái tới đỉnh cao Olympic mùa Đông. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arthur-liu-alysa-liu-177382629-4892-6962-1773826652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W3u-0xRdIjAZBIJ5QJrzZQ', '2026-03-20', 'admin', 209, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527730082600_26', 'YouTube bắt tay FIFA phát sóng World Cup 2026', 'Thỏa thuận giữa YouTube và FIFA mở ra cách tiếp cận mới cho người hâm mộ khi cho phép phát trực tiếp một phần trận đấu, cùng nhiều nội dung độc quyền trên nền tảng video lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/fifa-png-1773775939-1773775960-2114-1773775973.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mTLltq3Bja2F22bFYvpfeg', '2026-03-20', 'admin', 176, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527747316700_27', 'Flick tránh nói khả năng Barca vô địch Champions League', 'HLV Hansi Flick duy trì thận trọng dù Barca đại thắng Newcastle 7-2 ở lượt về vòng 1/8 Champions League, tối 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/NewProject20260319T060911579-1-1339-6481-1773875561.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kHoAQi7TDUXFcr6h89ZyQg', '2026-03-20', 'admin', 56, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527764318800_28', 'Tottenham bị Atletico loại khỏi Champions League', 'Thắng 3-2 ở lượt về tối 18/3, Tottenham vẫn dừng bước ở vòng 1/8 Champions League vì thua Atletico Madrid chung cuộc 5-7. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773874559636-1773874569-6754-8611-1773874805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WXigzq_XHtDG2K8l9lNCZA', '2026-03-20', 'admin', 409, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527781259300_29', 'Liverpool đấu PSG ở tứ kết Champions League', 'Thắng Galatasaray 4-0 ở lượt về vòng 1/8, Liverpool đi tiếp tại Champions League với tổng tỷ số 4-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773872898601-1773872921-9151-5872-1773873066.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VPoCGTfzNrIzO40T4XdRA', '2026-03-20', 'admin', 309, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527797406200_30', 'Barca thắng Newcastle 7-2 ở Champions League', 'Barca thắng đội khách Newcastle 7-2 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 8-3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/barca-png-1773868979-177386900-2805-1625-1773869128.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Vsem5oeB9FuV0jTuy2_2DQ', '2026-03-20', 'admin', 306, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527813579300_31', 'Rakitic: ''Barca thời tôi lẽ ra phải giành thêm ba Champions League''', 'Trả lời phỏng vấn kênh radio Catalonia Cadena SER, cựu tiền vệ Croatia Ivan Rakitic nhìn lại thời kỳ vàng son của Barca, tiếc nuối về những cơ hội bị bỏ lỡ ở Champions League và phân tích tình hình hiện tại của thầy trò Hansi Flick. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/top-1773834422-9056-1773834524.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BjNtzP_sflZqa-6YmD-Mjg', '2026-03-20', 'admin', 218, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527829426300_32', 'Vợ chạy 10 km tưởng nhớ Diogo Jota', 'Rute Cardoso hoàn thành cuộc đua 10 km tại Porto với số áo 20, trong Ngày của Cha đầu tiên kể từ khi cố tiền đạo Liverpool Diogo Jota tử nạn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/rutePNG-1773826559-2930-1773826561.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7s8TcEYo0ktvOznkvcFIqg', '2026-03-20', 'admin', 99, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527845762700_33', 'Senegal khiếu nại khi bị tước chức vô địch châu Phi', 'Senegal tuyên bố kiện lên Tòa Trọng tài Thể thao (CAS) về việc bị tước chức vô địch châu Phi 2025, hai tháng sau khi đăng quang ở Morocco. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/senegal-sadio-mane-1773831398-9470-4714-1773831475.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7UQcAQYUPCumgb9DXiwMgQ', '2026-03-20', 'admin', 361, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527861651900_34', 'Tốc độ - điểm tựa để Duplantis định nghĩa lại nhảy sào', 'Qua nhiều năm, Armand Duplantis tập trung tối đa vào tốc độ, tạo nên cơ chế vận động đặc biệt để 15 lần phá kỷ lục thế giới với mốc mới nhất là 6,31 m thiết lập hôm 12/3 tại Uppsala, Thụy Điển. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image-1773820570531-1773820590-6075-3474-1773821051.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=49kqAoW8YXRKEskZTYDonA', '2026-03-20', 'admin', 52, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527877287900_35', 'Chuyên gia Malaysia: ''Không được buông xuôi khi tái đấu Việt Nam''', 'Đã mất vé dự Asian Cup 2027 vì bê bối nhập tịch, nhưng chuyên gia Zulakbal Abdul Karim cho rằng Malaysia nên xem trận đấu sắp tới với Việt Nam là cơ hội gỡ gạc thể diện. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/559442709-122153351474803027-6-6606-4056-1773807723.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=w_jBT4_2sv3DRmpLwsBwAQ', '2026-03-20', 'admin', 139, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527896021800_36', 'Henry: ''CĐV trung lập không muốn Arsenal vô địch''', 'Huyền thoại Thierry Henry cảm thấy khó hiểu khi nhiều CĐV trung lập không muốn Arsenal đăng quang Ngoại hạng Anh, đồng thời lên tiếng bảo vệ lối chơi thực dụng của đội bóng dưới thời HLV Mikel Arteta. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/arsenal-png-1773750496-1773750-9517-8995-1773750527.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5eRI7k-GSroryTc-98-Txg', '2026-03-20', 'admin', 392, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527915446800_37', 'Carragher: ''Liverpool đang đánh mất bản sắc và niềm tin CĐV dưới thời Slot''', 'Cựu hậu vệ Jamie Carragher cho rằng Liverpool không chỉ đánh mất lối chơi pressing từng làm nên thương hiệu dưới thời Jurgen Klopp mà còn dần đánh mất sự ủng hộ từ khán giả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tottenham-png-1773752395-17737-1382-6361-1773752445.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tBvdxo8jIKctwoKedMDx-Q', '2026-03-20', 'admin', 185, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527933391800_38', 'AFC được đánh giá cao khi không nương tay với Malaysia', 'Nhiều tờ báo trong khu vực khen ngợi Liên đoàn bóng đá châu Á vì thẳng tay xử thua Malaysia ở vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/img-3473-1773740118-3722-1773740123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bVLAgWv6TX4y-ZOuQjnB4w', '2026-03-20', 'admin', 128, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527949568200_39', 'Thùy Linh thắng nghẹt thở ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh hạ đối thủ được đánh giá cao hơn Lin Hsiang-ti 2-1 ở trận ra quân giải cầu lông Orleans Masters, chiều 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/11-jpg-1773830995-1186-1773831360.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JfNGXkiE-GdJF-YVUI1xIA', '2026-03-20', 'admin', 226, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527965754200_40', 'Enrique bất ngờ khi PSG thắng đậm Chelsea', 'HLV Luis Enrique thừa nhận chưa từng nghĩ PSG có thể đè bẹp Chelsea với tổng tỷ số 8-2 ở vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/enrique-png-1773811580-1773811-5639-2995-1773811650.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=po-EQiJAXJnHV1MIbhu0vA', '2026-03-20', 'admin', 438, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527982475300_41', 'Flick sẽ giải nghệ sau khi rời Barca', 'HLV Hansi Flick phủ nhận đồng ý gia hạn với Barca, nhưng khẳng định đội bóng xứ Catalonia sẽ là bến đỗ cuối cùng trong sự nghiệp cầm quân. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/flick1-png-1773778564-17737786-8387-6182-1773778660.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=UV3lPCVahzoE3Zt9PxbbEA', '2026-03-20', 'admin', 126, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3527998967700_42', 'Guardiola: ''Ai cũng muốn tôi bị sa thải''', 'HLV Pep Guardiola bác bỏ khả năng chia tay Man City dù bị Real Madrid loại khỏi Champions League, đồng thời tin tưởng vào triển vọng tích cực mùa tới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/pep-png-1773798800-1773798815-7191-1773798881.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=rtxOlOuaZAhTncoH24ReRg', '2026-03-20', 'admin', 402, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528015685500_43', 'Vinícius giả vờ khóc để châm chọc CĐV Man City', 'Tiền đạo Vinicius cho biết những màn mừng bàn thắng trong trận hạ Man City 2-1 ở lượt về vòng 1/8 Champions League là lời đáp trả tấm banner chế giễu anh từ mùa trước. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-png-1773792039-1773792047-1924-1773793390.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=2plZZ9Z-BT5gzPf8L3aT1w', '2026-03-20', 'admin', 117, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528032797900_44', 'Senegal bị tước chức vô địch Cup châu Phi 2026', 'Kết quả trận chung kết Cup châu Phi (AFCON) 2026 bị đảo ngược, khi chủ nhà Morocco được xử thắng 3-0 trước Senegal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773790138504-1773790163-8054-1773790485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=e5EhHcs6VXNKBStFraLlbw', '2026-03-20', 'admin', 506, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528049203200_45', 'CĐV Malaysia: ''Vụ gian lận nhập tịch là nỗi hổ thẹn quốc gia''', 'Làn sóng phẫn nộ bùng lên sau khi LĐBĐ châu Á (AFC) xử thua Malaysia 0-3 ở trận gặp Nepal và Việt Nam vì dùng cầu thủ nhập tịch không đủ tư cách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/malaysia-bi-xu-thua-1773745350-8129-9070-1773745502.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=61ulTsK_fGL0qbEZOxtOKQ', '2026-03-20', 'admin', 198, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528066039500_46', 'Siêu sao bóng bàn Trung Quốc tạo cơn sốt chuyển nhượng tại Đức', 'Fan Zhendong sẽ rời 1. FC Saarbrucken TT sau mùa giải này để gia nhập kình địch Borussia Dusseldorf, tạo nên một trong những thương vụ gây chú ý nhất của Bundesliga bóng bàn Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/zhendong-1773720139-1773720150-9937-1773720478.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KixJarScZbvUNkyUJgurtA', '2026-03-20', 'admin', 220, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528082411600_47', 'Real hạ Man City, vào tứ kết Champions League', 'Vinicius lập cú đúp giúp Real Madrid thắng 2-1 trên sân của Man City, đội phải đá thiếu người từ hiệp một ở lượt về vòng 1/8 Champions League, để đi tiếp với kết quả chung cuộc 5-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-1773788393-1773788421-8762-1773788445.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fOykQp0zSx7XL-euN6VMfw', '2026-03-20', 'admin', 244, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528099721800_48', 'PSG vùi dập Chelsea ở Champions League', 'Sau trận thắng 5-2 ở lượt đi, ĐKVĐ PSG tiếp tục đè bẹp Chelsea 3-0 ngay tại Stamford Bridge ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/psg1-png-1773787486-1773787582-5228-1773787664.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NNYls03Jvo3QkKWark4Qtg', '2026-03-20', 'admin', 346, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528116410100_49', 'Arsenal vào tứ kết Champions League', 'Arsenal thắng đội khách Leverkusen 2-0 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 3-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arsenal2-png-1773785414-177378-5607-7238-1773785517.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ws_yDnDrbPSZ6RSu3aJyuQ', '2026-03-20', 'admin', 111, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528133784500_50', '''Ngựa ô'' Bodo/Glimt bị loại khỏi Champions League', 'Thắng 3-0 từ lượt đi, nhưng Bodo/Glimt vẫn bị loại khi thua Sporting Lisbon 0-5 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773782561242-1773782577-8615-1345-1773782755.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T6CIsrQnBsmht0o3buqKWQ', '2026-03-20', 'admin', 52, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528185250300_51', 'Runner Trung Quốc bị chặn ngay trước vạch đích khi đang dẫn đầu', 'Xueji Sheng bất ngờ bị trọng tài ngăn cản ngay trước vạch đích do nhầm với người chạy half marathon, phải "về đích lại" để hoàn tất thủ tục ghi nhận kết quả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdvPNG-1773791774-1248-1773791779.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=md9z0cz3Co2j-wIP4EWpjA', '2026-03-20', 'admin', 391, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528210388500_52', 'Iran muốn dời các trận World Cup 2026 từ Mỹ sang Mexico', 'LĐBĐ Iran (FFIRI) đang bàn với FIFA chuyển các trận của đội tuyển nước này ở World Cup 2026 từ Mỹ sang quốc gia đồng chủ nhà Mexico, do những lo ngại về an toàn của các cầu thủ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/image-1773751920118-1773751934-4946-8771-1773752024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=g06qKBljyPM39QVRjhwpIA', '2026-03-20', 'admin', 123, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528234919400_53', 'Enrique: ''Câu đùa về Ngoại hạng Anh theo tôi khắp nơi''', 'HLV Luis Enrique nói câu đùa của ông về việc đánh bại các CLB Ngoại hạng Anh bị nhắc lại ở khắp nơi, khi PSG chuẩn bị tái đấu Chelsea ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/enrique-1773716464-1773716640-3320-1773716649.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=JuRfLttCMERhjkDaYEbmMA', '2026-03-20', 'admin', 452, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528255950400_54', 'Guardiola nói về ''văn hóa đón nhận thất bại'' trước thềm đại chiến Real', 'Pep Guardiola đã có những phân tích trước thềm trận lượt về Man City - Real Madrid ở vòng 1/8 Champions League, đồng thời đưa ra những chiêm nghiệm về "văn hóa đón nhận thất bại" trong thể thao. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/idjv5irrtfitraeiaqouzqasri-177-8609-2353-1773752110.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GHaNqqdTA3lETSjOvwg2vw', '2026-03-20', 'admin', 496, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528273103200_55', 'Leverkusen ra sức châm chọc Arsenal', 'Trước trận lượt đi lẫn lượt về vòng 1/8 Champions League, trang mạng xã hội chính thức của Bayer Leverkusen liên tục đăng tải các bài viết mang tính hài hước, trêu đùa đối thủ Arsenal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7629011609378-12196e04c788300-4265-4771-1773751277.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xcRrq5P1zJMGGLlmFQ7jGA', '2026-03-20', 'admin', 98, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528290610000_56', 'David Silva: ''Nếu Real thủng lưới trong 25 phút đầu, Man City sẽ có cơ hội''', 'Theo cựu danh thủ Man City David Silva, nếu chọc thủng lưới Real Madrid sớm, Man City sẽ có cơ hội lật ngược thế cờ sau khi thua 0-3 ở lượt đi vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/courtois-1773750600-1773750655-7749-1871-1773750912.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zOs8AH1FGSS7W7yjXb4GJA', '2026-03-20', 'admin', 39, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528307385600_57', 'Hai tuyển thủ eSports Thái Lan bị giam 3 tháng vì gian lận tại SEA Games', 'Sáng 17/3, tòa án quận Pathum Wan, Bangkok tuyên 6 tháng tù với Tokyogurl và Cheerio vì gian lận thi đấu tại SEA Games 33, nhưng giảm còn 3 tháng giam giữ do nhận tội. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tokyogurl-png-1773741329-17737-9236-3266-1773741471.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1xskZ9TIuyxAg2hn8Nzjkw', '2026-03-20', 'admin', 415, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528323389900_58', 'Việt kiều Croatia được đôn lên U23 Việt Nam', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, được đôn từ đội tuyển U19 lên U23 Việt Nam để ban huấn luyện đánh giá khả năng. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7630059415036-96db7a349004a0d-6837-4270-1773745617.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-g6RkAXzhB_htlIhsyapCw', '2026-03-20', 'admin', 327, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_3528339007100_59', 'Ancelotti: ''Real thời Mbappe cần thời gian để tạo nên di sản riêng''', 'Trả lời Radio Marca, cựu HLV Real Madrid Carlo Ancelotti kể về những tháng đầu dẫn dắt tuyển Brazil, quan hệ với đội bóng cũ, sự tiến hóa của bóng đá và cái nhìn về những học trò cũ như Mbappe, Vinicius hay Fede Valverde. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/download-11-1773738753-1773738-2303-4952-1773738784.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eZdhblJJcYn-9YBYl1v4nA', '2026-03-20', 'admin', 348, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772738251900_0', 'Ấn định thời gian tổ chức FIFA ASEAN Cup', 'Liên đoàn Bóng đá Thế giới (FIFA) đã phê duyệt kế hoạch tổ chức FIFA ASEAN Cup từ tháng 9-10/2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/AN-MUNG-VOI-CUP-VO-DICH57-2363-1773969526.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JidnBWJIvqfl2Dv9bvKkVQ', '2026-03-20', 'admin', 322, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772752531900_1', 'Cầu thủ Bayern từ chối phỏng vấn vì hết giờ làm việc', 'Filip Pavic và Deniz Ofli không trả lời phỏng vấn sau trận thắng Atalanta 4-1 ở lượt về vòng 1/8 Champions League tối 19/3 vì quá giới hạn giờ làm việc theo luật Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/image-1773967945398-1773967962-1222-8032-1773968011.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OAbrLeaaF4YcCa7BDbrymw', '2026-03-20', 'admin', 344, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772765775800_2', 'Thùy Linh vào tứ kết ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh chỉ mất 36 phút để thắng Lo Sin Yan Happy 21-12, 21-14, vào tứ kết giải cầu lông Orleans Masters, tối 19/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/20/thuy-linh-vo-dich10-jpg-177396-2060-5273-1773960838.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WC1v2qFlvAKogW4s3KTmlg', '2026-03-20', 'admin', 400, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772779958300_3', 'Tuyển Iran tẩy chay Mỹ nhưng vẫn dự World Cup', 'Chủ tịch LĐBĐ Iran (FFIRI) Mehdi Taj khẳng định đội tuyển nước này vẫn tham dự World Cup 2026 nhưng không muốn thi đấu tại Mỹ, khiến lịch thi đấu có thể xáo trộn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-png-1773924012-1773924022-2141-1773924048.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=v8T67oMfZFJdDkEG28y_uw', '2026-03-20', 'admin', 30, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772793666000_4', 'Tuyển nữ Iran được vinh danh ngày về nước', 'Đội tuyển bóng đá nữ Iran, ngoại trừ hai cầu thủ, đã về nước sau khi quá cảnh ở nhiều quốc gia, khép lại vụ việc gây chú ý tại Asian Cup nữ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/iran-1773919073-1773919081-7375-1773919159.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vHBTQCcZgQ23NsODfnyjhA', '2026-03-20', 'admin', 220, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772807202700_5', 'Neymar ''rất buồn'' vì quyết định của Ancelotti', 'Neymar bày tỏ sự thất vọng sau khi tiếp tục bị HLV Carlo Ancelotti từ chối cho trở lại tuyển Brazil. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t081833527-1-5964-1473-1773796972.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=AtSAIHhqEbf5SswZ44u2Ng', '2026-03-20', 'admin', 157, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772821018900_6', 'WADA lùi quyết định, tránh đối đầu ông Trump trước World Cup', 'Cơ quan Phòng chống Doping Thế giới (WADA) hoãn xem xét quy định có thể dẫn tới việc cấm Tổng thống Donald Trump tham dự các sự kiện thể thao lớn, qua đó tạm tránh nguy cơ đối đầu Mỹ trước thềm World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/trump-png-1773922699-177392270-5580-2360-1773922717.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tPI61WljNUU7JS-nfrvVbg', '2026-03-20', 'admin', 288, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772835382100_7', 'Thầy cũ làm cố vấn cho Van Persie', 'HLV lừng danh Dick Advocaat sẽ làm cố vấn cho Robin Van Persie, người đang gặp thách thức trên cương vị thuyền trưởng của Feyenoord. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t123143546-1-2315-7842-1773898604.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EGRmKUov_VUr9RywpY2_YA', '2026-03-20', 'admin', 55, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772848545700_8', 'Từ chối chung bục với nhà vô địch điền kinh Mỹ vì nghi vấn doping', '14 VĐV từ chối đứng chung bục với nhà vô địch các nội dung chạy 3.000m và 5.000m nam Seth Clevenger tại giải điền kinh sinh viên Mỹ, gây tranh cãi về quyền thi đấu của anh. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdv-png-1773826186-1773826265-6895-1773826290.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=3dlRyQmZif8TQv2oOJyjFg', '2026-03-20', 'admin', 314, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772861434600_9', 'Tiền đạo Việt kiều quyết bám trụ ở châu Âu, chưa nghĩ đến V-League', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, muốn tồn tại ở bóng đá châu Âu lâu nhất có thể trước khi nghĩ đến V-League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/lth-5549-1773919500-5935-1773919652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Oq80kL4Is_HxS-kTYViQCA', '2026-03-20', 'admin', 315, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772874730400_10', 'Tiền đạo Galatasaray đứt lìa đầu ngón tay khi thua Liverpool', 'Noa Lang chấn thương nghiêm trọng ở tay vì va chạm với bảng quảng cáo trong trận Galatasaray thua Liverpool 0-4 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/langPNG-1773891618-9616-1773891670.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ualx7vYEkEkQ4wvn8FuJsA', '2026-03-20', 'admin', 207, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772888444400_11', 'Carrick nêu tên ba cầu thủ Man Utd xứng đáng lên tuyển Anh', 'HLV Michael Carrick tin rằng Kobbie Mainoo, Harry Maguire và Luke Shaw đủ khả năng góp mặt trong đội hình tuyển Anh dự World Cup 2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/carrick-png-1773866556-1773866-3302-4474-1773866646.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=s4VmHxaB8FrD6zxszqsHTA', '2026-03-20', 'admin', 133, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772904157500_12', 'Malaysia chưa từ bỏ vụ bị xử thua Việt Nam', 'Malaysia đang tìm các hướng pháp lý để bảo vệ quyền lợi cho tuyển Malaysia, sau khi bị LĐBĐ châu Á xử thua vì bê bối cầu thủ nhập tịch. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/rob-friend-1773901649-17739016-6362-7761-1773901757.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1r2nj7BO1ioCJju3OWuaZw', '2026-03-20', 'admin', 238, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772919300400_13', 'Malaysia không có cầu thủ nhập tịch mới để đấu Việt Nam', 'Hai cầu thủ gốc nước ngoài Bergson và Giancarlo Gallifuoco không kịp nhập tịch để phục vụ tuyển Malaysia, trước lượt cuối vòng loại Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/img-3275-1773906019-5001-1773906024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=8DxpsIhPLEHK1qWD0FoaeQ', '2026-03-20', 'admin', 460, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772936602500_14', 'VĐV Esports Hoa Tranh: ''Ngày trở về từ SEA Games là lần đầu tiên tôi thấy bố khóc''', 'Trước khi giành HC vàng SEA Games 33, Bùi Nguyễn Hoa Tranh (1S RuuRuu) từng nghĩ đến khả năng từ bỏ con đường VĐV thể thao điện tử chuyên nghiệp vì bị bố mẹ phản đối. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/anh-4-1773897015-5035-17738994-5898-6381-1773899533.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=XlTU1AR6fUvNI4kafT6cqA', '2026-03-20', 'admin', 141, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772951181800_15', 'Xuân Son: ''Tôi muốn thắng, không cần biết Malaysia bị xử thua thế nào''', 'Trước ngày hội quân cùng tuyển Việt Nam, tiền đạo nhập tịch Nguyễn Xuân Son thể hiện quyết tâm cùng đồng đội đánh bại Malaysia ở lượt về vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/nam-dinh-vo-dich-v-league-2023-1951-6365-1773892546.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Og1tfVvmaRUSNkjUexYb-A', '2026-03-20', 'admin', 283, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772965682500_16', 'Slot nhắc khéo PSG', 'HLV Arne Slot nhấn mạnh việc Liverpool là đội duy nhất có thể kéo PSG vào loạt luân lưu tại Champions League mùa trước, qua đó thể hiện sự tự tin trước màn tái đấu ở tứ kết mùa này. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/slot-png-1773889897-1773889909-9873-1773889992.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=LWYXqv20DzmP7MWG6myD6Q', '2026-03-20', 'admin', 158, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772980980700_17', 'Arsenal 3 lần hưởng lợi từ VAR', 'Arsenal thoát ba quả phạt đền nhờ sai lầm của hệ thống video hỗ trợ trọng tài ở Ngoại hạng Anh, theo đánh giá của Ban xử lý các sự cố (KMI). (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/newproject20260318t172026934-1-9592-1762-1773829628.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=tNx-3Eh8U0xSzKdU6raA8w', '2026-03-20', 'admin', 353, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_772994693100_18', 'Philippines dự World Cup nữ lần thứ hai liên tiếp', 'Philippines hạ Uzbekistan 2-0 ở trận play-off khu vực châu Á trưa 19/3, để giành vé dự World Cup nữ 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/653430702-1381904660620992-221-2609-7183-1773897232.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=R7UmlWaDifmKsN3taZ-Gmw', '2026-03-20', 'admin', 334, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773008123800_19', 'Vì sao các đội bóng Anh rơi rụng ở Champions League?', 'Ngoại hạng Anh có tới sáu đội vào vòng 1/8 ở Champions League, nhưng chỉ còn Arsenal và Liverpool vào tứ kết. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/1773710180948mancityrealmadrid-2653-6959-1773757914.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=p1eLBPPG0hP-iPNgzdpC1Q', '2026-03-20', 'admin', 445, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773021841200_20', 'Messi chạm mốc 900 bàn, vẫn không cứu nổi Inter Miami', 'Đội trưởng Lionel Messi sớm ghi bàn nhưng chủ nhà Inter Miami chỉ hòa Nashville 1-1 ở lượt về vòng 1/8 CONCACAF Champions Cup, và bị loại bởi luật ghi bàn sân khách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/messi-jpeg-1773881744-17738817-5037-1960-1773882092.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=hwHF05gvNVSC4Ef0nGjKNg', '2026-03-20', 'admin', 322, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773035633000_21', 'Lewandowski phá một kỷ lục của Messi', 'Robert Lewandowski trở thành cầu thủ ghi bàn vào lưới nhiều đội bóng khác nhau nhất tại Champion League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/newproject20260319t074116697-1-5000-1174-1773881038.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2ngI4cwv3baoRsJpP6Nbpg', '2026-03-20', 'admin', 499, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773049696100_22', 'Xác định 4 cặp tứ kết Champions League', 'ĐKVĐ PSG đại chiến Liverpool, trong khi Real Madrid đấu Bayern Munich là những cặp đấu được chờ đợi ở tứ kết Champions League mùa 2025-2026. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/arsenal-png-1773874075-1773874-8366-3595-1773874264.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=YpF-4_ge5FhXJnWMzGNsuA', '2026-03-20', 'admin', 68, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773062604000_23', 'Kane chạm mốc 50 bàn ở Champions League', 'Lập cú đúp trong trận Bayern thắng Atalanta 4-1 ở lượt về vòng 1/8, Harry Kane trở thành cầu thủ người Anh đầu tiên chạm mốc 50 bàn ở Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/kane1-png-1773870859-177387087-1321-5328-1773871258.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=lrF0ArtaeTryRxVftXmeYA', '2026-03-20', 'admin', 76, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773075984700_24', 'Hai nữ cầu thủ Iran không đội hijab khi tập luyện tại Australia', 'Fatemeh Pasandideh và Atefeh Ramezanisadeh, hai cầu thủ xin tị nạn tại Australia, tham gia buổi tập cùng CLB Brisbane Roar mà không đội hijab - trang phục che kín từ cổ đến chân vốn bị bắt buộc theo quy định của Cộng hòa Hồi giáo Iran. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/iranPNG-1773840815-5081-1773840989.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=4fIEt2Y3tfrEr8P1tun_lw', '2026-03-20', 'admin', 500, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773090473000_25', 'Bố ''Thiên thần băng'' Alysa Liu thừa nhận sai lầm khi dạy con', 'Người cha của "Thiên thần băng" Alysa Liu thừa nhận những sai lầm trong quá khứ, khi nhìn lại hành trình đưa con gái tới đỉnh cao Olympic mùa Đông. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arthur-liu-alysa-liu-177382629-4892-6962-1773826652.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=W3u-0xRdIjAZBIJ5QJrzZQ', '2026-03-20', 'admin', 84, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773105916700_26', 'YouTube bắt tay FIFA phát sóng World Cup 2026', 'Thỏa thuận giữa YouTube và FIFA mở ra cách tiếp cận mới cho người hâm mộ khi cho phép phát trực tiếp một phần trận đấu, cùng nhiều nội dung độc quyền trên nền tảng video lớn nhất thế giới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/fifa-png-1773775939-1773775960-2114-1773775973.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=mTLltq3Bja2F22bFYvpfeg', '2026-03-20', 'admin', 202, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773120208900_27', 'Flick tránh nói khả năng Barca vô địch Champions League', 'HLV Hansi Flick duy trì thận trọng dù Barca đại thắng Newcastle 7-2 ở lượt về vòng 1/8 Champions League, tối 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/NewProject20260319T060911579-1-1339-6481-1773875561.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=kHoAQi7TDUXFcr6h89ZyQg', '2026-03-20', 'admin', 90, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773134416800_28', 'Tottenham bị Atletico loại khỏi Champions League', 'Thắng 3-2 ở lượt về tối 18/3, Tottenham vẫn dừng bước ở vòng 1/8 Champions League vì thua Atletico Madrid chung cuộc 5-7. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773874559636-1773874569-6754-8611-1773874805.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=WXigzq_XHtDG2K8l9lNCZA', '2026-03-20', 'admin', 108, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773148095200_29', 'Liverpool đấu PSG ở tứ kết Champions League', 'Thắng Galatasaray 4-0 ở lượt về vòng 1/8, Liverpool đi tiếp tại Champions League với tổng tỷ số 4-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/image1773872898601-1773872921-9151-5872-1773873066.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-VPoCGTfzNrIzO40T4XdRA', '2026-03-20', 'admin', 350, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773162913100_30', 'Barca thắng Newcastle 7-2 ở Champions League', 'Barca thắng đội khách Newcastle 7-2 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 8-3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/19/barca-png-1773868979-177386900-2805-1625-1773869128.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=Vsem5oeB9FuV0jTuy2_2DQ', '2026-03-20', 'admin', 383, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773177597400_31', 'Rakitic: ''Barca thời tôi lẽ ra phải giành thêm ba Champions League''', 'Trả lời phỏng vấn kênh radio Catalonia Cadena SER, cựu tiền vệ Croatia Ivan Rakitic nhìn lại thời kỳ vàng son của Barca, tiếc nuối về những cơ hội bị bỏ lỡ ở Champions League và phân tích tình hình hiện tại của thầy trò Hansi Flick. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/top-1773834422-9056-1773834524.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=BjNtzP_sflZqa-6YmD-Mjg', '2026-03-20', 'admin', 337, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773191769100_32', 'Vợ chạy 10 km tưởng nhớ Diogo Jota', 'Rute Cardoso hoàn thành cuộc đua 10 km tại Porto với số áo 20, trong Ngày của Cha đầu tiên kể từ khi cố tiền đạo Liverpool Diogo Jota tử nạn. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/rutePNG-1773826559-2930-1773826561.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=7s8TcEYo0ktvOznkvcFIqg', '2026-03-20', 'admin', 501, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773205851700_33', 'Senegal khiếu nại khi bị tước chức vô địch châu Phi', 'Senegal tuyên bố kiện lên Tòa Trọng tài Thể thao (CAS) về việc bị tước chức vô địch châu Phi 2025, hai tháng sau khi đăng quang ở Morocco. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/senegal-sadio-mane-1773831398-9470-4714-1773831475.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=7UQcAQYUPCumgb9DXiwMgQ', '2026-03-20', 'admin', 125, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773218737600_34', 'Tốc độ - điểm tựa để Duplantis định nghĩa lại nhảy sào', 'Qua nhiều năm, Armand Duplantis tập trung tối đa vào tốc độ, tạo nên cơ chế vận động đặc biệt để 15 lần phá kỷ lục thế giới với mốc mới nhất là 6,31 m thiết lập hôm 12/3 tại Uppsala, Thụy Điển. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image-1773820570531-1773820590-6075-3474-1773821051.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=49kqAoW8YXRKEskZTYDonA', '2026-03-20', 'admin', 436, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773235155900_35', 'Chuyên gia Malaysia: ''Không được buông xuôi khi tái đấu Việt Nam''', 'Đã mất vé dự Asian Cup 2027 vì bê bối nhập tịch, nhưng chuyên gia Zulakbal Abdul Karim cho rằng Malaysia nên xem trận đấu sắp tới với Việt Nam là cơ hội gỡ gạc thể diện. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/559442709-122153351474803027-6-6606-4056-1773807723.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=w_jBT4_2sv3DRmpLwsBwAQ', '2026-03-20', 'admin', 416, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773254155900_36', 'Henry: ''CĐV trung lập không muốn Arsenal vô địch''', 'Huyền thoại Thierry Henry cảm thấy khó hiểu khi nhiều CĐV trung lập không muốn Arsenal đăng quang Ngoại hạng Anh, đồng thời lên tiếng bảo vệ lối chơi thực dụng của đội bóng dưới thời HLV Mikel Arteta. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/arsenal-png-1773750496-1773750-9517-8995-1773750527.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=5eRI7k-GSroryTc-98-Txg', '2026-03-20', 'admin', 500, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773272903900_37', 'Carragher: ''Liverpool đang đánh mất bản sắc và niềm tin CĐV dưới thời Slot''', 'Cựu hậu vệ Jamie Carragher cho rằng Liverpool không chỉ đánh mất lối chơi pressing từng làm nên thương hiệu dưới thời Jurgen Klopp mà còn dần đánh mất sự ủng hộ từ khán giả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tottenham-png-1773752395-17737-1382-6361-1773752445.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=tBvdxo8jIKctwoKedMDx-Q', '2026-03-20', 'admin', 389, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773290185100_38', 'AFC được đánh giá cao khi không nương tay với Malaysia', 'Nhiều tờ báo trong khu vực khen ngợi Liên đoàn bóng đá châu Á vì thẳng tay xử thua Malaysia ở vòng loại cuối Asian Cup 2027. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/img-3473-1773740118-3722-1773740123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=bVLAgWv6TX4y-ZOuQjnB4w', '2026-03-20', 'admin', 77, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773306716900_39', 'Thùy Linh thắng nghẹt thở ở giải Pháp', 'Tay vợt nữ số một Việt Nam Nguyễn Thùy Linh hạ đối thủ được đánh giá cao hơn Lin Hsiang-ti 2-1 ở trận ra quân giải cầu lông Orleans Masters, chiều 18/3. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/11-jpg-1773830995-1186-1773831360.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JfNGXkiE-GdJF-YVUI1xIA', '2026-03-20', 'admin', 229, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773321496300_40', 'Enrique bất ngờ khi PSG thắng đậm Chelsea', 'HLV Luis Enrique thừa nhận chưa từng nghĩ PSG có thể đè bẹp Chelsea với tổng tỷ số 8-2 ở vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/enrique-png-1773811580-1773811-5639-2995-1773811650.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=po-EQiJAXJnHV1MIbhu0vA', '2026-03-20', 'admin', 358, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773335417600_41', 'Flick sẽ giải nghệ sau khi rời Barca', 'HLV Hansi Flick phủ nhận đồng ý gia hạn với Barca, nhưng khẳng định đội bóng xứ Catalonia sẽ là bến đỗ cuối cùng trong sự nghiệp cầm quân. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/flick1-png-1773778564-17737786-8387-6182-1773778660.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=UV3lPCVahzoE3Zt9PxbbEA', '2026-03-20', 'admin', 351, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773348905800_42', 'Guardiola: ''Ai cũng muốn tôi bị sa thải''', 'HLV Pep Guardiola bác bỏ khả năng chia tay Man City dù bị Real Madrid loại khỏi Champions League, đồng thời tin tưởng vào triển vọng tích cực mùa tới. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/pep-png-1773798800-1773798815-7191-1773798881.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=rtxOlOuaZAhTncoH24ReRg', '2026-03-20', 'admin', 221, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773361882400_43', 'Vinícius giả vờ khóc để châm chọc CĐV Man City', 'Tiền đạo Vinicius cho biết những màn mừng bàn thắng trong trận hạ Man City 2-1 ở lượt về vòng 1/8 Champions League là lời đáp trả tấm banner chế giễu anh từ mùa trước. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-png-1773792039-1773792047-1924-1773793390.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=2plZZ9Z-BT5gzPf8L3aT1w', '2026-03-20', 'admin', 356, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773374319800_44', 'Senegal bị tước chức vô địch Cup châu Phi 2026', 'Kết quả trận chung kết Cup châu Phi (AFCON) 2026 bị đảo ngược, khi chủ nhà Morocco được xử thắng 3-0 trước Senegal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773790138504-1773790163-8054-1773790485.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=e5EhHcs6VXNKBStFraLlbw', '2026-03-20', 'admin', 505, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773386921500_45', 'CĐV Malaysia: ''Vụ gian lận nhập tịch là nỗi hổ thẹn quốc gia''', 'Làn sóng phẫn nộ bùng lên sau khi LĐBĐ châu Á (AFC) xử thua Malaysia 0-3 ở trận gặp Nepal và Việt Nam vì dùng cầu thủ nhập tịch không đủ tư cách. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/malaysia-bi-xu-thua-1773745350-8129-9070-1773745502.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=61ulTsK_fGL0qbEZOxtOKQ', '2026-03-20', 'admin', 142, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773401077900_46', 'Siêu sao bóng bàn Trung Quốc tạo cơn sốt chuyển nhượng tại Đức', 'Fan Zhendong sẽ rời 1. FC Saarbrucken TT sau mùa giải này để gia nhập kình địch Borussia Dusseldorf, tạo nên một trong những thương vụ gây chú ý nhất của Bundesliga bóng bàn Đức. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/zhendong-1773720139-1773720150-9937-1773720478.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=KixJarScZbvUNkyUJgurtA', '2026-03-20', 'admin', 271, 'SPORT', 1, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773414145800_47', 'Real hạ Man City, vào tứ kết Champions League', 'Vinicius lập cú đúp giúp Real Madrid thắng 2-1 trên sân của Man City, đội phải đá thiếu người từ hiệp một ở lượt về vòng 1/8 Champions League, để đi tiếp với kết quả chung cuộc 5-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vini-1773788393-1773788421-8762-1773788445.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=fOykQp0zSx7XL-euN6VMfw', '2026-03-20', 'admin', 393, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773427528900_48', 'PSG vùi dập Chelsea ở Champions League', 'Sau trận thắng 5-2 ở lượt đi, ĐKVĐ PSG tiếp tục đè bẹp Chelsea 3-0 ngay tại Stamford Bridge ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/psg1-png-1773787486-1773787582-5228-1773787664.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=NNYls03Jvo3QkKWark4Qtg', '2026-03-20', 'admin', 15, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773440273000_49', 'Arsenal vào tứ kết Champions League', 'Arsenal thắng đội khách Leverkusen 2-0 ở lượt về vòng 1/8, qua đó vào tứ kết Champions League với tổng tỷ số 3-1. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/arsenal2-png-1773785414-177378-5607-7238-1773785517.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=ws_yDnDrbPSZ6RSu3aJyuQ', '2026-03-20', 'admin', 384, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773455473800_50', '''Ngựa ô'' Bodo/Glimt bị loại khỏi Champions League', 'Thắng 3-0 từ lượt đi, nhưng Bodo/Glimt vẫn bị loại khi thua Sporting Lisbon 0-5 ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/image1773782561242-1773782577-8615-1345-1773782755.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=T6CIsrQnBsmht0o3buqKWQ', '2026-03-20', 'admin', 413, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773469513900_51', 'Runner Trung Quốc bị chặn ngay trước vạch đích khi đang dẫn đầu', 'Xueji Sheng bất ngờ bị trọng tài ngăn cản ngay trước vạch đích do nhầm với người chạy half marathon, phải "về đích lại" để hoàn tất thủ tục ghi nhận kết quả. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/18/vdvPNG-1773791774-1248-1773791779.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=md9z0cz3Co2j-wIP4EWpjA', '2026-03-20', 'admin', 72, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773482580300_52', 'Iran muốn dời các trận World Cup 2026 từ Mỹ sang Mexico', 'LĐBĐ Iran (FFIRI) đang bàn với FIFA chuyển các trận của đội tuyển nước này ở World Cup 2026 từ Mỹ sang quốc gia đồng chủ nhà Mexico, do những lo ngại về an toàn của các cầu thủ. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/image-1773751920118-1773751934-4946-8771-1773752024.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=g06qKBljyPM39QVRjhwpIA', '2026-03-20', 'admin', 381, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773496252200_53', 'Enrique: ''Câu đùa về Ngoại hạng Anh theo tôi khắp nơi''', 'HLV Luis Enrique nói câu đùa của ông về việc đánh bại các CLB Ngoại hạng Anh bị nhắc lại ở khắp nơi, khi PSG chuẩn bị tái đấu Chelsea ở lượt về vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/enrique-1773716464-1773716640-3320-1773716649.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=JuRfLttCMERhjkDaYEbmMA', '2026-03-20', 'admin', 467, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773508419000_54', 'Guardiola nói về ''văn hóa đón nhận thất bại'' trước thềm đại chiến Real', 'Pep Guardiola đã có những phân tích trước thềm trận lượt về Man City - Real Madrid ở vòng 1/8 Champions League, đồng thời đưa ra những chiêm nghiệm về "văn hóa đón nhận thất bại" trong thể thao. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/idjv5irrtfitraeiaqouzqasri-177-8609-2353-1773752110.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GHaNqqdTA3lETSjOvwg2vw', '2026-03-20', 'admin', 50, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773521627100_55', 'Leverkusen ra sức châm chọc Arsenal', 'Trước trận lượt đi lẫn lượt về vòng 1/8 Champions League, trang mạng xã hội chính thức của Bayer Leverkusen liên tục đăng tải các bài viết mang tính hài hước, trêu đùa đối thủ Arsenal. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7629011609378-12196e04c788300-4265-4771-1773751277.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xcRrq5P1zJMGGLlmFQ7jGA', '2026-03-20', 'admin', 80, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773534840400_56', 'David Silva: ''Nếu Real thủng lưới trong 25 phút đầu, Man City sẽ có cơ hội''', 'Theo cựu danh thủ Man City David Silva, nếu chọc thủng lưới Real Madrid sớm, Man City sẽ có cơ hội lật ngược thế cờ sau khi thua 0-3 ở lượt đi vòng 1/8 Champions League. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/courtois-1773750600-1773750655-7749-1871-1773750912.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zOs8AH1FGSS7W7yjXb4GJA', '2026-03-20', 'admin', 310, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773547656400_57', 'Hai tuyển thủ eSports Thái Lan bị giam 3 tháng vì gian lận tại SEA Games', 'Sáng 17/3, tòa án quận Pathum Wan, Bangkok tuyên 6 tháng tù với Tokyogurl và Cheerio vì gian lận thi đấu tại SEA Games 33, nhưng giảm còn 3 tháng giam giữ do nhận tội. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/tokyogurl-png-1773741329-17737-9236-3266-1773741471.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1xskZ9TIuyxAg2hn8Nzjkw', '2026-03-20', 'admin', 46, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773560603000_58', 'Việt kiều Croatia được đôn lên U23 Việt Nam', 'Antonio Moric, mang hai dòng máu Việt Nam và Croatia, được đôn từ đội tuyển U19 lên U23 Việt Nam để ban huấn luyện đánh giá khả năng. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/z7630059415036-96db7a349004a0d-6837-4270-1773745617.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-g6RkAXzhB_htlIhsyapCw', '2026-03-20', 'admin', 152, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_SPORT_773573531000_59', 'Ancelotti: ''Real thời Mbappe cần thời gian để tạo nên di sản riêng''', 'Trả lời Radio Marca, cựu HLV Real Madrid Carlo Ancelotti kể về những tháng đầu dẫn dắt tuyển Brazil, quan hệ với đội bóng cũ, sự tiến hóa của bóng đá và cái nhìn về những học trò cũ như Mbappe, Vinicius hay Fede Valverde. (Nguồn: VNExpress)', 'https://i1-thethao.vnecdn.net/2026/03/17/download-11-1773738753-1773738-2303-4952-1773738784.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=eZdhblJJcYn-9YBYl1v4nA', '2026-03-20', 'admin', 127, 'SPORT', 0, 1, 'Bóng đá');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215590059700_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 333, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215703287500_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 357, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215717939100_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 236, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215732544400_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 431, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215747345000_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 246, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215762524500_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 363, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215777778600_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 342, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215794243700_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 125, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215810902500_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 61, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215826279000_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 440, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215841992400_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 319, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215859279500_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 166, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215876033300_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 289, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215892410700_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 321, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215907644500_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 455, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215923125200_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 401, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215937844900_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 311, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215952561600_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 118, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215966076300_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 376, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215979715500_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 242, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1215993760000_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 312, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216008208600_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 32, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216022231000_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 433, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216036244600_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 82, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216049828600_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 276, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216064336800_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 444, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216077880600_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 210, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216091813100_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 65, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216105460100_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 190, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216119280300_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 359, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216132912800_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 381, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216146500700_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 214, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216159977500_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 270, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216174232300_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 269, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216187982900_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 284, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216201497800_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 87, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216215314100_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 127, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216229482400_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 152, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216243630000_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 193, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216257602600_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 195, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216271280500_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 427, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216290747300_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 424, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216310346200_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 406, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216331539700_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 105, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216348547900_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 215, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216363762200_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 308, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216378415900_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 378, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216392932000_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 227, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216407764000_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 195, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216421952100_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 207, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216436300800_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 266, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216449625000_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 433, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216463632700_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 410, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216478312500_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 261, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216492657900_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 365, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216506896500_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 274, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216521141300_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 348, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216535156300_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 448, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216549238800_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 61, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1216562667500_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 198, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217635009300_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 162, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217648627100_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 166, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217662356800_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 20, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217675735000_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 265, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217688878300_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 297, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217703508700_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 376, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217716764600_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 479, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217730329300_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 24, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217743608900_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 453, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217763094900_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 24, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217776489900_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 141, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217789805200_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 306, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217802992300_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 423, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217815927600_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 56, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217829688200_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 261, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217844320200_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 330, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217857469200_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 494, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217871888100_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 493, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217886640700_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 174, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217900377500_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 141, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217913364500_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 195, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217933390800_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 141, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217951392200_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 126, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217968356800_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 15, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1217986271500_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 329, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218001166800_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 140, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218015432400_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 390, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218028392900_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 115, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218041303300_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 326, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218054493000_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 187, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218067908900_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 279, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218081082800_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 265, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218094576200_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 101, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218107402900_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 382, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218121093600_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 294, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218134139100_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 390, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218147149300_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 209, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218160309400_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 282, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218174416800_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 271, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218187671600_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 236, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218201088600_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 222, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218214491000_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 366, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218228468200_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 501, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218242471300_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 161, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218256162500_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 384, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218270594500_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 242, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218284435500_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 454, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218298807800_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 369, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218313225500_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 203, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218328112900_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 44, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218342406500_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 326, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218356464900_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 126, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218371283700_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 294, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218384575400_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 117, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218399407200_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 280, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218419629400_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 78, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218438152500_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 390, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218454966400_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 174, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218469468900_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 360, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1218487660700_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 458, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_144268847700_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 199, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152113353000_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 435, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152141101200_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 138, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152164764500_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 496, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152185456600_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 357, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152209587900_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 404, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152234914300_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 364, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152256302200_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 250, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152277443100_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 408, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152303333600_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 312, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152324286300_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 190, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152349807300_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 50, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152369453100_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 215, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152389368200_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 258, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152407719000_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 258, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152425605700_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 26, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152444785000_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 491, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152462890700_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 323, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152481390900_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 161, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152500062200_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 496, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152517916700_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 72, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152535207100_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 473, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152550700800_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 190, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152565423600_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 197, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152580466400_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 420, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152594829800_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 82, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152608636000_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 373, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152628285200_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 337, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152642123600_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 498, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152655612100_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 10, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152669796600_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 500, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152683684000_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 462, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152698659900_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 277, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152713794000_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 278, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152729475800_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 471, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152743836900_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 233, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152759017800_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 286, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152774511100_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 24, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152789126200_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 413, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152802904800_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 379, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152816607900_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 197, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152831984700_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 22, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152846085800_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 161, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152860585700_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 149, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152873466100_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 114, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152890231900_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 208, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152903535800_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 282, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152915592800_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 283, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152927117900_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 313, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152940275400_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 240, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152953692500_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 11, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152967226100_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 100, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152980452300_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 338, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_152993305900_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 288, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_153005524800_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 509, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_153018444700_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 425, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154135467100_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 461, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154150406400_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 337, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154164271300_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 63, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154179047200_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 251, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154193200500_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 161, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154207654300_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 430, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154222751500_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 410, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154241962800_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 80, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154265509900_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 376, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154286396600_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 407, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154304120500_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 14, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154318317600_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 98, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154332744500_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 430, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154347388200_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 304, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154361552200_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 273, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154375982600_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 379, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154390437400_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 150, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154405805000_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 218, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154420191000_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 206, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154434207600_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 509, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154448405000_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 311, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154462802600_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 56, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154477580900_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 350, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154491946100_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 107, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154507007500_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 185, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154522116900_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 229, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154537905400_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 184, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154554023700_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 347, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154569083100_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 84, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154583974700_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 440, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154598454900_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 40, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154612199300_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 230, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154626178400_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 402, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154639521300_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 398, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154653045900_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 73, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154667067000_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 453, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154681086600_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 324, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154696577100_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 353, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154710121000_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 13, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154723578500_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 381, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154737533300_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 446, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154752129300_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 17, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154766064200_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 506, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154779528300_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 211, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154793666100_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 207, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154807814600_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 37, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154821311800_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 21, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154834811100_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 80, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154848126800_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 155, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154862220100_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 328, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154881599400_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 383, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154896016000_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 471, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154909522400_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 185, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154923004000_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 179, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154936398500_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 153, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154949830300_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 410, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154963522700_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 16, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154977154900_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 184, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_154990807900_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 179, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_155003835600_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 55, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935359766_0', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-19', 'admin', 149, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360107_1', 'Robot hình người bị lôi khỏi nhà hàng vì đập bát đĩa', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-19', 'admin', 495, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360124_2', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-19', 'admin', 73, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360142_3', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-19', 'admin', 507, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360160_4', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-19', 'admin', 99, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360180_5', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-19', 'admin', 508, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360200_6', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-19', 'admin', 269, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360224_7', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-19', 'admin', 452, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360252_8', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-19', 'admin', 81, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773935360272_9', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-19', 'admin', 431, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084711_0', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-19', 'admin', 52, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084824_1', 'Robot hình người bị lôi khỏi nhà hàng vì đập bát đĩa', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-19', 'admin', 310, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084837_2', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-19', 'admin', 253, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084853_3', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-19', 'admin', 18, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084869_4', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-19', 'admin', 106, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084884_5', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-19', 'admin', 186, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084899_6', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-19', 'admin', 418, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084918_7', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-19', 'admin', 365, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936084938_8', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-19', 'admin', 396, 'TECH', 0, 1, 'Chuyển đổi số');
