INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936509065_5', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-19', 'admin', 316, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936509083_6', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-19', 'admin', 211, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936509100_7', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-19', 'admin', 41, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936509116_8', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-19', 'admin', 319, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936509133_9', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-19', 'admin', 435, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936728784_0', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-19', 'admin', 380, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936729123_1', 'Robot hình người bị lôi khỏi nhà hàng vì đập bát đĩa', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-19', 'admin', 40, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_1773936729159_2', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-19', 'admin', 82, 'TECH', 0, 1, 'Chuyển đổi số');
