INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21306904942700_10', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-19', 'admin', 337, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21306922583400_11', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-19', 'admin', 255, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21306938954700_12', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-19', 'admin', 408, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21306955617900_13', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-19', 'admin', 332, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21306974108400_14', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-19', 'admin', 237, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21306991893000_15', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-19', 'admin', 233, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307009656000_16', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-19', 'admin', 367, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307026089800_17', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-19', 'admin', 454, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307055063100_18', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-19', 'admin', 265, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307075633400_19', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-19', 'admin', 413, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307093007800_20', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-19', 'admin', 59, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307109734200_21', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-19', 'admin', 414, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307125529100_22', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-19', 'admin', 433, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307142008200_23', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-19', 'admin', 503, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307157596300_24', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-19', 'admin', 478, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307173308900_25', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-19', 'admin', 434, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307190931300_26', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-19', 'admin', 232, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307205714300_27', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-19', 'admin', 205, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307226587700_28', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-19', 'admin', 327, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307250493700_29', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-19', 'admin', 276, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307274240700_30', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-19', 'admin', 392, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307294063000_31', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-19', 'admin', 106, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307314520400_32', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-19', 'admin', 314, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307331431700_33', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-19', 'admin', 74, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307348154500_34', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-19', 'admin', 474, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307363119200_35', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-19', 'admin', 150, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307377415400_36', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-19', 'admin', 311, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307391363000_37', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-19', 'admin', 412, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307406842300_38', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-19', 'admin', 370, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307424709900_39', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-19', 'admin', 57, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307440598000_40', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-19', 'admin', 494, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307455645300_41', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-19', 'admin', 88, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307469408100_42', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-19', 'admin', 415, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307482972800_43', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-19', 'admin', 187, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307496496200_44', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-19', 'admin', 266, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307510226400_45', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-19', 'admin', 96, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307524856100_46', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-19', 'admin', 450, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307539202100_47', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-19', 'admin', 439, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307553515600_48', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-19', 'admin', 314, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307567791900_49', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-19', 'admin', 508, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307584159300_50', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-19', 'admin', 276, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307609339300_51', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-19', 'admin', 439, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307632018600_52', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-19', 'admin', 363, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307655566800_53', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-19', 'admin', 57, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307674925900_54', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-19', 'admin', 94, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307692585300_55', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-19', 'admin', 372, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307711527300_56', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-19', 'admin', 224, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307726687400_57', 'JBL BandBox - loa di động đầu tiên tích hợp AI tách nhạc', 'JBL BandBox trang bị công nghệ Stem AI cho phép tách tiếng nhạc cụ và giọng hát theo thời gian thực không cần kết nối mạng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/DSC4720-1773301532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6tcrIEyYJcs5Oln-zi1oAg', '2026-03-19', 'admin', 335, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307740754400_58', 'CT Group phát triển UAV bầy đàn chữa cháy', 'Công ty CT UAV, thành viên của tập đoàn CT Group, phát triển hệ thống UAV bầy đàn hỗ trợ chữa cháy trong ngõ nhỏ, hẻm sâu, nơi xe cứu hỏa khó tiếp cận. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/ct-uav-chua-chay-1-1773380349-8933-6405-1773380405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=PKoTWze2Ex_F1khr1UkpXg', '2026-03-19', 'admin', 124, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307754712100_59', 'Đóng góp GDP của ngành khoa học và công nghệ tăng 35% sau hợp nhất hai Bộ', 'Sau một năm hợp nhất Bộ Khoa học và Công nghệ với Bộ Thông tin và Truyền thông, giá trị đóng góp vào GDP của toàn ngành tăng trưởng 35%. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/1-nam-1-1773418794-1308-1773418982.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ActkFKy_J3nkUaFwxb0vtw', '2026-03-19', 'admin', 440, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307890254800_0', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-19', 'admin', 446, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307905129200_1', 'Robot hình người bị lôi khỏi nhà hàng vì đập bát đĩa', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-19', 'admin', 171, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307919031900_2', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-19', 'admin', 248, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307932559000_3', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-19', 'admin', 68, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307946279700_4', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-19', 'admin', 431, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307960309700_5', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-19', 'admin', 346, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307974473500_6', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-19', 'admin', 111, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21307988369700_7', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-19', 'admin', 85, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308002642500_8', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-19', 'admin', 47, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308017182600_9', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-19', 'admin', 451, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308034869800_10', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-19', 'admin', 278, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308053220700_11', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-19', 'admin', 242, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308067766700_12', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-19', 'admin', 384, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308082112900_13', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-19', 'admin', 317, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308106050000_14', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-19', 'admin', 149, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308126841100_15', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-19', 'admin', 58, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308147822700_16', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-19', 'admin', 400, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308165911200_17', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-19', 'admin', 56, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308187663800_18', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-19', 'admin', 451, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308203407000_19', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-19', 'admin', 106, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308219636300_20', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-19', 'admin', 381, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308235581900_21', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-19', 'admin', 396, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308250133100_22', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-19', 'admin', 280, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308265015000_23', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-19', 'admin', 468, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308279554000_24', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-19', 'admin', 203, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308293109100_25', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-19', 'admin', 98, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308306618600_26', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-19', 'admin', 249, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308319672500_27', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-19', 'admin', 223, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308333513900_28', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-19', 'admin', 55, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308354107100_29', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-19', 'admin', 391, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308368492100_30', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-19', 'admin', 480, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308386134000_31', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-19', 'admin', 466, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308402483900_32', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-19', 'admin', 391, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308417602600_33', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-19', 'admin', 468, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308432000400_34', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-19', 'admin', 233, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308445584600_35', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-19', 'admin', 445, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308459742200_36', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-19', 'admin', 488, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308479712400_37', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-19', 'admin', 211, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308500388600_38', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-19', 'admin', 159, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308521076900_39', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-19', 'admin', 80, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308539946600_40', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-19', 'admin', 153, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308558406200_41', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-19', 'admin', 457, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308575887400_42', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-19', 'admin', 232, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308595708300_43', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-19', 'admin', 203, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308612867100_44', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-19', 'admin', 197, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308626798600_45', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-19', 'admin', 217, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308640716800_46', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-19', 'admin', 90, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308653899600_47', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-19', 'admin', 18, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308667810000_48', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-19', 'admin', 456, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308681824100_49', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-19', 'admin', 402, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308696138900_50', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-19', 'admin', 88, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308710168000_51', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-19', 'admin', 389, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308723986400_52', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-19', 'admin', 254, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308737303600_53', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-19', 'admin', 231, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308750545500_54', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-19', 'admin', 41, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308764388400_55', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-19', 'admin', 191, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308778062900_56', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-19', 'admin', 316, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308791250700_57', 'JBL BandBox - loa di động đầu tiên tích hợp AI tách nhạc', 'JBL BandBox trang bị công nghệ Stem AI cho phép tách tiếng nhạc cụ và giọng hát theo thời gian thực không cần kết nối mạng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/DSC4720-1773301532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=6tcrIEyYJcs5Oln-zi1oAg', '2026-03-19', 'admin', 118, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308804623800_58', 'CT Group phát triển UAV bầy đàn chữa cháy', 'Công ty CT UAV, thành viên của tập đoàn CT Group, phát triển hệ thống UAV bầy đàn hỗ trợ chữa cháy trong ngõ nhỏ, hẻm sâu, nơi xe cứu hỏa khó tiếp cận. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/ct-uav-chua-chay-1-1773380349-8933-6405-1773380405.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=PKoTWze2Ex_F1khr1UkpXg', '2026-03-19', 'admin', 223, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_21308818761700_59', 'Đóng góp GDP của ngành khoa học và công nghệ tăng 35% sau hợp nhất hai Bộ', 'Sau một năm hợp nhất Bộ Khoa học và Công nghệ với Bộ Thông tin và Truyền thông, giá trị đóng góp vào GDP của toàn ngành tăng trưởng 35%. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/1-nam-1-1773418794-1308-1773418982.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ActkFKy_J3nkUaFwxb0vtw', '2026-03-19', 'admin', 88, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3209963997800_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 100, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210134538500_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 139, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210153541200_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 23, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210175095800_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 108, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210197899200_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 499, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210219960000_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 273, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210295994400_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 156, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210329331500_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 441, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210353013500_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 162, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210375578500_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 185, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210397273800_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 112, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210418655200_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 288, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210441121900_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 140, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210463176700_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 465, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210484360200_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 236, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210505226400_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 160, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210523627100_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 57, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210544740600_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 432, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210564001600_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 247, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210582830300_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 276, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210600543900_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 343, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210619379600_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 178, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210638274500_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 358, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210656038300_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 373, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210674307800_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 496, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210692498700_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 468, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210710915200_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 208, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210727982000_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 49, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210745442900_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 484, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210763168500_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 394, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210781316200_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 289, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210799145600_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 103, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210817689900_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 22, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210835654200_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 294, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210853633400_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 169, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210871885100_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 444, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210889590500_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 88, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210906974600_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 84, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210925961000_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 421, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210943771200_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 285, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210961825200_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 165, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210979298900_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 262, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3210996933700_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 324, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211015564200_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 438, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211032636800_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 313, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211050709100_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 489, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211097738300_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 501, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211124330400_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 179, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211145270300_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 317, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211163219000_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 255, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211181160800_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 290, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211198902800_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 251, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211216578500_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 270, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211234419200_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 274, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211252314800_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 277, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211269605200_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 220, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211287115800_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 70, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211304859300_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 378, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211324337600_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 43, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3211342710000_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 508, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213270329400_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 452, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213293813400_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 305, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213318125400_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 289, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213340944700_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 57, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213372862200_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 287, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213404968900_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 390, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213430914200_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 144, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213453165200_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 214, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213473698000_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 503, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213496871600_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 311, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213516556100_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 82, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213533729000_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 28, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213554439000_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 133, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213574840700_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 148, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213596103100_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 491, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213616937100_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 299, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213637871600_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 76, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213657962500_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 164, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213679020000_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 69, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213699802300_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 332, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213721372500_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 332, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213742135100_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 297, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213762502800_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 354, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213809452800_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 472, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213846163300_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 51, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213867214200_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 44, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213896229600_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 300, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213914969900_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 134, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213936457600_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 397, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213956682500_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 465, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213977743700_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 452, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3213999041900_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 145, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214019486200_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 335, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214040286900_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 228, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214061244800_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 399, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214081734200_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 365, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214102950100_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 72, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214123661000_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 205, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214143572100_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 301, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214163257700_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 163, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214180636200_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 17, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214197842600_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 251, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214214250600_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 403, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214231453700_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 451, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214247957800_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 253, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214264541500_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 449, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214282203900_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 107, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214299140100_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 108, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214315843000_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 113, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214332840900_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 203, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214349468600_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 254, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214366519900_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 248, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214383724700_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 126, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214400647300_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 202, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214416957100_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 431, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214434343000_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 413, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214451462100_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 160, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214467950000_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 395, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214486463500_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 212, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3214502840400_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 400, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512000301200_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 375, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512070871500_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 116, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512098774600_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 36, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512125828700_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 153, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512153154700_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 499, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512179387800_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 26, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512204150900_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 50, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512229262900_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 349, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512255393400_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 440, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512277518700_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 477, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512301867800_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 112, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512325212500_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 454, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512348614300_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 192, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512373799300_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 237, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512395541100_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 389, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512417276200_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 482, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512440119400_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 92, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512463920200_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 185, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512485598000_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 31, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512538617700_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 171, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512600927500_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 264, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512638564700_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 234, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512660182000_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 117, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512685851900_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 195, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512706729900_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 406, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512728110100_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 257, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512750117000_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 389, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512772277800_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 252, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512793594400_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 379, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512816904000_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 294, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512838340400_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 363, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512857488000_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 351, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512878697400_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 238, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512898721700_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 413, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512919715200_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 455, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512942586600_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 259, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512963010300_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 420, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3512984134400_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 254, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513004939800_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 454, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513026171700_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 183, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513045224400_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 469, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513067468800_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 404, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513087138700_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 235, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513109808000_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 394, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513130560900_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 258, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513151827100_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 357, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513173185900_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 282, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513195581800_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 128, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513226093200_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 355, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513261721900_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 464, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513290762600_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 190, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513321410800_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 206, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513348829300_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 233, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513376650200_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 375, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513401648600_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 438, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513427789200_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 474, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513452933200_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 214, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513477788400_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 139, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513501971100_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 366, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3513526767700_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 242, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522757513400_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 115, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522775609700_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 209, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522819720600_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 397, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522851700900_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 78, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522872028700_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 215, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522892733800_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 246, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522910481700_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 183, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522935823400_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 389, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522955583700_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 280, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3522979599500_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 259, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523010050800_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 473, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523037626400_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 390, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523064938000_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 506, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523093533400_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 200, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523120882600_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 125, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523150780000_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 149, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523174824400_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 362, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523199494100_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 291, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523223033400_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 312, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523248737900_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 48, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523276358200_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 448, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523298464200_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 483, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523325197700_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 96, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523352239200_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 112, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523376278800_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 115, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523401384500_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 49, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523429678900_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 169, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523463057800_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 285, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523500110100_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 181, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523531102600_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 473, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523549810900_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 182, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523567844200_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 362, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523585432800_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 261, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523601812600_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 379, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523618291800_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 217, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523635083600_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 400, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523652688700_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 298, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523670374000_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 414, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523686687300_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 70, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523703047000_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 74, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523720995600_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 46, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523736921200_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 96, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523753633900_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 141, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523770902300_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 44, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523787923600_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 359, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523804663800_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 256, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523821698900_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 374, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523838917400_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 53, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523856407800_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 274, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523872621200_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 366, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523890195400_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 261, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523909362700_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 72, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523928678100_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 501, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523945412200_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 121, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523961997000_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 123, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3523979371800_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 458, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3524000376100_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 55, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3524067319800_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 319, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3524100773600_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 440, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_3524141374900_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 203, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770027463300_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 200, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770372282000_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 302, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770396535300_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 277, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770417798500_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 454, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770435795000_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 272, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770453620600_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 112, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770471893200_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 399, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770488186400_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 473, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770503808100_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 63, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770520053000_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 408, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770537417900_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 304, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770554747600_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 481, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770573975100_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 342, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770590760900_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 55, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770607162100_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 63, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770624985200_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 365, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770641394700_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 13, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770660819100_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 495, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770677194500_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 391, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770693000200_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 48, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770711217100_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 499, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770725867600_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 96, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770740017800_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 326, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770754424300_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 170, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770768571000_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 216, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770782760700_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 110, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770796311500_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 19, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770810146100_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 38, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770824320000_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 226, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770838208100_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 95, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770851955300_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 296, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770866499300_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 264, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770880448200_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 266, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770901372800_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 286, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770920063100_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 240, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770940758800_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 145, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770955968700_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 488, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770973296900_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 28, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_770989699200_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 203, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771008624200_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 461, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771023784700_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 366, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771038019000_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 506, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771052915400_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 253, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771068540500_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 481, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771083172400_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 344, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771096761900_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 140, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771111059500_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 203, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771124604900_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 111, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771138800100_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 443, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771152133900_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 122, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771165869800_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 490, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771179254000_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 224, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771192697400_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 135, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771206258900_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 207, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771220241500_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 298, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771233623200_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 356, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771247428000_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 463, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771260604800_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 506, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771273914300_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 441, 'TECH', 1, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771288103800_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 49, 'TECH', 0, 1, 'Chuyển đổi số');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771733987200_0', 'Robot hình người chơi tennis với người thật', 'Robot hình người G1 trang bị thuật toán mới, trình diễn khả năng phản ứng nhanh, di chuyển linh hoạt và đập bóng chính xác trong trận đánh tennis. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/327f096946744cd194a3e153b4cb18-3095-5464-1773896737.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YN82vWVGyHvmqxgSesDjsA', '2026-03-20', 'admin', 474, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771748192700_1', 'Doanh số iPhone tăng mạnh tại Trung Quốc', 'Doanh số iPhone tăng 23% trong 9 tuần đầu năm tại Trung Quốc, ngược với xu hướng giảm chung của thị trường này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/apple-store-4512-1773914113-5044-1773914123.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=a6SDSTseBB3SfbX_oE3wGQ', '2026-03-20', 'admin', 129, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771761886700_2', 'Memories AI - công ty tạo ''ký ức'' cho robot và thiết bị đeo', 'Với công nghệ "tầng bộ nhớ thị giác", Memories AI đang giúp robot và thiết bị đeo có khả năng ghi nhớ và gợi lại ký ức qua hình ảnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/mavi-1773854479-1773854504-177-5256-6519-1773854529.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=1KP0-QtF2pZwVBn8Lc3WlA', '2026-03-20', 'admin', 143, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771775099700_3', 'Robot hình người bị lôi khỏi nhà hàng vì mất kiểm soát', 'Một robot hình người bị "đuổi" khỏi nhà hàng ở California sau khi biểu diễn nhảy múa nhưng mất kiểm soát và làm vỡ bát đĩa. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/sss-1773895058-2796-1773895164.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=ctMA_RV54MWMFdqS-XN58g&t=image', '2026-03-20', 'admin', 292, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771788938500_4', 'Poco X8 Pro Max - cấu hình mạnh, pin 8.500 mAh', 'Poco X8 Pro Max trang bị chip hiệu năng cao Dimensity 9500s mới nhất, pin dung lượng lớn nhất phân khúc 8.500 mAh và giá từ 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/NTG08175-1773823532.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=UZsf4vzLICCtEe0NWxogkA', '2026-03-20', 'admin', 172, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771803010100_5', 'Sam Altman bị chế giễu sau khi cảm ơn lập trình viên', 'CEO OpenAI Sam Altman đăng lời cảm ơn các lập trình viên lên X, nhưng nhanh chóng nhận phản hồi tiêu cực từ cộng đồng này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/d9faeec305aa9369a2b700322dc79b-5682-9694-1773891520.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=V8CdfULFtqMBrOBxd4O4Ww', '2026-03-20', 'admin', 167, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771816323700_6', 'Tình trạng thiếu hụt chip nhớ ''kéo dài đến năm 2030''', 'Chey Tae-won, Chủ tịch SK Hynix, cho biết khủng hoảng chip nhớ toàn cầu sẽ tiếp tục trong 4-5 năm nữa do nguồn cung tấm wafer thiếu hụt. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/177d777a-31f1-4f89-b42d-42aeed-8940-7107-1773884903.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=zAe0dTMkPkGZfQeQnKnCjg', '2026-03-20', 'admin', 495, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771829272500_7', 'Startup Việt phát triển nền tảng AI cho đồ chơi tại Mỹ', 'Olli, startup Việt phát triển "hệ điều hành" cho đồ chơi AI, được nhiều ông lớn trên thế giới sử dụng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/buddy-1773656060-9065-17736566-8134-4542-1773885610.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LUPv2jx4wlzn3y4vE0JAcQ', '2026-03-20', 'admin', 82, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771843255200_8', 'Tại sao đập nhẹ giúp điều khiển TV hoạt động lại?', 'Thói quen dùng tay vỗ nhẹ khi điều khiển TV trục trặc đôi khi hiệu quả vì làm bong lớp oxy hóa, cho phép pin tiếp tục cung cấp điện. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/tvremotesmackingonhand-1773750-8264-9751-1773752384.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=OlDhZDjom_Xr0ZVCxm88-g', '2026-03-20', 'admin', 318, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771856602500_9', 'Việt Nam muốn làm chủ công nghệ lò phản ứng hạt nhân module nhỏ', 'Chiến lược phát triển, ứng dụng năng lượng nguyên tử vì mục đích hòa bình vừa được Chính phủ phê duyệt đặt mục tiêu làm chủ công nghệ lò phản ứng module nhỏ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/dsc06282-1773911930-3041-1773911987.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ICnaMwE7zydyHMLX9HEi2Q', '2026-03-20', 'admin', 132, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771870002400_10', 'FPT khởi công tổ hợp giáo dục tại Hải Phòng', 'Tổ hợp giáo dục FPT Hải Phòng đào tạo chương trình phổ thông, đại học và sau đại học, nhằm thúc đẩy nhân lực chất lượng cao, đặc biệt về khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/Anh5TCBCKhoicongHaiPhong-17738-8031-2818-1773898616.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=jsrVNFeaaOef8yHYhXwb-g', '2026-03-20', 'admin', 472, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771883598200_11', 'Việt Nam đứng đầu Đông Nam Á về nguy cơ mã độc từ USB', 'Trung bình cứ hai người dùng Việt Nam thì có một người đối mặt với mã độc phát tán qua thiết bị nội bộ, phần lớn là USB, theo Kaspersky. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/19/img-8150-3147-1745900520-17738-2623-3587-1773884573.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=4H_mUH-DB36uMcH6sE6Q1Q', '2026-03-20', 'admin', 293, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771897688800_12', 'Anthropic, OpenAI tuyển chuyên gia ngăn ''bom bẩn'' cho AI', 'Anthropic và OpenAI tuyển dụng chuyên gia ngăn nguy cơ AI hướng dẫn người dùng chế tạo vũ khí hóa học hoặc phóng xạ, hay "bom bẩn". (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/872c8a683bbe44379c63e75701bd30-3445-8792-1773849705.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=U7t09g5jz4mQzH4nMQh0Wg', '2026-03-20', 'admin', 40, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771911492700_13', 'iPhone 5 thành sản phẩm ''lỗi thời''', 'Sau 14 năm có mặt trên thị trường, Apple mới đưa iPhone 5 vào danh sách "lỗi thời", chấm dứt mọi hỗ trợ sửa chữa cho mẫu iPhone đầu tiên sử dụng cổng Lightning. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/iphone-5-16x9-1773760447-17737-4798-8151-1773760636.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=xo4MocRY-diR5Vj_xUYOmQ', '2026-03-20', 'admin', 85, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771925069200_14', 'Một tên miền Việt Nam được bán giá 217 triệu đồng', 'Trong phiên đấu giá đầu tiên, một tên miền ".vn" thuộc hàng hiếm, có hai ký tự, được đấu giá thành công với giá 217 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/Ten-mien-9609-1772166243-17738-6760-2592-1773835255.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=JD5p64QOzzRt4G3jri_L4w', '2026-03-20', 'admin', 24, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771938310000_15', 'Tim Cook bác tin đồn nghỉ hưu', 'Tim Cook, CEO Apple, bác bỏ những đồn đoán ngày càng lan rộng về tương lai của ông tại công ty, khẳng định vẫn yêu thích công việc hiện tại. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/ap25218800595274-1773834434-6099-1773834696.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ZFoUoz6DUPsho_jcbTuNpw', '2026-03-20', 'admin', 152, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771951431200_16', 'Thiên thạch 7 tấn nổ tung trên bầu trời Mỹ', 'Một thiên thạch nặng 7 tấn lao qua bầu trời Cleveland tạo thành quả cầu lửa bay với tốc độ 72.420 km/h trước khi tạo ra tiếng nổ long trời và vỡ vụn. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/s-1773812522-2930-1773812633.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=NVVw4yz_i2fWtTiTvBS4cQ&t=image', '2026-03-20', 'admin', 331, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771964743300_17', 'Loạt laptop chạy Core Ultra Series 3 đầu tiên tại Việt Nam', 'Dòng vi xử lý Core Ultra Series 3, tên mã Panther Lake, được Intel công bố tại Việt Nam thông qua loạt sản phẩm từ đối tác OEM. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc03823-jpg-1773742326-177376-8824-6228-1773763198.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rooF5lmFxusU2FJ_S3J7Qw', '2026-03-20', 'admin', 309, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771978628900_18', 'Google Maps bắt đầu cập nhật bản đồ hành chính của Việt Nam', 'Google Maps cập nhật địa giới hành chính một số tỉnh, thành phố tại Việt Nam sau hơn 8 tháng sáp nhập tỉnh, thành. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/bando-1773799691-1773799760-17-3705-6121-1773800176.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=1Y1i5YkxZPaZeiSL0a6dng', '2026-03-20', 'admin', 404, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_771992160600_19', 'Samsung dừng bán điện thoại gập ba Z TriFold sau 3 tháng ra mắt', 'Galaxy Z TriFold, smartphone gập ba đầu tiên của Samsung, ngừng kinh doanh tại Hàn Quốc, sau đó sẽ dần rút khỏi thị trường toàn cầu. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/a2-1764648119-5184-1764648311-9230-1687-1773760906.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rzaPe-1gZsefulL1zsgoCQ', '2026-03-20', 'admin', 240, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772006362200_20', 'Hai trường công nghệ hợp tác ươm tạo 5-10 doanh nghiệp mỗi năm', 'Học viện Công nghệ Bưu chính Viễn thông và Đại học Quốc gia Hà Nội hợp tác với mục tiêu ươm tạo và thúc đẩy doanh nghiệp khởi nguồn công nghệ (spin-off). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/ptit-1-1773761185-1773761231-3769-1773761280.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=ezfR9su_X9y7mfL1RWqxmg', '2026-03-20', 'admin', 130, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772021080400_21', 'Lập trình viên Việt xoay xở thế nào khi AI làm giảm thu nhập', 'Nhiều lập trình viên làm thêm "nghề phụ", cấp tốc tham gia các khóa học, hay tự vận hành AI tại nhà khi tác nhân AI đang tác động đến nghề nghiệp của họ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/chatgpt-image-11-40-37-16-thg-9959-9606-1773644685.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=18WJeNS7EZcsXoNdGMqnEA', '2026-03-20', 'admin', 26, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772034680700_22', 'Siêu El Nino có thể đẩy nhiệt độ toàn cầu tăng kỷ lục', 'Hiện tượng El Nino đặc biệt mạnh có khả năng xảy ra nửa cuối năm nay, đẩy nhiệt độ toàn cầu lên mức cao chưa từng thấy. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/Nangnongset4787168191080357846-2016-7236-1773724431.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=-P6wamSlAQ7IgnhDr8ASYw', '2026-03-20', 'admin', 470, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772047681000_23', '''AI đang thay đổi cách cảnh báo thiên tai''', 'Lãnh đạo Trung tâm Dự báo Khí tượng Thủy văn quốc gia cho rằng trí tuệ nhân tạo (AI) đang mở ra khả năng cảnh báo sớm theo thời gian thực, từng bước thay đổi cách dự báo thiên tai. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/653898870-1233248422311512-562-5420-4029-1773832588.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=75YEqA2TmqXlfOgB2ooAYA', '2026-03-20', 'admin', 67, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772060941400_24', 'Roborock Saros 20 nâng cấp lực hút và khả năng vượt rào', 'Saros 20, mẫu robot hút bụi cao cấp mới ra mắt của Roborock, có lực hút 35.000 Pa gần gấp đôi thế hệ trước và có thể vượt chướng ngại vật cao 8,5 cm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/DSC4951-1773761130.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=EJstG5GHPSILd6rbcEkDPQ', '2026-03-20', 'admin', 334, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772074158400_25', '''Nhiều kết quả nghiên cứu khoa học chưa gắn chặt với sản xuất và thị trường''', 'Nhiều kết quả nghiên cứu khoa học hiện vẫn chưa gắn chặt với sản xuất và thị trường, dù thể chế đã có bước tháo gỡ, nguồn lực được bố trí, theo Tổng Bí thư Tô Lâm. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/IMG-3734-JPG-6432-1699695925-1-3412-2217-1773751641.webp?w=1200&h=0&q=100&dpr=1&fit=crop&s=PhYfFYHDf3JHNlxBqzmekQ', '2026-03-20', 'admin', 255, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772088191900_26', 'Lý do Galaxy Buds4 bỏ qua thiết kế ''tai nghe chuẩn lab''', 'Tai nghe Galaxy Buds4 series không thiết kế theo điều kiện lý tưởng trong phòng lab mà dựa trên dữ liệu thực tế, nhằm đảm bảo trải nghiệm ổn định khi sử dụng hàng ngày. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/kbs-1773832350-1773832394-1149-1773832482.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=InumWpWWphaG1DjoUivebA', '2026-03-20', 'admin', 379, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772101689200_27', 'Samsung: AI mở rộng khả năng sáng tạo với camera Galaxy S26', 'AI giúp Galaxy S26 vượt qua giới hạn phần cứng, cho giai đoạn hậu kỳ thông minh hơn, cải thiện chất lượng ảnh zoom cao, từ đó nâng cấp trải nghiệm nhiếp ảnh, theo ông Joshua Cho. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/18/smsh-1773826040-1773826162-2543-1773826229.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=24nIuNOtHez-bo4gctQixw', '2026-03-20', 'admin', 408, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772115082100_28', 'Giá Starlink chênh thế nào so với dịch vụ Internet tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink của SpaceX có giá dự kiến 2,2 triệu đồng mỗi tháng tại Việt Nam, được cho là đắt đỏ đối với người dùng cá nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/dsc09681-1773724796-9130-1773726789.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=X4jgaZys0io-ry73cyhS3Q', '2026-03-20', 'admin', 174, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772129023200_29', 'Cơn sốt AI kéo Gen Z vào nghề thợ điện', 'Khi bằng đại học không còn đảm bảo mang lại công việc tốt, nhiều Gen Z học thêm nghề thợ điện, tận dụng làn sóng xây trung tâm dữ liệu AI. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/mediazenfs4-1773430319-1773430-6616-8570-1773432079.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=v6n6toiwrIRj1BzKL8qBQA', '2026-03-20', 'admin', 64, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772142143800_30', 'NIC sẽ quy tụ 100 nhân tài công nghệ Việt toàn cầu', 'Dự án quy tụ 100 nhân tài công nghệ Việt Nam trên thế giới được đề cập trong tọa đàm phát triển các ngành công nghệ chiến lược do NIC tổ chức tại Thung lũng Silicon. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-2192-9378-1773594201.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0IV_h2DbRYAv9pMOwqPP0w', '2026-03-20', 'admin', 184, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772155137600_31', 'Bảo mật trên Galaxy S26 có gì mới?', 'Trên bộ ba Galaxy S26, bên cạnh nâng cấp về phần cứng, camera và thời lượng pin, Samsung cũng tập trung hơn về bảo mật cho dòng smartphone này. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/s-1773552013-3747-1773552202.gif?w=1200&h=0&q=100&dpr=1&fit=crop&s=VLZntzvfKrubqfsGB42B9g&t=image', '2026-03-20', 'admin', 173, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772168487300_32', 'Nvidia ra ''OpenClaw phiên bản bảo mật''', 'Nvidia công bố NemoClaw - nền tảng tác nhân được xây dựng dựa trên OpenClaw nhưng tích hợp thêm tính năng bảo mật và quyền riêng tư cấp doanh nghiệp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/17/nvidia-gtc-2026-keynote-nemocl-2932-7873-1773707373.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=khHCwDPehP2a6AgZJVXsKw', '2026-03-20', 'admin', 58, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772181470600_33', 'TP HCM muốn huy động 1.000 tỷ đồng kiều hối cho khoa học công nghệ', 'TP HCM sẽ lập quỹ đầu tư công nghệ và triển khai các sản phẩm tiền gửi chuyên biệt dành cho kiều bào nhằm huy động nguồn lực đầu tư cho khoa học công nghệ và chuyển đổi xanh trong sản xuất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/phong-thi-nghiem-ban-dan-khu-c-5855-5596-1773670792.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=0yIO0-wPU30L0ni_TCMclg', '2026-03-20', 'admin', 55, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772194582900_34', 'iPhone 17e - khi Apple tự tin với hệ sinh thái iOS', 'iPhone 17e cho thấy sự tự tin của Apple khi đây là sản phẩm bổ sung lựa chọn cho người dùng yêu thích hệ sinh thái iOS thay vì để cạnh tranh với đối thủ Android. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773631863.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GajlgvXQm-NT_7PVnsznag', '2026-03-20', 'admin', 464, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772208133900_35', 'Ban hành Nghị định xử phạt hành chính lĩnh vực năng lượng nguyên tử', 'Chính phủ quy định mức phạt hành chính cao nhất 2 tỷ đồng đối với hành vi không thực hiện các biện pháp ngăn ngừa để xảy ra sự cố tại nhà máy điện hạt nhân. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hatnhan-2-1773645693-9737-1773645702.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=vr9KXQvxtWHLGcZWSNdCuQ', '2026-03-20', 'admin', 265, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772227483300_36', 'Tranh cãi về bức ảnh cá mập Greenland 392 tuổi', 'Ảnh chụp cá mập Greenland với chú thích 392 tuổi gây chú ý trên mạng xã hội, nhưng các nhà nghiên cứu suy đoán nó hơn 150 tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/hc5sx08wmaejtvs-1773660192-177-7780-1121-1773661244.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=LNd-fJ2ca-IcksyRHQAEoQ', '2026-03-20', 'admin', 69, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772246755400_37', 'Hai anh em tự chế robot xoay rubik', 'The Revenger, robot tự chế của hai anh em Matthew và Thomas Pidden (Anh), lập kỷ lục thế giới về thời gian giải khối rubik 4x4x4 ngắn nhất. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/fastestrobotrubikscubesolve-17-3568-2850-1773631148.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=EAVTJT68kNARAWkiP3hFxA', '2026-03-20', 'admin', 90, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772266388000_38', 'Apple ra AirPods Max 2 chống ồn tốt hơn, giá 15 triệu đồng', 'Apple giới thiệu tai nghe mới AirPods Max 2, nâng cấp chip H2 cho khả năng chống ồn tốt hơn, âm thanh trong hơn và giá 15 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/a1-1773670611-8930-1773670623.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YXtOtYKAp5Ft73wsxrs3QQ', '2026-03-20', 'admin', 274, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772283287700_39', '''Gia công phần mềm không thể giúp Việt Nam thành cường quốc công nghệ''', 'Thứ trưởng Khoa học và Công nghệ Bùi Hoàng Phương cho rằng gia công phần mềm đã giúp Việt Nam tạo bước đà quan trọng, nhưng không thể là cường quốc công nghệ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/img-20260316-152938-1773669614-8976-5107-1773670598.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=Ru-NOvXtbUlkUcZ1BIRHoA', '2026-03-20', 'admin', 450, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772299704000_40', '30 tỷ hình ảnh thu thập từ Pokémon Go được dùng để huấn luyện robot', 'Nhà phát triển Pokemon Go cho biết dữ liệu hơn 30 tỷ hình ảnh do người chơi chụp trên khắp thế giới sẽ được sử dụng để giúp robot giao hàng điều hướng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/pokemongoarkitarplus12-1773650-8370-3769-1773650701.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=_rb2RRMgsNT4PAItG74hAw', '2026-03-20', 'admin', 458, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772312644800_41', 'Internet vệ tinh Starlink dự kiến có giá 2,2 triệu mỗi tháng tại Việt Nam', 'Dịch vụ Internet vệ tinh Starlink tại Việt Nam dự kiến có giá thiết bị 9,2 triệu và cước thuê bao hàng tháng 2,2 triệu đồng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/dsc09672-1773648063-8230-1773648094.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=2WSUYcgmmB7a91fwi43szQ', '2026-03-20', 'admin', 360, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772326226700_42', 'Những điểm mới của AirTag 2 giá 890.000 đồng', 'AirTag 2, được bán tại Việt Nam từ 11/3, giữ nguyên giá 890.000 đồng như thế hệ trước, nhưng loa lớn hơn, kết nối và tìm thiết bị ở xa hơn nhờ chip Ultra Wideband 2. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/16/top-1773645893.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=cSgT8x6NSWNapzWGnFdGOg', '2026-03-20', 'admin', 292, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772339582600_43', 'Sony WF-1000XM6 nâng cấp chống ồn, âm thanh 32 TINYINT(1)', 'WF-1000XM6, tai nghe TWS đầu bảng của Sony, có khả năng khử ổn tốt hơn 25% so với thế hệ trước, khả năng xử lý âm thanh 32 TINYINT(1). (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/DSC4745-1773505278.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=GhkumNkfhEst4HeCg-d9iQ', '2026-03-20', 'admin', 426, 'TECH', 1, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772353430400_44', 'Giá chip nhớ sẽ ''bóp nghẹt'' phân khúc điện thoại giá rẻ', 'Chip nhớ liên tục tăng giá và chiếm tỷ trọng lớn trong cơ cấu giá thành smartphone, khiến nhiều nhà sản xuất điện thoại phải điều chỉnh giá bán. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/lq-02564-1773581233-5953-1773581381.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=rDhIfVGRp2SG-mhnN8CwMA', '2026-03-20', 'admin', 80, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772367139000_45', 'Cơn sốt OpenClaw ''đảo chiều'' tại Trung Quốc', 'Từng xếp hàng cài đặt OpenClaw, nhiều người dùng Trung Quốc hiện chi tiền nhờ gỡ tác nhân AI này khỏi thiết bị vì lo ngại bảo mật. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/dtzvzxmpaa8zmjow733zva-1773507-6806-9690-1773507531.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=waYhHQeLa8ZS6W29Nvysfg', '2026-03-20', 'admin', 25, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772380281000_46', 'Những tính năng có thể trang bị trên iPhone gập', 'Mẫu iPhone màn hình gập đầu tiên của Apple có thể mang tên Ultra, dùng chip 2 nm, bản lề kim loại lỏng và giá gần 3.000 USD. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/details-about-how-the-foldable-1417-8778-1773326630.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=lof6gO9Di_qFveCTNVt9Bg', '2026-03-20', 'admin', 193, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772394557600_47', 'Ông chủ ChatGPT: AI đang trở thành ''vật tế'' cho sa thải', 'CEO OpenAI Sam Altman cho rằng AI đang trở thành "vật tế", tức là lý do cho doanh nghiệp cắt giảm nhân sự và chi phí tiện ích gia tăng. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/2024-09-26t000000z-404445706-i-9716-5191-1773457349.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=nYTC2wlkLUDZVSeMPn0xPQ', '2026-03-20', 'admin', 390, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772409223300_48', 'Meta có thể sa thải nhân viên quy mô lớn vì AI', 'Meta cân nhắc cắt giảm lượng lớn nhân sự trong bối cảnh chi phí đầu tư hạ tầng AI tăng mạnh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/20230422-162819-1773565322-3641-1773565329.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=iuffS0dLXljqX89hG8R6nw', '2026-03-20', 'admin', 355, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772424681800_49', 'Bạn biết gì về ''đội quân vệ tinh'' quanh Trái Đất?', 'Hàng nghìn vệ tinh quay quanh Trái Đất, giúp định vị, chụp ảnh, cung cấp Internet và dự báo thời tiết. Bạn hiểu "đội quân" này đến đâu? (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/vetinh3-1773563004-3878-1773563019.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=zZyTaBcLQ2qNfJOWPcz75w', '2026-03-20', 'admin', 311, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772438051600_50', 'Đề xuất 84 công nghệ cao ưu tiên đầu tư phát triển', 'Bộ Khoa học và Công nghệ đang lấy ý kiến về dự thảo danh mục công nghệ cao, trong đó đề xuất ưu tiên nhiều lĩnh vực cốt lõi, như bán dẫn, AI và năng lượng mới. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/robot-vinmotion-1773513735-8782-1773513768.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=qJg1aEuyND-Dj1-rVhftXw', '2026-03-20', 'admin', 377, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772451502600_51', 'Cuộc thi Sáng kiến Khoa học 2026 thu hút nhiều giải pháp AI', 'Nhiều dự án, giải pháp AI đã gửi đơn đăng ký tham dự sân chơi khoa học thường niên do VnExpress tổ chức. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/lq-02564-1773502060-1794-1773502744.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JI58VqySOmOTAON5VQGJcA', '2026-03-20', 'admin', 15, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772464279500_52', 'Gen Z hoài niệm TikTok cũ', 'Khảo sát mới cho thấy người dùng Gen Z nhớ thời kỳ đầu của TikTok, khi bảng tin tràn ngập video ngắn ngẫu hứng, ít dàn dựng hay quảng cáo. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/11/afp-20200214-1p00jl-v1-highres-6897-6693-1773224629.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=r2aXe4pQUtBYZ9Q8Ee4zOw', '2026-03-20', 'admin', 468, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772477120100_53', 'Ngày Trái Đất dài ra với tốc độ kỷ lục', 'Nghiên cứu mới công bố cho thấy giai đoạn 2000-2020, ngày Trái Đất dài ra với tốc độ khoảng 1,33 mili giây mỗi thế kỷ. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/issm-1773488743-1773488762-3608-1773489247.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=iBbUUPgiAOuYfFqSs8kMvA', '2026-03-20', 'admin', 16, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772489925100_54', 'Khai trương trung tâm dữ liệu tỉnh Thái Nguyên', 'Trung tâm dữ liệu tỉnh Thái Nguyên gồm kho dữ liệu dùng chung, Trung tâm điều hành thông minh (IOC) và ứng dụng C-Thainguyen bản nâng cấp, vận hành từ ngày 13/3. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/15/trung-tam-du-lieu-thai-nguyen-3412-3995-1773538543.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=yjt19V_Z9dpvLz1frrGotQ', '2026-03-20', 'admin', 339, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772502783200_55', 'Robot hình người bị bắt vì dọa cụ bà 70 tuổi', 'Robot hình người Unitree G1 bị cảnh sát "áp giải" sau khi khiến một cụ bà hoảng sợ, phải vào bệnh viện kiểm tra. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/image1773167072elhrtgwi-177346-2458-4330-1773463991.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=JEzewjIFsbkiHtNGP9vtdA', '2026-03-20', 'admin', 406, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772516112800_56', 'Giá tiền ảo Pi tăng 50% sau giai đoạn lao dốc', 'Giá Pi Network tăng 50%, khiến cộng đồng tiền ảo sôi động trở lại, dù còn xa mức đỉnh, trong bối cảnh dự án tròn 7 năm tuổi. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/13/DSC03809JPG-1773400311-9360-1773400398.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=YjKrNJpCai3AbzGgF8Zg6Q', '2026-03-20', 'admin', 125, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772529219400_57', 'FPT đề xuất hướng tiếp cận cho giao thông bằng dữ liệu và AI', 'Theo đại diện FPT, phát triển hệ thống metro tại Việt Nam không chỉ là bài toán hạ tầng giao thông mà còn mở ra cơ hội hình thành nền tảng dữ liệu và công nghệ cho đô thị thông minh. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/fpt1-1773462928-9997-1773463036.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=p49nj9VIf7ps_es9EZq3-A', '2026-03-20', 'admin', 65, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772542449300_58', 'Nhà mạng phải ứng trực 24/24 ngày bầu cử', 'Doanh nghiệp viễn thông được yêu cầu duy trì chế độ trực lãnh đạo, trực ban và trực ứng cứu thông tin trong thời gian bầu cử đại biểu Quốc hội khóa XVI và đại biểu Hội đồng nhân dân các cấp. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/14/vien-thong-1773420845-17734209-6722-2961-1773423192.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=A7Xm4qsND1ROySTK9yZX6A', '2026-03-20', 'admin', 52, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
INSERT News (NewsId, Title, Content, Image, PostedDate, Author, ViewCount, CategoryId, Home, Status, SubCategory) VALUES ('AUTO_TECH_772555969500_59', 'Trung Quốc phát triển sợi carbon mỏng bằng 1/10 sợi tóc', 'Tập đoàn Vật liệu Xây dựng Quốc gia Trung Quốc (CNBM) chế tạo sợi carbon bền hơn thép nhưng mỏng bằng 1/10 sợi tóc, có thể dùng trong hàng không vũ trụ và nhiều ngành khác. (Nguồn: VNExpress)', 'https://i1-vnexpress.vnecdn.net/2026/03/12/27c37603ff8f49808e814579544349-9863-4654-1773307487.png?w=1200&h=0&q=100&dpr=1&fit=crop&s=aOBgter6H8sFNVePr_5GMw', '2026-03-20', 'admin', 186, 'TECH', 0, 1, 'AI - Trí tuệ nhân tạo');
